window.OBJECTIVES = [{"id":"1.1","domain":"1.0 General Security Concepts","label":"Security Controls"},{"id":"1.2","domain":"1.0 General Security Concepts","label":"Fundamental Security Concepts (CIA, AAA, Zero Trust)"},{"id":"1.3","domain":"1.0 General Security Concepts","label":"Change Management"},{"id":"1.4","domain":"1.0 General Security Concepts","label":"Cryptographic Solutions"},{"id":"2.1","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Threat Actors & Motivations"},{"id":"2.2","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Threat Vectors & Attack Surfaces"},{"id":"2.3","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Vulnerability Types"},{"id":"2.4","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Indicators of Malicious Activity"},{"id":"2.5","domain":"2.0 Threats, Vulnerabilities & Mitigations","label":"Mitigation Techniques"},{"id":"3.1","domain":"3.0 Security Architecture","label":"Architecture Models"},{"id":"3.2","domain":"3.0 Security Architecture","label":"Enterprise Infrastructure Security"},{"id":"3.3","domain":"3.0 Security Architecture","label":"Data Protection Concepts"},{"id":"3.4","domain":"3.0 Security Architecture","label":"Resilience & Recovery"},{"id":"4.1","domain":"4.0 Security Operations","label":"Securing Computing Resources & Hardening"},{"id":"4.2","domain":"4.0 Security Operations","label":"Asset Management"},{"id":"4.3","domain":"4.0 Security Operations","label":"Vulnerability Management"},{"id":"4.4","domain":"4.0 Security Operations","label":"Security Monitoring & Alerting"},{"id":"4.5","domain":"4.0 Security Operations","label":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)"},{"id":"4.6","domain":"4.0 Security Operations","label":"Identity & Access Management (IAM)"},{"id":"4.7","domain":"4.0 Security Operations","label":"Automation & Orchestration"},{"id":"4.8","domain":"4.0 Security Operations","label":"Incident Response"},{"id":"4.9","domain":"4.0 Security Operations","label":"Digital Forensics & Investigation Data Sources"},{"id":"5.1","domain":"5.0 Security Program Management & Oversight","label":"Security Governance"},{"id":"5.2","domain":"5.0 Security Program Management & Oversight","label":"Risk Management"},{"id":"5.3","domain":"5.0 Security Program Management & Oversight","label":"Third-Party Risk Management"},{"id":"5.4","domain":"5.0 Security Program Management & Oversight","label":"Security Compliance"},{"id":"5.5","domain":"5.0 Security Program Management & Oversight","label":"Audits & Assessments"},{"id":"5.6","domain":"5.0 Security Program Management & Oversight","label":"Security Awareness Training"}];
window.QUESTION_BANK = [{"id":1,"question":"A hospital IT department is implementing a security control that automatically blocks USB storage devices from connecting to workstations to prevent malware infections and data theft.","options":["Detective control","Corrective control","Preventive control","Compensating control"],"correctIndex":2,"explanation":"1. The core action is blocking the connection before it occurs. 2. Because it stops the threat from ever entering the system, it is categorized as preventive. 3. Detective or corrective controls would only address the issue after the USB was already connected.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":2,"question":"A financial company hires a third-party auditor to review firewall logs and identify suspicious activity after a security incident.","options":["Detective control","Preventive control","Directive control","Deterrent control"],"correctIndex":0,"explanation":"1. The auditor is reviewing logs of events that have already taken place[cite: 9]. 2. Identifying suspicious activity post-incident is a classic detective function[cite: 11]. 3. Unlike preventive controls, this does not stop the incident but ensures it is discovered and understood.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":3,"question":"An organization places warning signs around its data center stating that all activities are monitored and recorded.","options":["Corrective control","Deterrent control","Operational control","Preventive control"],"correctIndex":1,"explanation":"1. Warning signs are intended to discourage potential attackers by making them aware of consequences[cite: 15]. 2. This psychological discouragement defines a deterrent control[cite: 18]. 3. It does not physically block access (preventive) or fix a problem (corrective), but seeks to prevent the attempt entirely.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":4,"question":"A systems administrator restores corrupted files from a backup after a ransomware attack encrypted production servers.","options":["Preventive control","Detective control","Directive control","Corrective control"],"correctIndex":3,"explanation":"1. The organization is reacting to damage that has already been done by ransomware[cite: 21]. 2. Restoring from backups is a corrective action because it returns the system to a functional state[cite: 26]. 3. This control focuses on recovery rather than prevention or mere detection.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"100 questions Sec + v3.html"},{"id":5,"question":"A security analyst notices that customer data was altered without authorization during transmission between two servers.","options":["Availability","Confidentiality","Integrity","Non-repudiation"],"correctIndex":2,"explanation":"1. The scenario describes data being 'altered,' which refers to the consistency and accuracy of information[cite: 28]. 2. The 'I' in the CIA triad stands for Integrity, which ensures data remains unchanged by unauthorized parties[cite: 32]. 3. Confidentiality would be the concern if the data were merely seen, while Availability concerns access to the data.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"100 questions Sec + v3.html"},{"id":6,"question":"A law firm requires employees to digitally sign all contracts so the sender cannot later deny submitting the document.","options":["Authentication","Authorization","Accounting","Non-repudiation"],"correctIndex":3,"explanation":"1. Digital signatures provide a way to prove who sent a message[cite: 34]. 2. Non-repudiation ensures that a party cannot deny the authenticity of their signature or the sending of a document[cite: 39]. 3. This principle is vital for legal contracts to ensure accountability for all signatories.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"100 questions Sec + v3.html"},{"id":7,"question":"61. A security team creates a hardened baseline image for all company laptops before deployment. What is the PRIMARY purpose of the baseline? [cite: 306-307]","options":["Reduce backup size","Ensure consistent security configurations","Eliminate all malware","Increase processor performance"],"correctIndex":1,"explanation":"1. A security baseline defines a minimum set of security requirements and configurations. 2. Applying this image to all laptops ensures that every device starts with a known, secure configuration. 3. This consistency simplifies management and reduces the chance of configuration drift.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"61-80 Secv1.html"},{"id":8,"question":"62. An employee loses a company-issued smartphone containing confidential email. Which feature BEST protects company data? [cite: 307-308]","options":["Screen timeout","Mobile hotspot restriction","Remote wipe capability","Bluetooth pairing"],"correctIndex":2,"explanation":"1. Remote wipe is a mobile device management (MDM) feature that allows administrators to erase all data from a lost or stolen device. 2. This is the most effective way to prevent unauthorized access to confidential emails when the physical device is no longer in the owner's possession. 3. It ensures that even if the screen lock is bypassed, the sensitive data is no longer on the storage.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"61-80 Secv1.html"},{"id":9,"question":"63. A company configures wireless networks to require AES encryption and strong authentication for all users. Which wireless security standard BEST meets this requirement? [cite: 309-310]","options":["WEP","WPA","WPA3","Open authentication"],"correctIndex":2,"explanation":"1. WPA3 is the latest wireless security standard designed to provide enhanced protection for modern networks. 2. It mandates the use of AES-based encryption (GCMP) and offers stronger authentication through Simultaneous Authentication of Equals (SAE). 3. Unlike WEP or WPA, WPA3 addresses many of the cryptographic weaknesses found in earlier protocols.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"61-80 Secv1.html"},{"id":10,"question":"64. An organization executes suspicious applications inside an isolated environment to observe behavior without affecting production systems. Which technology is being used? [cite: 310-311]","options":["Honeypot","Sandboxing","Container orchestration","Tokenization"],"correctIndex":1,"explanation":"1. Sandboxing is a security mechanism for separating running programs to prevent system failures and software vulnerabilities from spreading. 2. It creates a tightly controlled environment where suspicious code can be executed without risk to the host operating system or network. 3. Analysts use this to observe malware behavior safely and determine its intended function.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":11,"question":"65. A company tracks all laptops using asset tags and inventory management software. Which operational function is being performed? [cite: 311-312]","options":["Vulnerability scanning","Asset management","Threat hunting","Penetration testing"],"correctIndex":1,"explanation":"1. Asset management is the process of tracking physical hardware and software licenses throughout their lifecycle. 2. Using asset tags and inventory software allows an organization to know exactly what devices are on the network and who is responsible for them. 3. This is a foundational security practice because you cannot protect what you do not know you have.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"61-80 Secv1.html"},{"id":12,"question":"66. A vulnerability scanner identifies outdated software versions on several servers. What should administrators do NEXT? [cite: 312-313]","options":["Ignore the findings","Replace the firewalls","Remediate the vulnerabilities","Disable logging"],"correctIndex":2,"explanation":"1. Once vulnerabilities are identified by a scanner, the next logical step in the lifecycle is remediation. 2. Remediation involves applying patches, changing configurations, or implementing compensating controls to fix the security gap. 3. Delaying this step leaves the organization exposed to potential exploitation of known weaknesses.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"61-80 Secv1.html"},{"id":13,"question":"67. A security analyst receives alerts whenever unusual outbound traffic volumes leave the corporate network. Which type of tool is MOST likely generating these alerts? [cite: 313-315]","options":["DHCP server","Load balancer","Intrusion detection system (IDS)","Proxy cache"],"correctIndex":2,"explanation":"1. An Intrusion Detection System (IDS) monitors network traffic for suspicious patterns and policy violations. 2. Unusual outbound traffic volumes can indicate data exfiltration or a botnet infection, triggering an alert. 3. While a firewall blocks traffic, the IDS focuses on visibility and alerting the security team to potential breaches.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"61-80 Secv1.html"},{"id":14,"question":"68. A company blocks access to known malicious domains before users can connect to them. Which enterprise security control is being used? [cite: 315-316]","options":["NAC","EDR","DNS filtering","Tokenization"],"correctIndex":2,"explanation":"1. DNS filtering prevents users from accessing specific IP addresses or domains by blocking them at the DNS level. 2. By preventing the resolution of known malicious domains, the organization stops the connection before it can ever be established. 3. This is a highly effective way to block phishing sites and malware command-and-control (C2) servers.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"61-80 Secv1.html"},{"id":15,"question":"69. A network only allows devices that meet company security requirements to connect to internal resources. Which technology is being implemented? [cite: 316-317]","options":["IDS","Network access control (NAC)","SIEM","DLP"],"correctIndex":1,"explanation":"1. Network Access Control (NAC) is a security solution that enforces policy-based access to network resources. 2. It evaluates the security posture of a device (e.g., antivirus status, patch level) before allowing it to connect to the internal network. 3. This ensures that only 'healthy' and authorized devices can access sensitive corporate data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"61-80 Secv1.html"},{"id":16,"question":"70. A security platform monitors endpoints, correlates activity across systems, and automates threat response actions. Which solution BEST fits this description? [cite: 317-318]","options":["VPN concentrator","NAC","XDR","Proxy server"],"correctIndex":2,"explanation":"1. Extended Detection and Response (XDR) provides a holistic view of security by integrating data from endpoints, networks, and cloud environments. 2. It correlates alerts from multiple sources to detect complex, multi-stage attacks that siloed tools might miss. 3. XDR also includes automated response capabilities to contain threats quickly across the entire infrastructure.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"61-80 Secv1.html"},{"id":17,"question":"71. A company deploys multifactor authentication for remote employees logging into cloud applications. What is the PRIMARY security benefit? [cite: 318-319]","options":["Increased network speed","Reduced backup size","Reduced risk of credential compromise","Elimination of phishing attacks"],"correctIndex":2,"explanation":"1. Multi-factor authentication (MFA) requires users to provide two or more verification factors to gain access. 2. Even if a password is stolen through phishing or a breach, the attacker cannot log in without the second factor (e.g., a phone app or token). 3. This significantly reduces the success rate of credential-based attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":18,"question":"72. A user authenticates once and gains access to several approved applications without re-entering credentials. Which identity solution is being used? [cite: 319-320]","options":["Federation","Single sign-on (SSO)","Tokenization","Privileged escalation"],"correctIndex":1,"explanation":"1. Single Sign-On (SSO) allows a user to log in once and gain access to a variety of interconnected systems. 2. It improves user experience and security by reducing the number of passwords a user must remember and manage. 3. From an admin perspective, it centralizes access control and simplifies the deprovisioning process.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":19,"question":"73. A company grants temporary elevated privileges to administrators only when critical maintenance tasks are performed. Which security tool is MOST likely being used? [cite: 320-322]","options":["IDS","DLP","Privileged access management (PAM)","SIEM"],"correctIndex":2,"explanation":"1. Privileged Access Management (PAM) consists of technologies to exercise control over elevated access. 2. It allows for 'just-in-time' privilege elevation, granting high-level rights only when a specific task needs to be performed. 3. This prevents persistent administrative access, which is a major target for attackers.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"61-80 Secv1.html"},{"id":20,"question":"74. A security operations team uses scripts to automatically isolate infected endpoints after malware is detected. Which concept is being demonstrated? [cite: 322-323]","options":["Risk acceptance","Automation and orchestration","Data classification","High availability"],"correctIndex":1,"explanation":"1. Security Orchestration, Automation, and Response (SOAR) uses playbooks to execute repetitive security tasks without human intervention. 2. Automatically isolating an infected endpoint as soon as malware is detected minimizes the 'dwell time' of the threat. 3. This rapid response helps prevent lateral movement and limits the overall damage of an incident.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":21,"question":"75. After detecting suspicious activity, a company follows a documented process to identify, contain, eradicate, and recover from the attack. Which process is being executed? [cite: 323-324]","options":["Business continuity planning","Incident response","Change management","Disaster recovery testing"],"correctIndex":1,"explanation":"1. Incident response is a structured process used by organizations to handle security breaches and cyberattacks. 2. The standard phases include preparation, identification, containment, eradication, recovery, and lessons learned. 3. Following a documented plan ensures that the response is consistent, efficient, and thorough.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"61-80 Secv1.html"},{"id":22,"question":"76. A security analyst reviews firewall, server, and authentication logs to determine how an attacker gained access. Which investigation activity is occurring? [cite: 324-325]","options":["Vulnerability remediation","Risk transference","Digital forensics analysis","Configuration baselining"],"correctIndex":2,"explanation":"1. Digital forensics analysis involves the collection and examination of digital evidence after a security event. 2. Reviewing logs and system artifacts helps investigators reconstruct the timeline of an attack and identify the root cause. 3. This detailed analysis is vital for understanding how the breach occurred and preventing future recurrences.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"61-80 Secv1.html"},{"id":23,"question":"77. A company conducts proactive searches through logs and endpoint data to identify hidden threats that automated tools may have missed. Which activity is this? [cite: 325-327]","options":["Penetration testing","Threat hunting","Asset tagging","Load balancing"],"correctIndex":1,"explanation":"1. Threat hunting is a proactive security exercise where analysts manually search through data for indicators of compromise (IoCs). 2. It assumes that attackers may have already bypassed automated defenses and are hiding within the network. 3. By actively looking for anomalies, hunting teams can discover sophisticated 'living off the land' attacks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"61-80 Secv1.html"},{"id":24,"question":"78. An organization configures DLP rules to prevent employees from emailing customer credit card numbers outside the company. Which objective is MOST directly supported? [cite: 327-328]","options":["Availability","Authentication","Preventing data exfiltration","Network redundancy"],"correctIndex":2,"explanation":"1. Data Loss Prevention (DLP) tools are designed to identify and block the unauthorized transfer of sensitive information. 2. Detecting credit card numbers in outbound emails allows the system to stop the message before the data leaves the organization. 3. This directly supports the confidentiality of customer data and helps maintain regulatory compliance.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"61-80 Secv1.html"},{"id":25,"question":"79. A system administrator removes inactive user accounts after employees leave the company. Which IAM activity is being performed? [cite: 328-329]","options":["Federation","Deprovisioning","Accounting","Threat hunting"],"correctIndex":1,"explanation":"1. Deprovisioning is the process of removing or disabling user access to systems and data when it is no longer required. 2. Regularly removing inactive accounts from former employees is a critical security hygiene practice. 3. It prevents 'orphan accounts' from being exploited by attackers to gain unauthorized entry to the network.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"61-80 Secv1.html"},{"id":26,"question":"80. A security team validates that vulnerabilities were successfully fixed after patches were installed. Which step of vulnerability management is occurring? [cite: 329-330]","options":["Identification","Reporting","Prioritization","Validation"],"correctIndex":3,"explanation":"1. Validation is the final step in the vulnerability management cycle where administrators confirm that a fix was successful. 2. Re-scanning systems after patching ensures that the vulnerability is truly gone and no new issues were introduced. 3. Without validation, an organization might mistakenly believe they are protected when the patch failed to install correctly.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"61-80 Secv1.html"},{"id":27,"question":"A company creates a written document that defines acceptable employee behavior when using corporate systems. What type of governance document is this? [cite: 330-332]","options":["Standard","Procedure","Policy","Guideline"],"correctIndex":2,"explanation":"1. A policy is a high-level document that outlines an organization's requirements and goals regarding security. 2. It sets the foundation for acceptable use by defining what is and isn't allowed. 3. Policies are generally mandatory and form the top tier of the governance hierarchy.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"81-100 Secv1.html"},{"id":28,"question":"A security team documents detailed step-by-step instructions for configuring firewalls. What type of governance document is this? [cite: 332-333]","options":["Policy","Guideline","Standard","Procedure"],"correctIndex":3,"explanation":"1. Procedures provide the 'how-to' for specific tasks through sequential steps. 2. They ensure consistency by providing a repeatable process for technical actions. 3. While policies say what to do, procedures provide the exact map to get it done.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"81-100 Secv1.html"},{"id":29,"question":"A company requires all passwords to contain at least 14 characters and include special symbols. What type of governance element is this? [cite: 333-334]","options":["Procedure","Standard","Risk register","Guideline"],"correctIndex":1,"explanation":"1. Standards define specific mandatory requirements or benchmarks for technology and configurations. 2. Password complexity requirements are a classic example of a security standard. 3. Standards ensure that security levels are uniform across all systems in the organization.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":30,"question":"A business identifies a risk but decides the cost of mitigation is higher than the potential damage. Which risk strategy is being applied? [cite: 334-335]","options":["Risk transfer","Risk avoidance","Risk acceptance","Risk mitigation"],"correctIndex":2,"explanation":"1. Risk acceptance is a conscious decision to acknowledge a risk without taking action to reduce it. 2. This is typically done when the cost-benefit analysis shows that fixing the risk is too expensive. 3. It implies that the organization is willing to absorb the impact if the threat occurs.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":31,"question":"A company purchases cyber insurance to reduce the financial impact of future security incidents. Which risk management strategy is being used? [cite: 335-336]","options":["Risk acceptance","Risk transfer","Risk avoidance","Risk escalation"],"correctIndex":1,"explanation":"1. Risk transfer moves the financial burden of a risk to a third party. 2. Insurance is the most common method of transferring risk, as the insurer pays for losses. 3. It doesn't eliminate the risk itself but mitigates the negative economic consequences.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"81-100 Secv1.html"},{"id":32,"question":"A security manager calculates the potential financial impact of a ransomware attack on business operations. Which process is being performed? [cite: 336-337]","options":["Penetration testing","Business impact analysis (BIA)","Threat hunting","Vulnerability scanning"],"correctIndex":1,"explanation":"1. A BIA evaluates the potential consequences of disrupting critical business functions. 2. It calculates financial and operational impacts to help prioritize recovery efforts. 3. This process identifies recovery time objectives (RTOs) and recovery point objectives (RPOs).","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":33,"question":"An organization maintains a document listing identified risks, likelihood, impact, and mitigation plans. What is this document called? [cite: 338-339]","options":["Security baseline","Configuration guide","Risk register","Audit report"],"correctIndex":2,"explanation":"1. A risk register is a central repository for all identified risks facing an organization. 2. It tracks the status of risks and the owners responsible for managing them. 3. This document is a living artifact used for ongoing risk monitoring and reporting.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":34,"question":"Before hiring a cloud provider, a company reviews security practices, compliance certifications, and service agreements. Which process is occurring? [cite: 339-340]","options":["Threat hunting","Vendor assessment","Digital forensics","Patch validation"],"correctIndex":1,"explanation":"1. Vendor assessments ensure third parties meet an organization's security standards. 2. This process involves verifying that the provider has proper controls in place. 3. It is critical for managing supply chain risk and protecting shared data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"81-100 Secv1.html"},{"id":35,"question":"A penetration testing agreement clearly defines what systems can be tested and what activities are prohibited. What section of the agreement is this? [cite: 340-341]","options":["Recovery objective","Rules of engagement","Separation of duties","Asset inventory"],"correctIndex":1,"explanation":"1. Rules of Engagement (RoE) define the parameters and constraints of a security test. 2. They protect the organization from unintended downtime during testing. 3. RoEs ensure that both the tester and the client have a clear understanding of the project's scope.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":36,"question":"A healthcare provider must comply with regulations protecting patient privacy and medical records. What security area is MOST directly involved? [cite: 341-342]","options":["Asset management","Compliance and privacy","Platform diversity","Sandboxing"],"correctIndex":1,"explanation":"1. Compliance involves adhering to laws, regulations, and industry standards like HIPAA. 2. Privacy focuses on the legal right of individuals to control their personal information. 3. Healthcare providers are heavily regulated to ensure sensitive patient data remains confidential.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"81-100 Secv1.html"},{"id":37,"question":"An external auditor independently reviews company controls to confirm regulatory compliance. Which process is occurring? [cite: 342-344]","options":["Threat intelligence","Risk acceptance","External audit","Threat hunting"],"correctIndex":2,"explanation":"1. An external audit is an objective review performed by a third party outside the organization. 2. It provides an unbiased validation that security controls are functioning as intended. 3. These audits are often required by law or for specific industry certifications.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":38,"question":"A company performs a simulated cyberattack to evaluate the effectiveness of its defenses. Which assessment method is being used? [cite: 344-345]","options":["Vulnerability scanning","Penetration testing","Configuration management","Asset tracking"],"correctIndex":1,"explanation":"1. Penetration testing is an active attempt to exploit vulnerabilities to see if a breach is possible. 2. It goes beyond scanning by simulating the actual methods used by attackers. 3. The results help organizations understand the real-world impact of their security gaps.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"81-100 Secv1.html"},{"id":39,"question":"A manager signs a document formally confirming that implemented security controls meet compliance requirements. What is this process called? [cite: 345-346]","options":["Tokenization","Attestation","Threat modeling","Change approval"],"correctIndex":1,"explanation":"1. Attestation is a formal statement by a person in authority that a control is operating correctly. 2. It provides evidence for auditors that management is taking responsibility for compliance. 3. This process is a key part of financial and security reporting frameworks.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":40,"question":"Employees receive regular simulated phishing emails followed by training when they click suspicious links. What is the PRIMARY goal? [cite: 346-347]","options":["Improve encryption strength","Increase server uptime","Security awareness training","Reduce backup costs"],"correctIndex":2,"explanation":"1. Security awareness programs aim to reduce human-related risks by educating staff. 2. Phishing simulations teach employees to recognize and report social engineering attempts. 3. Improving the human firewall is often more effective than technical controls alone.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":41,"question":"A security team notices a user logging in from two different countries within ten minutes. What should the organization encourage employees to do? [cite: 347-349]","options":["Ignore the activity","Delete system logs","Report anomalous behavior","Disable MFA"],"correctIndex":2,"explanation":"1. This scenario describes 'impossible travel,' a strong indicator of account compromise. 2. Reporting anomalous behavior allows the security team to investigate and contain potential breaches quickly. 3. Vigilance by both employees and automated systems is essential for early threat detection.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"81-100 Secv1.html"},{"id":42,"question":"An organization separates financial transaction approval responsibilities between two employees to reduce fraud risk. Which principle is applied? [cite: 350-351]","options":["Least privilege","Separation of duties","Zero trust","Sandboxing"],"correctIndex":1,"explanation":"1. Separation of duties ensures that no single person has enough power to complete a critical task alone. 2. This control requires collusion for fraud to occur, making malicious activity much harder. 3. It is a fundamental administrative control for maintaining integrity and accountability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"81-100 Secv1.html"},{"id":43,"question":"A company enforces mandatory vacations for employees handling financial systems to help identify fraudulent activities. Which risk management concept is this? [cite: 351-352]","options":["High availability","Job rotation","Operational oversight control","Threat intelligence"],"correctIndex":1,"explanation":"1. Mandatory vacations are a security control where employees must take time off, allowing others to step in. 2. While away, any ongoing fraudulent schemes may be uncovered when the substitute takes over. 3. This is often categorized alongside job rotation as a personnel security control.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"81-100 Secv1.html"},{"id":44,"question":"A security administrator conducts regular reviews to ensure employees only retain access necessary for their current roles. What process is being performed? [cite: 352-353]","options":["Data masking","Access review and recertification","Threat hunting","Load balancing"],"correctIndex":1,"explanation":"1. Access reviews prevent 'privilege creep,' where users accumulate rights they no longer need. 2. Recertification requires managers to periodically confirm that their employees' access is still appropriate. 3. This maintains the principle of least privilege throughout the employee lifecycle.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"81-100 Secv1.html"},{"id":45,"question":"A company develops disaster recovery plans and performs tabletop exercises to evaluate response during emergencies. What is the PRIMARY purpose? [cite: 353-354]","options":["Increase processor speed","Test preparedness and response effectiveness","Reduce software licensing costs","Improve wireless coverage"],"correctIndex":1,"explanation":"1. Tabletop exercises are discussion-based sessions that walk through a simulated disaster scenario. 2. They allow key personnel to practice their roles and identify flaws in the recovery plan. 3. This preparedness ensures a faster, more effective response when a real crisis occurs.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"81-100 Secv1.html"},{"id":46,"question":"An organization monitors regulatory changes and updates internal policies to maintain legal compliance. Which activity is MOST directly being performed? [cite: 355]","options":["Threat hunting","Asset disposal","Governance and compliance monitoring","Sandboxing"],"correctIndex":2,"explanation":"1. Governance and compliance monitoring is the ongoing process of staying aligned with legal requirements. 2. As laws like GDPR or CCPA evolve, internal policies must be updated to avoid fines and liability. 3. This proactive approach ensures the organization remains legally protected and operationally compliant.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"81-100 Secv1.html"},{"id":47,"question":"A healthcare org is migrating a claims app to SaaS. The BIA shows severe impact if the provider is down, but leadership refuses additional budget this quarter. What should security do NEXT to keep governance intact?","options":["Document the residual risk and present it for formal acceptance by leadership","Purchase a secondary SaaS subscription immediately using the emergency response fund","Inform the cloud provider that they must maintain 100% uptime per healthcare laws","Delay the migration indefinitely until the budget for redundancy is approved"],"correctIndex":0,"explanation":"When a security gap is identified but cannot be mitigated due to budget or business constraints, it must be formally documented in the risk register. This ensures that leadership is aware of the potential impact and takes accountability for the risk. This process maintains governance by keeping an audit trail of informed decision-making.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":48,"question":"A vulnerability scan identifies an end-of-life (EOL) operating system on a critical legacy server that runs an essential proprietary application. What is the BEST risk mitigation strategy?","options":["Decommission the server immediately to prevent exploitation","Isolate the server on a dedicated VLAN with strict firewall rules","Install a third-party antivirus tool to block all known exploits","Submit a bug report to the OS vendor requesting an emergency patch"],"correctIndex":1,"explanation":"End-of-life systems no longer receive security updates, making them permanently vulnerable to new exploits. If the system cannot be replaced, network isolation through a VLAN or 'sandboxing' restricts its communication to only what is necessary. This prevents lateral movement and reduces the server's exposure to the rest of the network.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Overall 81-100 v1.html"},{"id":49,"question":"An administrator wants to ensure that only approved software can run on company laptops. Which technology provides the STRONGEST protection against unauthorized binaries?","options":["Application Allowlisting","Heuristic Antivirus","File Integrity Monitoring (FIM)","Standard User Permissions"],"correctIndex":0,"explanation":"Application allowlisting (or blocklisting) explicitly defines which executables are permitted to run on a system. Unlike antivirus, which looks for known bad files, allowlisting prevents anything not specifically authorized from executing. This is highly effective against zero-day malware and unauthorized 'shadow IT' applications.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall 81-100 v1.html"},{"id":50,"question":"While reviewing system logs, a security analyst notices that a web server is making high volumes of DNS queries for random subdomains of a known malicious domain. What is this indicative of?","options":["DNS Sinkholing","DNS Beaconing/Exfiltration","BGP Route Hijacking","Domain Sharding"],"correctIndex":1,"explanation":"DNS beaconing is a common command-and-control (C2) technique where malware 'calls home' to a server by making DNS requests. Attackers can also encode stolen data into the subdomain portion of the query to exfiltrate it past firewalls. Monitoring for unusual DNS volume or patterns is a key part of incident detection.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall 81-100 v1.html"},{"id":51,"question":"Which of the following is the primary purpose of a 'Purge' sanitization method on a magnetic hard drive?","options":["Removing data such that it cannot be recovered even by laboratory techniques","Formatting the drive using a high-level operating system command","Deleting the file allocation table while leaving the raw data intact","Resetting the drive to factory default settings without overwriting sectors"],"correctIndex":0,"explanation":"Purging is a media sanitization level that protects against robust laboratory attacks. It typically involves techniques like degaussing or multiple-pass overwriting to ensure no residual data can be reconstructed. This is more intensive than 'Clear,' which only protects against standard software recovery tools.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall 81-100 v1.html"},{"id":52,"question":"A security engineer is configuring a new server. They disable the print spooler service, remove unused sample code, and close all ports except 443. Which process is being performed?","options":["Vulnerability Assessment","System Hardening","Penetration Testing","Patch Management"],"correctIndex":1,"explanation":"System hardening is the process of reducing the attack surface by removing unnecessary software, services, and users. By closing unused ports and disabling non-essential features, the engineer limits the entry points available to an attacker. This is a proactive security measure recommended for every enterprise deployment.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":53,"question":"Which cloud service model provides the customer with the MOST control over the operating system and middleware?","options":["Software as a Service (SaaS)","Platform as a Service (PaaS)","Infrastructure as a Service (IaaS)","Function as a Service (FaaS)"],"correctIndex":2,"explanation":"In the Infrastructure as a Service (IaaS) model, the provider only manages the hardware and virtualization layer. The customer is responsible for installing, patching, and securing the operating system and everything above it. This offers maximum flexibility but also the highest security management burden for the user.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Overall 81-100 v1.html"},{"id":54,"question":"A vulnerability scanner reports a 'False Positive' on a web server. How should the security team respond?","options":["Ignore the report and disable the scanner for that specific server","Verify the vulnerability manually or via secondary tools","Immediately apply the recommended patch to ensure compliance","Delete the vulnerability scan history to clear the audit trail"],"correctIndex":1,"explanation":"False positives occur when a scanner incorrectly identifies a vulnerability that does not actually exist. The team must manually investigate to confirm the finding before dedicating resources to remediation. Accurate verification prevents unnecessary downtime and ensures the team focuses on real risks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Overall 81-100 v1.html"},{"id":55,"question":"An organization wants to detect unauthorized changes to critical system files in real-time. Which tool is BEST suited for this?","options":["File Integrity Monitoring (FIM)","Network Intrusion Detection System (NIDS)","Log Aggregator","Vulnerability Scanner"],"correctIndex":0,"explanation":"File Integrity Monitoring (FIM) tools compute hashes of system files and alert administrators if those hashes change. This is critical for detecting rootkits or unauthorized modifications by malicious insiders. FIM is often a requirement for compliance standards like PCI DSS.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall 81-100 v1.html"},{"id":56,"question":"What is the primary benefit of using a CASB (Cloud Access Security Broker)?","options":["It provides physical security for cloud data centers","It enforces security policies between on-premises users and cloud providers","It replaces the need for a corporate firewall and VPN","It automates the deployment of virtual machines in the cloud"],"correctIndex":1,"explanation":"A CASB acts as a security enforcement point between cloud users and cloud applications. It provides visibility into 'Shadow IT' and enforces policies like data loss prevention (DLP) and encryption. This helps organizations maintain a consistent security posture across multiple cloud environments.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall 81-100 v1.html"},{"id":57,"question":"Which attack involves taking advantage of the trust a user's browser has in a website?","options":["XSRF (CSRF)","SQLi","XSS","Buffer Overflow"],"correctIndex":0,"explanation":"XSRF (Cross-Site Request Forgery) exploits the trust a site has in a user's browser to execute unwanted actions. You arrive at this answer by focusing on the 'trust a user's browser has in a website' key phrase. It forces an authenticated user to submit a request that the web application perceives as legitimate.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":58,"question":"An attacker uses a computer to repeatedly ping a server until it crashes. What type of attack is this?","options":["DoS","DDoS","MITM","Spoofing"],"correctIndex":0,"explanation":"A Denial of Service (DoS) attack aims to make a service unavailable by overwhelming it with requests from a single source. In this scenario, a single computer is used to crash a server via pings, matching the DoS definition. This differs from a DDoS, which utilizes multiple distributed systems to achieve the same result.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":59,"question":"Which of the following is a 'Supply Chain Attack'?","options":["Compromising a software vendor","Guessing a user's password","Sending a phishing email","Stealing a laptop"],"correctIndex":0,"explanation":"A Supply Chain attack targets the third-party vendors and software providers that an organization trusts. By injecting malicious code into a vendor's update, the attacker gains access to all of that vendor's customers simultaneously. This is a high-impact threat because it bypasses traditional perimeter defenses by riding on trusted software.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":60,"question":"What is 'Typosquatting'?","options":["Registering domains with slight misspellings","Stealing data from a keyboard buffer","Watching someone type a password","Breaking a physical keyboard"],"correctIndex":0,"explanation":"Typosquatting relies on users making small typing errors when manually entering a web address into a browser. Attackers register these misspelled domains to lead users to malicious clones of popular sites for credential harvesting. It is a common social engineering tactic that exploits human error in navigation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":61,"question":"Which threat actor is usually motivated by political or social causes?","options":["Script Kiddie","APT","Hacktivist","Insider Threat"],"correctIndex":2,"explanation":"Hacktivists are threat actors motivated by social, political, or religious ideologies rather than financial gain. Their primary goal is usually to draw attention to a specific cause or protest a government or corporation. This distinguishes them from organized crime groups who are typically driven by monetary profit.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall Sec 41-80v1.html"},{"id":62,"question":"Which network device uses ACLs to filter traffic based on IP addresses and ports?","options":["Switch","Router","Firewall","Hub"],"correctIndex":2,"explanation":"Firewalls use Access Control Lists (ACLs) to filter incoming and outgoing traffic based on source/destination IP addresses and port numbers. They act as the primary barrier between different network zones to enforce specific security policies. You arrive at this answer because the question specifically mentions filtering via IPs and ports.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":63,"question":"A company wants to encrypt all traffic between two offices over the internet. What should they use?","options":["VLAN","Site-to-Site VPN","Remote Access VPN","Honeypot"],"correctIndex":1,"explanation":"A Site-to-Site VPN creates a secure, encrypted tunnel between two physical office locations over the public internet. This allows users in different offices to access shared resources as if they were on the same local network. It is the industry-standard solution for connecting branch offices securely.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":64,"question":"Which protocol is used to secure web traffic?","options":["HTTP","FTP","HTTPS (TLS)","SNMP"],"correctIndex":2,"explanation":"HTTPS uses TLS (Transport Layer Security) to encrypt communication between a web browser and a server. It ensures that data remains confidential while also providing server authentication through digital certificates. This is the fundamental protocol for secure web browsing and e-commerce today.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":65,"question":"What is the purpose of a 'DMZ'?","options":["To store internal databases","To provide a buffer for public-facing services","To encrypt internal emails","To manage user passwords"],"correctIndex":1,"explanation":"A DMZ (Demilitarized Zone) is a subnetwork that sits between the internal private network and the public internet. It hosts public-facing services like web or mail servers to prevent external users from accessing the internal network directly. This adds a critical layer of defense-in-depth for organizational assets.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":66,"question":"Which technology allows multiple isolated networks to exist on a single physical switch?","options":["VPN","VLAN","NAT","DHCP"],"correctIndex":1,"explanation":"A Virtual Local Area Network (VLAN) segments a single physical switch into multiple isolated logical networks. It improves security by restricting broadcast domains and controlling traffic flow between different departments. This allows for flexible network management without requiring additional physical hardware.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Overall Sec 41-80v1.html"},{"id":67,"question":"Which cloud service model provides the consumer with the most control over the OS?","options":["SaaS","PaaS","IaaS","XaaS"],"correctIndex":2,"explanation":"Infrastructure as a Service (IaaS) provides virtualized computing resources like servers, storage, and networking over the internet. In this model, the customer has the most control because they are responsible for managing the operating system and applications. You arrive at this answer by identifying the high level of OS-level control granted to the user.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Overall Sec 41-80v1.html"},{"id":68,"question":"A security admin wants to prevent unauthorized devices from connecting to a switch port. What should they implement?","options":["Port Security (MAC Filtering)","Loop Protection","VLAN Tagging","Spanning Tree"],"correctIndex":0,"explanation":"Port Security (specifically MAC Filtering) limits which devices can connect to a physical switch port based on their unique hardware address. It prevents unauthorized hardware from being plugged into the network in empty cubicles or public areas. This is a vital Layer 2 security control for managing physical office access.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall Sec 41-80v1.html"},{"id":69,"question":"Which protocol is used to securely manage network devices?","options":["Telnet","SSH","FTP","SNMPv1"],"correctIndex":1,"explanation":"Secure Shell (SSH) provides an encrypted channel for managing network devices and servers remotely. It was designed as a secure replacement for Telnet, which sent login credentials and data in cleartext. You arrive at this answer because it is the global standard for 'securely managing' infrastructure.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":70,"question":"What does 'Load Balancing' primarily provide?","options":["Confidentiality","Availability","Integrity","Non-repudiation"],"correctIndex":1,"explanation":"Load balancing distributes incoming network traffic across multiple servers to ensure that no single server becomes overwhelmed. This directly supports the goal of Availability by providing redundancy and preventing service downtime during traffic spikes. You arrive at this answer by linking traffic distribution to system uptime.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":71,"question":"A company moving to the cloud wants a dedicated, private connection to the provider. What is this called?","options":["Public Cloud","Community Cloud","Direct Connect / ExpressRoute","Hybrid Cloud"],"correctIndex":2,"explanation":"Cloud providers offer dedicated, private network connections (like AWS Direct Connect or Azure ExpressRoute) that bypass the public internet entirely. These provide more consistent performance, lower latency, and improved security for enterprise workloads. This is the preferred method for hybrid cloud environments requiring high-speed data transfer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":72,"question":"Which of the following is used to store and manage digital certificates?","options":["SIEM","PKI","IDS","UTM"],"correctIndex":1,"explanation":"Public Key Infrastructure (PKI) is the framework of hardware, software, and policies used to manage and distribute digital certificates. It enables the secure exchange of data by providing identity verification via a trusted third party. You arrive at this answer by associating the management of certificates with its governing architecture.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":73,"question":"Which standard is used for network-based authentication (Port-based)?","options":["802.11","802.1X","802.3","802.1Q"],"correctIndex":1,"explanation":"802.1X is an IEEE standard for port-based network access control (PNAC) on wired and wireless networks. It requires devices to authenticate with a central server (like RADIUS) before they are granted access to the physical network. This ensures that only authorized users and devices can connect to the organization's ports.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall Sec 41-80v1.html"},{"id":74,"question":"Which of the following is an 'Air Gap'?","options":["A network with no physical/wireless connection","A high-speed fiber connection","A type of firewall","A ventilated server room"],"correctIndex":0,"explanation":"An Air Gap is a security measure that ensures a network is physically isolated from all other networks, including the internet. It is used for highly sensitive systems where the risk of remote intrusion or data exfiltration must be minimized to zero. You arrive at this answer because the description mentions a network with no physical or wireless connections.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":75,"question":"Which technology translates private IP addresses to a public IP address?","options":["DNS","NAT","DHCP","ARP"],"correctIndex":1,"explanation":"Network Address Translation (NAT) allows multiple devices on a private network to share a single public IP address for internet access. It hides the internal network structure from the outside world while conserving the limited pool of IPv4 addresses. This translation typically occurs at the perimeter router or firewall level.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":76,"question":"What is a 'CASB'?","options":["A home firewall","A security tool between cloud users and apps","A secure cable","A biometric scanner"],"correctIndex":1,"explanation":"A Cloud Access Security Broker (CASB) is a tool that enforces security policies between cloud service users and cloud applications. It provides visibility into cloud usage, data protection (DLP), and threat prevention for SaaS platforms. You arrive at this answer because it sits specifically between the 'cloud user' and the 'cloud application.'","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":77,"question":"Which of the following is a stateless inspection?","options":["Monitoring the entire conversation","Checking each packet individually","Blocking based on geography","Inspecting encrypted packets"],"correctIndex":1,"explanation":"Stateless inspection (or packet filtering) examines each packet individually without considering the context of the entire connection. It is faster than stateful inspection but less secure because it doesn't track the 'state' or flow of sessions. You arrive at this answer because the description specifies checking 'each packet individually.'","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":78,"question":"A company uses a single sign-on (SSO) solution. Which protocol might they be using?","options":["SAML","WPA3","TKIP","SNMP"],"correctIndex":0,"explanation":"Security Assertion Markup Language (SAML) is an XML-based standard used for exchanging authentication and authorization data. It is the primary protocol used to enable Single Sign-On (SSO) across different web applications and domains. This allows a user to log in once and access multiple services seamlessly.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":79,"question":"Which of the following is a symmetric encryption algorithm?","options":["RSA","ECC","AES","Diffie-Hellman"],"correctIndex":2,"explanation":"Advanced Encryption Standard (AES) is a symmetric block cipher used worldwide to secure sensitive data. Symmetric encryption uses the same key for both encryption and decryption, making it significantly faster for large amounts of data. You arrive at this answer by identifying it as a common 'symmetric' algorithm compared to asymmetric ones like RSA.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":80,"question":"What is the purpose of 'Hashing'?","options":["To encrypt data for storage","To provide integrity via a unique fixed value","To hide data in an image","To speed up the network"],"correctIndex":1,"explanation":"Hashing takes an input of any size and produces a unique, fixed-length string of characters (a digest). Because even a tiny change in the input results in a completely different hash, it is used to verify data integrity. You arrive at this answer by focusing on the goal of creating a 'unique fixed-length value' for verification.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":81,"question":"Which protocol provides secure file transfers?","options":["TFTP","SFTP","FTP","Telnet"],"correctIndex":1,"explanation":"SSH File Transfer Protocol (SFTP) uses the Secure Shell (SSH) protocol to provide a secure, encrypted tunnel for moving files. It is superior to standard FTP, which transmits data and passwords in cleartext. You arrive at this answer by seeking the protocol that provides 'secure file transfers' via encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":82,"question":"What is a 'Honeypot'?","options":["A password vault","A decoy system to study attackers","A type of malware","A high-speed server"],"correctIndex":1,"explanation":"A Honeypot is a decoy system designed to look like a high-value target to lure in attackers. It allows security teams to study the attacker's methods and divert them from real production systems. You arrive at this answer because it is described as a 'decoy system' for study and distraction purposes.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall Sec 41-80v1.html"},{"id":83,"question":"Which concept involves keeping the same encryption key for only a short period?","options":["Key Stretching","Ephemeral Keys","Key Escrow","Key Revocation"],"correctIndex":1,"explanation":"Ephemeral keys are temporary cryptographic keys generated for a single session or transaction and then discarded. By frequently changing keys, an organization ensures that even if one key is compromised, past and future sessions remain secure. This concept is a core component of achieving Perfect Forward Secrecy (PFS).","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":84,"question":"Which type of hypervisor runs directly on the hardware?","options":["Type 1 (Bare Metal)","Type 2 (Hosted)","Type 3 (Cloud)","Container"],"correctIndex":0,"explanation":"A Type 1 hypervisor (Bare Metal) runs directly on the host's hardware to manage guest operating systems. It is more efficient and secure than Type 2 hypervisors, which must run on top of a host operating system. You arrive at this answer because the scenario specifies running 'directly on the hardware.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":85,"question":"A mobile device is lost. The admin wants to delete all data on it remotely. What is this called?","options":["Remote Wipe","Geofencing","Sideloading","Jailbreaking"],"correctIndex":0,"explanation":"Remote Wipe is a security feature that allows an administrator to erase all data on a mobile device from a distance. It is a critical control for protecting corporate data when a phone or tablet is lost or stolen. You arrive at this answer because the goal is to 'delete all data' on a lost device.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":86,"question":"Which technology provides a centralized way to manage and automate network security?","options":["SDN (Software Defined Networking)","VLAN","Hub","Repeater"],"correctIndex":0,"explanation":"Software-Defined Networking (SDN) decouples the network control plane from the forwarding plane (data plane). This allows for centralized management and programmable automation of network traffic and security policies. You arrive at this answer because it describes a 'centralized way to manage and automate' network logic.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Overall Sec 41-80v1.html"},{"id":87,"question":"Which tool is used to aggregate and correlate logs from multiple sources?","options":["IDS","SIEM","DLP","UPS"],"correctIndex":1,"explanation":"Security Information and Event Management (SIEM) tools collect and analyze log data from throughout the enterprise. They correlate disparate events to identify potential security threats that might be missed by individual systems. You arrive at this answer because the tool's primary role is to 'aggregate and correlate logs.'","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Overall Sec 41-80v1.html"},{"id":88,"question":"What is the first step in the Incident Response process?","options":["Eradication","Preparation","Containment","Recovery"],"correctIndex":1,"explanation":"Preparation is the foundational stage of the incident response lifecycle where policies, teams, and tools are established. It ensures that the organization is trained and equipped to handle an attack before it actually occurs. You arrive at this answer because it is universally recognized as the 'first step' in the IR process.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Overall Sec 41-80v1.html"},{"id":89,"question":"During an investigation, the legal team wants to ensure that the evidence has not been tampered with. What is required?","options":["Data Masking","Chain of Custody","Hot Site","Qualitative Analysis"],"correctIndex":1,"explanation":"Chain of Custody is a chronological record that tracks the collection, handling, and storage of evidence during an investigation. It ensures that evidence remains untampered and admissible in a court of law. You arrive at this answer because the legal team wants to verify 'evidence has not been tampered with.'","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Overall Sec 41-80v1.html"},{"id":90,"question":"Which of the following is an 'Indicator of Compromise' (IoC)?","options":["High network latency","Unknown IP communication at 3 AM","A forgotten password","A Windows update"],"correctIndex":1,"explanation":"An Indicator of Compromise (IoC) is a piece of forensic data that suggests a system has been breached. Unexpected outbound traffic to an unknown IP at an odd hour is a classic sign of an active threat or exfiltration. You arrive at this answer by identifying which event represents a specific 'sign' of a security incident.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":91,"question":"What is the purpose of 'Sandboxing'?","options":["To play games","To run suspicious programs in isolation","To encrypt data at rest","To increase database speed"],"correctIndex":1,"explanation":"Sandboxing creates a safe, isolated environment where suspicious files or code can be executed without risking the host system. It is commonly used by malware analysts and security tools to observe malicious behavior in real-time. You arrive at this answer because the goal is to 'run suspicious programs in an isolated environment.'","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall Sec 41-80v1.html"},{"id":92,"question":"Which of the following is 'Volatile Data'?","options":["Hard drive contents","RAM","USB Stick","DVD-ROM"],"correctIndex":1,"explanation":"Volatile data is information that is lost when power is removed from a computer system. RAM (Random Access Memory) is the most common example of volatile storage used in digital forensics. You arrive at this answer by identifying which storage medium requires power to maintain its contents.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Overall Sec 41-80v1.html"},{"id":93,"question":"A company wants to simulate a real-world attack to test their defenses. Which team performs the attack?","options":["Blue Team","Red Team","White Team","Purple Team"],"correctIndex":1,"explanation":"The Red Team acts as the adversary in a security exercise, using real-world attack techniques to test an organization's defenses. Their goal is to identify weaknesses by thinking and acting like a malicious threat actor. You arrive at this answer because the Red Team is explicitly the group that 'performs the attack.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall Sec 41-80v1.html"},{"id":94,"question":"What does 'DLP' stand for?","options":["Data Loss Prevention","Digital Log Processor","Dynamic Link Protocol","Data Layer Protection"],"correctIndex":0,"explanation":"Data Loss Prevention (DLP) consists of tools and policies designed to ensure that sensitive information does not leave the corporate network. It scans data in motion, in use, and at rest to prevent unauthorized exfiltration. You arrive at this answer by recognizing the standard industry acronym for 'Data Loss Prevention.'","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall Sec 41-80v1.html"},{"id":95,"question":"Which command-line tool can be used to view active network connections?","options":["ipconfig","netstat","ping","tracert"],"correctIndex":1,"explanation":"The 'netstat' (network statistics) command-line tool displays all active network connections and listening ports on a local machine. It is a vital tool for troubleshooting and identifying unauthorized or suspicious network activity. You arrive at this answer because the objective is to 'view active network connections.'","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall Sec 41-80v1.html"},{"id":96,"question":"What is the main goal of 'Containment' in incident response?","options":["To fix the vulnerability","To stop the incident from spreading","To identify the attacker","To restore the system"],"correctIndex":1,"explanation":"Containment is the IR phase focused on limiting the scope and impact of a security incident to prevent further damage. By isolating infected systems, the security team prevents the threat from spreading deeper into the network. You arrive at this answer because the primary goal is to 'stop the incident from spreading.'","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Overall Sec 41-80v1.html"},{"id":97,"question":"A security administrator is implementing a system where access is granted based on the user's role within the organization. Which access control model is being used?","options":["DAC","MAC","RBAC","ABAC"],"correctIndex":2,"explanation":"RBAC (Role-Based Access Control) assigns permissions to specific job functions rather than individual users. To arrive at this answer, look for the keyword 'role' which defines the access structure. This model simplifies management because users automatically inherit permissions when assigned to a role.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":98,"question":"Which of the following security goals ensures that data has not been modified by unauthorized entities?","options":["Confidentiality","Integrity","Availability","Non-repudiation"],"correctIndex":1,"explanation":"Integrity is the core security pillar focused on preventing unauthorized data alteration. You can identify this by the focus on data being 'modified' or changed. Tools like hashing and digital signatures are commonly used to verify that integrity remains intact.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":99,"question":"An organization wants to verify that a message was sent by a specific user and that the content was not altered. What should the user apply to the message?","options":["Encryption with a public key","A digital signature","A salted hash","Steganography"],"correctIndex":1,"explanation":"A digital signature provides both integrity and non-repudiation, verifying the sender's identity. To arrive at this answer, notice the requirement for both identity verification and content validation. By signing with a private key, the sender ensures only their public key can decrypt the hash.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":100,"question":"Which concept assumes that no user or device is trusted by default, even if they are inside the network perimeter?","options":["Defense in Depth","Zero Trust","Honeynet","Air Gap"],"correctIndex":1,"explanation":"Zero Trust architecture removes the concept of an implicit 'trusted' internal network. You can arrive at this answer by focusing on the 'no trust by default' phrase in the scenario. Every access request must be continuously authenticated and authorized regardless of location.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall quiz Secv1.html"},{"id":101,"question":"A technician is tasked with ensuring that a critical server remains online even if a single power supply fails. Which concept does this represent?","options":["Scalability","Redundancy","Elasticity","Non-persistence"],"correctIndex":1,"explanation":"Redundancy involves duplicating critical components to ensure system operation continues during a failure. The phrase 'remains online even if a component fails' is the key indicator for this concept. This ensures high availability by eliminating single points of failure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Overall quiz Secv1.html"},{"id":102,"question":"Which of the following is a physical security control?","options":["Firewall","ACL","Faraday cage","Encryption"],"correctIndex":2,"explanation":"A Faraday cage is a physical enclosure used to block electromagnetic fields from entering or leaving an area. To arrive at this answer, identify which option represents a tangible, physical barrier rather than software. It is primarily used to prevent electronic eavesdropping or signal interference.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":103,"question":"A company requires employees to use a password and a hardware token to log in. What type of authentication is this?","options":["Single-factor","Mutual","Multi-factor","Federation"],"correctIndex":2,"explanation":"Multi-factor authentication (MFA) requires two or more distinct categories of credentials. In this case, a password is 'something you know' and a token is 'something you have.' Combining these two different factors satisfies the multi-factor requirement.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":104,"question":"Which term describes the probability of a threat actor exploiting a vulnerability?","options":["Asset","Risk","Impact","Mitigation"],"correctIndex":1,"explanation":"Risk is mathematically defined as the likelihood (probability) of a threat occurring multiplied by the impact. You arrive at this answer by connecting the potential for exploitation with the term 'probability.' Understanding risk helps organizations prioritize which vulnerabilities to patch first.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Overall quiz Secv1.html"},{"id":105,"question":"Which policy defines how long data should be kept and when it should be destroyed?","options":["Acceptable Use Policy (AUP)","Data Retention Policy","Incident Response Policy","Separation of Duties"],"correctIndex":1,"explanation":"A Data Retention Policy sets the timeline for how long data must be stored for legal or business reasons. The keywords 'how long' and 'destroyed' directly point to data lifecycle management. This policy helps reduce liability and storage costs by purging unnecessary data.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall quiz Secv1.html"},{"id":106,"question":"A user cannot deny having sent an email because the email was digitally signed. Which concept is this?","options":["Integrity","Availability","Non-repudiation","Obfuscation"],"correctIndex":2,"explanation":"Non-repudiation ensures that a party in a communication cannot deny the authenticity of their signature or message. You arrive at this answer because the scenario explicitly mentions the user 'cannot deny' the action. This is achieved through the use of asymmetric cryptography.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":107,"question":"Which of the following is considered a corrective control?","options":["CCTV","Guard","Restoring from backups","Security policy"],"correctIndex":2,"explanation":"Corrective controls are used to restore a system to a normal state after an incident has occurred. Restoring from backups is the classic example of fixing the damage caused by a threat. You arrive at this answer by identifying which action occurs 'after' the incident to remediate it.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":108,"question":"What is the primary purpose of a 'Gap Analysis'?","options":["To find the root cause of an incident","To compare current security levels against desired standards","To encrypt data at rest","To scan for network vulnerabilities"],"correctIndex":1,"explanation":"A Gap Analysis identifies the 'gap' between the current security posture and the required compliance or industry standard. You arrive at this answer by focusing on the comparison of 'current' versus 'desired.' This process creates a roadmap for security improvements and budgeting.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":109,"question":"Which role is responsible for the technical environment where data resides?","options":["Data Owner","Data Custodian","Data Controller","Data Processor"],"correctIndex":1,"explanation":"The Data Custodian is responsible for the technical implementation of security controls and data maintenance. To arrive at this answer, look for the 'technical environment' keyword, which distinguishes it from the management role of the Owner. They handle backups, encryption settings, and storage access.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Overall quiz Secv1.html"},{"id":110,"question":"A security admin uses a 'Mantrap' at the entrance of a data center. What is the primary purpose?","options":["To prevent tailgating","To detect fire","To monitor traffic","To block EMI"],"correctIndex":0,"explanation":"A mantrap is a physical access control consisting of two interlocking doors to ensure only one person enters at a time. The primary goal is to prevent 'tailgating' or 'piggybacking' into a secure area. You arrive at this answer by recognizing the physical design of the entryway system.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":111,"question":"Which of the following describes 'security through obscurity'?","options":["Changing the default port of a service","Using AES-256 encryption","Implementing MFA","Hardening a Linux kernel"],"correctIndex":0,"explanation":"Security through obscurity relies on hiding information or configuration details to prevent discovery by attackers. Changing a default port is a classic example, as it doesn't actually secure the service, just makes it harder to find. You arrive at this answer by identifying a tactic that hides rather than fixes a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":112,"question":"An attacker sends an email to a CEO pretending to be the legal department to steal credentials. What is this called?","options":["Phishing","Whaling","Vishing","Smishing"],"correctIndex":1,"explanation":"Whaling is a highly targeted form of phishing aimed at high-profile individuals like CEOs or executives. You arrive at this answer because the target specified is a 'CEO.' This attack typically uses more sophisticated social engineering than standard phishing.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Overall quiz Secv1.html"},{"id":113,"question":"Which type of malware encrypts a user's files and demands payment?","options":["Spyware","Rootkit","Ransomware","Logic Bomb"],"correctIndex":2,"explanation":"Ransomware is malicious software designed to block access to a computer system or files until a sum of money is paid. The keyword 'encrypts' and 'demands payment' is the definitive characteristic of this malware. It primarily targets the availability of data.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":114,"question":"A user notices their computer is slow, and the CPU usage is high even when idle. A technician finds a process running that is mining cryptocurrency. What is this?","options":["Adware","Cryptojacking","Trojan","Worm"],"correctIndex":1,"explanation":"Cryptojacking is the unauthorized use of a person's computing power to mine cryptocurrency. To arrive at this answer, connect the symptoms of 'high CPU usage' with the activity of 'mining.' It often occurs through malicious scripts in a browser or infected software.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":115,"question":"An attacker redirects a website's traffic to a fake site by poisoning the DNS cache. What is this?","options":["Pharming","Typosquatting","Spim","Shoulder Surfing"],"correctIndex":0,"explanation":"Pharming involves redirecting victims to a malicious website by corrupting DNS resolution or host files. You arrive at this answer by noting the 'poisoning the DNS cache' method mentioned. Unlike phishing, the user may type the correct URL and still be redirected.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":116,"question":"Which attack involves an attacker capturing a session token and using it to impersonate a user?","options":["SQL Injection","Session Hijacking","Cross-site Scripting","Replay Attack"],"correctIndex":1,"explanation":"Session Hijacking occurs when an attacker steals a valid session ID to gain unauthorized access to a web server. The 'capturing a session token' phrase is the key indicator for this attack. Once the token is stolen, the attacker can bypass authentication entirely.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Overall quiz Secv1.html"},{"id":117,"question":"An attacker enters a string like ' OR 1=1 -- into a login field. What attack is being attempted?","options":["XSS","SQL Injection","Buffer Overflow","LDAP Injection"],"correctIndex":1,"explanation":"SQL Injection (SQLi) is an attack that inserts malicious SQL code into input fields to manipulate a database. You arrive at this answer by recognizing the SQL syntax 'OR 1=1' used to bypass authentication. This exploit targets vulnerabilities in the application's data layer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":118,"question":"A vulnerability is discovered in a software package that has no known patch. What is this called?","options":["Zero-day","False positive","Legacy system","Shadow IT"],"correctIndex":0,"explanation":"A Zero-day vulnerability is a security flaw that is unknown to the software vendor and has no available patch. The phrase 'no known patch' is the defining characteristic of this threat. These are highly dangerous because there are zero days of protection available.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":119,"question":"Which type of attack uses a list of common words to try and crack a password?","options":["Brute Force","Dictionary Attack","Birthday Attack","Rainbow Table"],"correctIndex":1,"explanation":"A Dictionary Attack uses a predefined list of likely words or previously leaked passwords to guess credentials. You arrive at this answer by identifying the 'list of common words' method. It is more efficient than a pure brute force attack but less effective against complex strings.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":120,"question":"A person walks into an office following an employee who just swiped their badge. What is this called?","options":["Piggybacking","Tailgating","Dumpster diving","Social engineering"],"correctIndex":1,"explanation":"Tailgating is the act of following an authorized person into a secure area without their knowledge or consent. You arrive at this answer because the individual is 'following' someone through a badge-protected door. It is a common physical security breach.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":121,"question":"What is the primary difference between a worm and a virus?","options":["A worm requires human action","A virus is self-replicating","A worm is self-replicating and spreads over the network","A virus only affects mobile devices"],"correctIndex":2,"explanation":"Worms are standalone programs that replicate and spread across networks without needing a host file or human interaction. Viruses, by contrast, require a user to execute an infected file to spread. You arrive at this answer by focusing on the 'network' and 'self-replicating' traits of the worm.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":122,"question":"Which of the following is a physical threat?","options":["Skimming","Bluejacking","Bluesnarfing","Spoofing"],"correctIndex":0,"explanation":"Skimming involves physical devices placed over card readers to steal credit card information during a transaction. You arrive at this answer by identifying which threat requires a physical device interaction. The other options are wireless or software-based attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":123,"question":"An attacker uses an authorized user's Bluetooth connection to steal data. What is this?","options":["Bluejacking","Bluesnarfing","Evil Twin","Rogue Access Point"],"correctIndex":1,"explanation":"Bluesnarfing is the unauthorized access of information from a wireless device through a Bluetooth connection. You arrive at this answer because the goal is to 'steal data' (snarfing) rather than just send messages (jacking). It exploits vulnerabilities in the Bluetooth protocol.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":124,"question":"A technician finds that a program is crashing because it is trying to write more data to a memory buffer than it can hold. What is this?","options":["Integer Overflow","Buffer Overflow","Resource Exhaustion","Race Condition"],"correctIndex":1,"explanation":"A Buffer Overflow occurs when a program writes data beyond the boundaries of its fixed-length block of memory. This leads to system crashes or the execution of malicious code. You arrive at this answer by identifying the 'writing more data than memory can hold' description.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":125,"question":"Which of the following is a passive reconnaissance technique?","options":["Port scanning with Nmap","Banner grabbing","Searching Whois records","Vulnerability scanning"],"correctIndex":2,"explanation":"Passive reconnaissance involves gathering information about a target without directly interacting with their systems. Searching Whois records is passive because you are querying a public database, not the target's server. To arrive at this answer, distinguish between direct interaction and indirect data gathering.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":126,"question":"An attacker sets up a fake Wi-Fi hotspot with the same name as a legitimate one. What is this?","options":["War Driving","Evil Twin","Bluejacking","Dissociative Attack"],"correctIndex":1,"explanation":"An Evil Twin is a fraudulent Wi-Fi access point that appears to be legitimate by using the same SSID. Users connect to it thinking it is the official network, allowing the attacker to intercept traffic. You arrive at this answer by identifying the 'fake hotspot with the same name' scenario.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":127,"question":"What is the purpose of a 'Logic Bomb'?","options":["To steal passwords","To execute malicious code when a specific condition is met","To provide remote access","To replicate across the network"],"correctIndex":1,"explanation":"A Logic Bomb is a string of code intentionally inserted into software that triggers a malicious action when certain conditions are met. You arrive at this answer by focusing on the 'specific condition' (like a date or user action). It is often planted by disgruntled employees as an insider threat.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Overall quiz Secv1.html"},{"id":128,"question":"A pen tester is given no information about the target network. What type of test is this?","options":["White Box","Grey Box","Black Box","Known Environment"],"correctIndex":2,"explanation":"Black Box testing simulates an outside attacker who has no prior knowledge of the internal systems or architecture. You arrive at this answer because the tester is given 'no information.' This forces the tester to perform their own reconnaissance and discovery.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":129,"question":"Which of the following is a non-credentialed vulnerability scan?","options":["Scanning as an administrator","Scanning from the perspective of an outsider without login rights","Reviewing code for logic errors","Checking file permissions manually"],"correctIndex":1,"explanation":"Non-credentialed scans attempt to find vulnerabilities without having login access to the target system. This simulates what an unauthenticated hacker would see from the outside. You arrive at this answer by identifying the 'outsider without login rights' perspective.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Overall quiz Secv1.html"},{"id":130,"question":"An attacker exploits a flaw where two threads are competing for the same resource. What is this?","options":["Buffer Overflow","Race Condition","DLL Injection","Memory Leak"],"correctIndex":1,"explanation":"A Race Condition occurs when the output of a process depends on the sequence or timing of uncontrollable events. You arrive at this answer by focusing on the 'two threads competing for the same resource' description. This timing flaw can be exploited to gain unauthorized privileges or bypass security checks.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":131,"question":"Which of the following describes 'Vishing'?","options":["Phishing over SMS","Phishing over Voice/Phone","Phishing over Social Media","Phishing over Email"],"correctIndex":1,"explanation":"Vishing (Voice Phishing) is a social engineering attack conducted over the phone or via VoIP. To arrive at this answer, look for the 'Voice' or 'Phone' keywords. Attackers often use caller ID spoofing to appear as a trusted organization like a bank.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":132,"question":"An attacker uses a precomputed table of hashes to crack passwords. What is this table called?","options":["Hash Map","Rainbow Table","Logic Table","Salt Table"],"correctIndex":1,"explanation":"A Rainbow Table is a precomputed database of plaintext passwords and their corresponding hash values. You arrive at this answer by identifying the 'precomputed table of hashes' method. Salting passwords makes these tables ineffective because it changes the hash outcome.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Overall quiz Secv1.html"},{"id":133,"question":"What is 'Shadow IT'?","options":["IT departments working at night","Unauthorized hardware or software","A backup IT site","Stealthy malware"],"correctIndex":1,"explanation":"Shadow IT refers to information technology systems and solutions used within an organization without explicit departmental approval. You arrive at this answer by looking for 'unauthorized' use of tech by employees. This creates security risks because these devices are not managed or patched by the security team.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":134,"question":"Which of the following is a 'Man-in-the-Middle' attack?","options":["SQL Injection","ARP Poisoning","Brute Force","Salted Hashing"],"correctIndex":1,"explanation":"ARP Poisoning is a method where an attacker sends faked ARP messages to a LAN to link their MAC address with the IP of a legitimate server. This allows the attacker to intercept, modify, or block data meant for that server. You arrive at this answer by recognizing it as a primary way to sit 'in the middle' of traffic.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":135,"question":"What does a 'Rootkit' primarily aim to do?","options":["Steal credit card info","Maintain persistent, hidden access","Display unwanted ads","Encrypt the hard drive"],"correctIndex":1,"explanation":"A Rootkit is a collection of software designed to provide privileged (root) access to a computer while hiding its presence. You arrive at this answer because the primary goal is 'hidden' and 'persistent' access. They often subvert the OS kernel to remain invisible to standard antivirus tools.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Overall quiz Secv1.html"},{"id":136,"question":"A user receives a text message saying their bank account is locked and to click a link. What is this?","options":["Phishing","Smishing","Vishing","Whaling"],"correctIndex":1,"explanation":"Smishing is a form of phishing that uses SMS (Short Message Service) or text messaging as the attack vector. You arrive at this answer because the scenario specifies a 'text message.' It targets mobile users who may be less likely to verify links than they are on a computer.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Overall quiz Secv1.html"},{"id":137,"question":"Which security principle ensures that information is accessible only to authorized individuals?","options":["Confidentiality","Integrity","Availability","Non-repudiation"],"correctIndex":0,"explanation":"Confidentiality prevents unauthorized access to sensitive information.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":138,"question":"Which concept ensures that data has not been altered, tampered with, or modified?","options":["Integrity","Confidentiality","Availability","Authentication"],"correctIndex":0,"explanation":"Integrity ensures data remains accurate and unchanged unless modified by authorized users.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":139,"question":"Ensuring systems and data are accessible when needed is known as:","options":["Availability","Integrity","Confidentiality","Authorization"],"correctIndex":0,"explanation":"Availability ensures that systems and data remain usable and accessible.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":140,"question":"Which security goal prevents individuals from denying their actions?","options":["Non-repudiation","Confidentiality","Integrity","Availability"],"correctIndex":0,"explanation":"Non-repudiation ensures actions can be proven and cannot be denied later.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":141,"question":"What is the process of verifying a user’s identity?","options":["Authentication","Authorization","Accounting","Auditing"],"correctIndex":0,"explanation":"Authentication verifies that a user is who they claim to be.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":142,"question":"Which AAA component determines what a user is allowed to do?","options":["Authorization","Authentication","Accounting","Auditing"],"correctIndex":0,"explanation":"Authorization defines permissions and access rights after authentication.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":143,"question":"Which security control type includes firewalls and IDS/IPS?","options":["Technical controls","Managerial controls","Operational controls","Physical controls"],"correctIndex":0,"explanation":"Technical controls use technology to enforce security.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":144,"question":"Security guards, fences, and cameras are examples of:","options":["Physical controls","Technical controls","Managerial controls","Operational controls"],"correctIndex":0,"explanation":"Physical controls protect the physical environment and infrastructure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":145,"question":"Policies, risk assessments, and security planning are examples of:","options":["Managerial controls","Technical controls","Physical controls","Corrective controls"],"correctIndex":0,"explanation":"Managerial controls focus on governance and risk management.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":146,"question":"Which control type attempts to stop an attack before it succeeds?","options":["Preventive","Detective","Corrective","Compensating"],"correctIndex":0,"explanation":"Preventive controls aim to block threats before they occur.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":147,"question":"Which control type identifies that an attack is occurring?","options":["Detective","Preventive","Corrective","Deterrent"],"correctIndex":0,"explanation":"Detective controls discover and alert on malicious activity.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":148,"question":"Which control type restores systems after an incident?","options":["Corrective","Preventive","Detective","Deterrent"],"correctIndex":0,"explanation":"Corrective controls help return systems to normal operation.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":149,"question":"What is the term for reducing risk to an acceptable level?","options":["Risk mitigation","Risk acceptance","Risk avoidance","Risk transference"],"correctIndex":0,"explanation":"Mitigation reduces the likelihood or impact of a risk.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":150,"question":"Cyber insurance is an example of which risk response?","options":["Risk transference","Risk mitigation","Risk acceptance","Risk avoidance"],"correctIndex":0,"explanation":"Transference shifts risk to a third party, such as an insurer.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":151,"question":"Which term describes the potential for loss or damage?","options":["Risk","Threat","Vulnerability","Impact"],"correctIndex":0,"explanation":"Risk is the likelihood that a threat will exploit a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":152,"question":"A weakness that can be exploited by a threat actor is known as a:","options":["Vulnerability","Risk","Threat","Impact"],"correctIndex":0,"explanation":"A vulnerability is a flaw or weakness that can be exploited.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":153,"question":"An individual or event that can exploit a vulnerability is called a:","options":["Threat","Risk","Impact","Control"],"correctIndex":0,"explanation":"A threat is any potential danger that can exploit a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":154,"question":"Which concept ensures that users only have the permissions they need to perform their job?","options":["Least privilege","Separation of duties","Defense in depth","Zero trust"],"correctIndex":0,"explanation":"Least privilege limits access to only what is necessary.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":155,"question":"Splitting critical tasks between multiple people is known as:","options":["Separation of duties","Least privilege","Job rotation","Mandatory vacations"],"correctIndex":0,"explanation":"Separation of duties prevents fraud and misuse by dividing responsibilities.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":156,"question":"Which principle uses multiple layers of security controls?","options":["Defense in depth","Zero trust","Least privilege","Separation of duties"],"correctIndex":0,"explanation":"Defense in depth uses layered security to reduce risk.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":157,"question":"Which model assumes no user or device is trusted by default?","options":["Zero trust","Defense in depth","Least privilege","Mandatory access control"],"correctIndex":0,"explanation":"Zero trust requires continuous verification of all users and devices.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":158,"question":"Which access control model uses labels such as 'Top Secret' and 'Confidential'?","options":["Mandatory Access Control (MAC)","Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)","Attribute-Based Access Control (ABAC)"],"correctIndex":0,"explanation":"MAC uses security labels and strict centralized control.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":159,"question":"Which access control model assigns permissions based on job functions?","options":["RBAC","MAC","DAC","ABAC"],"correctIndex":0,"explanation":"Role-Based Access Control assigns permissions based on roles.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":160,"question":"Which access control model allows resource owners to determine access?","options":["DAC","MAC","RBAC","ABAC"],"correctIndex":0,"explanation":"DAC gives owners control over who can access their resources.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":161,"question":"Which access control model uses policies based on attributes such as location or device type?","options":["ABAC","RBAC","MAC","DAC"],"correctIndex":0,"explanation":"ABAC uses attributes to dynamically determine access.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":162,"question":"Which term describes the likelihood that a threat will exploit a vulnerability?","options":["Risk","Impact","Threat","Exposure"],"correctIndex":0,"explanation":"Risk is the probability of a threat exploiting a vulnerability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":163,"question":"Which concept ensures that logs and audit trails accurately reflect user actions?","options":["Accountability","Authentication","Authorization","Integrity"],"correctIndex":0,"explanation":"Accountability ties actions to specific users through logging.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":164,"question":"Which security concept ensures that systems continue operating even during failures?","options":["Fault tolerance","Integrity","Non-repudiation","Authentication"],"correctIndex":0,"explanation":"Fault tolerance uses redundancy to maintain availability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":165,"question":"Which term describes the total harm or damage caused by a security incident?","options":["Impact","Risk","Threat","Exposure"],"correctIndex":0,"explanation":"Impact measures the severity of a security incident.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":166,"question":"Which concept involves verifying both the identity and integrity of a device before granting access?","options":["Device authentication","Zero trust","Least privilege","MAC"],"correctIndex":0,"explanation":"Device authentication ensures the device is trusted and uncompromised.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 1.html"},{"id":167,"question":"Which cryptographic property ensures that data has not been altered between sender and receiver?","options":["Confidentiality","Integrity","Availability","Obfuscation"],"correctIndex":1,"explanation":"Integrity ensures that data remains unmodified; hashing and digital signatures are common mechanisms.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":168,"question":"Which of the following is a symmetric block cipher commonly used for VPNs and full-disk encryption?","options":["RSA","ECC","AES","Diffie-Hellman"],"correctIndex":2,"explanation":"AES is a symmetric block cipher widely used for VPNs, disk encryption, and many other secure applications.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":169,"question":"A company wants to securely exchange a symmetric key over an insecure channel. Which algorithm is BEST suited?","options":["AES","Diffie-Hellman","SHA-256","MD5"],"correctIndex":1,"explanation":"Diffie-Hellman is designed for secure key exchange over an insecure channel.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":170,"question":"Which of the following is primarily used to provide non-repudiation?","options":["Symmetric encryption","Hashing","Digital signatures","Steganography"],"correctIndex":2,"explanation":"Digital signatures provide integrity, authentication, and non-repudiation by binding a signer to the message.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":171,"question":"Which hashing algorithm is considered broken and should NOT be used for security purposes?","options":["SHA-256","SHA-3","MD5","BLAKE2"],"correctIndex":2,"explanation":"MD5 is vulnerable to collisions and is no longer considered secure for cryptographic use.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":172,"question":"Which concept describes adding random data to a password before hashing to defend against rainbow table attacks?","options":["Key stretching","Salting","Peppering","Key escrow"],"correctIndex":1,"explanation":"Salting adds unique random data to each password before hashing, making precomputed tables ineffective.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":173,"question":"Which of the following BEST describes perfect forward secrecy (PFS)?","options":["Using the same key for encryption and decryption","Ensuring that compromise of a long-term key does not compromise past session keys","Using a longer key length than required","Encrypting data at rest and in transit"],"correctIndex":1,"explanation":"PFS ensures that even if a long-term key is compromised, past session keys remain secure.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":174,"question":"Which protocol is commonly used to provide secure email with digital signatures and encryption?","options":["S/MIME","SNMPv3","SRTP","FTPS"],"correctIndex":0,"explanation":"S/MIME provides secure email with encryption and digital signatures using X.509 certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":175,"question":"Which of the following is an example of asymmetric encryption?","options":["AES-256","3DES","RSA","ChaCha20"],"correctIndex":2,"explanation":"RSA is a widely used asymmetric (public key) cryptographic algorithm.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":176,"question":"A security engineer needs to verify that a downloaded file has not been tampered with. Which is the BEST method?","options":["Compare the file size","Check the file's digital signature or hash","Open the file and visually inspect it","Re-download the file from another mirror"],"correctIndex":1,"explanation":"Verifying a cryptographic hash or digital signature ensures the file's integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":177,"question":"Which of the following is a key stretching algorithm commonly used for password hashing?","options":["PBKDF2","RSA","Diffie-Hellman","SHA-1"],"correctIndex":0,"explanation":"PBKDF2 is a key stretching algorithm that applies a hash function many times to slow down brute-force attacks.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":178,"question":"Which cryptographic concept ensures that the same plaintext will not always produce the same ciphertext?","options":["Initialization vector (IV)","Key escrow","Key wrapping","Certificate pinning"],"correctIndex":0,"explanation":"An IV introduces randomness so that identical plaintexts encrypt to different ciphertexts.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":179,"question":"Which of the following BEST describes a digital certificate?","options":["A symmetric key used for bulk encryption","A signed binding between a public key and an identity","A random number used for key generation","A hardware token used for MFA"],"correctIndex":1,"explanation":"A digital certificate binds a public key to an identity and is signed by a CA.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":180,"question":"Which access control model uses labels such as 'Secret' and 'Top Secret' and enforces access based on clearance?","options":["Discretionary Access Control (DAC)","Mandatory Access Control (MAC)","Role-Based Access Control (RBAC)","Rule-Based Access Control"],"correctIndex":1,"explanation":"MAC uses labels and clearances, with access decisions enforced by a central authority.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":181,"question":"In Role-Based Access Control (RBAC), permissions are primarily assigned to:","options":["Users directly","Roles","Objects","Networks"],"correctIndex":1,"explanation":"In RBAC, permissions are assigned to roles, and users are assigned to those roles.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":182,"question":"Which of the following is an example of something you HAVE in multifactor authentication?","options":["Password","PIN","Smart card","Fingerprint"],"correctIndex":2,"explanation":"A smart card is a physical token and represents 'something you have'.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":183,"question":"Which protocol is commonly used for centralized authentication, authorization, and accounting for network devices?","options":["RADIUS","DNSSEC","SFTP","NTP"],"correctIndex":0,"explanation":"RADIUS provides centralized AAA services for network access and devices.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 2.html"},{"id":184,"question":"Which protocol is often used for secure, ticket-based authentication in Windows domains?","options":["TACACS+","Kerberos","LDAP","SAML"],"correctIndex":1,"explanation":"Kerberos uses tickets and symmetric cryptography for secure authentication in domains.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":185,"question":"Which of the following BEST describes single sign-on (SSO)?","options":["Using multiple passwords for different systems","Using one set of credentials to access multiple systems","Using a hardware token for every login","Using a local account instead of a domain account"],"correctIndex":1,"explanation":"SSO allows a user to authenticate once and gain access to multiple systems or applications.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":186,"question":"Which standard is commonly used to provide federated identity and SSO between organizations using XML-based assertions?","options":["SAML","OAuth 2.0","OpenID Connect","RADIUS"],"correctIndex":0,"explanation":"SAML uses XML-based assertions for federated identity and SSO between identity and service providers.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 2.html"},{"id":187,"question":"Which of the following is MOST associated with authorization of API calls and delegated access?","options":["SAML","OAuth 2.0","Kerberos","CHAP"],"correctIndex":1,"explanation":"OAuth 2.0 is commonly used for delegated authorization, especially for APIs.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":188,"question":"Which identity concept describes a centralized directory that stores user accounts and attributes?","options":["RADIUS","LDAP directory","TACACS+ server","NTP server"],"correctIndex":1,"explanation":"LDAP directories (like Active Directory) store user accounts, groups, and attributes centrally.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":189,"question":"A security team wants to enforce that users only have the minimum permissions necessary to perform their jobs. This is an example of:","options":["Separation of duties","Job rotation","Least privilege","Mandatory vacations"],"correctIndex":2,"explanation":"Least privilege ensures users have only the access they need and no more.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":190,"question":"Which of the following BEST describes separation of duties?","options":["Requiring two people to approve all changes","Ensuring that critical tasks are divided among multiple people","Rotating employees through different roles","Requiring strong passwords"],"correctIndex":1,"explanation":"Separation of duties divides critical tasks so no single person can complete them alone, reducing fraud risk.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":191,"question":"Which authentication factor category does a retina scan fall under?","options":["Something you know","Something you have","Something you are","Somewhere you are"],"correctIndex":2,"explanation":"Biometric identifiers like retina scans are 'something you are'.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":192,"question":"Which of the following is a common risk of using shared accounts?","options":["Improved accountability","Simplified auditing","Lack of non-repudiation","Stronger authentication"],"correctIndex":2,"explanation":"Shared accounts make it difficult to attribute actions to a specific individual, reducing accountability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 2.html"},{"id":193,"question":"Which cryptographic attack attempts to find two different inputs that produce the same hash value?","options":["Brute-force attack","Collision attack","Birthday attack","Replay attack"],"correctIndex":1,"explanation":"A collision attack aims to find two distinct inputs with the same hash output.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":194,"question":"Which of the following is MOST appropriate for encrypting large amounts of data on a storage device?","options":["RSA","ECC","AES","DSA"],"correctIndex":2,"explanation":"AES, a symmetric cipher, is efficient and commonly used for bulk data encryption such as full-disk encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":195,"question":"Which identity and access management concept ensures that user access is reviewed and adjusted when roles change?","options":["Onboarding","Offboarding","Access recertification (account review)","Password rotation"],"correctIndex":2,"explanation":"Access recertification periodically reviews user access to ensure it still aligns with job responsibilities.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 2.html"},{"id":196,"question":"Which of the following BEST describes just-in-time (JIT) access?","options":["Permanent elevated privileges for administrators","Granting elevated access only when needed and for a limited time","Using shared admin accounts","Using static passwords for service accounts"],"correctIndex":1,"explanation":"JIT access provides temporary, time-bound elevated privileges only when required, reducing risk.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 2.html"},{"id":197,"question":"Which architectural approach most effectively limits lateral movement by enforcing granular communication rules between internal workloads?","options":["Microsegmentation using workload-level policy enforcement boundaries","Static VLAN assignments based solely on switch port groupings","Perimeter filtering that relies on a single external firewall layer","Flat network routing that forwards internal traffic without restrictions"],"correctIndex":0,"explanation":"Microsegmentation enforces fine-grained controls between workloads, reducing lateral movement opportunities.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 3.html"},{"id":198,"question":"In a three-tier application design, which component should be placed in the most restrictive network zone to minimize exposure?","options":["Database tier containing sensitive structured application data","Presentation tier responsible for handling external client requests","Load balancing tier distributing inbound session traffic","DNS resolution tier providing general name lookup services"],"correctIndex":0,"explanation":"The database tier contains sensitive data and requires the strongest isolation.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":199,"question":"Which design pattern describes placing public-facing systems in a controlled zone between internal and external networks?","options":["DMZ architecture using screened subnets between firewall layers","Single-segment architecture with unified internal routing","Mesh topology allowing unrestricted peer-to-peer connectivity","Legacy perimeter model relying solely on NAT for protection"],"correctIndex":0,"explanation":"A DMZ isolates public systems to reduce risk to internal networks.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 3.html"},{"id":200,"question":"Which traffic pattern is characterized by communication between internal systems rather than inbound or outbound flows?","options":["East-west traffic moving laterally between internal workloads","North-south traffic moving between clients and external services","Transit traffic routed between remote branch locations","Overlay traffic encapsulated for tunneling across WAN links"],"correctIndex":0,"explanation":"East-west traffic refers to lateral internal communication.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":201,"question":"Which control is most appropriate for enforcing policy boundaries between internal network segments?","options":["Internal firewalls applying granular inter-segment filtering rules","Layer 2 switches forwarding frames based on MAC learning","Hubs broadcasting all frames to every connected interface","Repeaters regenerating signals without traffic inspection"],"correctIndex":0,"explanation":"Internal firewalls enforce segmentation and policy boundaries.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 3.html"},{"id":202,"question":"Which design choice best supports high availability for critical perimeter security devices?","options":["Redundant firewall pairs configured for synchronized failover","Single high-capacity firewall with enhanced throughput settings","Distributed endpoint firewalls replacing network-level filtering","Perimeter filtering performed only at upstream ISP routers"],"correctIndex":0,"explanation":"Redundant firewall pairs ensure continuity during device failure.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":203,"question":"Which architectural principle ensures that a single component failure does not disrupt overall service availability?","options":["Fault-tolerant design using redundant and resilient components","Minimalist design using a single consolidated service instance","Prototype design relying on experimental hardware modules","Legacy design using monolithic centralized infrastructure"],"correctIndex":0,"explanation":"Fault tolerance ensures continued operation despite component failures.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":204,"question":"Which architectural model emphasizes continuous verification and localized enforcement rather than implicit internal trust?","options":["Zero trust architecture with distributed access validation","Perimeter-centric architecture relying on external firewalls","Implicit trust architecture assuming internal traffic is safe","Best-effort architecture using broad shared access policies"],"correctIndex":0,"explanation":"Zero trust removes implicit trust and enforces continuous verification.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":205,"question":"Which system is used to centralize administrative access into sensitive management networks?","options":["Jump server providing controlled entry to management segments","Caching proxy accelerating outbound web browsing requests","Wireless controller managing guest network associations","Public web server hosting external customer applications"],"correctIndex":0,"explanation":"Jump servers centralize and secure administrative access.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":206,"question":"Which design element is most important when building a secure management network for infrastructure devices?","options":["Out-of-band management network isolated from user traffic paths","Shared VLAN carrying both user and administrative traffic","Public internet path used for remote administrative sessions","Guest wireless network temporarily used for device management"],"correctIndex":0,"explanation":"OOB networks isolate management traffic for security and reliability.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":207,"question":"Which component accepts client requests and forwards them to internal application servers while masking backend details?","options":["Reverse proxy providing controlled access to internal services","NAT gateway translating outbound private address traffic","Layer 2 switch forwarding frames based on learned MAC tables","Routing appliance advertising default routes to internal hosts"],"correctIndex":0,"explanation":"Reverse proxies protect backend servers and manage client requests.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":208,"question":"Which deployment model distributes application components across multiple geographically separated sites for resilience?","options":["Active-active multi-site architecture with synchronized workloads","Single-site architecture with centralized monolithic services","Branch-only architecture with isolated local deployments","Ad hoc architecture using unmanaged local installations"],"correctIndex":0,"explanation":"Active-active multi-site deployments improve resilience and availability.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":209,"question":"Which principle is applied when service accounts are restricted to only the permissions required for their specific tasks?","options":["Least privilege applied to system and service accounts","Implicit trust applied to authenticated internal accounts","Open access applied to shared administrative credentials","Full control applied to all authenticated user identities"],"correctIndex":0,"explanation":"Least privilege limits permissions to reduce risk of compromise.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":210,"question":"Which concept describes applying fine-grained security controls between individual workloads in a virtualized environment?","options":["Microsegmentation using workload-specific policy boundaries","Static VLAN segmentation based on physical switch ports","Perimeter filtering using a single external firewall layer","Legacy segmentation relying on broad trust zones internally"],"correctIndex":0,"explanation":"Microsegmentation enforces granular controls between workloads.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 3.html"},{"id":211,"question":"Which method best supports secure remote administration over untrusted networks?","options":["VPN tunnels using strong authentication and encrypted sessions","Telnet access permitted from any external network location","HTTP-based management exposed on public interfaces","Open wireless networks used for administrative connectivity"],"correctIndex":0,"explanation":"VPNs protect administrative traffic with encryption and authentication.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":212,"question":"Which component enforces application-layer security policies by inspecting and filtering HTTP traffic?","options":["Web application firewall analyzing inbound and outbound requests","Layer 2 switch forwarding frames based on MAC addresses","Network hub repeating traffic to all connected devices","Patch panel providing passive cable termination points"],"correctIndex":0,"explanation":"WAFs enforce application-layer protections.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 3.html"},{"id":213,"question":"Which principle is demonstrated by using multiple independent security controls to protect the same asset?","options":["Defense in depth using layered and overlapping safeguards","Single-layer protection relying on one primary control","Implicit trust assuming internal traffic is inherently safe","Best-effort security using loosely defined control placement"],"correctIndex":0,"explanation":"Defense in depth ensures redundancy across security layers.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 3.html"},{"id":214,"question":"Which solution evaluates device posture before granting network access?","options":["Network access control validating compliance before connection","Log aggregation system storing long-term audit records","Identity provider managing cloud authentication workflows","Email encryption gateway securing internal message flows"],"correctIndex":0,"explanation":"NAC evaluates device posture and compliance.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":215,"question":"Which design choice best supports isolation between tenants in a cloud environment?","options":["Separate virtual networks and security groups per tenant","Shared flat network segment for all tenant workloads","Unrestricted routing between tenant environments","Single administrative account shared across all tenants"],"correctIndex":0,"explanation":"Tenant isolation requires separate virtual networks and policies.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":216,"question":"Which component distributes client requests across multiple backend servers to improve availability?","options":["Load balancer directing traffic using defined distribution logic","Network tap passively copying traffic for monitoring tools","Patch panel connecting cables between racks and switches","Console server providing serial access to infrastructure devices"],"correctIndex":0,"explanation":"Load balancers distribute traffic to improve performance and uptime.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 3.html"},{"id":217,"question":"Which principle is applied when development, testing, and production environments are separated?","options":["Environment separation reducing risk of unintended production impact","Unified environment simplifying deployment and configuration","Shared environment maximizing resource utilization only","Ad hoc environment supporting rapid experimental changes"],"correctIndex":0,"explanation":"Environment separation prevents development activities from affecting production.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":218,"question":"Which system is intentionally hardened and exposed to untrusted networks to provide controlled access?","options":["Bastion host designed to withstand targeted external attacks","Unmanaged workstation used for general internet browsing","Legacy server running outdated operating system versions","Guest kiosk used for temporary visitor access"],"correctIndex":0,"explanation":"Bastion hosts are hardened for exposure to untrusted networks.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":219,"question":"Which design choice best supports secure logging and monitoring across distributed infrastructure?","options":["Centralized log aggregation with secure forwarding mechanisms","Local log storage only with no centralized collection","Manual review of logs stored on individual devices","Unencrypted log transmission across public network paths"],"correctIndex":0,"explanation":"Centralized logging enables correlation and secure retention.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":220,"question":"Which architecture uses small, independently deployable services that communicate through APIs?","options":["Microservices architecture with loosely coupled components","Monolithic architecture using a single large application","Mainframe architecture with centralized batch processing","Client-server architecture using thick desktop clients"],"correctIndex":0,"explanation":"Microservices improve scalability and resilience.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":221,"question":"Which principle is applied when unnecessary services and open ports are removed from an internet-facing server?","options":["Attack surface reduction through service minimization","Implicit trust through broad internal service exposure","Open access through unrestricted service publication","Best-effort security using default service configurations"],"correctIndex":0,"explanation":"Reducing exposed services minimizes the number of potential attack vectors.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 3.html"},{"id":222,"question":"Which option best describes the role of a CASB in a cloud-centric architecture?","options":["Broker enforcing security policies between users and cloud services","Device providing physical connectivity between racks and switches","Appliance used solely for encrypting local storage volumes","Server dedicated to running on-premises directory services"],"correctIndex":0,"explanation":"CASBs enforce policy and visibility between users and cloud applications.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 3.html"},{"id":223,"question":"Which design choice best supports secure integration between on-premises infrastructure and public cloud resources?","options":["Using dedicated VPN or private connectivity with strong authentication","Allowing unrestricted public internet access to internal services","Using open wireless networks to bridge cloud and on-premises","Relying on unsecured legacy protocols for all connectivity"],"correctIndex":0,"explanation":"VPN or private links secure hybrid connectivity.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Day 3.html"},{"id":224,"question":"Which architecture component is primarily responsible for isolating broadcast domains within a switched network?","options":["Router or Layer 3 switch performing inter-VLAN routing functions","Hub broadcasting all inbound frames to every connected interface","Patch panel providing passive cable termination for copper links","Network tap duplicating traffic streams for monitoring systems"],"correctIndex":0,"explanation":"Routers and Layer 3 switches isolate broadcast domains by routing between VLANs.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":225,"question":"Which design principle is applied when critical security functions are distributed across separate dedicated components rather than consolidated into a single device?","options":["Separation of duties across distinct and independently controlled systems","Centralized control using one unified multi-purpose appliance","Implicit trust model allowing broad administrative privileges","Best-effort security relying on default hardware configurations"],"correctIndex":0,"explanation":"Separating duties across components reduces risk and avoids a single point of failure.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":226,"question":"Which option best describes the purpose of a secure enclave within an enterprise architecture?","options":["Isolated environment designed to protect highly sensitive workloads","Shared environment used for general-purpose user applications","Legacy environment used for unsupported operating systems","Guest environment used for temporary visitor access only"],"correctIndex":0,"explanation":"A secure enclave provides enhanced isolation and controls for highly sensitive data and workloads.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 3.html"},{"id":227,"question":"A security team needs a recurring method to identify missing patches and insecure configurations across all managed servers. Which approach best supports this requirement?","options":["Use credentialed vulnerability scans to validate configuration states across all managed systems.","Rely on periodic log reviews to identify configuration drift across production workloads.","Deploy agentless discovery tools that highlight network‑visible weaknesses during routine sweeps.","Analyze firewall rule changes to detect potential exposure created by misaligned access paths."],"correctIndex":0,"explanation":"Credentialed scans provide deeper visibility into host‑level settings and patch status.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 4.html"},{"id":228,"question":"A company wants to safely verify whether identified weaknesses can actually be exploited in a controlled environment. Which approach best meets this objective?","options":["Conduct targeted penetration testing to confirm whether identified weaknesses are practically exploitable.","Review historical incident reports to determine whether similar vulnerabilities were exploited previously.","Use passive monitoring tools to observe abnormal behavior without interacting with the system.","Rely on automated patch deployment to mitigate weaknesses before validation occurs."],"correctIndex":0,"explanation":"Penetration testing validates whether a vulnerability can be exploited under real conditions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 4.html"},{"id":229,"question":"A critical remote code execution flaw is discovered on a public web server. Which factor most increases the urgency of addressing this vulnerability?","options":["The system is directly internet‑facing and accessible to unauthenticated external attackers.","The server hosts non‑sensitive content that rarely changes during normal operations.","The vulnerability requires multiple chained conditions before exploitation is possible.","The system is monitored by a SIEM that alerts on suspicious inbound traffic."],"correctIndex":0,"explanation":"Internet‑facing systems are at significantly higher risk because attackers can reach them directly.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 4.html"},{"id":230,"question":"A security analyst is reviewing a vulnerability scoring report and wants to understand how easily an attacker could exploit a weakness. Which focus best supports this analysis?","options":["Evaluate exploitability metrics such as attack vector, complexity, and required privileges.","Prioritize vulnerabilities based solely on the age of the published advisory.","Review system uptime statistics to determine how frequently services restart.","Analyze user login frequency to estimate potential exposure to credential misuse."],"correctIndex":0,"explanation":"Exploitability metrics indicate how easily an attacker can leverage a vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":231,"question":"A vulnerability with a high severity score is found on an isolated lab system with no production connectivity. Which concept best explains why remediation may be deprioritized?","options":["The system’s limited exposure reduces the likelihood of meaningful exploitation attempts.","The vulnerability is unlikely to generate alerts within centralized monitoring tools.","The system’s hardware lifecycle is nearing end‑of‑support within the next year.","The vulnerability affects only optional features not enabled on the system."],"correctIndex":0,"explanation":"Risk is influenced by exposure; isolated systems present far less opportunity for exploitation.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":232,"question":"After a vulnerability scan completes, several new findings are identified on production systems. Which step should occur next in a formal vulnerability management process?","options":["Prioritize the findings based on severity, asset value, and operational impact.","Immediately deploy patches to all affected systems without further evaluation.","Archive the scan results for long‑term compliance reporting requirements.","Disable network access to all systems showing new vulnerabilities."],"correctIndex":0,"explanation":"Triage ensures vulnerabilities are addressed in an order aligned with business risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Day 4.html"},{"id":233,"question":"A security engineer notices that some vulnerabilities are not being detected on systems that are known to be unpatched. Which scanning characteristic is most likely contributing to these false negatives?","options":["The scans are running without authentication, limiting visibility into host‑level details.","The scans are scheduled too frequently, causing incomplete data collection cycles.","The scanner is configured to ignore informational findings during routine assessments.","The network uses redundant routing paths that obscure endpoint identification."],"correctIndex":0,"explanation":"Unauthenticated scans often miss vulnerabilities that require deeper system access to detect.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":234,"question":"A team wants to ensure that newly deployed virtual machines consistently follow a hardened baseline before entering production. Which approach best supports this objective?","options":["Use standardized system images that enforce consistent baseline configurations across deployments.","Allow administrators to manually configure each system according to documented guidelines.","Enable automatic updates to apply patches immediately after system installation.","Perform quarterly audits to verify whether deployed systems match expected configurations."],"correctIndex":0,"explanation":"Standardized images ensure new systems start with a consistent, hardened configuration.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":235,"question":"An application relies heavily on third-party libraries. The security team wants to reduce the risk of vulnerabilities introduced through these components. Which approach is most appropriate?","options":["Track and update third‑party components using a structured dependency management process.","Disable all optional features within the application to reduce its overall attack surface.","Increase logging verbosity to detect abnormal behavior caused by outdated libraries.","Restrict outbound network access to prevent libraries from communicating externally."],"correctIndex":0,"explanation":"Dependency management ensures third‑party components remain updated and free of known vulnerabilities.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 4.html"},{"id":236,"question":"A medium-severity vulnerability is identified on a mission-critical database that stores regulated data. Which consideration could justify treating this as a higher-priority issue?","options":["The system stores sensitive regulated data that increases the impact of potential compromise.","The vulnerability affects a feature that is rarely used during normal operations.","The system is hosted on hardware nearing its scheduled replacement cycle.","The database is backed up daily using encrypted storage mechanisms."],"correctIndex":0,"explanation":"Data sensitivity increases the potential impact, raising the priority of remediation.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":237,"question":"A workstation fleet is being reviewed to reduce the overall attack surface. Which approach most directly supports this goal?","options":["Restrict which applications can run by enforcing approved software execution policies.","Increase system logging levels to capture more detailed operational activity.","Extend patch deployment windows to reduce disruption during business hours.","Enable remote desktop access for administrators to streamline maintenance tasks."],"correctIndex":0,"explanation":"Application control reduces the attack surface by limiting unauthorized software execution.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"Sec + Day 4.html"},{"id":238,"question":"A security architect wants to prevent unauthorized code from running during system startup on corporate laptops. Which approach best addresses this requirement?","options":["Enable secure boot mechanisms that validate trusted components during system initialization.","Require multi‑factor authentication before users can access the operating system.","Encrypt the system drive to protect data stored on the device.","Disable unused hardware ports to limit opportunities for physical tampering."],"correctIndex":0,"explanation":"Secure boot ensures only trusted components load during system startup.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":239,"question":"A security program wants to define how quickly vulnerabilities must be remediated based on severity. Which type of guidance should describe these expectations?","options":["Document remediation timelines within formal vulnerability management policy requirements.","Store remediation expectations in archived audit reports for future reference.","Communicate remediation expectations informally during team meetings and briefings.","Include remediation expectations within optional training materials for administrators."],"correctIndex":0,"explanation":"Policies define required remediation timelines and establish organizational expectations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 4.html"},{"id":240,"question":"Different administrators are interpreting vulnerability scan results in inconsistent ways, leading to uneven remediation. Which approach best improves consistency?","options":["Adopt standardized criteria for interpreting vulnerability severity and required actions.","Allow each team to determine its own remediation priorities based on workload.","Increase scan frequency to ensure more up‑to‑date vulnerability information.","Disable low‑severity findings to reduce the number of items requiring review."],"correctIndex":0,"explanation":"Standardized interpretation ensures consistent remediation decisions across teams.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":241,"question":"Users sometimes access corporate resources from unmanaged or shared devices. The organization wants to limit the risk of credential theft on those endpoints. Which approach is most appropriate?","options":["Provide isolated virtual desktop environments that prevent sensitive activity on untrusted devices.","Require users to rotate passwords more frequently when using shared devices.","Disable all remote access capabilities to prevent connections from unmanaged systems.","Allow browser‑based access only when users acknowledge additional security warnings."],"correctIndex":0,"explanation":"Virtual desktops isolate corporate activity from untrusted or unmanaged endpoints.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Day 4.html"},{"id":242,"question":"A known vulnerability exists on a production server. The organization wants to reduce the likelihood that this weakness will be exploited. Which approach is most effective?","options":["Apply the appropriate patch to eliminate the underlying vulnerability on the system.","Increase monitoring frequency to detect suspicious activity targeting the system.","Restrict user login hours to reduce opportunities for unauthorized access attempts.","Disable non‑essential services to reduce the number of running processes."],"correctIndex":0,"explanation":"Patching directly removes the vulnerability, reducing the likelihood of exploitation.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":243,"question":"A vulnerability report indicates that a service is using deprecated cipher suites. Which approach best addresses this issue?","options":["Update the service configuration to use modern, supported cryptographic algorithms.","Increase key rotation frequency to compensate for weaker encryption strength.","Enable additional logging to capture details about encrypted session activity.","Restrict access to the service to reduce exposure to external users."],"correctIndex":0,"explanation":"Replacing deprecated cipher suites ensures secure, modern cryptographic protection.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":244,"question":"Several servers with the same intended role show different security settings and patch levels. Which issue is most likely occurring?","options":["Configuration drift is causing systems to deviate from their expected baseline state.","The servers are using incompatible hardware that prevents consistent patching.","The systems are receiving excessive updates that exceed vendor recommendations.","The servers are assigned to different network segments with varying access rules."],"correctIndex":0,"explanation":"Configuration drift occurs when systems diverge from their intended baseline.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":245,"question":"A compromised user account should have limited ability to affect other computing resources. Which approach best supports this objective?","options":["Enforce least‑privilege access controls to limit what each account can perform.","Require users to authenticate more frequently during normal business operations.","Enable verbose logging to capture detailed user activity across all systems.","Increase password complexity requirements for all user accounts."],"correctIndex":0,"explanation":"Least‑privilege access limits the impact of a compromised account.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":246,"question":"After remediation work is completed for a critical vulnerability, the security team wants to confirm that the issue is no longer present. Which approach is most appropriate?","options":["Perform a follow‑up scan to verify that the vulnerability has been resolved.","Review patch notes to confirm that the update addressed the vulnerability.","Monitor system logs for several days to ensure no related alerts appear.","Request user feedback to determine whether system behavior has improved."],"correctIndex":0,"explanation":"Follow‑up scanning confirms whether remediation successfully removed the vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":247,"question":"An organization wants to reduce the chance that malware will exploit unpatched software on endpoints. Which approach best supports this goal?","options":["Ensure endpoint applications receive timely updates through a structured patch management process.","Increase antivirus scan frequency to detect malware before it becomes active.","Restrict user access to administrative tools during normal business operations.","Enable detailed event logging to capture suspicious activity across all endpoints."],"correctIndex":0,"explanation":"Regular patching reduces the number of exploitable software vulnerabilities on endpoints.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":248,"question":"Business priorities and threat landscapes change over time. Which approach best ensures that vulnerability management activities remain aligned with these changes?","options":["Conduct periodic reviews to adjust vulnerability priorities based on updated business needs.","Increase the number of vulnerability scans performed each week for better visibility.","Assign remediation tasks to whichever team has the most available resources.","Disable low‑severity findings to reduce the volume of items requiring review."],"correctIndex":0,"explanation":"Regular reviews ensure vulnerability priorities reflect current business and threat conditions.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":249,"question":"A workstation image includes several legacy services that are not required for business operations. Which approach best reduces potential vulnerabilities from these services?","options":["Remove unnecessary services through a hardened baseline to reduce the attack surface.","Increase system monitoring to detect unusual activity associated with legacy components.","Restrict outbound network access to prevent legacy services from communicating externally.","Schedule quarterly audits to verify whether legacy components remain active."],"correctIndex":0,"explanation":"Hardening eliminates unnecessary services, reducing exposure to avoidable vulnerabilities.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"Sec + Day 4.html"},{"id":250,"question":"Laptops used by employees may be lost or stolen. The organization wants to protect the data stored on these devices. Which approach is most appropriate?","options":["Use full‑disk encryption to protect stored data if the device is lost or stolen.","Require users to change their passwords more frequently when traveling.","Disable USB ports to prevent unauthorized data transfers from the device.","Enable remote desktop access to reduce the need for local data storage."],"correctIndex":0,"explanation":"Full‑disk encryption protects data even if the physical device is compromised.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 4.html"},{"id":251,"question":"Major infrastructure changes have recently been deployed. The security team wants to identify any new weaknesses introduced by these changes. Which approach is most suitable?","options":["Perform targeted vulnerability scans following major changes to detect newly introduced issues.","Delay scanning until the next scheduled assessment cycle to avoid operational disruption.","Rely on user reports to identify any unexpected behavior after the changes.","Increase firewall logging to capture unusual traffic patterns after deployment."],"correctIndex":0,"explanation":"Post‑change scanning identifies vulnerabilities introduced during infrastructure updates.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 4.html"},{"id":252,"question":"The security team wants to make it harder for attackers to exploit memory corruption vulnerabilities in applications. Which approach best supports this goal?","options":["Enable exploit‑mitigation features such as ASLR and DEP to reduce attack success.","Increase application logging to detect abnormal memory usage patterns.","Restrict user permissions to prevent unauthorized access to application files.","Require code reviews for all future software updates to improve quality."],"correctIndex":0,"explanation":"Exploit‑mitigation features make memory‑based attacks significantly harder to execute.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":253,"question":"A security team wants to ensure that only approved, hardened operating system builds are used for new servers. Which approach best enforces this requirement?","options":["Provision new servers using standardized, hardened images maintained by the security team.","Allow administrators to configure new servers manually using documented guidelines.","Require post‑deployment audits to verify whether servers meet baseline expectations.","Enable automatic updates to ensure servers receive patches immediately after deployment."],"correctIndex":0,"explanation":"Standardized hardened images ensure consistent, secure server deployments.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":254,"question":"A newly disclosed vulnerability is being actively exploited in environments similar to the organization’s infrastructure. Which factor most strongly indicates that this issue requires emergency remediation?","options":["Active exploitation in similar environments significantly increases the likelihood of attack.","The vulnerability affects a feature that is rarely used during normal operations.","The vendor has not yet released a patch for the vulnerability.","The vulnerability was published recently and has limited public documentation."],"correctIndex":0,"explanation":"Active exploitation indicates attackers are already targeting this vulnerability.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":255,"question":"After an initial compromise, the organization wants to limit the ability of malware to move laterally between systems. Which approach best supports this objective?","options":["Segment internal networks to restrict unauthorized movement between systems.","Increase password complexity requirements for all user accounts.","Enable verbose logging to capture detailed information about system interactions.","Require multi‑factor authentication for all internal administrative actions."],"correctIndex":0,"explanation":"Segmentation limits how far malware can spread after an initial compromise.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 4.html"},{"id":256,"question":"Leadership wants vulnerability management activities to be repeatable, measurable, and suitable for long-term improvement. Which approach best supports this requirement?","options":["Establish governance processes that define metrics, reporting, and continuous improvement goals.","Increase scan frequency to gather more data for long‑term analysis.","Assign remediation tasks to teams based on available staffing levels.","Store vulnerability reports indefinitely to maintain historical reference material."],"correctIndex":0,"explanation":"Governance establishes structure, metrics, and consistency for long‑term program maturity.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 4.html"},{"id":257,"question":"Which monitoring platform aggregates logs and correlates alerts across enterprise security systems?","options":["Centralized SIEM analytics correlating multi source telemetry through behavioral detection engines","Endpoint configuration platform enforcing local device compliance through isolated host policies","Layer three routing device forwarding packets using static route configuration tables","Patch deployment service distributing vendor software updates through scheduled workflows"],"correctIndex":0,"explanation":"SIEM platforms aggregate and correlate logs.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":258,"question":"Which alerting technique reduces repetitive duplicate security notifications?","options":["Alert suppression consolidating recurring detections into grouped security notification events","Traffic mirroring duplicating packets toward dedicated analysis monitoring interfaces","Network segmentation dividing infrastructure through logical virtual LAN enforcement","Firmware lifecycle automation replacing outdated embedded device operating systems"],"correctIndex":0,"explanation":"Alert suppression reduces alert fatigue.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Day 5.html"},{"id":259,"question":"Which monitoring solution analyzes endpoint behavior to detect suspicious runtime activity?","options":["Endpoint detection analytics monitoring processes through behavioral anomaly detection telemetry","Perimeter firewall inspection filtering inbound packets through static rule evaluation policies","Secure proxy service relaying outbound web traffic through content filtering mechanisms","System imaging platform deploying standardized workstation builds through automated scripts"],"correctIndex":0,"explanation":"EDR tools analyze endpoint behavior.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + Day 5.html"},{"id":260,"question":"Which log source records authentication successes and failures from identity providers?","options":["Directory service audit logs documenting login attempts and authorization validation events","Wireless controller metrics tracking device roaming behavior across enterprise access points","Switch forwarding tables listing learned MAC addresses across physical network interfaces","Printer job queues recording completed printing activity across departmental resources"],"correctIndex":0,"explanation":"Directory logs record authentication activity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 5.html"},{"id":261,"question":"Which monitoring practice validates alerts by correlating multiple telemetry sources?","options":["Event correlation comparing security data across diverse monitoring platforms for validation","Port scanning enumerating open services through sequential probing of network hosts","Configuration auditing verifying system baselines against regulatory compliance standards","Backup restoration testing validating disaster recovery procedures through scheduled simulations"],"correctIndex":0,"explanation":"Event correlation confirms suspicious activity.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 5.html"},{"id":262,"question":"Which alert severity classification requires immediate containment response actions?","options":["Critical severity classification indicating confirmed malicious activity requiring urgent mitigation","Informational severity classification documenting normal operational system status messages","Low severity classification describing minor deviations unlikely to affect enterprise operations","Medium severity classification indicating suspicious activity requiring standard investigation"],"correctIndex":0,"explanation":"Critical alerts require immediate action.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 5.html"},{"id":263,"question":"Which monitoring method establishes normal activity baselines to identify anomalies?","options":["Behavioral analytics comparing current metrics against historical baseline performance thresholds","Signature inspection matching network packets against predefined threat detection rules","Manual log review analyzing archived events through periodic analyst investigation","Compliance scanning validating device configurations against industry benchmark templates"],"correctIndex":0,"explanation":"Behavioral analytics detect deviations from baselines.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":264,"question":"Which tool inspects packet captures to identify suspicious protocol anomalies?","options":["Network protocol analyzer dissecting captured traffic using deep packet inspection techniques","Endpoint configuration manager deploying standardized security baselines across enterprise devices","Federated identity service providing cross domain authentication through trust relationships","Database optimization engine restructuring queries to improve application performance"],"correctIndex":0,"explanation":"Protocol analyzers examine packet captures.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 5.html"},{"id":265,"question":"Which monitoring output occurs when detection rule conditions are met?","options":["Automated alert notification generated after predefined detection thresholds are exceeded","Maintenance schedule report documenting upcoming planned service downtime periods","Asset inventory export listing approved enterprise hardware and licensed software resources","Capacity forecast analysis predicting future storage utilization across production systems"],"correctIndex":0,"explanation":"Alerts are generated when rules trigger.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":266,"question":"Which alert tuning practice reduces false positives while maintaining detection coverage?","options":["Detection rule refinement adjusting thresholds using validated historical incident telemetry","Network expansion extending monitoring visibility into newly deployed organizational subnets","Backup retention modification altering archival storage lifecycle management policies","Encryption enforcement applying cryptographic protections across enterprise application traffic"],"correctIndex":0,"explanation":"Rule tuning reduces false positives.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":267,"question":"Which monitoring platform identifies abnormal outbound traffic suggesting data exfiltration?","options":["Network traffic analysis engine evaluating outbound flows using behavioral anomaly detection models","Operating system hardening toolkit disabling unnecessary services across endpoint builds","Cloud orchestration system provisioning virtual machines during workload scaling operations","Wireless management controller optimizing signal distribution across office floor deployments"],"correctIndex":0,"explanation":"NTA tools detect abnormal outbound traffic.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Day 5.html"},{"id":268,"question":"Which prioritization method ranks alerts based on potential organizational risk impact?","options":["Risk based prioritization scoring incidents using asset value and threat likelihood calculations","Chronological sorting arranging alerts based solely on timestamp order of occurrence","Alphabetical categorization organizing events through standardized naming conventions","Geographic grouping clustering alerts based on physical infrastructure deployment locations"],"correctIndex":0,"explanation":"Risk-based prioritization evaluates impact and likelihood.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 5.html"},{"id":269,"question":"Which monitoring solution analyzes DNS queries to detect suspicious domains?","options":["DNS telemetry monitoring platform capturing query logs for anomaly detection analysis","Switch configuration utility modifying VLAN assignments across enterprise network infrastructure","Certificate authority server issuing digital certificates for encrypted communication channels","File compression utility reducing archive sizes for efficient long term storage management"],"correctIndex":0,"explanation":"DNS monitoring detects malicious domains.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":270,"question":"Which detection approach compares file hashes against known malicious signatures?","options":["Signature based detection verifying file fingerprints against curated threat intelligence databases","Behavioral anomaly detection comparing runtime user activity against established usage baselines","Manual threat hunting analyzing historical telemetry through investigator driven research methods","Compliance monitoring validating configurations against published regulatory frameworks"],"correctIndex":0,"explanation":"Signature detection uses known malicious hashes.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 5.html"},{"id":271,"question":"Which monitoring capability detects abnormal privilege escalation attempts?","options":["User behavior analytics monitoring privilege changes through contextual access pattern analysis","Bandwidth optimization appliance compressing traffic streams to improve network performance","Disk defragmentation utility reorganizing storage sectors to improve read write efficiency","Time synchronization service aligning device clocks using centralized network protocols"],"correctIndex":0,"explanation":"UBA identifies abnormal privilege changes.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 5.html"},{"id":272,"question":"Which log source best detects unauthorized firewall configuration changes?","options":["Firewall administrative audit logs documenting rule modifications and configuration updates","Wireless interference reports measuring channel congestion across access point deployments","Printer usage metrics summarizing departmental printing activity across shared resources","Operating system boot records documenting workstation startup times across enterprise fleets"],"correctIndex":0,"explanation":"Firewall admin logs record configuration changes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 5.html"},{"id":273,"question":"Which alert suggests a brute force login attack against authentication services?","options":["Repeated failed authentication attempts exceeding predefined account lockout thresholds","Authorized software installation logs generated during scheduled enterprise deployment windows","Scheduled system restarts performed following approved patch management cycles","Routine vulnerability scans identifying outdated packages across managed production servers"],"correctIndex":0,"explanation":"Multiple login failures indicate brute force attacks.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":274,"question":"Which monitoring strategy detects lateral movement across internal networks?","options":["East west traffic monitoring analyzing internal communication patterns for abnormal behavior","North south filtering inspecting inbound internet traffic through perimeter gateway devices","Peripheral hardware inventory tracking authorized USB device usage across endpoints","Electrical consumption monitoring measuring power utilization across data center equipment"],"correctIndex":0,"explanation":"East-west monitoring identifies lateral movement.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":275,"question":"Which alert pattern indicates malware beaconing to command infrastructure?","options":["Consistent periodic outbound connections to a single external destination at regular intervals","Large enterprise software update downloads during approved scheduled maintenance windows","Short DNS query bursts generated during typical authenticated web browsing activities","Routine database synchronization uploads executed during automated nightly backup processes"],"correctIndex":0,"explanation":"Regular outbound communication indicates beaconing.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 5.html"},{"id":276,"question":"Which monitoring platform correlates vulnerability scan results with active threat alerts?","options":["Integrated security analytics platform combining vulnerability findings with real time event correlation","Desktop imaging system deploying standardized operating systems across enterprise endpoints","Load balancing appliance distributing incoming web traffic across redundant application servers","Virtual desktop infrastructure hosting remote sessions through centralized hypervisor clusters"],"correctIndex":0,"explanation":"Integrated analytics correlate vulnerabilities with alerts.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 5.html"},{"id":277,"question":"Which monitoring metric may indicate a denial of service attack?","options":["Sudden spike in inbound connections exceeding historical baseline network traffic patterns","Gradual increase in employee login frequency during normal operational business hours","Stable CPU utilization observed during predictable scheduled batch processing operations","Incremental storage growth caused by routine automated database backup archival"],"correctIndex":0,"explanation":"Traffic spikes suggest DoS attacks.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 5.html"},{"id":278,"question":"Which monitoring solution analyzes web application logs for injection attempts?","options":["Web application firewall analytics inspecting HTTP request payloads for malicious input patterns","Layer two switch monitoring system recording MAC address learning events across network ports","System temperature monitoring utility tracking hardware thermal performance across servers","Help desk ticketing system categorizing user support requests using standardized templates"],"correctIndex":0,"explanation":"WAF analytics detect injection attacks.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 5.html"},{"id":279,"question":"Which alert indicates possible data staging prior to exfiltration?","options":["Large sensitive files aggregated into temporary directories outside normal workflow patterns","Routine archive compression jobs executed during scheduled enterprise backup automation","Patch repository synchronization downloading update packages during maintenance windows","Operating system cache files expanding temporarily during high performance application execution"],"correctIndex":0,"explanation":"Unexpected file staging can indicate exfiltration preparation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 5.html"},{"id":280,"question":"Which monitoring process proactively searches historical logs for hidden threats?","options":["Threat hunting analysis reviewing archived telemetry through hypothesis driven investigative methods","Routine log rotation archiving historical records to conserve available disk storage capacity","Configuration baseline enforcement applying standardized hardening policies across endpoints","Infrastructure provisioning automation deploying servers through predefined template scripts"],"correctIndex":0,"explanation":"Threat hunting proactively searches for hidden threats.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 5.html"},{"id":281,"question":"Which alert suggests insider threat behavior involving abnormal file access?","options":["User accessing large volumes of sensitive files outside established working hour patterns","Employee updating contact information through authorized human resource management portals","Administrator deploying approved system updates during scheduled maintenance operations","Department staff printing quarterly business reports during normal reporting cycle periods"],"correctIndex":0,"explanation":"Abnormal file access can indicate insider threats.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":282,"question":"Which monitoring technique detects impossible travel login scenarios?","options":["Geolocation anomaly detection comparing login timestamps against realistic travel duration thresholds","Password expiration enforcement requiring credential rotation through scheduled authentication policies","Certificate validation verifying encrypted sessions using trusted public key infrastructures","Disk quota monitoring limiting storage allocation across departmental shared file repositories"],"correctIndex":0,"explanation":"Impossible travel detection flags suspicious logins.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 5.html"},{"id":283,"question":"Which monitoring tool detects malicious scripts executed inside web browsers?","options":["Endpoint browser telemetry monitoring script execution using runtime behavioral anomaly detection","Network address translation gateway converting private addresses for outbound internet connectivity","Cloud billing dashboard summarizing monthly infrastructure resource consumption reports","System uptime tracker reporting availability metrics for business critical application services"],"correctIndex":0,"explanation":"Browser monitoring detects malicious scripts.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 5.html"},{"id":284,"question":"Which alert indicates unauthorized persistence mechanisms after reboot?","options":["Unapproved startup registry entries created outside authorized enterprise application deployment tools","Temporary diagnostic log files generated during scheduled system performance benchmarking","Driver updates installed automatically through vendor supported hardware update utilities","Group policy refresh operations applied across domain joined workstations during synchronization"],"correctIndex":0,"explanation":"Unauthorized startup entries indicate persistence.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 5.html"},{"id":285,"question":"Which monitoring approach correlates badge access logs with workstation login events?","options":["Context aware authentication analytics comparing physical entry records against digital login timestamps","Network throughput monitoring measuring bandwidth consumption across enterprise departments","Asset lifecycle management tracking procurement stages of new hardware inventory requests","Printer queue optimization distributing print jobs across multiple shared network print servers"],"correctIndex":0,"explanation":"Correlating physical and logical access improves detection.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":286,"question":"Which monitoring control analyzes cloud API activity for suspicious administrative behavior?","options":["Cloud activity monitoring platform evaluating API calls using anomaly detection and behavior baselines","Local disk monitoring utility tracking storage fragmentation levels across endpoint devices","Wireless signal survey tool mapping coverage strength across corporate office floor layouts","Environmental monitoring sensor measuring humidity levels inside data center facilities"],"correctIndex":0,"explanation":"Cloud monitoring detects suspicious API actions.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 5.html"},{"id":287,"question":"1. Which incident response phase primarily focuses on limiting spread while investigation continues?","options":["Containment by isolating impacted hosts quickly","Preparation by updating runbooks and training staff","Recovery by returning services to production safely","Lessons learned by documenting process gaps clearly"],"correctIndex":0,"explanation":"Containment is intended to stop or limit damage and prevent further spread while analysis proceeds.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":288,"question":"2. A sudden spike in outbound traffic to unfamiliar IPs most strongly suggests which indicator?","options":["Normal telemetry uploading to trusted vendor endpoints","Data exfiltration or command-and-control callbacks","Routine patch distribution using content delivery nodes","Standard directory replication across internal servers"],"correctIndex":1,"explanation":"Unusual outbound connections—especially to unknown or rare destinations—commonly indicate C2 activity or exfiltration.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":289,"question":"3. Which activity is MOST associated with the lessons learned phase?","options":["Holding a post-incident review and updating playbooks","Restoring production services after removing malware","Capturing volatile memory before powering down hosts","Blocking suspicious domains at the secure web gateway"],"correctIndex":0,"explanation":"Lessons learned includes after-action reviews, documentation, and process improvements.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":290,"question":"4. Multiple failed logins followed by a successful login from the same source is a classic sign of:","options":["Credential stuffing or brute-force password attempts","Normal authentication retries during network latency","Scheduled account provisioning by identity services","Routine security scanning by approved assessment tools"],"correctIndex":0,"explanation":"Repeated failures followed by success can indicate password guessing or use of leaked credentials.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 6.html"},{"id":291,"question":"5. Which action best fits the eradication phase of incident response?","options":["Removing malware artifacts and patching the root flaw","Isolating affected network segments to stop propagation","Drafting the communications plan for stakeholders","Capturing baseline metrics for future event detection"],"correctIndex":0,"explanation":"Eradication removes the threat and addresses root causes (e.g., patching vulnerabilities, removing persistence).","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":292,"question":"6. Unexpected registry modifications that reappear after reboot most commonly indicate:","options":["Malware persistence using autorun or startup entries","Standard user profile synchronization across endpoints","Routine OS tuning applied by enterprise hardening tools","Normal application updates adjusting configuration keys"],"correctIndex":0,"explanation":"Persistence mechanisms often modify registry run keys or similar startup settings to survive reboots.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":293,"question":"7. The primary objective of the recovery phase is to:","options":["Return systems to operation with validated clean state","Identify the initial infection vector with certainty","Create IOCs and distribute them to threat feeds","Collect volatile memory and packet captures immediately"],"correctIndex":0,"explanation":"Recovery focuses on safely restoring services (often with monitoring and validation) after eradication.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 6.html"},{"id":294,"question":"8. Which item is an example of an Indicator of Compromise (IOC)?","options":["A known malicious file hash observed on an endpoint","A quarterly awareness training completion percentage","A documented acceptable use policy with revisions","A configuration baseline stored in a change system"],"correctIndex":0,"explanation":"IOCs include hashes, domains, IPs, registry keys, filenames, and other artifacts tied to malicious activity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":295,"question":"9. Which solution is MOST commonly used to aggregate and correlate logs for incident analysis?","options":["Security Information and Event Management platform","Network Time Protocol synchronization service","Dynamic Host Configuration Protocol address manager","Simple Network Management Protocol polling engine"],"correctIndex":0,"explanation":"SIEMs centralize log ingestion and correlation to identify suspicious patterns across sources.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":296,"question":"10. Sustained high CPU usage caused by an unfamiliar process on many endpoints is a strong indicator of:","options":["Unauthorized cryptocurrency mining or resource hijacking","Normal endpoint compliance scanning during off-hours","Routine OS indexing and search optimization services","Approved software distribution pushing large updates"],"correctIndex":0,"explanation":"Cryptominers and some malware families cause notable CPU usage, especially when widespread.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":297,"question":"11. A user reports that files were renamed and now have unfamiliar extensions, plus a ransom note appears. This indicates:","options":["Ransomware encrypting data and demanding payment","Standard disk compression performed by maintenance jobs","Normal file format conversion by productivity software","Authorized data archival and lifecycle management policy"],"correctIndex":0,"explanation":"Renamed/encrypted files and ransom notes are hallmark ransomware indicators.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":298,"question":"12. Which artifact is MOST helpful for proving evidence integrity during a forensic process?","options":["Cryptographic hash values recorded for the evidence","A screenshot of the file directory showing timestamps","A printed copy of system information from the host","A list of installed applications exported to a text file"],"correctIndex":0,"explanation":"Hashes (e.g., SHA-256) help verify evidence has not changed during handling and analysis.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":299,"question":"13. In incident response, chain of custody primarily ensures:","options":["Documentation of evidence handling from start to finish","Automatic restoration of systems using trusted backups","Immediate blocking of malicious domains at the firewall","Encryption of logs before forwarding to a central system"],"correctIndex":0,"explanation":"Chain of custody documents who handled evidence, when, and how, supporting legal defensibility.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 6.html"},{"id":300,"question":"14. Which is the BEST example of lateral movement activity in logs?","options":["One workstation authenticating to many hosts rapidly","A single server applying patches to its own services","A user opening a local file from their documents folder","A printer requesting DHCP renewal after a lease expires"],"correctIndex":0,"explanation":"Lateral movement often appears as unusual authentication patterns from a compromised host to many internal systems.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":301,"question":"15. An endpoint begins beaconing every 60 seconds to a rare domain using HTTPS. This most likely indicates:","options":["Command-and-control communications using regular beacons","Standard certificate revocation checks by web browsers","Normal OS time synchronization with an external service","Routine content retrieval from a well-known CDN provider"],"correctIndex":0,"explanation":"Periodic, regular connections to rare infrastructure are typical C2 beacon behavior.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":302,"question":"16. A user receives an email requesting urgent payment and the sender domain is slightly misspelled. This is most likely:","options":["Business email compromise or targeted phishing attempt","Routine invoice processing from a vendor mail gateway","An automated password expiration reminder from identity","A harmless marketing message sent from a mailing list"],"correctIndex":0,"explanation":"Lookalike domains and urgency cues are common in phishing/BEC attempts.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":303,"question":"17. Which action is MOST appropriate FIRST when malware is suspected on a critical server?","options":["Isolate the server to contain impact while preserving data","Immediately wipe the system drive to remove the malware","Publicly notify customers before initial triage is complete","Disable all logging to prevent the attacker from noticing"],"correctIndex":0,"explanation":"Containment is typically the first operational step—limit spread while maintaining evidence for analysis.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":304,"question":"18. Which indicator most strongly suggests DNS tunneling?","options":["Many long and random-looking DNS queries to one domain","A normal number of DNS queries to common SaaS services","Short DNS queries for internal hostnames during business","DNS replies cached locally reducing outbound query volume"],"correctIndex":0,"explanation":"DNS tunneling often uses long subdomains, high query volume, and unusual patterns to carry data.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"Sec + Day 6.html"},{"id":305,"question":"19. A security analyst sees a new local admin account created outside change control. This is most likely evidence of:","options":["Privilege escalation or persistence via rogue accounts","Routine group policy refresh applying standard accounts","A normal endpoint enrollment process for device management","Standard password rotation applied by the PAM solution"],"correctIndex":0,"explanation":"Unexpected admin account creation is a strong sign of compromise or policy violation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 6.html"},{"id":306,"question":"20. Which response best describes the purpose of an incident response playbook?","options":["A step-by-step guide for handling a specific incident type","A list of user passwords stored for emergency access use","A vendor catalog describing security products and pricing","A legal contract defining service uptime requirements only"],"correctIndex":0,"explanation":"Playbooks standardize actions and decision points for consistent handling of common incident scenarios.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":307,"question":"21. Which log source is MOST useful for detecting abnormal privilege use on Windows systems?","options":["Security event logs showing logons and privilege changes","Printer spooler logs showing queued and completed jobs","Application theme logs showing user display preferences","Battery usage logs showing charge and discharge cycles"],"correctIndex":0,"explanation":"Windows Security logs (and related auditing) are key for tracking logons, group changes, and privileged actions.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":308,"question":"22. Which technique best helps reduce false positives during indicator-based detection?","options":["Correlating multiple signals before escalating an alert","Alerting on a single IOC match without additional context","Disabling endpoint telemetry to prevent noisy detections","Blocking all outbound traffic to avoid any beacon traffic"],"correctIndex":0,"explanation":"Correlation (SIEM/EDR context) helps confirm suspicious behavior versus one-off matches.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 6.html"},{"id":309,"question":"23. A host shows repeated authentication attempts using many usernames against one service. This most likely indicates:","options":["Password spraying attempt against a common credential set","Normal SSO token refresh activity across multiple users","Routine HR onboarding automatically validating accounts","Standard VPN reconnection events due to network jitter"],"correctIndex":0,"explanation":"Password spraying tries a few common passwords against many accounts to avoid lockouts.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":310,"question":"24. Which activity is MOST appropriate during the detection and analysis phase?","options":["Confirming the incident, triaging scope, and collecting IOCs","Rebuilding all impacted systems without preserving evidence","Publishing a public statement before internal validation","Removing all logs to prevent further attacker discovery"],"correctIndex":0,"explanation":"Detection/analysis validates the event, determines scope/impact, and gathers details for containment/eradication.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":311,"question":"25. A file integrity monitoring alert shows critical binaries changed without a patch window. This most likely indicates:","options":["Unauthorized modification or tampering with system files","Routine update activity completed during planned downtime","Standard user personalization settings applied at login","Normal backup deduplication rewriting unchanged content"],"correctIndex":0,"explanation":"Unexpected changes to critical files can indicate compromise, rootkits, or malicious tampering.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 6.html"},{"id":312,"question":"26. Which indicator best aligns with a rootkit infection on a host?","options":["Hidden processes or drivers and inconsistent system outputs","A single blocked pop-up window from a web browser tab","An increase in helpdesk tickets during a password reset day","A normal reboot after applying an approved security update"],"correctIndex":0,"explanation":"Rootkits often hide processes/drivers and manipulate system calls, causing inconsistent views between tools.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 6.html"},{"id":313,"question":"27. Which step helps preserve evidence BEST when collecting data from a suspect disk?","options":["Create a forensic image using a write blocker when possible","Open the files directly and copy only the suspicious ones","Run a cleanup utility to remove temporary files beforehand","Defragment the drive to speed up scanning and collection"],"correctIndex":0,"explanation":"Forensic imaging with write blockers helps prevent altering evidence and supports repeatable analysis.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"Sec + Day 6.html"},{"id":314,"question":"28. Which communication is MOST appropriate as part of an incident response communications plan?","options":["Defined internal and external notification procedures and roles","A list of employee personal accounts for emergency contact use","A schedule of marketing campaigns for the next quarter year","A catalog of office equipment replacement part identifiers"],"correctIndex":0,"explanation":"A communications plan defines who communicates what, to whom, and when (legal/PR/leadership/technical).","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":315,"question":"29. A user reports their browser homepage and proxy settings changed without permission. This most likely indicates:","options":["Potential browser hijacking or unauthorized configuration change","Routine browser updates applying standard security defaults","Normal DHCP changes updating gateway and DNS information","Approved enterprise management applying user experience settings"],"correctIndex":0,"explanation":"Unexpected proxy/homepage changes can indicate adware, browser hijackers, or malicious configuration changes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 6.html"},{"id":316,"question":"30. Which outcome best reflects successful incident containment?","options":["Further spread is stopped while evidence and operations are managed","All systems are wiped immediately without determining scope first","A public press release is issued before internal validation completes","Logs are disabled to prevent attackers from noticing investigation steps"],"correctIndex":0,"explanation":"Containment aims to stop propagation and limit impact while maintaining the ability to investigate and recover.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 6.html"},{"id":317,"question":"Which activity best demonstrates effective security governance rather than day-to-day security operations?","options":["Approving security policy and risk direction through executive oversight","Adjusting IDS rules to reduce repeated false positive alerts","Rotating service account credentials on a set monthly schedule","Reimaging an infected workstation to remove persistent malware"],"correctIndex":0,"explanation":"Governance is direction and oversight (policy approval, risk appetite). The others are operational tasks.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":318,"question":"A company wants security decisions aligned with business goals and clear accountability. What is MOST appropriate?","options":["Establish a security steering committee with authority and metrics","Let each department select controls without centralized coordination","Assign all approvals to the SOC manager without executive input","Outsource security entirely and remove internal decision oversight"],"correctIndex":0,"explanation":"A steering committee supports governance via alignment, authority, accountability, and escalation paths.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":319,"question":"Which document MOST directly translates high-level security objectives into specific, measurable requirements?","options":["Security standards that define mandatory technical requirements","Acceptable use policy describing expected user behavior","Incident response playbook describing response workflows","Network topology diagram showing paths and device placement"],"correctIndex":0,"explanation":"Policies state intent; standards define measurable requirements such as versions, lengths, and configurations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":320,"question":"A policy states: “Sensitive data must be protected in transit.” Which supporting standard is BEST?","options":["Require TLS 1.2+ with approved cipher suites for sensitive transfers","Encourage employees to avoid sending sensitive data when possible","Require the help desk to verify identity during password resets","Ask developers to document APIs that handle sensitive information"],"correctIndex":0,"explanation":"A standard is specific and testable. TLS version and ciphers are enforceable requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":321,"question":"Which is the BEST example of separation of duties (SoD)?","options":["One person requests payment, another approves, and a third reconciles","Administrators use MFA for all privileged access sessions","Developers complete security training during annual refresher events","Users change passwords every 90 days based on written policy"],"correctIndex":0,"explanation":"SoD splits critical steps across different roles to reduce fraud and mistakes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":322,"question":"A company is adopting a new cloud service. Which governance artifact best sets security expectations for vendors?","options":["Third-party risk requirements and contract security clauses for services","An internal list of employee job titles and reporting structure","A wireless coverage diagram showing access point placement areas","A collection of old incident tickets from prior unrelated systems"],"correctIndex":0,"explanation":"TPRM artifacts and contract clauses define responsibilities, reporting, and security requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":323,"question":"Which metric BEST supports governance by demonstrating executive-level security program effectiveness?","options":["Risk reduction trends for critical services based on periodic assessments","Number of firewall packets dropped during the previous business hour","CPU usage percentage on SIEM collectors averaged across all nodes","Total help desk calls related to printers and peripheral connectivity"],"correctIndex":0,"explanation":"Governance metrics should tie to business risk and critical service outcomes, not low-level telemetry.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":324,"question":"What is the PRIMARY goal of data classification within a security governance program?","options":["Apply handling rules based on sensitivity and business impact of data","Ensure all data uses a single encryption method across the enterprise","Eliminate the need for access controls through uniform permissions","Require all data to remain on-premises without any cloud storage use"],"correctIndex":0,"explanation":"Classification drives appropriate controls (access, retention, encryption, sharing) based on sensitivity.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":325,"question":"A team is asked to implement controls that match the organization’s risk appetite. What should happen FIRST?","options":["Perform a risk assessment to prioritize threats and business impacts","Deploy DLP to all endpoints immediately to prevent any data movement","Block all external attachments to reduce exposure to malware risks","Require biometrics for every user login regardless of role needs"],"correctIndex":0,"explanation":"You select controls after understanding risk and prioritizing based on likelihood/impact and objectives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":326,"question":"Which scenario BEST represents a formal exception (policy waiver) process?","options":["A time-bound deviation approved with compensating controls and tracking","A developer disables logging permanently to improve application speed","A user shares credentials to meet a deadline and avoid ticket delays","A vendor rejects clauses and the business proceeds without documentation"],"correctIndex":0,"explanation":"Exceptions should be documented, authorized, time-limited, and include compensating controls.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":327,"question":"What is the PRIMARY difference between an internal audit and an external audit?","options":["Internal audits are organizational; external audits require independent review","Internal audits are always financial; external audits are only technical","Internal audits do not require evidence; external audits always require it","Internal audits cannot report results to management or leadership teams"],"correctIndex":0,"explanation":"Independence is key: internal audits are internal assurance, external audits are independent/regulatory.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":328,"question":"During an audit, which item is the BEST example of objective evidence?","options":["System logs showing administrative login attempts over a set time window","A manager stating that access reviews are performed on a regular basis","A policy stating access reviews should be performed quarterly by owners","An employee claiming MFA is enforced everywhere across all environments"],"correctIndex":0,"explanation":"Objective evidence is verifiable (logs, tickets, signed reviews), not statements or intent documents.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":329,"question":"Which assessment BEST validates the effectiveness of security controls over time?","options":["Periodic control testing with documented results and follow-up actions","A one-time asset inventory completed during initial system onboarding","A diagram review that does not validate configuration or implementation","A marketing survey measuring customer sentiment toward company products"],"correctIndex":0,"explanation":"Ongoing effectiveness is demonstrated through repeatable testing, evidence, and remediation tracking.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 7.html"},{"id":330,"question":"A penetration test is MOST likely to answer which question?","options":["Can an attacker exploit weaknesses to achieve a defined objective?","Are employees aware of the exact password policy wording in place?","Has the board formally approved the organization’s data classification policy?","Are vendor invoices approved and reconciled properly by accounting teams?"],"correctIndex":0,"explanation":"Pen tests validate exploitability and attack paths to objectives like privilege escalation or data access.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":331,"question":"Which activity BEST represents a vulnerability assessment rather than a penetration test?","options":["Scanning for known weaknesses and prioritizing fixes based on risk","Using social engineering to obtain credentials and pivot across systems","Chaining exploits to reach sensitive data and prove end-to-end impact","Establishing persistence with covert command-and-control communications"],"correctIndex":0,"explanation":"Vulnerability assessments identify and prioritize weaknesses; penetration tests attempt exploitation.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":332,"question":"Which document BEST defines scope, rules of engagement, and authorization for a penetration test?","options":["A signed SOW/ROE document with explicit written authorization details","An acceptable use policy describing how employees should use systems","A disaster recovery plan describing recovery strategies during outages","A data retention schedule listing required retention periods per record"],"correctIndex":0,"explanation":"A formal SOW/ROE plus authorization defines scope, windows, limitations, and legal permission.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":333,"question":"After an audit identifies a high-risk finding, what is the MOST appropriate next step?","options":["Create a remediation plan with owners, dates, and tracked verification","Delete the report to reduce exposure and avoid discovery in litigation","Wait until the next annual audit cycle before addressing the issue","Terminate employees immediately without validating facts or root cause"],"correctIndex":0,"explanation":"High-risk findings require owned remediation, timelines, tracking, and verification to closure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":334,"question":"Which is the BEST example of a compensating control for an audit finding?","options":["Use a jump host with MFA and session recording until direct access ends","Accept risk informally without documenting approval or compensations","Disable security logs to reduce storage costs and simplify operations","Grant broader privileges to reduce the number of access request tickets"],"correctIndex":0,"explanation":"Compensating controls reduce risk when the primary control cannot be implemented immediately.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 7.html"},{"id":335,"question":"A security awareness program wants to measure improvement in phishing detection. Which metric is MOST direct?","options":["Phishing simulation click and credential submission rates over time","Total number of emails received by the organization each calendar month","Average laptop battery health across the endpoint fleet over quarters","Number of employee badges issued and replaced due to normal wear"],"correctIndex":0,"explanation":"Simulated phishing outcomes directly measure susceptibility and trends in user behavior.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 7.html"},{"id":336,"question":"Which approach BEST improves awareness training effectiveness across different employee roles?","options":["Role-based training tailored to job functions and likely threat scenarios","One annual generic video for everyone regardless of duties or exposure","Training only new hires and skipping refresher training for all others","Using posters only without interaction, testing, or follow-up evaluation"],"correctIndex":0,"explanation":"Role-based training increases relevance and retention for groups like devs, finance, and executives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":337,"question":"When preparing for a compliance audit, which action BEST supports audit readiness?","options":["Maintain a mapped repository of control evidence aligned to requirements","Recreate evidence only after auditors arrive and request documentation","Disable logging to reduce the volume of evidence auditors can review","Provide only policy documents and avoid operational evidence collection"],"correctIndex":0,"explanation":"Readiness is improved when evidence is organized, current, and mapped to control requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":338,"question":"Which item is MOST associated with SOC 2 Type II compared to Type I?","options":["Testing operating effectiveness of controls over a defined time period","A point-in-time description of controls without effectiveness testing","A quarterly network penetration test across the public address space","A one-time vulnerability scan of perimeter systems and public services"],"correctIndex":0,"explanation":"Type I focuses on design at a point in time; Type II evaluates operating effectiveness over time.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":339,"question":"What is the BEST description of the outcome of a gap analysis against a security framework?","options":["A mapped comparison showing deficiencies and prioritized actions to close gaps","A list of discovered vulnerabilities produced only by scanning tools output","A record of incidents over the last year sorted by attack type categories","A diagram of VLANs and network segments showing routing and access paths"],"correctIndex":0,"explanation":"Gap analysis compares current state to target requirements and produces remediation actions.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 7.html"},{"id":340,"question":"Which concept BEST describes ensuring security policies are followed through monitoring and corrective actions?","options":["Compliance management with tracking, reporting, and corrective remediation","Threat hunting for hidden adversaries in internal telemetry and logs","Vulnerability chaining to demonstrate multi-step exploitation in networks","Packet capture analysis to troubleshoot latency and connection behavior"],"correctIndex":0,"explanation":"Compliance management ensures adherence to policies/standards via monitoring, reporting, and remediation.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":341,"question":"To reduce insider risk by minimizing unnecessary access, which governance practice BEST supports the goal?","options":["Least privilege with periodic access reviews and timely deprovisioning","Increasing Wi-Fi coverage to improve roaming and reduce dead zones","Allowing shared accounts for convenience when workloads become heavy","Disabling EDR alerts broadly to reduce notification fatigue in teams"],"correctIndex":0,"explanation":"Least privilege plus access reviews and deprovisioning reduces excess permissions and insider risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":342,"question":"Which role is MOST commonly responsible for setting strategic security direction aligned with business goals?","options":["CISO or equivalent executive leader accountable for security strategy","Help desk technician responsible for resolving end-user access issues","Junior system administrator managing day-to-day server configurations","Facilities supervisor coordinating building access and maintenance work"],"correctIndex":0,"explanation":"Strategic security direction and alignment are executive responsibilities typically led by the CISO.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":343,"question":"Which governance practice BEST ensures critical systems remain secure as changes occur?","options":["Formal change management with security review and documented approvals","Allowing direct production deployments without review to move quickly","Disabling version control to reduce complexity and simplify workflows","Relying on annual audits as the primary method to detect issues later"],"correctIndex":0,"explanation":"Change management enforces review, testing, approval, and logging to reduce change-related risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":344,"question":"A company needs to define how long records are kept and how they are disposed. Which policy area applies?","options":["Data retention and disposal policy covering lifecycle and secure destruction","Password complexity policy defining length, history, and rotation requirements","Wireless encryption policy defining supported protocols for Wi-Fi networks","Patch management policy defining timelines for updating OS and applications"],"correctIndex":0,"explanation":"Retention and disposal policies define how long to keep records and how to dispose of them securely.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":345,"question":"What is the PRIMARY purpose of a tabletop exercise (TTX) for security preparedness?","options":["Validate plans and decision-making using scenarios without live system changes","Perform live exploitation against production systems to test attacker success","Replace the need for documented incident response procedures entirely","Guarantee compliance automatically by simulating regulator expectations only"],"correctIndex":0,"explanation":"TTXs are discussion-based exercises used to validate roles, processes, and decisions without impacting systems.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Day 7.html"},{"id":346,"question":"Which audit approach is MOST accurately described as risk-based?","options":["Prioritizing testing for controls that mitigate the highest business risks","Testing every control equally regardless of criticality or impact levels","Auditing only controls with evidence that is easy to gather quickly","Auditing primarily after a breach occurs to document what happened"],"correctIndex":0,"explanation":"Risk-based auditing focuses coverage on areas with the highest likelihood and impact to the business.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":347,"question":"Which item MOST indicates readiness for a formal certification-style audit with respect to documentation?","options":["Documented policies and standards with evidence of use and periodic review","One policy PDF that has never been communicated or reviewed since creation","Verbal procedures known to a few employees without any recorded evidence","A backlog of untracked security issues without owners or due date fields"],"correctIndex":0,"explanation":"Readiness requires documented requirements, proof of implementation, and governance processes like reviews.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":348,"question":"Which item is the MOST appropriate evidence that quarterly access reviews occurred?","options":["Dated review records showing reviewer identity, outcomes, and approvals","A policy statement requiring quarterly reviews for privileged user access","A manager email stating that access reviews are important for security","An IAM architecture diagram showing where access review features reside"],"correctIndex":0,"explanation":"Evidence must show the control operated: dates, reviewer identity, results, approvals, and follow-up.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":349,"question":"A security awareness team wants to reduce risky behavior quickly. Which method is MOST effective?","options":["Just-in-time micro-training delivered immediately after risky user actions","Posting long policy documents and assuming employees read them closely","Training only the IT department because they are the most technical users","Sending generic emails monthly without measuring behavior change outcomes"],"correctIndex":0,"explanation":"Just-in-time training is timely and relevant, making it more effective than generic messaging alone.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 7.html"},{"id":350,"question":"Which assessment is BEST suited to identify weaknesses in overall security program maturity?","options":["A maturity assessment mapped to a framework with capability levels defined","A malware scan of a single host to confirm detection capability status","A printer inventory review that validates asset counts and locations only","A password reset campaign that focuses only on credential hygiene changes"],"correctIndex":0,"explanation":"Maturity assessments evaluate program capabilities across people, process, and measurement over time.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec + Day 7.html"},{"id":351,"question":"Which outcome BEST reflects successful remediation verification after fixing an audit finding?","options":["Re-test the control and retain evidence showing the issue is resolved and sustained","Close the ticket as soon as the change request is submitted to an engineering queue","Wait for users to report problems if the issue returns during daily operations","Assume the fix worked because the vendor claimed the feature is enabled now"],"correctIndex":0,"explanation":"Verification requires re-testing and evidence that the corrected control is operating effectively.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 7.html"},{"id":352,"question":"Which statement BEST describes 'risk appetite'?","options":["The level and type of risk leadership is willing to accept to meet goals","A list of vulnerabilities ranked by CVSS scores for technical prioritization","The number of incidents the SOC can handle per day based on staffing","The encryption algorithm selected for data at rest across all systems"],"correctIndex":0,"explanation":"Risk appetite expresses how much risk the organization is willing to accept in pursuit of objectives.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":353,"question":"Which governance control BEST ensures policies remain current as technology and threats change?","options":["Defined review cadence with version control and stakeholder approval workflow","One-time approval at creation with no scheduled updates or periodic checks","Allowing each team to interpret policy requirements without documentation","Storing policies on a shared drive without any change tracking enabled"],"correctIndex":0,"explanation":"Formal review cycles and version control keep policies accurate and aligned with the environment.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":354,"question":"An organization wants critical processes to continue during disruptions. Which activity is MOST relevant?","options":["Business impact analysis to prioritize services and set recovery objectives","Replacing endpoints with new hardware to reduce the chance of device failure","Blocking all internet traffic except email to reduce the external attack surface","Increasing password complexity to 40 characters for all users without exceptions"],"correctIndex":0,"explanation":"A BIA identifies critical services and informs RTO/RPO and recovery planning priorities.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":355,"question":"Why is security sign-off in the SDLC considered an important governance control?","options":["It ensures security requirements are addressed before release to reduce rework","It guarantees software will have zero vulnerabilities in all environments","It eliminates the need for unit testing because security covers all defects","It replaces change management by allowing direct releases once approved"],"correctIndex":0,"explanation":"Security gates help address requirements and risks early, reducing exposure and costly last-minute fixes.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Day 7.html"},{"id":356,"question":"A financial services firm is updating its risk register after a series of phishing-related near misses. Leadership wants a numeric estimate to justify a new control, but historical incident frequency is limited. Which approach best aligns with quantitative analysis while acknowledging data constraints?","options":["Use SLE and ALE estimates with documented assumptions, then sensitivity-test ARO ranges for variance.","Use a heat map with High/Medium/Low labels and convene SMEs to vote on overall risk severity.","Use a qualitative narrative of potential impacts and prioritize risks based on stakeholder perception alone.","Use only vulnerability scan scores as a proxy for business impact and treat CVSS as financial loss."],"correctIndex":0,"explanation":"Quantitative analysis uses numeric loss models (SLE/ALE). When ARO is uncertain, you document assumptions and run sensitivity analysis rather than switching to purely qualitative methods.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":357,"question":"During a BIA review, an online retailer states the maximum downtime for the order processing system is 6 hours, but the target recovery objective is 2 hours. What is the relationship being described?","options":["MTD is the absolute limit, and RTO is the target time that must be less than or equal to the MTD value.","RPO is the absolute limit, and MTD is the target time that must be less than or equal to the RPO value.","WRT is the absolute limit, and RPO is the target time that must be less than or equal to the WRT value.","SLE is the absolute limit, and ALE is the target time that must be less than or equal to the SLE value."],"correctIndex":0,"explanation":"MTD (maximum tolerable downtime) is the hard ceiling. RTO is the targeted recovery time and should be shorter than (or at most equal to) the MTD.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":358,"question":"A security manager selects a mitigation strategy that transfers a portion of financial impact to a third party without reducing the probability of a cyber event. Which option best fits this strategy?","options":["Purchase cyber insurance and align coverage limits to modeled ALE and contractual exposure thresholds.","Deploy EDR with behavioral rules and tune detections to reduce dwell time and lateral movement paths.","Implement secure baselines and disable legacy protocols to reduce attack surface and exploit likelihood.","Accept the risk by documenting residual exposure and scheduling review at the next governance cycle."],"correctIndex":0,"explanation":"Risk transference shifts financial impact to another party (e.g., insurance), but does not inherently reduce likelihood. Controls like EDR/baselines are risk reduction.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":359,"question":"A hospital is implementing compensating controls because a legacy imaging device cannot support modern encryption. Which mitigation technique best addresses confidentiality risk without replacing the device immediately?","options":["Segment the device on an isolated VLAN with strict ACLs and a monitored jump host for administration only.","Enable full-disk encryption on the device and require TPM-backed keys for all imaging data at rest.","Deploy client-side certificates directly on the device and enforce mutual TLS across all communications.","Recompile the device firmware to support modern cipher suites and apply vendor patches weekly."],"correctIndex":0,"explanation":"When the asset cannot support strong crypto, compensating controls like segmentation, ACLs, and controlled administration reduce exposure and limit lateral movement.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 8.html"},{"id":360,"question":"A company identifies that its biggest business risk is prolonged outage from a regional disaster. They decide to maintain a secondary site with hardware installed but requiring configuration and data restoration before use. Which site type is being described?","options":["Warm site with partial readiness, requiring some restoration and configuration before full production service.","Cold site with no equipment, requiring procurement and installation prior to any operational capability.","Hot site with full synchronization, enabling near-immediate failover with minimal manual intervention steps.","Mobile site with temporary facilities, requiring shipping containers and satellite communications on demand."],"correctIndex":0,"explanation":"Warm sites have equipment but are not fully current or instantly available like hot sites; they require configuration/restoration. Cold sites are largely empty facilities.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + Day 8.html"},{"id":361,"question":"A risk owner wants to ensure that control selection is traceable to business goals and regulatory requirements. Which documentation set most directly supports this alignment?","options":["Policies, standards, and a control framework mapping that ties requirements to implemented controls and owners.","Packet captures and IDS signatures showing exploitation attempts against externally facing perimeter services.","A list of discovered vulnerabilities ranked only by CVSS base score and scanner plugin criticality levels.","An inventory of employee training completions and phishing click rates without linkage to risk statements."],"correctIndex":0,"explanation":"Governance alignment comes from policy/standards and framework mappings (e.g., NIST/ISO) that trace requirements to controls, owners, and evidence.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Day 8.html"},{"id":362,"question":"A CISO is prioritizing mitigations using a risk matrix. Multiple risks are rated 'High' because likelihood is high, but impact differs significantly between systems. What is the most appropriate next step to improve prioritization accuracy?","options":["Refine impact criteria with business owners and incorporate asset criticality so impact levels differentiate meaningfully.","Treat all High likelihood risks as equal priority and remediate them strictly in alphabetical order by system name.","Ignore impact criteria and prioritize only by likelihood because impact is subjective and difficult to validate.","Convert the matrix into CVSS-only scoring and remove business context to improve technical objectivity."],"correctIndex":0,"explanation":"When impact is not discriminating well, you tune impact criteria and include asset criticality/business context so the matrix produces more useful prioritization.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":363,"question":"A team is selecting controls to reduce ransomware blast radius. Which mitigation technique most directly limits lateral movement inside the enterprise network?","options":["Network segmentation with least privilege ACLs and restricted east-west traffic between critical subnets.","Full-disk encryption on endpoints to prevent unauthorized read access when devices are physically stolen.","A data retention policy that deletes older files to reduce storage costs and improve archival governance.","A public key infrastructure rollout intended to standardize identity issuance for external partner access."],"correctIndex":0,"explanation":"Segmentation and restrictive east-west controls reduce lateral movement and contain ransomware spread. The other options address different risk dimensions.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":364,"question":"A risk assessment identifies a control gap for privileged account monitoring. Which mitigation best supports detection and response while maintaining auditability?","options":["Implement PAM with session recording, just-in-time elevation, and centralized logging to a SIEM for review.","Disable all administrative accounts permanently and require standard users to perform all server maintenance.","Use a shared administrator password in a vault to simplify access and reduce time spent on account requests.","Allow privileged access only from unmanaged personal devices to reduce load on corporate endpoint controls."],"correctIndex":0,"explanation":"PAM with JIT and session recording improves visibility, reduces standing privilege, and creates auditable evidence. Shared passwords and unmanaged devices increase risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":365,"question":"An organization calculates SLE for a database breach as $250,000. The event is expected to occur once every five years. What is the ALE?","options":["ALE equals $50,000 per year because ARO is 0.2 and ALE is SLE multiplied by ARO for expected annual loss.","ALE equals $1,250,000 per year because ARO is 5 and ALE is SLE multiplied by ARO for expected annual loss.","ALE equals $250,000 per year because ARO is not used when the event frequency is less than one per year.","ALE equals $0 per year because events that occur every five years are excluded from annualized modeling."],"correctIndex":0,"explanation":"ARO is 1/5 = 0.2. ALE = SLE × ARO = 250,000 × 0.2 = 50,000.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":366,"question":"A vendor hosts an application for your company and commits to uptime, response times, and penalties if targets are not met. Which agreement type is most applicable?","options":["SLA that defines measurable service targets, reporting cadence, and remedies when the service level is missed.","MOU that documents shared intentions without enforceable metrics or operational penalties for missed targets.","NDA that prevents disclosure of confidential information but does not specify availability or response metrics.","ISA that defines encryption and authentication for network interconnection, not service availability measures."],"correctIndex":0,"explanation":"An SLA specifies service metrics like uptime and response times plus penalties/remedies. MOU/NDA/ISA do not primarily define service performance metrics.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":367,"question":"A security analyst proposes replacing annual tabletop exercises with a single incident response policy document to reduce costs. From a risk management perspective, what is the most accurate concern?","options":["Removing exercises reduces preparedness evidence and increases residual risk because plans must be validated and improved.","Removing exercises improves security because fewer staff learn the plan and therefore attackers gain less knowledge.","Replacing exercises with a policy increases control effectiveness because documentation always prevents operational errors.","Eliminating exercises decreases risk because it reduces audit scope and therefore reduces findings and compliance effort."],"correctIndex":0,"explanation":"Exercises test assumptions, reveal gaps, and improve response readiness. Eliminating them often increases residual risk and reduces evidence of control effectiveness.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":368,"question":"A company wants to mitigate the risk of credential stuffing on a customer portal. Which control most directly reduces the likelihood of automated login abuse?","options":["Implement MFA with rate limiting and bot detection controls to degrade automated attempts and enforce strong auth.","Add full-disk encryption to the web server to protect data at rest from local administrator access threats.","Move the portal to a different DNS provider to reduce network latency and improve customer page load times.","Deploy a new SIEM dashboard to visualize authentication logs without changing authentication control behavior."],"correctIndex":0,"explanation":"MFA, rate limiting, and bot detection directly reduce credential stuffing success. Encryption, DNS changes, and dashboards do not directly prevent automated login abuse.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":369,"question":"A risk committee approves acceptance of a low-impact, low-likelihood risk. What is the BEST supporting governance action to keep acceptance defensible over time?","options":["Document the risk owner, rationale, residual risk, and review date in the risk register with sign-off evidence.","Ignore the risk entirely because accepted risks do not require monitoring or periodic reassessment activities.","Delete the risk from the register to prevent auditors from discovering it during future compliance checks.","Mitigate the risk immediately anyway so acceptance never appears in documentation or management reporting."],"correctIndex":0,"explanation":"Risk acceptance should be explicit, documented, owned, and reviewed. This preserves accountability and supports audit defensibility as conditions change.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":370,"question":"A software team must deploy quickly but wants mitigation that reduces the probability of vulnerabilities reaching production. Which control is most appropriate?","options":["Integrate SAST/DAST into CI/CD with gating thresholds and peer code review to catch defects before release.","Rely solely on a quarterly penetration test and defer remediation until the next annual budgeting cycle.","Disable logging in production to reduce storage costs and limit sensitive data exposure in log aggregation.","Allow developers to bypass change control for emergency releases and document fixes after customer complaints."],"correctIndex":0,"explanation":"Shift-left controls like SAST/DAST, gated pipelines, and peer review reduce the likelihood of shipping vulnerabilities, supporting proactive mitigation.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Day 8.html"},{"id":371,"question":"An organization wants mitigation that primarily reduces impact, not likelihood, for a data loss scenario. Which control best fits that objective?","options":["Implement immutable backups with offline copies and tested restore procedures to limit operational impact of loss.","Deploy web application firewalls with tuned signatures to block malicious payloads and reduce exploit attempts.","Enforce strict password complexity rules to increase brute-force cost and reduce authentication attack success.","Conduct security awareness training to reduce phishing susceptibility and reduce probability of credential compromise."],"correctIndex":0,"explanation":"Backups and tested restores reduce impact by improving recovery capability. WAF, passwords, and training primarily reduce likelihood.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Day 8.html"},{"id":372,"question":"A security architect recommends a risk mitigation plan but must ensure controls are cost-effective. Which concept best supports comparing control cost to expected loss reduction?","options":["Cost-benefit analysis using ALE reduction versus control implementation and operational costs for a rational decision.","Threat modeling using only STRIDE categories to label issues without financial context or control cost comparisons.","Vulnerability prioritization using only CVSS temporal metrics to avoid business impact and cost considerations.","Compliance mapping that checks boxes for frameworks without evaluating measurable reduction in expected losses."],"correctIndex":0,"explanation":"Cost-benefit analysis compares expected annual loss reduction (e.g., ALE delta) against control cost, supporting defensible mitigation decisions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":373,"question":"A company mitigates a high-risk finding by outsourcing a function to a managed service provider. However, regulatory accountability remains with the company. What is the BEST mitigation add-on?","options":["Establish SLA/contract clauses, audit rights, and continuous vendor risk monitoring to manage third-party exposure.","Assume the provider now owns all compliance requirements and remove the service from internal control testing.","Stop collecting logs from the outsourced function to reduce data handling risk and simplify operational overhead.","Disable incident response playbooks for the function because the provider will always handle all incidents alone."],"correctIndex":0,"explanation":"Outsourcing introduces third-party risk. Strong contracts, audit rights, and ongoing monitoring are key to mitigating residual and compliance risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":374,"question":"A SOC receives frequent false positives from a detection rule, causing analyst fatigue and slower response. Which mitigation best reduces operational risk while preserving detection value?","options":["Tune the rule with better thresholds and context enrichment, then validate changes with purple-team testing.","Disable the rule permanently and ignore related alerts to reduce workload regardless of threat exposure changes.","Route all alerts to a single analyst mailbox without triage so that accountability is centralized and consistent.","Increase alert severity for all events so fewer items appear on dashboards and analysts focus only on criticals."],"correctIndex":0,"explanation":"Tuning and validation reduce false positives while keeping detection coverage. Disabling blindly or manipulating severity increases risk and reduces response effectiveness.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Day 8.html"},{"id":375,"question":"A company wants to mitigate risk from unauthorized USB usage on sensitive workstations. Which control set is most appropriate?","options":["Apply device control policies with allowlists, endpoint DLP, and least privilege to restrict removable media access.","Install a second antivirus product to increase signature coverage and allow all removable media for productivity.","Disable screen locking to avoid disrupting workflows and require users to self-report suspicious USB devices.","Move user profiles to local storage only and remove centralized logging to reduce sensitive data in transit."],"correctIndex":0,"explanation":"Device control allowlists plus DLP and least privilege address the threat path (removable media exfil/malware). Extra AV or reduced controls are not targeted mitigation.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Day 8.html"},{"id":376,"question":"A risk analysis identifies that the probability of a rare event is low, but the financial impact is catastrophic. Which prioritization outcome is most appropriate?","options":["Treat it as high priority due to extreme impact and consider resilience controls that reduce consequence severity.","Treat it as low priority because likelihood is low and only likely risks should receive mitigation funding now.","Ignore it because catastrophic events cannot be modeled and therefore cannot be mitigated effectively in practice.","Accept it without documentation because discussing catastrophic risk increases stakeholder anxiety and audit scrutiny."],"correctIndex":0,"explanation":"Low likelihood but catastrophic impact can still be high risk, especially with business-critical services. Resilience controls can reduce impact even if likelihood remains low.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":377,"question":"A company is using qualitative risk assessment. Which output is MOST consistent with qualitative analysis?","options":["A risk heat map with likelihood and impact labeled as High/Medium/Low and supported by SME rationale notes.","An ALE table that calculates annualized losses for each risk using SLE and ARO with currency-based results.","A Monte Carlo simulation showing probabilistic distributions for annual losses based on event frequency ranges.","A depreciation schedule that amortizes security tooling purchases over time for financial accounting and taxation."],"correctIndex":0,"explanation":"Qualitative analysis commonly uses ordinal ratings (High/Medium/Low) and risk matrices/heat maps, often based on SME input rather than monetary calculations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":378,"question":"A security team must mitigate risk from outdated TLS configurations on public web services. Which mitigation is MOST appropriate?","options":["Disable weak protocols and ciphers, enforce modern TLS, and validate via scanning and change control evidence.","Increase password complexity for all users because authentication strength automatically fixes transport weaknesses.","Move the web server to a private subnet with no public access and keep the same TLS to avoid disruption.","Enable WEP on internal Wi-Fi to standardize encryption across networks and simplify security configuration."],"correctIndex":0,"explanation":"Transport security is addressed by disabling weak TLS versions/ciphers and enforcing modern configurations, validated by scanning and controlled change management.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":379,"question":"An organization wants to reduce data exfiltration risk from cloud object storage that is frequently misconfigured. Which mitigation technique best addresses the root cause?","options":["Implement CSPM with policy-as-code guardrails, least privilege IAM, and continuous misconfiguration monitoring.","Disable cloud logging to reduce the volume of security events and rely on quarterly manual checks for access.","Allow public read access by default and ask teams to self-audit periodically to avoid delays in development.","Replace object storage with email attachments so data remains within familiar workflows and user interfaces."],"correctIndex":0,"explanation":"CSPM plus guardrails and least privilege IAM reduces misconfigurations and detects drift continuously, directly targeting the root cause.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":380,"question":"A risk register shows 'Residual Risk' remains medium after a control is implemented. What does residual risk represent?","options":["The remaining exposure after controls are applied, acknowledging that mitigations reduce but rarely eliminate risk.","The total inherent exposure before any control is applied, representing the raw baseline risk state of the asset.","A risk that has been transferred completely to a third party and therefore no longer requires internal oversight.","A risk that has been accepted permanently and therefore cannot be revisited during future governance reviews."],"correctIndex":0,"explanation":"Residual risk is what remains after applying controls. Inherent risk is the pre-control baseline. Transference and acceptance do not remove oversight requirements.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":381,"question":"A company is selecting mitigation for insider threats where users have legitimate access but misuse it. Which control combination is MOST effective?","options":["Apply least privilege, UEBA monitoring, and separation of duties to reduce misuse opportunity and increase detection.","Increase perimeter firewall rules and block inbound traffic because insiders primarily attack from external networks.","Disable MFA and rely on password length alone so that authentication remains simple and consistent for users.","Encrypt all email subject lines only and ignore attachments so that data exfiltration attempts are harder to see."],"correctIndex":0,"explanation":"Insider threat mitigation often combines least privilege, separation of duties, and behavioral analytics (UEBA) to limit misuse and increase detection visibility.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Day 8.html"},{"id":382,"question":"A risk owner wants to reduce the likelihood of successful social engineering attacks. Which mitigation is MOST directly aligned?","options":["Run targeted security awareness with phishing simulations and reinforce reporting workflows with measurable metrics.","Implement tape backups and offsite storage to ensure data can be recovered regardless of how compromise occurs.","Deploy RAID for storage redundancy to reduce disk failure probability and increase system availability levels.","Purchase additional cyber insurance to transfer financial impact if attackers successfully compromise user accounts."],"correctIndex":0,"explanation":"Awareness training with simulations directly targets user susceptibility and reduces likelihood. Backups reduce impact; RAID is availability; insurance transfers impact.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Day 8.html"},{"id":383,"question":"A company identifies that a legacy business process cannot be redesigned quickly, so it chooses to reduce exposure by limiting when and where the process is executed. What mitigation approach is being applied?","options":["Risk reduction via administrative controls that constrain operating conditions and reduce the attack surface window.","Risk avoidance via elimination of the process entirely so the exposure category is removed from the environment.","Risk transference via a contract that shifts all operational responsibility and liabilities to an external party.","Risk acceptance via explicit sign-off to do nothing, with no change to operations or monitoring requirements."],"correctIndex":0,"explanation":"Constraining when/where an activity happens is administrative risk reduction (reducing exposure). Avoidance would eliminate the activity entirely.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":384,"question":"A company is validating that mitigations are actually effective. Which activity provides the BEST evidence of control effectiveness over time?","options":["Continuous monitoring with metrics, control testing results, and periodic audits mapped to control objectives.","A one-time screenshot of a configuration page showing the setting was enabled at an unknown prior date.","A verbal statement from a system owner that controls are working, without logs, metrics, or test artifacts.","An unsigned spreadsheet that lists controls but does not show implementation status or validation outcomes."],"correctIndex":0,"explanation":"Ongoing metrics, testing, and audit evidence demonstrate sustained effectiveness. One-time screenshots or verbal statements are weak evidence in governance.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Day 8.html"},{"id":385,"question":"A company needs a mitigation technique to prevent configuration drift on hardened servers. Which option is MOST appropriate?","options":["Use configuration management with desired-state enforcement and continuous compliance scanning against baselines.","Allow local admins to customize settings to improve flexibility and track changes only when incidents occur.","Disable patch management to prevent unexpected changes and rely solely on network controls for protection.","Move all server configuration steps to ad-hoc runbooks and prohibit automated tooling to reduce complexity."],"correctIndex":0,"explanation":"Desired-state configuration management and baseline scanning prevent drift and quickly detect deviations, supporting consistent hardening and risk reduction.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Day 8.html"},{"id":386,"question":"A risk team is asked to recommend a mitigation for web-based attacks that can be deployed quickly while longer-term application fixes are scheduled. What is the BEST short-term compensating control?","options":["Deploy a WAF with tuned rules and monitoring to reduce exploit success while developers remediate root causes.","Disable TLS entirely so payload inspection is easier and remove encryption barriers for network monitoring tools.","Move the application to an unmanaged hosting provider to avoid internal change control and accelerate releases.","Require users to change passwords weekly because frequent changes directly prevent SQL injection and XSS attacks."],"correctIndex":0,"explanation":"A WAF is a common compensating control for web apps, reducing likelihood/impact of attacks while permanent fixes are implemented. Password changes do not stop injection/XSS.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Day 8.html"},{"id":387,"question":"A company wants to mitigate risk by removing a risky service entirely from its environment. Which risk response does this represent?","options":["Risk avoidance by eliminating the exposure source and removing the associated threat surface from operations.","Risk acceptance by documenting the risk and proceeding with operations without deploying additional controls.","Risk transference by purchasing insurance and continuing the service with no operational or technical changes.","Risk reduction by deploying controls that lower likelihood or impact while keeping the service operational."],"correctIndex":0,"explanation":"Avoidance means removing the activity/system/service that creates the risk. Reduction keeps it but controls it; acceptance tolerates; transference shifts impact.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + Day 8.html"},{"id":388,"question":"Your policy says, “Encrypt sensitive data in transit.” During a readiness audit, a team asks what proves compliance. Which artifact BEST makes the policy testable?","options":["A standard specifying TLS versions, cipher suites, and certificate requirements","A guideline suggesting encryption when practical based on team preferences","A diagram showing where sensitive data flows between apps and databases","A procedure describing how to request an exception for urgent deployments"],"correctIndex":0,"explanation":"Standards create measurable requirements that can be validated (TLS version/ciphers/certs), unlike guidelines or diagrams.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":389,"question":"An auditor rejects your access review evidence because it is only screenshots with no ownership or dates. You need a durable fix that will pass future audits. What is BEST?","options":["Use a system-of-record workflow with approvers, timestamps, and immutable logs","Collect more screenshots quarterly and save them to a shared drive folder","Ask managers to verbally attest reviews occurred and document it in meeting notes","Pause access reviews until a new GRC tool is purchased and fully configured"],"correctIndex":0,"explanation":"Evidence must be attributable and time-bound; a tracked workflow with approvals and logs provides audit-quality proof.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Full Review.html"},{"id":390,"question":"A vendor must administer only one cloud app for 30 days. The vendor requests tenant-wide admin to avoid delays. Which solution BEST meets least privilege and reduces standing access?","options":["Scoped RBAC for the app plus time-bound elevation through PAM/JIT approval","A shared admin account with a long password rotated monthly by the help desk","Grant Global Admin, then review their activity logs at the end of the month","Allow access from any IP if they use CAPTCHA and a strong password policy"],"correctIndex":0,"explanation":"Least privilege is achieved with scoped roles and short-lived elevation; PAM/JIT reduces standing privileges and exposure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":391,"question":"The SOC sees a workstation making HTTPS requests every 60 seconds to a brand-new domain with low reputation. You suspect C2 but must minimize disruption. What control MOST directly limits impact right now?","options":["Enforce egress allow-listing and DNS security to block rare outbound destinations","Disable TLS inspection so analysts cannot see encrypted traffic and reduce alerts","Increase internet bandwidth to reduce latency and shorten investigation timelines","Move the workstation into the same VLAN as servers to simplify monitoring paths"],"correctIndex":0,"explanation":"Egress/DNS controls disrupt C2 and exfil routes quickly, with less broad disruption than blanket port blocks.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":392,"question":"A critical VM is suspected compromised but must remain online for billing. Your IR plan requires preserving volatile evidence. What is the BEST first step?","options":["Capture volatile data and snapshot memory before containment actions change state","Power off the VM to preserve the disk image and stop attacker processes quickly","Rebuild the VM from gold image immediately to restore trust and reduce downtime","Enable additional logging now and rely on future events to reconstruct activity"],"correctIndex":0,"explanation":"Volatile evidence (memory, connections, processes) disappears quickly; capture it first before actions that alter state.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":393,"question":"A DevOps team wants mutual authentication for internal APIs without shared secrets and with automated rotation. Which option BEST fits?","options":["mTLS using internal CA-issued certificates with short lifetimes and automation","A single PSK shared across all services and rotated annually through tickets","HTTP Basic authentication over TLS using long-lived service passwords only","Kerberos without managing SPNs, ticket lifetimes, or service key rotation steps"],"correctIndex":0,"explanation":"mTLS provides mutual authentication with asymmetric keys and supports automation with short-lived certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":394,"question":"A customer portal returns “syntax error near SELECT” when special characters are entered. The team proposes a WAF rule to block apostrophes. What is the BEST remediation?","options":["Use parameterized queries and proper server-side input handling for database calls","Block special characters at the WAF and disable detailed error messages in prod","Move the database into a private subnet and keep the application logic unchanged","Add a warning banner telling users not to enter certain characters in the form"],"correctIndex":0,"explanation":"Parameterized queries address the root cause by separating code from data; WAF-only controls are incomplete and bypassable.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":395,"question":"EDR shows a process creating scheduled tasks, disabling AV updates, and modifying registry run keys. No ransomware encryption is observed yet. Which technique is MOST likely?","options":["Persistence and defense evasion through tampering with security control settings","Credential stuffing against VPN portals using breached username/password pairs","Bluejacking over Bluetooth to push unsolicited messages to nearby devices","Watering-hole compromise of a website that employees frequently visit at lunch"],"correctIndex":0,"explanation":"Scheduled tasks + AV tampering + run keys strongly indicate persistence and defense evasion behaviors.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Full Review.html"},{"id":396,"question":"Two internal zones must communicate, but only one application flow is permitted. The business wants the smallest blast radius if a workstation is compromised. What is the BEST design?","options":["Microsegmentation with default-deny rules and only the required service path allowed","A flat network with host firewalls and broad routing to simplify connectivity needs","A site-to-site VPN between the zones so all traffic is encrypted across segments","NAT both zones into one subnet so tools see all hosts as a single address range"],"correctIndex":0,"explanation":"Microsegmentation enforces least privilege for east-west traffic and limits lateral movement to the single required flow.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":397,"question":"Your SIEM alerts heavily on normal admin actions, causing alert fatigue. You must reduce noise without losing detection coverage. What is the BEST approach?","options":["Tune rules using baselines, allow-lists for expected behavior, and log enrichment","Disable detections for admin actions since privileged activity is always expected","Stop ingesting authentication logs so there are fewer events to correlate daily","Replace the SIEM vendor and import the same ruleset without any customization"],"correctIndex":0,"explanation":"Baselining, allow-lists, and enrichment reduce false positives while retaining meaningful detection and correlation.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"Sec + Full Review.html"},{"id":398,"question":"A vendor claims compliance but refuses to share evidence due to confidentiality. You need a contractual control that enables verification. What clause is BEST?","options":["Right-to-audit and evidence-sharing language with confidentiality and scoping terms","A clause requiring encryption at rest for vendor-managed storage and databases only","A clause requiring quarterly feature roadmaps to be shared with your IT department","A clause requiring vendor staff to use corporate email accounts while on projects"],"correctIndex":0,"explanation":"Right-to-audit and evidence-sharing clauses enable independent verification while preserving confidentiality through scoped terms.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":399,"question":"A company wants per-user authentication on Wi-Fi, strong encryption, and no shared password. The environment supports certificate issuance. What is BEST?","options":["WPA3-Enterprise with 802.1X using EAP-TLS backed by a RADIUS service","WPA2-Personal with a long passphrase rotated quarterly and posted in the office","WEP with MAC filtering and hidden SSID to reduce unauthorized device access","Open Wi-Fi with captive portal and SMS verification for each daily connection"],"correctIndex":0,"explanation":"WPA3-Enterprise + EAP-TLS provides strong per-user auth and avoids shared secrets; certificates are highly resistant to phishing.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":400,"question":"A storage bucket with regulated data was accidentally made public through a console change. You must prevent recurrence and detect drift quickly. What is BEST?","options":["Policy-as-code guardrails blocking public access plus continuous configuration monitoring","A quarterly manual checklist review of permissions performed by one cloud admin","An awareness email reminding engineers to never change permissions on buckets","Disabling cloud storage entirely and moving all files back to on-prem servers"],"correctIndex":0,"explanation":"Guardrails (prevent) plus continuous monitoring (detect drift) is the strongest control for fast-moving cloud environments.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":401,"question":"Analytics teams need to work with large datasets containing PII, but privacy risk must be reduced and re-identification tightly controlled. What is BEST?","options":["Tokenize or anonymize data and restrict re-identification through controlled processes","Store datasets unencrypted to maximize performance and rely on network controls only","Use only full-disk encryption and share raw datasets broadly within the department","Compress datasets before sharing to reduce size and limit content visibility slightly"],"correctIndex":0,"explanation":"Tokenization/anonymization reduces exposure while enabling analytics; re-identification should be gated and audited.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":402,"question":"A data center has repeated tailgating during shift changes. Security needs a control that prevents piggybacking while maintaining throughput. What is BEST?","options":["Mantrap with badge plus biometric verification and anti-passback enforcement rules","A single door with a camera for after-the-fact review and a sign to deter entry","A visitor sign-in sheet and a printed badge that employees can pick up anytime","Rack locks only, while leaving facility entrances unmanaged to avoid bottlenecks"],"correctIndex":0,"explanation":"Mantraps and anti-passback enforce single-person entry while still allowing controlled flow during high traffic periods.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":403,"question":"After collecting a disk image, legal asks whether evidence handling will stand up in court. What practice BEST supports chain of custody?","options":["Record collection, transfers, storage conditions, and handler signatures for each step","Encrypt the evidence with a password known only to the incident commander on call","Copy the evidence to several USB drives so analysts can work in parallel quickly","Upload the evidence to a shared drive so the whole team can access it freely"],"correctIndex":0,"explanation":"Chain of custody is maintained by documented handling and integrity across time and personnel, not by encryption alone.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":404,"question":"Your org wants to stop unknown executables while allowing approved apps. You must reduce malware execution even if signatures lag. What control is BEST?","options":["Application allow-listing with code signing enforcement and a staged approval process","Antivirus only with weekly full scans and daily signature updates on endpoints","Disable UAC prompts to reduce friction during installs and improve user experience","Grant users local admin rights so they can install tools without help desk delays"],"correctIndex":0,"explanation":"Allow-listing with signing is preventive and blocks unknown code, reducing reliance on detection-only security.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec + Full Review.html"},{"id":405,"question":"Two sites need a secure tunnel for internal subnets with encryption and integrity. The team suggests AH to save overhead. What configuration BEST meets requirements?","options":["IPsec ESP in tunnel mode using strong encryption and modern DH key exchange groups","IPsec AH in transport mode using MD5 integrity for compatibility with older devices","Telnet over restricted firewall rules since source IPs are controlled and trusted","FTP with complex passwords and account lockout since files are internal and small"],"correctIndex":0,"explanation":"ESP provides confidentiality + integrity; tunnel mode is typical for site-to-site; AH does not encrypt.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":406,"question":"After quarterly phishing training, leadership wants proof that risk is decreasing—not just that people attended. Which metric BEST demonstrates improvement?","options":["Phishing simulation click and credential rates trended over time with consistent campaigns","Total count of emails received monthly across the organization and all business units","Number of employees who completed training modules with no behavioral measurement","Quantity of posters placed in hallways and break rooms during each awareness push"],"correctIndex":0,"explanation":"Behavioral outcomes from controlled simulations best show whether user susceptibility is decreasing.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"Sec + Full Review.html"},{"id":407,"question":"A scanner flags a critical CVE on a server, but inventory shows the vulnerable service is not installed. Your team still wants to patch immediately. What is BEST?","options":["Validate exposure, document evidence, and mark as false positive with tracked rationale","Patch every host in the subnet to be safe because scanning is usually accurate enough","Ignore the result entirely because scanners often report issues that do not exist here","Disable scanning on that asset so it stops generating confusing vulnerability tickets"],"correctIndex":0,"explanation":"Validate findings against inventory/exposure; document decisions with evidence so remediation is risk-based and auditable.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec + Full Review.html"},{"id":408,"question":"A project proposes removing internal segmentation because all users authenticate once at VPN login. Security recommends a Zero Trust approach instead. Which statement BEST reflects Zero Trust?","options":["Continuously evaluate access using identity, device posture, and context for each request","Treat internal traffic as trusted by default once the user has logged in successfully","Allow broad access within subnets to reduce complexity and improve performance quickly","Rely on perimeter controls only because threats are assumed to be external attackers"],"correctIndex":0,"explanation":"Zero Trust avoids implicit trust based on location; it continuously evaluates and enforces least privilege per request.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + Full Review.html"},{"id":409,"question":"Your domain is being spoofed in phishing campaigns. You want to reduce spoofing and improve validation for recipients. Which configuration BEST addresses this?","options":["Deploy SPF, DKIM, and DMARC with enforcement and reporting for aligned authentication","Enable TLS for email transport only so messages are encrypted in transit across hops","Use S/MIME for internal mail only and skip domain alignment controls for external mail","Add a disclaimer banner to external mail advising users to verify senders carefully"],"correctIndex":0,"explanation":"SPF/DKIM validate sender and content; DMARC enforces alignment with policy and provides reporting to reduce spoofing.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":410,"question":"A business unit requests broad access to a confidential dataset “for future projects.” There is no current use case and the data contains PII. What is BEST?","options":["Require documented need-to-know, grant least-privilege access, and time-bound approvals","Grant access now but log usage so any misuse can be investigated after the fact later","Grant access if they agree to use stronger passwords and complete annual training first","Move the dataset to a new share and email a link so the team can access it easily"],"correctIndex":0,"explanation":"Need-to-know and least privilege are primary controls; time-bound approvals reduce standing access and insider risk.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + Full Review.html"},{"id":411,"question":"Threat intel says a ransomware group targets your industry using stolen VPN creds and living-off-the-land tools. You want meaningful action, not fear-driven changes. What is BEST FIRST step?","options":["Map reported TTPs to detections and controls, then validate coverage with testing exercises","Block the entire country where the group is believed to operate to reduce exposure","Buy a new endpoint product immediately to ensure ransomware cannot execute anywhere","Wait for a confirmed incident before changing monitoring or adjusting defensive posture"],"correctIndex":0,"explanation":"Operationalize intel by translating TTPs into detections/control improvements and validating coverage via tests.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + Full Review.html"},{"id":412,"question":"A finance team is repeatedly targeted by credential phishing. You want passwordless authentication with strong phishing resistance. Which option is BEST?","options":["FIDO2/WebAuthn with hardware-backed credentials or platform authenticators for users","SMS one-time codes for logins because the phone carrier is trusted and available always","Security questions stored as hashed answers so attackers cannot easily read them back","Email-delivered TOTP codes required only for admins since finance is not privileged"],"correctIndex":0,"explanation":"FIDO2/WebAuthn is phishing-resistant by design (origin binding + asymmetric keys), unlike SMS or knowledge-based factors.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":413,"question":"You suspect lateral movement via Windows administrative shares (SMB). You want detection that correlates authentication and SMB sessions. Which logs are MOST important?","options":["Windows security authentication events plus SMB session/audit logs from endpoints and servers","DNS query logs only, because all lateral movement begins with name resolution activity","Web proxy logs only, because SMB traffic is typically routed through HTTP proxy services","Printer spooler logs only, because admin shares rely on print services for access"],"correctIndex":0,"explanation":"Lateral movement via SMB involves authentication and SMB sessions; security logs plus SMB auditing provide the best signal.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + Full Review.html"},{"id":414,"question":"A workstation is compromised in the user VLAN. You must reduce blast radius so it cannot reach the database subnet. What control MOST directly accomplishes this?","options":["Default-deny east-west rules with segmentation and explicit allow paths to critical services","Centralized DHCP reservations for all workstations to simplify IP-based monitoring at scale","A faster internet circuit to reduce attacker dwell time and shorten exfiltration windows","Shared local admin passwords to speed up IT support and reduce credential management work"],"correctIndex":0,"explanation":"Segmentation with default-deny limits lateral movement and enforces explicit access paths to crown-jewel systems.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":415,"question":"A baseline requires disabling legacy SMB versions. Leadership asks how you will prove compliance continuously, not just once. What is BEST?","options":["Continuous configuration assessment with drift detection and compliance reporting dashboards","An email asking users to confirm they changed settings manually on their own machines","Assume compliance since the baseline document was published on the intranet for teams","Spot-check a few endpoints yearly without tracking changes after patch cycles occur"],"correctIndex":0,"explanation":"Continuous assessment detects drift as systems change, providing strong ongoing assurance beyond a one-time check.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"Sec + Full Review.html"},{"id":416,"question":"A service outage occurred because a TLS certificate expired. You need to prevent repeats while supporting short certificate lifetimes. What is BEST?","options":["Automate certificate lifecycle management with monitoring, alerting, and staged renewal","Increase certificate validity to ten years so renewal rarely needs to happen at all","Disable certificate validation on clients so expired certificates do not break sessions","Remove TLS and use plaintext internally because the network is already considered trusted"],"correctIndex":0,"explanation":"Automation + monitoring prevents outages and supports safer short-lived certificates without manual failures.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + Full Review.html"},{"id":417,"question":"A mobile app stores an API token in plaintext local storage. The token grants access to customer data. What remediation BEST reduces risk?","options":["Store the token in the platform keystore/secure enclave and rotate tokens routinely","Base64-encode the token so it is not readable at a glance in local storage files","Move the token into a config file protected only by standard file permissions on disk","Hardcode multiple backup tokens in the app so users never lose connectivity access"],"correctIndex":0,"explanation":"Encoding is not protection. Use secure storage and rotate tokens to reduce exposure if a device or app storage is compromised.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":418,"question":"A host is suspected infected and communicating over 443. Business wants minimal disruption and no broad firewall changes. What containment action is BEST?","options":["Isolate the host using EDR/network quarantine while preserving evidence for analysis","Block all outbound TCP 443 across the organization until investigation is completed","Reboot the host to clear memory and remove attacker tools from active processes","Disable the SIEM rule so the incident stops generating alerts during triage work"],"correctIndex":0,"explanation":"Targeted isolation contains the incident with minimal blast radius and retains forensic opportunity.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":419,"question":"A popular open-source library is reported compromised upstream. Your CI/CD pulls dependencies automatically. What immediate control BEST reduces exposure?","options":["Pin versions, verify artifacts by signature/hash, and restrict repositories to trusted sources","Disable code review so developers can push quick changes to production without delay","Allow downloads from any mirror so builds are fast even if sources change often","Stop using version control so attackers cannot learn which dependencies you rely upon"],"correctIndex":0,"explanation":"Pinning and verifying artifacts prevents malicious upstream changes from silently entering builds; repository controls reduce risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":420,"question":"A terminated employee can still access a cloud resource because their role assignment remains active. Passwords were reset but access persists. What failed MOST likely?","options":["Offboarding deprovisioning tied to HR events and identity source-of-truth synchronization","Password complexity policy missing history requirements and minimum length enforcement","Firewall rules too permissive for inbound internet traffic to cloud management portals","Full-disk encryption not enabled on the user’s previous laptop used during employment"],"correctIndex":0,"explanation":"Role assignments are authorization artifacts; offboarding must revoke access/roles based on HR lifecycle events and IAM processes.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":421,"question":"A manager asks whether a new detection rule counts as a detective technical control. Which example BEST fits that classification?","options":["A SIEM correlation rule alerting on impossible travel sign-ins using multiple data points","A policy requiring annual awareness training and signed acknowledgment by all staff members","A mantrap preventing two people from entering a secure area at the same time each entry","A secure coding standard requiring parameterized queries for all database interactions"],"correctIndex":0,"explanation":"SIEM correlation is a detective technical control; policy is administrative, mantrap is physical preventive, coding standard is preventive.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + Full Review.html"},{"id":422,"question":"Regulated data must not be emailed externally, but internal collaboration should remain smooth. Security wants to reduce accidental leaks without blocking normal internal sharing. What is BEST?","options":["DLP with content inspection, internal allow rules, and user coaching for risky actions","Disable email entirely and require all communication through phone calls and meetings","Encrypt all outbound email automatically without inspecting content or recipient context","Require users to rename sensitive files before sending them outside to reduce mistakes"],"correctIndex":0,"explanation":"DLP can enforce internal vs external handling based on content/labels and provide coaching or blocking for risky behavior.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":423,"question":"A payment platform has RTO 2 hours and RPO 15 minutes. Leadership wants a realistic design that meets these objectives. What is BEST?","options":["Warm/hot design with frequent replication and tested failover procedures for the service","Cold site with weekly tape backups stored offsite and manual rebuild documentation steps","No redundancy but a detailed runbook to rebuild the environment in another region later","Monthly full backups with encryption and a plan to restore whenever time permits later"],"correctIndex":0,"explanation":"Tight RTO/RPO requires near-real-time replication and practiced failover—typically warm/hot, not cold/manual restore.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + Full Review.html"},{"id":424,"question":"UEBA flags a user downloading 20x their baseline data volume, then authenticating from a new geography. The user claims they are traveling. What is BEST immediate action?","options":["Validate context, enforce step-up auth, and restrict session/data access pending review","Disable UEBA alerts because behavior analytics frequently generates false positives anyway","Block all downloads for every user until the manager approves global policy changes soon","Assume malicious intent and wipe the device immediately without collecting any evidence"],"correctIndex":0,"explanation":"Use context to validate and apply conditional access controls (step-up auth/session limits) while investigating, minimizing disruption.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":425,"question":"Secrets are occasionally committed to source control during urgent fixes. You need prevention that works even under pressure. What is BEST?","options":["Pre-commit secret scanning plus centralized secret management and short-lived credentials","A policy telling developers to be careful and avoid committing secrets during emergencies","Storing secrets in comments so they are easy to find later and rotate after releases","Using longer passwords so accidentally committed secrets are harder to guess by attackers"],"correctIndex":0,"explanation":"Tooling and architecture prevent mistakes: pre-commit scanning blocks commits; secret managers and short-lived creds reduce blast radius.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + Full Review.html"},{"id":426,"question":"After containing a malware outbreak, IT wants to reconnect systems quickly. Security must ensure eradication and reduce recurrence. What is BEST next step?","options":["Remove persistence, fix root cause, patch weaknesses, and validate with re-scans before return","Restore from backup immediately without checking whether backups contain the same malware","Reconnect systems and rely on monitoring to catch any remaining activity after users return","Lower alert thresholds so the SOC receives fewer notifications while operations stabilize"],"correctIndex":0,"explanation":"Eradication means removing persistence, addressing root cause, patching exploited weaknesses, and validating clean state before recovery.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec + Full Review.html"},{"id":427,"question":"What does **BIA** stand for in business continuity planning?","options":["Business Impact Analysis","Baseline Integrity Assessment","Binary Incident Attribution","Bandwidth Inspection Authorization"],"correctIndex":0,"explanation":"BIA (Business Impact Analysis) identifies critical functions and the impact of disruptions to set recovery priorities (RTO/RPO/MTD).","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":428,"question":"In risk calculations, **SLE** most commonly means:","options":["Single Loss Expectancy","System Logging Endpoint","Security Level Estimate","Session Link Encryption"],"correctIndex":0,"explanation":"SLE (Single Loss Expectancy) is the expected loss from a single occurrence of a risk event.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":429,"question":"In quantitative risk, **ALE** is:","options":["Annual Loss Expectancy","Asset Loss Evaluation","Authorized Log Export","Applied Layer Encryption"],"correctIndex":0,"explanation":"ALE (Annual Loss Expectancy) is the expected annualized loss, typically SLE × ARO.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":430,"question":"In risk frequency modeling, **ARO** stands for:","options":["Annual Rate of Occurrence","Authorized Response Option","Aggregate Risk Objective","Applied Routing Overlay"],"correctIndex":0,"explanation":"ARO (Annual Rate of Occurrence) estimates how often a risk event occurs per year.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + acronyms.html"},{"id":431,"question":"In recovery planning, **RTO** means:","options":["Recovery Time Objective","Remote Transfer Operation","Risk Tolerance Output","Routing Table Optimization"],"correctIndex":0,"explanation":"RTO (Recovery Time Objective) is the target time to restore a system or process after a disruption.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"Sec + acronyms.html"},{"id":432,"question":"In recovery planning, **RPO** means:","options":["Recovery Point Objective","Remote Packet Output","Risk Priority Order","Routing Path Override"],"correctIndex":0,"explanation":"RPO (Recovery Point Objective) is the acceptable data loss measured in time (how far back you can restore).","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + acronyms.html"},{"id":433,"question":"In BCP/DR, **MTD** stands for:","options":["Maximum Tolerable Downtime","Managed Threat Detection","Minimum Transfer Delay","Maximum Ticket Duration"],"correctIndex":0,"explanation":"MTD (Maximum Tolerable Downtime) is the absolute limit for how long a process can be down.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"Sec + acronyms.html"},{"id":434,"question":"In recovery discussions, **WRT** means:","options":["Work Recovery Time","Wireless Routing Table","Web Response Threshold","Write Retention Time"],"correctIndex":0,"explanation":"WRT (Work Recovery Time) is the time to restore business operations to normal productivity after systems are back.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":435,"question":"A control mapping to security requirements often references **CIA** meaning:","options":["Confidentiality, Integrity, Availability","Control, Inspection, Authorization","Cryptography, Identity, Auditing","Compliance, Investigation, Assurance"],"correctIndex":0,"explanation":"CIA is the security triad: confidentiality, integrity, and availability.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":436,"question":"For access control, **RBAC** stands for:","options":["Role-Based Access Control","Risk-Based Authorization Control","Rule-Based Account Configuration","Resource Baseline Access Catalog"],"correctIndex":0,"explanation":"RBAC assigns permissions to roles, then users inherit privileges through role membership.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":437,"question":"For access control, **ABAC** stands for:","options":["Attribute-Based Access Control","Application-Based Account Control","Audit-Based Access Calculation","Adaptive Baseline Authorization Criteria"],"correctIndex":0,"explanation":"ABAC evaluates attributes (user, resource, environment) to make authorization decisions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":438,"question":"In identity systems, **MFA** stands for:","options":["Multi-Factor Authentication","Managed Firewall Appliance","Modular Forensic Analysis","Mandatory File Authorization"],"correctIndex":0,"explanation":"MFA uses two or more factors (know/have/are) to strengthen authentication.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":439,"question":"A trusted third party issuing certificates is a **CA**, which means:","options":["Certificate Authority","Control Auditor","Cryptographic Agent","Compliance Attestation"],"correctIndex":0,"explanation":"A Certificate Authority issues and signs digital certificates used in PKI.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":440,"question":"A policy defining expected uptime and response times is an **SLA**, meaning:","options":["Service-Level Agreement","Security Logging Addendum","System Lifecycle Authorization","Software License Amendment"],"correctIndex":0,"explanation":"SLA specifies service performance metrics and remedies/penalties for failure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"Sec + acronyms.html"},{"id":441,"question":"A confidential sharing contract is an **NDA**, meaning:","options":["Non-Disclosure Agreement","Network Data Authorization","Named Domain Allocation","New Device Attestation"],"correctIndex":0,"explanation":"NDA protects confidential information from unauthorized disclosure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":442,"question":"A secure hash used to ensure file integrity is commonly **SHA**, meaning:","options":["Secure Hash Algorithm","System Hardened Access","Session Header Authorization","Secure Host Allocation"],"correctIndex":0,"explanation":"SHA refers to hash functions (e.g., SHA-256) used for integrity verification.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":443,"question":"A symmetric encryption standard acronym **AES** stands for:","options":["Advanced Encryption Standard","Automated Endpoint Security","Authenticated Email Sender","Adaptive Encryption System"],"correctIndex":0,"explanation":"AES is a widely used symmetric block cipher used for data at rest and in transit.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":444,"question":"A widely used public-key algorithm acronym **RSA** stands for:","options":["Rivest–Shamir–Adleman","Random Session Algorithm","Remote Security Attestation","Rapid Stream Authentication"],"correctIndex":0,"explanation":"RSA is an asymmetric cryptosystem used for encryption and signatures.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":445,"question":"A common key exchange acronym **DH** stands for:","options":["Diffie–Hellman","Data Header","Domain Handoff","Dynamic Hashing"],"correctIndex":0,"explanation":"Diffie–Hellman enables key exchange over an untrusted network (often with ephemeral variants like DHE/ECDHE).","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":446,"question":"A security monitoring system acronym **SIEM** stands for:","options":["Security Information and Event Management","System Integrity and Endpoint Monitoring","Secure Identity and Email Management","Service Incident and Escalation Model"],"correctIndex":0,"explanation":"SIEM aggregates logs, correlates events, and supports alerting and investigations.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":447,"question":"An endpoint detection tool acronym **EDR** stands for:","options":["Endpoint Detection and Response","Encrypted Data Routing","Event-Driven Remediation","External Domain Resolution"],"correctIndex":0,"explanation":"EDR provides endpoint telemetry, detection, and response actions like isolation/quarantine.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":448,"question":"In cloud security posture tooling, **CSPM** stands for:","options":["Cloud Security Posture Management","Centralized Security Policy Module","Cloud Service Patch Mechanism","Configurable Security Proxy Model"],"correctIndex":0,"explanation":"CSPM detects cloud misconfigurations and policy drift across cloud resources.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + acronyms.html"},{"id":449,"question":"A common DLP acronym **DLP** stands for:","options":["Data Loss Prevention","Data Link Protocol","Dynamic Login Provisioning","Distributed Log Processing"],"correctIndex":0,"explanation":"DLP reduces unauthorized data exfiltration through monitoring and control policies.","domain":"4.0 Security Operations","objectiveId":"4.6","objective":"Identity & Access Management (IAM)","source":"Sec + acronyms.html"},{"id":450,"question":"A network segmentation concept acronym **ACL** stands for:","options":["Access Control List","Automated Compliance Ledger","Application Control Layer","Authenticated Connection Link"],"correctIndex":0,"explanation":"ACLs define permit/deny rules for traffic or permissions for objects.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"Sec + acronyms.html"},{"id":451,"question":"A secure remote access acronym **VPN** stands for:","options":["Virtual Private Network","Verified Protocol Node","Virtual Packet Negotiation","Variable Path Networking"],"correctIndex":0,"explanation":"VPN provides encrypted tunnels for remote access or site-to-site connectivity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":452,"question":"A secure web transport acronym **TLS** stands for:","options":["Transport Layer Security","Trusted Link Service","Token Login Standard","Tunneled Local Session"],"correctIndex":0,"explanation":"TLS secures data in transit and replaces older SSL versions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec + acronyms.html"},{"id":453,"question":"DNS encryption acronym **DoH** stands for:","options":["DNS over HTTPS","Domain over Host","Data on Hypertext","DNS over Handshake"],"correctIndex":0,"explanation":"DoH sends DNS queries over HTTPS (commonly port 443) for privacy and integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":454,"question":"DNS encryption acronym **DoT** stands for:","options":["DNS over TLS","Domain over Transport","Data over Token","DNS over Tunneling"],"correctIndex":0,"explanation":"DoT sends DNS queries over TLS (commonly port 853) to protect DNS traffic.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":455,"question":"For threat intel, **IOC** commonly stands for:","options":["Indicator of Compromise","Identity Operations Center","Internal Object Catalog","Incident Output Category"],"correctIndex":0,"explanation":"IOCs are observable artifacts like hashes, domains, IPs, and file paths linked to malicious activity.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"Sec + acronyms.html"},{"id":456,"question":"For adversary behavior, **TTPs** stands for:","options":["Tactics, Techniques, and Procedures","Tokens, Transfers, and Policies","Threat Tools and Platforms","Telemetry, Tuning, and Protection"],"correctIndex":0,"explanation":"TTPs describe how adversaries operate: their goals (tactics), methods (techniques), and playbooks (procedures).","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"Sec + acronyms.html"},{"id":457,"question":"A web protection control acronym **WAF** stands for:","options":["Web Application Firewall","Wide Area Forwarder","Web Access Framework","Wireless Authentication Filter"],"correctIndex":0,"explanation":"WAF filters HTTP/S traffic to mitigate common web attacks (e.g., injection, XSS) as a compensating control.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec + acronyms.html"},{"id":458,"question":"A privilege management acronym **PAM** stands for:","options":["Privileged Access Management","Protected Account Mechanism","Policy Audit Module","Password Authorization Model"],"correctIndex":0,"explanation":"PAM manages privileged accounts with vaulting, JIT elevation, and session recording.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.5","objective":"Audits & Assessments","source":"Sec + acronyms.html"},{"id":459,"question":"In cryptography, **HMAC** stands for:","options":["Hash-based Message Authentication Code","Host-managed Access Control","High-memory Application Cache","Hardware Mode Authorization Check"],"correctIndex":0,"explanation":"HMAC uses a hash function with a secret key to provide integrity and authenticity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":460,"question":"A common wireless encryption acronym **WPA3** expands to:","options":["Wi-Fi Protected Access 3","Wireless Privacy Algorithm 3","Web Proxy Authorization 3","Wideband Protected Attachment 3"],"correctIndex":0,"explanation":"WPA3 is the modern Wi-Fi security standard that improves protection over WPA2.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":461,"question":"A formal agreement describing secure system interconnections is an **ISA**, meaning:","options":["Interconnection Security Agreement","Internal Security Assessment","Integrated Service Authorization","Incident Severity Assignment"],"correctIndex":0,"explanation":"ISA documents technical and security requirements when connecting systems between organizations.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec + acronyms.html"},{"id":462,"question":"A common secure email protocol acronym **S/MIME** stands for:","options":["Secure/Multipurpose Internet Mail Extensions","System/Managed Identity Messaging Exchange","Secure/Modular Internet Message Encapsulation","Service/Multipoint Integrated Mail Encryption"],"correctIndex":0,"explanation":"S/MIME provides email signing and encryption using certificates.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec + acronyms.html"},{"id":463,"question":"Which aspect of security assurance specifically relies on cryptographic digital signatures unique to each user to prove that a message or document was sent by the claimed sender?","options":["Confidentiality","Non-repudiation","Availability","Discretionary access model"],"correctIndex":1,"explanation":"Non-repudiation ensures that a person cannot deny the validity of their actions or communications. It uses cryptographic digital signatures unique to each user to provide proof of origin and integrity.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"Sec+Day1Quiz.html"},{"id":464,"question":"An organization is evaluating its current security posture against the National Institute of Standards and Technology (NIST) Cybersecurity Framework (CSF). What type of analysis are they performing?","options":["Risk assessment","Gap analysis","Vulnerability analysis","BIA (Business Impact Analysis)"],"correctIndex":1,"explanation":"A gap analysis checks how well an organization's security setup matches a cybersecurity framework like the NIST CSF (National Institute of Standards and Technology Cybersecurity Framework) to identify missing, incomplete, or poorly configured controls.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":465,"question":"Which function of the NIST Cybersecurity Framework (CSF) focuses on developing security policies, evaluating risks, threats, and vulnerabilities, and recommending controls to mitigate them?","options":["Protect","Detect","Identify","Respond"],"correctIndex":2,"explanation":"The 'Identify' function of the NIST CSF (National Institute of Standards and Technology Cybersecurity Framework) involves developing security policies and capabilities, as well as evaluating risks, threats, and vulnerabilities to recommend security controls.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":466,"question":"What unique phase distinguishes the modern Identity and Access Management (IAM) framework from the earlier AAA framework?","options":["Identification","Authentication","Authorization","Accounting"],"correctIndex":0,"explanation":"The modern IAM (Identity and Access Management) framework includes standard AAA (Authentication, Authorization, and Accounting) functions PLUS the Identification component, which was omitted in the earlier framework.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":467,"question":"A system enforces pre-determined security rules and labels (such as Secret or Top Secret) that cannot be altered by any individual user within the system. Which access control model is being utilized?","options":["DAC (Discretionary Access Control)","RBAC (Role-Based Access Control)","MAC (Mandatory Access Control)","ABAC (Attribute-Based Access Control)"],"correctIndex":2,"explanation":"In a MAC (Mandatory Access Control) model, access rights are predetermined by system-enforced rules and security labels; they cannot be modified by any standard user within the system.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec+Day1Quiz.html"},{"id":468,"question":"Security guards and user security awareness training programs fall under which control category?","options":["Technical controls","Managerial controls","Operational controls","Physical controls"],"correctIndex":2,"explanation":"Operational controls are security measures implemented primarily by people rather than automated systems. Examples include security guards and training programs.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":469,"question":"A network administrator configures an automated firewall rule and sets up permission policies to block an active security attack from succeeding. What functional control type is this?","options":["Detective control","Preventive control","Corrective control","Deterrent control"],"correctIndex":1,"explanation":"Preventive controls (such as firewall rules, encryption, and permission policies) actively attempt to keep an attack from succeeding. Users do not need to have explicit knowledge of the control for it to function.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":470,"question":"Which functional control type psychologically discourages an intrusion, reduces the motive of an attacker, and explicitly requires users to have knowledge of the control to work effectively?","options":["Deterrent control","Directive control","Compensating control","Technical control"],"correctIndex":0,"explanation":"Deterrent controls psychologically discourage intrusions (e.g., warning signs, login banners, good lighting) and require users to have knowledge of the control to change their motivation.","domain":"1.0 General Security Concepts","objectiveId":"1.1","objective":"Security Controls","source":"Sec+Day1Quiz.html"},{"id":471,"question":"Which corporate role is primarily responsible for overall technology strategy and ensuring IT systems align with organizational goals, while also overseeing security policy implementation?","options":["CSO (Chief Security Officer)","CIO (Chief Information Officer)","ISSO (Information Systems Security Officer)","Security Manager"],"correctIndex":1,"explanation":"The CIO (Chief Information Officer) is responsible for the overall technology strategy and aligning IT systems with organization goals, while overseeing the broad implementation of security policies.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"Sec+Day1Quiz.html"},{"id":472,"question":"What security principle refers to an organization taking the necessary reasonable steps to protect its assets, data, and infrastructure to prevent harm or loss?","options":["Liability","Due Care","Non-repudiation","Auditing"],"correctIndex":1,"explanation":"Due Care refers to the baseline responsibility of an organization to actively take reasonable, protective steps to safeguard its assets and data from potential harm.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":473,"question":"A centralized unit within an enterprise continuously monitors network traffic, endpoints, and logs using tools to identify, investigate, contain, and mitigate active security events. What is this unit called?","options":["DevSecOps","CIRT (Cyber Incident Response Team)","SOC (Security Operations Center)","Change Control Board"],"correctIndex":2,"explanation":"The SOC (Security Operations Center) is a centralized organizational and technical unit that continuously monitors and analyzes an organization's security posture to capture alerts and mitigate risks.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"Sec+Day1Quiz.html"},{"id":474,"question":"Which team is specifically tasked with integrating automated security testing into Continuous Integration/Continuous Development (CI/CD) pipelines so that security is a shared responsibility at every stage of software creation?","options":["SOC (Security Operations Center)","CIRT (Cyber Incident Response Team)","DevSecOps (Development, Security, and Operations)","M-of-N Recovery Team"],"correctIndex":2,"explanation":"DevSecOps (Development, Security, and Operations) integrates security directly into the development process, implementing secure coding practices and automated security testing in the CI/CD pipeline.","domain":"4.0 Security Operations","objectiveId":"4.8","objective":"Incident Response","source":"Sec+Day1Quiz.html"},{"id":475,"question":"How do modern cyber threats differ significantly from traditional threats of the early internet era?","options":["Modern threats rely purely on signature-based virus detection.","Modern threats have shifted from simple opportunistic vandalism toward structured, well-funded campaigns driven by financial, espionage, and political motives.","Modern threats are exclusively internal and do not attempt remote network infiltration.","Modern threats have lower technical sophistication and capabilities."],"correctIndex":1,"explanation":"Threats have evolved from early opportunistic vandalism and worms into structured, long-term campaigns funded by nation-states or organized crime (such as Advanced Persistent Threats), shifting motivations toward profit, espionage, and warfare.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":476,"question":"A threat actor who uses advanced techniques, holds military or political backing, and conducts prolonged, targeted campaigns while remaining undetected in a network for extended periods is classified as what?","options":["Unskilled attacker","Hacktivist","APT (Advanced Persistent Threat)","Internal unintentional insider"],"correctIndex":2,"explanation":"An APT (Advanced Persistent Threat) describes sophisticated, prolonged, and highly targeted cyberattacks often associated with nation-state actors due to the immense resources and long-term entry goals required.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":477,"question":"What type of attack vector involves leaving infected removable USB flash drives in public spaces, hoping a target will plug them into a corporate machine and execute malicious code?","options":["Watering hole attack","Drop attack","Pharming attack","Typosquatting"],"correctIndex":1,"explanation":"In a drop attack, an attacker leaves infected removable media (like USB drives) in public or workplace areas hoping an unsuspecting user will find it and plug it into a computer system.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec+Day1Quiz.html"},{"id":478,"question":"A user purchases a third-party cloud software application to help complete daily tasks without requesting or obtaining the permission and security analysis of the corporate IT department. What does this describe?","options":["External threat surface","Shadow IT","Baiting attack","Discretionary authorization"],"correctIndex":1,"explanation":"Shadow IT refers to computer hardware or software introduced to the workplace by users without the explicit sanction, procurement review, or security analysis of the IT department.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"Sec+Day1Quiz.html"},{"id":479,"question":"What is the total sum of all points where an unauthorized user can try to enter data into or extract data from an environment?","options":["Attack vector","Attack surface","Vulnerability scanner","Trusted platform module"],"correctIndex":1,"explanation":"The attack surface is the total sum of all exposed points (hardware, software, network components) where an unauthorized attacker could try to exploit a vulnerability or interact with data.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec+Day1Quiz.html"},{"id":480,"question":"An automated vulnerability scanner requires a small software component to be explicitly installed on every endpoint device to collect internal data. What type of scanner is this?","options":["Agentless vulnerability scanner","Client-based vulnerability scanner","Passive network sniffer","Discretionary exploit engine"],"correctIndex":1,"explanation":"Client-based vulnerability scanners require an agent (a small software component) to be actively installed on each endpoint device to collect and report detailed system status.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"Sec+Day1Quiz.html"},{"id":481,"question":"A threat actor compromises a local pizza delivery website commonly visited by staff members of a target financial firm to run exploit code on the visitors' systems. What social engineering/reconnaissance strategy is this?","options":["Business Email Compromise (BEC)","Watering hole attack","Pretexting impersonation","Typospoofing"],"correctIndex":1,"explanation":"A watering hole attack targets a specific group of users by identifying and compromising an unsecure third-party website that the targets frequently visit.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"Sec+Day1Quiz.html"},{"id":482,"question":"An attacker registers the domain 'goggle.com' to catch traffic from users who make typographical mistakes while typing the address of a popular search engine. What is this practice called?","options":["Typosquatting","Typospoofing","Pharming","Email spoofing"],"correctIndex":0,"explanation":"Typosquatting involves specifically registering domain names that are slight misspellings or common typographical variations of popular websites to deceive users who make keyboard errors.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"Sec+Day1Quiz.html"},{"id":483,"question":"A Cybersecurity Analyst (CySA+) reviews an Nmap result showing TCP 22 open on a Linux jump host used by administrators. Which protocol is most likely expected, and why is it preferred over the legacy alternative?","options":["Secure Shell (SSH); it provides encrypted remote administration instead of cleartext Telnet.","Telnet; it provides encrypted remote administration instead of Secure Shell (SSH).","Remote Desktop Protocol (RDP); it provides encrypted Linux shell access over TCP 22.","Simple Network Management Protocol (SNMP); it provides encrypted command-line administration."],"correctIndex":0,"explanation":"TCP 22 is associated with Secure Shell (SSH), Secure File Transfer Protocol (SFTP), and Secure Copy Protocol (SCP). Telnet commonly uses TCP 23 and is a poor administrative choice because credentials and session data are not protected by default.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":484,"question":"During a hunt, an analyst finds repeated successful logins to network devices over TCP 23. Which finding should be prioritized?","options":["Telnet is exposed, creating a cleartext administrative-access risk.","Secure Shell (SSH) is exposed, creating a certificate-validation risk.","Trivial File Transfer Protocol (TFTP) is exposed, creating a zone-transfer risk.","Lightweight Directory Access Protocol (LDAP) is exposed, creating a mail-relay risk."],"correctIndex":0,"explanation":"TCP 23 is Telnet. It is commonly flagged because remote administration over Telnet can expose credentials and session contents. SSH on TCP 22 is the safer replacement.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":485,"question":"A web app cannot resolve internal hostnames. Firewall logs show blocked outbound UDP 53 from the app subnet to the internal resolver. Which protocol is being blocked?","options":["Domain Name System (DNS) name resolution.","Dynamic Host Configuration Protocol (DHCP) address leasing.","Network Time Protocol (NTP) time synchronization.","Lightweight Directory Access Protocol (LDAP) directory queries."],"correctIndex":0,"explanation":"Domain Name System (DNS) typically uses UDP 53 for standard queries and TCP 53 for zone transfers or larger responses. Blocking DNS can break hostname resolution even when the destination service is healthy.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.1","objective":"Security Governance","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":486,"question":"A Security Information and Event Management (SIEM) alert shows unusually large outbound TCP 53 sessions to an external host. What should the analyst suspect first?","options":["Possible Domain Name System (DNS) tunneling or unauthorized zone-transfer-like behavior.","Normal Dynamic Host Configuration Protocol (DHCP) lease renewal traffic.","Expected Network Time Protocol (NTP) clock correction traffic.","Routine Simple Mail Transfer Protocol (SMTP) mail submission traffic."],"correctIndex":0,"explanation":"DNS typically uses UDP 53, but TCP 53 can be normal for large responses and zone transfers. Large or persistent external TCP 53 flows can also be suspicious and deserve investigation for tunneling or exfiltration.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":487,"question":"A mail server must send mail between mail transfer agents. Which default port and protocol should be allowed?","options":["TCP 25 for Simple Mail Transfer Protocol (SMTP).","TCP 110 for Post Office Protocol version 3 (POP3).","TCP 143 for Internet Message Access Protocol (IMAP).","TCP 587 for Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"Simple Mail Transfer Protocol (SMTP) uses TCP 25 for server-to-server mail transfer. TCP 587 is commonly used for authenticated mail submission by clients, not LDAP.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":488,"question":"A company wants users to retrieve mailbox contents securely while leaving messages synchronized on the server. Which protocol and port best fits?","options":["Internet Message Access Protocol over Secure Sockets Layer/Transport Layer Security (IMAPS) on TCP 993.","Post Office Protocol version 3 (POP3) on TCP 110.","Simple Mail Transfer Protocol (SMTP) on TCP 25.","Simple Network Management Protocol version 3 (SNMPv3) on UDP 161."],"correctIndex":0,"explanation":"Internet Message Access Protocol (IMAP) keeps mail synchronized with the server. The secure default is IMAPS on TCP 993. POP3S on TCP 995 is secure too, but POP3 is more download-oriented and less ideal for multi-device synchronization.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":489,"question":"A firewall administrator sees authentication requests from a Virtual Private Network (VPN) appliance to a server on UDP 1812. Which service is most likely in use?","options":["Remote Authentication Dial-In User Service (RADIUS) authentication.","Terminal Access Controller Access-Control System Plus (TACACS+) authentication.","Kerberos authentication service ticketing.","Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS) directory binding."],"correctIndex":0,"explanation":"RADIUS commonly uses UDP 1812 for authentication and UDP 1813 for accounting. TACACS+ uses TCP 49. Kerberos uses TCP/UDP 88. LDAPS uses TCP 636.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":490,"question":"A network team wants centralized device administration with separate authentication, authorization, and accounting controls over TCP 49. Which protocol should be configured?","options":["Terminal Access Controller Access-Control System Plus (TACACS+).","Remote Authentication Dial-In User Service (RADIUS).","Kerberos.","Network Basic Input/Output System (NetBIOS)."],"correctIndex":0,"explanation":"TACACS+ uses TCP 49 and is common for network-device administration. It separates authentication, authorization, and accounting functions, which is useful for administrative command control.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":491,"question":"A vulnerability scan flags cleartext directory binds on TCP 389. Which secure replacement should the administrator prefer?","options":["Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS) on TCP 636.","Kerberos over TCP/UDP 88.","Server Message Block (SMB) over TCP 445.","Remote Authentication Dial-In User Service (RADIUS) over UDP 1812."],"correctIndex":0,"explanation":"LDAP commonly uses TCP 389. LDAPS uses TCP 636 to protect directory traffic with encryption. Kerberos and RADIUS are authentication-related, but they are not direct LDAP replacements.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":492,"question":"An incident responder sees suspicious authentication attempts to TCP 445 across many Windows servers. Which protocol is most relevant?","options":["Server Message Block (SMB) for file sharing and administrative access.","Simple Network Management Protocol (SNMP) for device telemetry.","Secure Shell (SSH) for encrypted terminal sessions.","Internet Message Access Protocol (IMAP) for mailbox synchronization."],"correctIndex":0,"explanation":"TCP 445 is Server Message Block (SMB). It is heavily monitored because it is tied to Windows file sharing, administrative shares, and many lateral movement techniques.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":493,"question":"A scan finds UDP 137, UDP 138, and TCP 139 exposed from a legacy Windows subnet. Which protocol family should be investigated?","options":["Network Basic Input/Output System (NetBIOS).","Border Gateway Protocol (BGP).","Simple Object Access Protocol (SOAP).","Internet Key Exchange (IKE)."],"correctIndex":0,"explanation":"NetBIOS commonly uses UDP 137 for name service, UDP 138 for datagram service, and TCP 139 for session service. Modern Windows file sharing commonly relies on SMB over TCP 445 instead.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":494,"question":"A Security Operations Center (SOC) notices event timestamps differ by several minutes across servers, weakening timeline analysis. Which protocol should be checked first?","options":["Network Time Protocol (NTP) on UDP 123.","Domain Name System (DNS) on UDP 53.","Simple Network Management Protocol (SNMP) on UDP 161.","Kerberos on TCP/UDP 88."],"correctIndex":0,"explanation":"NTP uses UDP 123 and is critical for consistent logs, Kerberos ticketing, and incident timelines. Kerberos can also be affected by time drift, but NTP is the service used to synchronize clocks.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":495,"question":"A public web application is available over TCP 80 and TCP 443. Which port should be preferred for user traffic?","options":["TCP 443 using Hypertext Transfer Protocol Secure (HTTPS).","TCP 80 using Hypertext Transfer Protocol (HTTP).","TCP 8080 using Simple Mail Transfer Protocol (SMTP).","TCP 8443 using Dynamic Host Configuration Protocol (DHCP)."],"correctIndex":0,"explanation":"HTTPS uses TCP 443 and protects web traffic with Transport Layer Security (TLS). HTTP on TCP 80 is cleartext and should usually redirect to HTTPS for user-facing applications.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":496,"question":"A scanner finds an internal admin console listening on TCP 8080. What is the best interpretation?","options":["It may be an alternate web service or proxy port that still needs access control and Transport Layer Security (TLS) review.","It is always Secure Shell (SSH), so password authentication should be disabled.","It is always Kerberos, so time synchronization is the main exposure.","It is always Domain Name System (DNS), so recursion should be disabled."],"correctIndex":0,"explanation":"TCP 8080 is commonly used for alternate HTTP services, proxies, or admin consoles. Nonstandard ports do not make services safe; they still need authentication, authorization, encryption, and exposure review.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":497,"question":"A network monitoring platform polls routers over UDP 161 and receives trap messages on UDP 162. Which protocol is in use?","options":["Simple Network Management Protocol (SNMP).","Simple Mail Transfer Protocol (SMTP).","Server Message Block (SMB).","Secure File Transfer Protocol (SFTP)."],"correctIndex":0,"explanation":"SNMP commonly uses UDP 161 for polling and UDP 162 for traps. SNMP version 3 is preferred because it supports authentication and encryption.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":498,"question":"A scan identifies Simple Network Management Protocol version 2 community strings in use. Which remediation is best?","options":["Migrate to Simple Network Management Protocol version 3 (SNMPv3) with authentication and encryption.","Replace it with Trivial File Transfer Protocol (TFTP) because both use User Datagram Protocol (UDP).","Move polling from UDP 161 to TCP 25 to protect management traffic.","Disable Network Time Protocol (NTP) because time sync exposes community strings."],"correctIndex":0,"explanation":"SNMPv1 and SNMPv2c rely on community strings and are weaker than SNMPv3. SNMPv3 can provide message integrity, authentication, and confidentiality.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":499,"question":"A device downloads boot configuration files from UDP 69 without authentication. Which protocol is this?","options":["Trivial File Transfer Protocol (TFTP).","File Transfer Protocol (FTP) control channel.","Secure Copy Protocol (SCP).","Network File System (NFS)."],"correctIndex":0,"explanation":"TFTP uses UDP 69 and is simple, unauthenticated, and commonly seen in network boot or device configuration workflows. It should be tightly restricted.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":500,"question":"A data-loss review finds credentials sent over TCP 21 before files are transferred over a separate data connection. Which protocol caused the concern?","options":["File Transfer Protocol (FTP).","Secure File Transfer Protocol (SFTP).","Hypertext Transfer Protocol Secure (HTTPS).","Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS)."],"correctIndex":0,"explanation":"FTP uses TCP 21 for control and TCP 20 for active-mode data. It is not encrypted by default. SFTP rides over SSH on TCP 22 and is usually preferred.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":501,"question":"An external scan shows TCP 3389 open to the internet on a Windows host. Which service should be restricted immediately?","options":["Remote Desktop Protocol (RDP).","Kerberos.","Server Message Block (SMB).","Post Office Protocol version 3 Secure (POP3S)."],"correctIndex":0,"explanation":"RDP uses TCP 3389. Internet-exposed RDP is commonly targeted for brute force, credential stuffing, exploitation, and ransomware intrusion paths.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.4","objective":"Indicators of Malicious Activity","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":502,"question":"A firewall change for an Internet Protocol Security (IPsec) VPN must allow Internet Key Exchange and Network Address Translation Traversal. Which ports should be included?","options":["UDP 500 and UDP 4500.","TCP 389 and TCP 636.","UDP 67 and UDP 68.","TCP 20 and TCP 21."],"correctIndex":0,"explanation":"IPsec commonly uses Internet Key Exchange (IKE) on UDP 500 and NAT Traversal on UDP 4500. ESP is protocol 50, but it is not a TCP or UDP port.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":503,"question":"A legacy remote-access profile uses TCP 1723 and Generic Routing Encapsulation (GRE). Which protocol is most likely configured?","options":["Point-to-Point Tunneling Protocol (PPTP).","Layer 2 Tunneling Protocol (L2TP).","Internet Key Exchange version 2 (IKEv2).","Secure Shell (SSH) tunneling."],"correctIndex":0,"explanation":"PPTP uses TCP 1723 and GRE. It is considered weak by modern standards and should generally be replaced with stronger VPN technologies.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":504,"question":"New endpoints on a subnet cannot obtain addresses. Packet captures show blocked broadcasts involving UDP 67 and UDP 68. Which process is failing?","options":["Dynamic Host Configuration Protocol (DHCP) leasing.","Domain Name System (DNS) recursive lookup.","Network Time Protocol (NTP) synchronization.","Kerberos ticket granting."],"correctIndex":0,"explanation":"DHCP commonly uses UDP 67 for the server and UDP 68 for the client. Blocking this exchange can prevent clients from receiving IP address configuration.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":505,"question":"An Active Directory environment has authentication failures after a firewall update. Which port should be checked for Kerberos authentication?","options":["TCP/UDP 88.","TCP 49.","UDP 1813.","TCP 995."],"correctIndex":0,"explanation":"Kerberos uses TCP and UDP 88. It is central to many Active Directory authentication flows and is sensitive to time synchronization issues.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":506,"question":"A Security Operations Center (SOC) wants network devices to forward logs confidentially instead of using default UDP 514. Which destination is the better choice?","options":["TCP 6514 for syslog over Transport Layer Security (TLS).","UDP 69 for syslog over Trivial File Transfer Protocol (TFTP).","TCP 23 for syslog over Telnet.","UDP 123 for syslog over Network Time Protocol (NTP)."],"correctIndex":0,"explanation":"Traditional syslog commonly uses UDP 514. Syslog over TLS commonly uses TCP 6514 and provides confidentiality and integrity protections for log transport.","domain":"1.0 General Security Concepts","objectiveId":"1.2","objective":"Fundamental Security Concepts (CIA, AAA, Zero Trust)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":507,"question":"A cloud security review finds TCP 3306 open to the internet on a server that stores customer records. Which service is most likely exposed?","options":["MySQL database service.","Microsoft SQL Server database service.","PostgreSQL database service.","MongoDB database service."],"correctIndex":0,"explanation":"MySQL commonly uses TCP 3306. Database services should rarely be internet-exposed; use private networking, access controls, strong authentication, and logging.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":508,"question":"A vulnerability report lists TCP 1433 open on a production database host. Which technology is most likely being reported?","options":["Microsoft SQL Server.","MySQL.","PostgreSQL.","Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"Microsoft SQL Server commonly uses TCP 1433. MySQL commonly uses TCP 3306, and PostgreSQL commonly uses TCP 5432.","domain":"4.0 Security Operations","objectiveId":"4.3","objective":"Vulnerability Management","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":509,"question":"An analyst detects an unauthorized remote-control tool listening on TCP 5900. Which protocol is most likely involved?","options":["Virtual Network Computing (VNC).","Remote Desktop Protocol (RDP).","Secure Shell (SSH).","Server Message Block (SMB)."],"correctIndex":0,"explanation":"VNC commonly uses TCP 5900. Like RDP, it should be tightly controlled and monitored because it enables interactive remote access.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":510,"question":"A phone system uses TCP/UDP 5060 for call setup and TCP 5061 when protected by Transport Layer Security (TLS). Which protocol is this?","options":["Session Initiation Protocol (SIP).","Simple Network Management Protocol (SNMP).","Server Message Block (SMB).","Secure Copy Protocol (SCP)."],"correctIndex":0,"explanation":"SIP commonly uses 5060 for signaling and 5061 for SIP over TLS. It is used for Voice over Internet Protocol (VoIP) call setup, not for media transport itself.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":511,"question":"An edge router unexpectedly begins session attempts to external peers on TCP 179. Which protocol should the network security team investigate?","options":["Border Gateway Protocol (BGP).","Dynamic Host Configuration Protocol (DHCP).","Domain Name System (DNS).","Lightweight Directory Access Protocol (LDAP)."],"correctIndex":0,"explanation":"BGP uses TCP 179 and is used for routing between autonomous systems. Unexpected BGP peering attempts can indicate misconfiguration or routing security concerns.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":512,"question":"A hardened Windows management subnet allows TCP 5986 but blocks TCP 5985. What administrative protocol is likely being secured?","options":["Windows Remote Management (WinRM) over Hypertext Transfer Protocol Secure (HTTPS).","Windows Remote Management (WinRM) over Hypertext Transfer Protocol (HTTP).","Server Message Block (SMB) over Transport Layer Security (TLS).","Remote Desktop Protocol (RDP) over Secure Shell (SSH)."],"correctIndex":0,"explanation":"WinRM commonly uses TCP 5985 for HTTP and TCP 5986 for HTTPS. The secure listener should be preferred when remote management is required.","domain":"4.0 Security Operations","objectiveId":"4.5","objective":"Enterprise Security Capabilities (Firewalls, IDS/IPS, DLP)","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":513,"question":"A load balancer terminates Transport Layer Security (TLS) for a customer portal. Which port should be expected for standard encrypted browser traffic?","options":["TCP 443 for Hypertext Transfer Protocol Secure (HTTPS).","TCP 80 for Hypertext Transfer Protocol Secure (HTTPS).","TCP 25 for Hypertext Transfer Protocol Secure (HTTPS).","UDP 443 for Lightweight Directory Access Protocol over Secure Sockets Layer/Transport Layer Security (LDAPS)."],"correctIndex":0,"explanation":"HTTPS defaults to TCP 443. Some newer protocols may use UDP 443, but the standard Security+ and CySA+ baseline answer for encrypted web traffic is HTTPS on TCP 443.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":514,"question":"A host exposes TCP 21, TCP 22, and TCP 23. The security team can keep only one remote-administration option available. Which should remain?","options":["TCP 22 because Secure Shell (SSH) supports encrypted administration and secure file transfer options.","TCP 21 because File Transfer Protocol (FTP) encrypts command and data channels by default.","TCP 23 because Telnet encrypts administrator credentials by default.","TCP 21 because it is the only port that can transfer files securely."],"correctIndex":0,"explanation":"SSH on TCP 22 is the best administrative choice among these. FTP and Telnet are cleartext by default and should be replaced or tightly restricted.","domain":"1.0 General Security Concepts","objectiveId":"1.4","objective":"Cryptographic Solutions","source":"comptia_ports_protocols_exam_mode_quiz.html"},{"id":515,"question":"A mid-sized financial services firm's change advisory board (CAB) meets weekly to review proposed IT changes. A systems administrator wants to apply an emergency patch to a public-facing web server after a critical zero-day vulnerability is disclosed by the vendor late on a Friday night, well outside the CAB's normal review cycle. According to standard change management practice, what should the administrator do?","options":["Follow the organization's emergency change process, which allows expedited approval and after-the-fact documentation for urgent security fixes","Wait until the next scheduled CAB meeting the following week before applying any patch, regardless of the vulnerability's severity","Apply the patch immediately without notifying anyone, since speed matters more than documentation","Ignore the vulnerability until a formal change request has been drafted, reviewed, and approved through the normal multi-week cycle"],"correctIndex":0,"explanation":"a well-designed change management process includes an emergency change procedure specifically for situations like actively exploitable zero-day vulnerabilities, allowing expedited approval by a smaller authority while still requiring documentation and retrospective review, balancing urgency with accountability.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":516,"question":"During a scheduled maintenance window, a network engineer plans to reconfigure firewall rules to support a new business application. Before the change is implemented, the engineer documents the current firewall configuration, identifies which systems and business processes depend on the affected rules, and prepares a rollback plan in case the change causes unexpected outages. What change management concept does this preparation MOST directly represent?","options":["Impact analysis and rollback planning as part of the change request process","Asset inventory tagging unrelated to the firewall change","Security awareness training for end users","Vulnerability scanning of the firewall itself"],"correctIndex":0,"explanation":"documenting the current state, identifying dependent systems and processes, and preparing a rollback plan are core elements of impact analysis and contingency planning within change management, ensuring that if the change causes problems, the organization can quickly and confidently revert to a known-good state.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":517,"question":"A company's change management policy requires that every proposed change include a documented technical implementation plan describing exactly how the change will be carried out step by step. Why is this documentation specifically valuable during a post-incident review, if the change later causes a service disruption?","options":["It allows investigators to compare what was planned against what actually happened, helping identify whether the disruption stemmed from the plan itself or from deviation during execution","It guarantees that no service disruption can ever occur, regardless of execution","It replaces the need for any rollback plan whatsoever","It is only useful for billing purposes and has no security or operational value"],"correctIndex":0,"explanation":"a documented implementation plan provides a clear baseline that investigators can compare against what actually occurred, making it possible to determine whether a disruption resulted from a flaw in the plan itself or from a deviation during execution, which directly informs corrective action.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":518,"question":"An organization's change management workflow requires that every proposed change be assigned an official owner who is accountable for coordinating the change, answering questions from the CAB, and ensuring post-implementation review occurs. A junior administrator submits a change request but lists no owner, assuming the CAB will simply assign one. What is the risk of allowing changes to proceed without a clearly assigned owner?","options":["Accountability becomes unclear, making it harder to coordinate communication, troubleshoot issues during implementation, and follow up after the change is complete","There is no risk at all, since the CAB tracks every detail automatically regardless of ownership","The change will automatically be rejected by the ticketing system, so this is a non-issue","Ownership only matters for changes involving physical hardware, not software or configuration changes"],"correctIndex":0,"explanation":"a clearly assigned change owner is accountable for coordinating implementation, communicating status, answering CAB questions, and ensuring post-implementation review occurs; without one, accountability becomes diffuse and it becomes harder to troubleshoot problems or follow up effectively.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":519,"question":"A company is preparing to migrate its email system to a new cloud provider. As part of the change management process, the IT team schedules the migration during a maintenance window that avoids the organization's month-end financial closing period, when email-dependent approval workflows are heavily used. What change management concept does scheduling around business-critical periods represent?","options":["Considering business process impact and choosing an appropriate maintenance window to minimize disruption to critical operations","Asset classification based on data sensitivity labels","Non-repudiation of the change request itself","Least privilege enforcement on the migration team's accounts"],"correctIndex":0,"explanation":"selecting a maintenance window that avoids a period of heavy reliance on the affected system, such as month-end financial closing, reflects a deliberate assessment of business process impact, which is a core part of responsible change scheduling within change management.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":520,"question":"A security analyst reviewing recent change requests notices that a critical database server's configuration was modified last month, but there is no corresponding entry in the change management log, no CAB approval record, and no documentation of who made the change or why. What risk does this undocumented change MOST directly represent?","options":["An unauthorized or unmanaged change that bypassed governance controls, potentially introducing untracked risk, misconfigurations, or a foothold for malicious activity","A perfectly normal and low-risk situation, since database servers are exempt from change management by default","Proof that the change management process is working exactly as intended","A finding that only affects billing accuracy, not security posture"],"correctIndex":0,"explanation":"a modification to a critical system with no corresponding change record, approval, or documentation represents an unauthorized or unmanaged change that bypassed governance controls entirely, which is a significant risk because such changes can introduce misconfigurations, instability, or even provide cover for malicious activity that governance processes are specifically designed to catch.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":521,"question":"An organization requires that any change affecting a system storing regulated customer data undergo a security impact analysis before approval, even if the change seems purely cosmetic, such as updating a web page's footer text. Why would even a seemingly minor change require this analysis?","options":["Because seemingly minor changes can sometimes have unintended consequences on underlying code, permissions, or data handling, and consistent review policy prevents assumptions from bypassing proper scrutiny","Because footer text changes always contain malware by definition","Because security impact analysis is only a formality with no real value","Because regulated data automatically becomes public once any change is made to the system"],"correctIndex":0,"explanation":"even changes that appear cosmetic on the surface, such as editing footer text, can sometimes touch underlying code, templates, or permissions in ways that have unintended consequences, so requiring consistent security impact analysis for all changes to sensitive systems prevents assumptions about a change's simplicity from bypassing proper scrutiny.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":522,"question":"A company's CAB rejects a proposed change to disable multi-factor authentication for a group of executive accounts, citing that the requester did not provide a documented business justification or risk acceptance sign-off from the security team. What core change management principle does this rejection demonstrate?","options":["Changes that increase risk require appropriate justification, review, and formal risk acceptance before approval, rather than being implemented purely on convenience","The CAB has no authority to reject any proposed change under any circumstances","Multi-factor authentication cannot legally be disabled for any account under any policy","Executive accounts are automatically exempt from all security controls and change review"],"correctIndex":0,"explanation":"the CAB's rejection reflects the principle that changes which increase organizational risk, such as disabling multi-factor authentication, require documented business justification and formal risk acceptance before approval, ensuring that convenience alone does not override proper security governance.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":523,"question":"During a change management review, a technician discovers that a previous 'standard' pre-approved change template for patching servers has been used to sneak through unrelated and much riskier configuration changes without additional scrutiny, since standard changes bypass full CAB review. What does this scenario illustrate about the use of standard/pre-approved change categories?","options":["Standard change templates should be scoped narrowly and periodically audited, since misuse of a low-scrutiny category can allow riskier changes to slip through without proper review","Standard changes should never be used under any circumstances because they are inherently insecure","Pre-approved changes automatically include unlimited scope for any future modification","CAB review is unnecessary for any category of change, standard or otherwise"],"correctIndex":0,"explanation":"standard or pre-approved change categories exist to streamline routine, well-understood, low-risk changes, but if their scope isn't narrowly defined and periodically audited, they can be misused to push through riskier changes without the scrutiny those changes actually require, undermining the purpose of the change management process.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":524,"question":"A network administrator proposes a change to reconfigure VLAN assignments across the corporate network. The change request includes a rollback plan that describes reverting to a saved switch configuration backup if the change causes connectivity issues. During implementation, the change causes widespread outages, and the team executes the rollback plan successfully within fifteen minutes. What does this scenario demonstrate about the value of rollback planning?","options":["A well-prepared rollback plan minimizes downtime and business impact when a change does not go as expected, allowing rapid recovery to a known-good state","Rollback plans are only useful for cosmetic changes, not network infrastructure changes","The change management process failed completely, since any need for rollback indicates total process failure","Rollback plans eliminate the need for testing changes before implementation"],"correctIndex":0,"explanation":"having a well-prepared rollback plan allowed the team to quickly revert to a known-good configuration once the change caused outages, minimizing downtime and business impact; this illustrates why rollback planning is a core requirement of responsible change management, not a sign of process failure.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":525,"question":"A company's change management policy requires a defined maintenance window, along with a specific start and end time, for every planned infrastructure change. During a recent database schema update, the change ran significantly longer than the approved window because unexpected complications arose. What should the implementation team have done once it became clear the change would exceed the approved window?","options":["Follow the organization's escalation and extension process, notifying stakeholders and either requesting an extension or rolling back before the window closes","Continue working past the approved window without notifying anyone, since finishing the task matters more than following the process","Immediately shut down the database server regardless of the consequences","Wait silently until the next business day to mention the overrun"],"correctIndex":0,"explanation":"when a change is at risk of exceeding its approved maintenance window, the appropriate response is to follow the organization's escalation and extension process, notifying stakeholders promptly and either requesting a formal extension or executing the rollback plan before the window closes, rather than continuing silently or abandoning the process.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":526,"question":"An organization is evaluating whether a proposed application update should go through the full change advisory board process or qualify as a 'standard change' that can be pre-approved and implemented without individual review. Which factor would MOST strongly support treating it as a standard change?","options":["The update is well-understood, low-risk, has been performed successfully many times before with a documented, repeatable process","The update has never been performed before and its impact is completely unknown","The update affects every critical system in the organization simultaneously","The update was requested verbally with no documentation of what it involves"],"correctIndex":0,"explanation":"standard changes are appropriate for well-understood, low-risk activities that follow a documented, repeatable process and have a proven track record of successful, low-impact implementation, which allows them to bypass full individual review without introducing undue risk, unlike novel, high-impact, or undocumented changes.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":527,"question":"A security team notices that several recent change requests were approved by the CAB but list vague descriptions such as 'server maintenance' with no specifics about what was actually modified. Why is this level of documentation a security concern?","options":["Vague change documentation makes it difficult to audit what was actually done, complicating incident investigation, compliance reporting, and configuration drift detection","Vague documentation is actually preferred because it saves time and has no downsides","Change documentation detail only matters for hardware changes, not software or configuration changes","The CAB is required by law to reject all changes with any documentation at all"],"correctIndex":0,"explanation":"vague change documentation undermines the ability to audit what was actually done to a system, which complicates incident investigation when something goes wrong, hampers compliance reporting that often requires specific change evidence, and makes it harder to detect unauthorized configuration drift over time.","domain":"1.0 General Security Concepts","objectiveId":"1.3","objective":"Change Management","source":"original-2026-batch"},{"id":528,"question":"A disgruntled former employee, who was terminated two weeks ago but whose VPN credentials were never revoked, logs into the corporate network late at night and deletes several critical project files before anyone notices. What threat actor category and motivation does this scenario MOST clearly represent?","options":["An insider threat motivated by revenge or grievance following termination","A nation-state actor motivated by espionage","A hacktivist motivated by political ideology","An unskilled attacker (script kiddie) motivated by curiosity"],"correctIndex":0,"explanation":"a former employee using retained access to intentionally damage company data out of anger over their termination is a textbook insider threat, since the individual had legitimate prior access and acted with a personal, revenge-based motivation rather than financial, political, or espionage-driven goals.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":529,"question":"A highly sophisticated attack against a defense contractor's network involves custom-built malware, months of patient reconnaissance, and a focus on stealing classified weapons system blueprints rather than causing immediate disruption or financial harm. Which threat actor type is MOST consistent with this level of resourcing and objective?","options":["A nation-state actor conducting espionage","A disgruntled insider acting alone","An unskilled attacker using off-the-shelf tools","A hacktivist seeking to embarrass the company publicly"],"correctIndex":0,"explanation":"the combination of custom malware, extended patient reconnaissance, substantial resourcing, and a focus on stealing classified defense information rather than quick financial gain is characteristic of a nation-state actor conducting espionage, as these actors typically have the funding, patience, and strategic objectives that other threat actor types lack.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":530,"question":"A group calling itself 'Ocean Defenders' defaces a seafood company's website, replacing the homepage with messages condemning the company's fishing practices and links to environmental advocacy sites. What is the group's MOST likely primary motivation?","options":["Ideological or political motivation, seeking to advance an environmental cause and embarrass the company publicly","Financial gain through data theft and resale","Espionage on behalf of a foreign government","Simple curiosity with no deeper motivation"],"correctIndex":0,"explanation":"defacing a website with messages tied to a specific cause, in this case environmental advocacy, and publicly embarrassing the target company is characteristic of hacktivism, where the primary motivation is ideological or political rather than financial gain or state-sponsored espionage.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":531,"question":"A teenager downloads a freely available password-cracking tool from an online forum and uses it, with no real understanding of how it works internally, to try to break into a classmate's social media account as a prank. What threat actor category best describes this individual?","options":["An unskilled attacker (commonly called a 'script kiddie')","An advanced persistent threat operator","A state-sponsored intelligence officer","An organized crime syndicate member"],"correctIndex":0,"explanation":"using a pre-built tool without a deep technical understanding of its inner workings, often for low-stakes or prankish purposes, is the defining characteristic of an unskilled attacker, sometimes called a script kiddie, as distinguished from more sophisticated, resourced, or strategically motivated threat actors.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":532,"question":"A criminal organization operates a large-scale ransomware operation, complete with a customer support chat for victims negotiating payment, an affiliate program that pays a percentage to independent operators who deploy the ransomware, and a dedicated data leak website. What does the business-like structure of this operation MOST strongly suggest about the threat actor?","options":["An organized crime group motivated primarily by financial gain, operating with a level of structure resembling a legitimate business","A lone hacktivist acting out of ideological conviction","A nation-state actor solely focused on military espionage","An unskilled attacker with no financial motivation"],"correctIndex":0,"explanation":"the presence of a support chat, an affiliate revenue-sharing program, and a dedicated leak site reflects a highly organized, business-like structure typical of organized crime groups, whose primary motivation is financial profit rather than ideology, espionage, or simple curiosity.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":533,"question":"A security researcher discovers that an attack against a power grid's industrial control systems used a previously unknown vulnerability, was active for over a year without detection, and appeared designed to gather intelligence on grid operations rather than cause an immediate blackout. What term describes this pattern of prolonged, stealthy, well-resourced intrusion?","options":["An advanced persistent threat (APT)","A simple phishing campaign","A denial-of-service attack","An unskilled attacker's opportunistic scan"],"correctIndex":0,"explanation":"a prolonged, stealthy intrusion using a previously unknown vulnerability, sustained for over a year while focused on intelligence gathering rather than immediate disruption, is the defining pattern of an advanced persistent threat, which typically involves significant resources, patience, and strategic long-term objectives.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":534,"question":"An employee at a manufacturing company is approached by a competitor who offers a substantial cash payment in exchange for proprietary product designs. The employee, motivated purely by the money offered, copies the files to a personal USB drive and hands them over. What is the PRIMARY motivation driving this insider's actions?","options":["Financial gain","Ideological conviction","Revenge for perceived mistreatment","Pure curiosity about the data's contents"],"correctIndex":0,"explanation":"the employee's actions were driven explicitly by the cash payment offered by the competitor, making financial gain the clear primary motivation, distinct from ideological, revenge-based, or curiosity-driven motivations that characterize other insider threat scenarios.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":535,"question":"A shadowy group with no clear public identity or stated cause repeatedly attacks a mid-sized company's e-commerce platform, stealing customer credit card numbers and selling them on underground marketplaces. Investigators note the group uses proven, well-established attack techniques rather than developing custom tools. What threat actor category and motivation combination BEST fits this description?","options":["Organized crime motivated by financial gain, using established techniques for reliable profit rather than nation-state-level custom tooling","A nation-state actor motivated by military espionage","A hacktivist motivated by political protest","An unskilled attacker with no clear goal"],"correctIndex":0,"explanation":"the group's focus on directly monetizable data like credit card numbers, combined with using proven established techniques rather than expensive custom tooling, points to organized crime motivated by financial gain, which typically favors reliable, cost-effective methods over the bespoke tooling associated with nation-state operations.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":536,"question":"A company's competitor hires a specialized firm to gather intelligence on the company's upcoming product launch, including infiltrating internal communications to learn pricing strategy before it becomes public. What term BEST describes this type of threat activity?","options":["Corporate or industrial espionage","Hacktivism","Script kiddie experimentation","Insider threat driven by revenge"],"correctIndex":0,"explanation":"a competitor deliberately hiring specialists to infiltrate internal communications and steal strategic business information, such as pricing plans, before a product launch is a clear example of corporate or industrial espionage, which is distinct from politically motivated hacktivism or low-skill opportunistic activity.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":537,"question":"An attacker gains access to a hospital's network and, rather than stealing data quietly, deploys ransomware that encrypts patient records and demands payment, explicitly threatening to leak sensitive medical data if the hospital does not pay within 48 hours. What does the explicit extortion threat and short deadline suggest about the attacker's motivation?","options":["Financial gain through direct extortion, using urgency and reputational threat to pressure quick payment","Political ideology with no interest in financial reward","Simple curiosity about hospital network architecture","State-sponsored espionage focused on stealing medical research"],"correctIndex":0,"explanation":"deploying ransomware with an explicit payment demand, a tight deadline, and a threat to leak sensitive data if unpaid is a direct extortion tactic aimed at maximizing financial gain by pressuring the victim through urgency and reputational risk, rather than reflecting political, curiosity-driven, or espionage motivations.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":538,"question":"A security team notices that an attack against their organization used techniques and infrastructure previously attributed by threat intelligence firms to a specific foreign government's cyber unit, and the targeted data was exclusively related to national defense contracts. What threat actor classification does this evidence MOST strongly support?","options":["A nation-state actor conducting espionage aligned with the foreign government's strategic interests","A financially motivated organized crime group","A hacktivist group with an environmental agenda","An unskilled attacker experimenting with downloaded tools"],"correctIndex":0,"explanation":"attribution to infrastructure and techniques previously linked to a specific government's cyber unit, combined with a narrow focus on national defense contract data rather than broadly monetizable information, strongly supports classification as a nation-state actor conducting espionage aligned with that government's strategic interests.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":539,"question":"A curious college student, without any malicious intent to cause harm, scans a university's public-facing servers purely to learn how port scanning tools work, and stops as soon as they notice the activity might be against university policy. What motivation category best fits this activity, even though it is still against policy?","options":["Curiosity or personal challenge, sometimes seen in unskilled or novice attackers exploring technical skills without strategic malicious intent","Financial gain through data resale","Nation-state sponsored espionage","Revenge against the university"],"correctIndex":0,"explanation":"activity driven purely by a desire to learn and experiment, with no intent to cause harm, steal data, or achieve any strategic objective, reflects curiosity or personal challenge as a motivation, which is common among novice or unskilled individuals exploring technical concepts, even though the activity itself may still violate policy or law.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":540,"question":"An activist group publicly claims responsibility for a distributed denial-of-service attack against a government agency's website, stating the attack was in protest of a controversial new law. What threat actor category does this group represent, based on their public claim and stated purpose?","options":["Hacktivists, motivated by political or social ideology rather than financial gain","Organized crime, motivated by financial profit","A nation-state actor conducting espionage","An unskilled attacker with no clear motivation"],"correctIndex":0,"explanation":"publicly claiming responsibility for an attack explicitly framed as protest against a specific law or policy is characteristic of hacktivism, where the primary motivation is advancing a political or social cause and drawing public attention, rather than pursuing financial profit or state-directed intelligence objectives.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":541,"question":"A security analyst is trying to distinguish between an opportunistic attacker and a targeted, well-resourced threat actor after a breach. Which piece of evidence would MOST strongly suggest the attacker was well-resourced and specifically targeting the organization, rather than opportunistic?","options":["The attack used a custom-developed exploit for a vulnerability specific to the organization's unique, internally built software","The attack used a widely available, publicly known exploit against a common, unpatched vulnerability","The attack was detected within minutes by standard antivirus software","The attacker sent a mass phishing email to thousands of random addresses"],"correctIndex":0,"explanation":"developing a custom exploit specifically targeting a vulnerability in an organization's unique internal software requires significant time, skill, and resources, and demonstrates the attacker had specific knowledge of and interest in that particular target, which is characteristic of a well-resourced, targeted threat actor rather than an opportunistic one using generic, widely available tools.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.1","objective":"Threat Actors & Motivations","source":"original-2026-batch"},{"id":542,"question":"An employee receives an email that appears to come from the company's CEO, urgently requesting a wire transfer to a new vendor before the end of the day, with subtle spelling differences in the sender's domain name that go unnoticed. What threat vector does this scenario represent?","options":["Email-based phishing (specifically business email compromise)","A physical attack vector involving unauthorized building access","A supply chain compromise of a hardware vendor","A wireless attack against the office Wi-Fi network"],"correctIndex":0,"explanation":"an email impersonating a trusted executive, using a spoofed or lookalike domain to pressure the recipient into an urgent financial action, is a classic example of business email compromise, a form of phishing delivered through the email attack vector.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":543,"question":"An attacker leaves several USB drives labeled 'Confidential - Salary Information' in the parking lot of a target company, hoping an employee will plug one into a work computer out of curiosity. What threat vector is being exploited here?","options":["A removable media attack vector, relying on human curiosity to bypass network-based defenses entirely","A wireless attack vector targeting the corporate Wi-Fi","A supply chain attack vector involving a compromised software update","A direct network intrusion attack vector"],"correctIndex":0,"explanation":"dropping physical USB drives designed to lure a curious employee into plugging them into a company device is a classic removable media attack vector, which bypasses network perimeter defenses entirely by exploiting human behavior and physical access to endpoints.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":544,"question":"A company discovers that a widely used third-party software library, embedded in dozens of its internal applications, was secretly modified by attackers at its source before being distributed to customers, including this company. What threat vector does this represent?","options":["A supply chain attack, where a trusted upstream component was compromised before reaching the end user","A phishing attack targeting individual employees directly","A physical attack involving unauthorized data center access","A wireless attack against guest Wi-Fi networks"],"correctIndex":0,"explanation":"compromising a trusted software component at its source, before it is distributed downstream to many organizations that rely on it, is the defining characteristic of a supply chain attack, which is especially dangerous because it can affect many victims through a single point of compromise.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":545,"question":"An organization's guest Wi-Fi network uses outdated encryption and is physically accessible from the public parking lot, allowing anyone nearby to attempt to intercept traffic or pivot toward internal resources. What kind of attack surface does this represent?","options":["A wireless network attack surface, expanded by weak encryption and physical proximity to unauthorized users","A supply chain attack surface involving vendor software","A social engineering attack surface targeting help desk staff","A removable media attack surface"],"correctIndex":0,"explanation":"a Wi-Fi network using outdated encryption that can be reached by anyone within physical range, such as the parking lot, expands the wireless attack surface by giving unauthorized individuals an opportunity to intercept traffic or attempt further compromise from outside the building's walls.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":546,"question":"A help desk technician receives a phone call from someone claiming to be a frantic executive who has forgotten their password and urgently needs it reset immediately, using pressure and authority to rush the technician past normal identity verification steps. What threat vector is being exploited?","options":["Social engineering via a vishing (voice phishing) phone call, exploiting urgency and authority to bypass verification procedures","A wireless attack against the help desk's network","A supply chain compromise of the ticketing software","A removable media attack via a malicious USB device"],"correctIndex":0,"explanation":"using a phone call, urgency, and claimed authority to pressure a help desk technician into skipping proper identity verification is a form of social engineering delivered via voice, commonly called vishing, which exploits human psychology rather than any technical vulnerability.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":547,"question":"A company's public-facing web application allows file uploads for user profile pictures, but does not properly validate file type or content, allowing an attacker to upload a malicious script disguised as an image. What does this scenario illustrate about attack surfaces?","options":["Every publicly accessible feature, including file upload functionality, expands the application's attack surface if not properly secured","Attack surfaces only include network ports, never application-level features like file uploads","File upload features can never be part of an attack surface since they are intended functionality","Attack surface only refers to physical building access points"],"correctIndex":0,"explanation":"any publicly accessible feature of an application, including something as seemingly ordinary as a profile picture upload, becomes part of the attack surface if it isn't properly secured, since attackers can exploit legitimate functionality, like an unvalidated file upload, to introduce malicious content.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":548,"question":"An attacker tailgates behind an employee through a badge-secured door by carrying a large box and appearing to need help, relying on the employee's politeness rather than any technical exploit. What threat vector does this represent?","options":["A physical social engineering attack (tailgating), exploiting human courtesy to bypass a physical access control","A network-based denial-of-service attack","A supply chain attack involving compromised hardware","A wireless attack against a badge reader's radio signal"],"correctIndex":0,"explanation":"following closely behind an authorized person through a secured door, relying on their politeness or unwillingness to challenge a stranger, is a physical social engineering technique known as tailgating, which bypasses badge-based access controls through human behavior rather than a technical flaw.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":549,"question":"A company's cloud storage bucket, intended to hold internal-only documents, is accidentally configured with public read access, allowing anyone on the internet to browse and download its contents without authentication. What does this scenario illustrate about cloud-based attack surfaces?","options":["Misconfigured cloud resources can unintentionally expose an organization's attack surface to the entire internet, even without any attacker action","Cloud storage is inherently immune to attack surface concerns since it is managed by the provider","Attack surface only applies to on-premises infrastructure, never cloud resources","Public cloud storage buckets are always intentionally public and pose no risk"],"correctIndex":0,"explanation":"a misconfigured cloud storage bucket that unintentionally grants public access demonstrates how a simple configuration error, with no attacker action required, can massively expand an organization's attack surface by exposing sensitive resources to anyone on the internet.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":550,"question":"An attacker sends a text message to an employee's personal phone claiming to be from the company's IT department, warning that their account will be locked unless they click a link and enter their credentials immediately. What threat vector is being used?","options":["Smishing (SMS-based phishing), exploiting the immediacy and personal nature of text messages to pressure quick action","A wireless attack directly against the phone's Bluetooth radio","A supply chain attack against the phone's manufacturer","A physical attack requiring in-person access to the device"],"correctIndex":0,"explanation":"delivering a phishing message via text message (SMS) that pressures the recipient into urgent action, such as clicking a credential-harvesting link, is a form of social engineering known as smishing, which exploits the personal and immediate nature of text messaging as an attack vector.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":551,"question":"A manufacturer ships network-connected security cameras with a default administrator password that many customers never change, and researchers later demonstrate that thousands of these cameras across the internet can be accessed using that same default credential. What does this scenario illustrate about attack vectors involving IoT devices?","options":["Default, unchanged credentials on widely deployed IoT devices create a broad and easily exploitable attack vector across many organizations at once","IoT devices are inherently more secure than traditional computers because they run simplified operating systems","Default credentials only pose a risk if the device is physically accessible to an attacker","IoT security cameras cannot be part of a network attack surface"],"correctIndex":0,"explanation":"shipping devices with default credentials that many customers never change creates a widespread, easily exploitable attack vector, since an attacker who knows the default password can potentially access every unchanged device of that model across the internet, not just one target.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":552,"question":"An attacker researches a company's employees on social media and discovers a project manager frequently posts about their pet's name and their favorite sports team, then uses this information to guess the answers to that employee's password reset security questions. What threat vector does this represent?","options":["Open-source intelligence (OSINT) gathering used to enable a social engineering or account takeover attack","A direct network intrusion using a zero-day exploit","A wireless attack against the employee's home router","A supply chain compromise involving the employee's software vendor"],"correctIndex":0,"explanation":"gathering publicly available personal information from social media to answer security questions or otherwise impersonate a target is a form of open-source intelligence (OSINT) gathering, which serves as reconnaissance enabling a subsequent social engineering or account takeover attack.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":553,"question":"A vendor that provides HVAC monitoring services for a retail chain is given remote network access to manage the building systems, but that same access is later used by attackers who compromised the vendor's credentials to pivot into the retailer's payment card network. What does this scenario illustrate about third-party attack vectors?","options":["Trusted third-party vendor access, if not properly segmented and restricted, can become an attack vector into unrelated and more sensitive parts of the network","Third-party vendors can never pose a security risk if they are contractually bound by an agreement","Vendor access to HVAC systems is always completely isolated from other network segments by default","Attack vectors can only originate from an organization's own employees, never external vendors"],"correctIndex":0,"explanation":"granting a third-party vendor broad or poorly segmented network access, even for an unrelated purpose like HVAC monitoring, can become an attack vector if that vendor's credentials are compromised and used to pivot into more sensitive parts of the network, such as payment card systems, highlighting the importance of network segmentation and least privilege for vendor access.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":554,"question":"An attacker scans a company's public IP address range and discovers an old, forgotten development server still running with default credentials and no recent patches, unlike the company's actively maintained production servers. What security concept does this forgotten server represent?","options":["Attack surface expansion through unmanaged or 'shadow IT' assets that fall outside normal patching and monitoring processes","A properly hardened and monitored production asset","A physical attack vector requiring building access","A supply chain attack originating from a software vendor"],"correctIndex":0,"explanation":"a forgotten, unmanaged server that isn't part of regular patching and monitoring processes represents an expanded and often invisible attack surface, since it lacks the security controls applied to actively managed production systems, making it an easy target for attackers who discover it.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":555,"question":"An attacker impersonates a building maintenance worker, wearing a uniform and carrying tools, to walk past a receptionist without being challenged and gain physical access to a server room. What threat vector category does this represent?","options":["A physical social engineering attack vector, relying on impersonation and visual cues of legitimacy to bypass human scrutiny","A wireless attack vector exploiting Wi-Fi encryption weaknesses","A supply chain attack vector involving compromised maintenance equipment","A removable media attack vector using an infected USB drive"],"correctIndex":0,"explanation":"impersonating a legitimate role, such as a maintenance worker, using a convincing uniform and props to avoid being challenged while gaining physical access is a physical social engineering attack vector, exploiting human trust in visual cues of legitimacy rather than any technical vulnerability.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":556,"question":"A company allows employees to connect personal smartphones to the corporate email system without any mobile device management (MDM) policy or security requirements. What risk does this expand?","options":["The organization's attack surface, since unmanaged personal devices may lack encryption, security patches, or malware protection while still accessing corporate data","No additional risk, since personal devices are entirely the employee's responsibility and outside the attack surface","The risk is limited only to the employee's personal data, never corporate data","The company's attack surface actually shrinks, since fewer company-owned devices need to be managed"],"correctIndex":0,"explanation":"allowing unmanaged personal devices to access corporate email without security requirements like encryption or minimum patch levels expands the organization's overall attack surface, since these devices may be less secure than company-managed hardware while still handling sensitive corporate data.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":557,"question":"An attacker sets up a fake Wi-Fi access point in a coffee shop near a company's office, naming it identically to the company's legitimate guest network, hoping employees on lunch break will connect to it automatically. What threat vector does this represent?","options":["An evil twin wireless attack, exploiting devices that automatically reconnect to previously known network names","A supply chain attack against the coffee shop's internet provider","A physical social engineering attack requiring building access","A removable media attack using a malicious USB device"],"correctIndex":0,"explanation":"creating a fraudulent wireless access point with the same name as a legitimate network, hoping devices will automatically connect due to a matching network name, is known as an evil twin attack, a wireless threat vector that exploits automatic reconnection behavior in client devices.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":558,"question":"A company's application programming interface (API), used by its mobile app to fetch user data, does not require authentication for certain endpoints, allowing anyone who discovers the API's web address to retrieve other users' private information directly. What does this scenario illustrate?","options":["Unsecured or improperly authenticated APIs represent a significant and often overlooked attack surface, especially as more functionality moves to API-driven architectures","APIs are never part of an organization's attack surface since they are not user-facing","This is a purely cosmetic issue with no real security impact","API endpoints are automatically secured by the mobile app itself, regardless of server-side controls"],"correctIndex":0,"explanation":"an API endpoint that fails to require proper authentication, allowing anyone who discovers its address to access other users' private data, illustrates how unsecured or improperly authenticated APIs represent a significant and increasingly common attack surface, particularly as modern applications rely heavily on API-driven architectures.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.2","objective":"Threat Vectors & Attack Surfaces","source":"original-2026-batch"},{"id":559,"question":"A web application accepts a username and password directly into a database query without sanitizing the input, allowing an attacker to enter special characters that alter the query's logic and bypass the login screen entirely. What type of vulnerability does this represent?","options":["SQL injection","Buffer overflow","Race condition","Improper certificate validation"],"correctIndex":0,"explanation":"a web application that inserts unsanitized user input directly into a database query, allowing an attacker to manipulate the query's logic with special characters, is vulnerable to SQL injection, one of the most common and dangerous input validation flaws in web applications.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":560,"question":"A program allocates a fixed-size memory area for user input, but fails to check whether the input exceeds that size, allowing an attacker to write data beyond the allocated boundary and potentially execute malicious code. What type of vulnerability does this describe?","options":["Buffer overflow","Cross-site scripting","Broken access control","Weak cryptographic implementation"],"correctIndex":0,"explanation":"a program that fails to enforce boundaries on how much data can be written into a fixed-size memory area, allowing input to overflow beyond that boundary and potentially corrupt adjacent memory or execute injected code, is vulnerable to a buffer overflow.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":561,"question":"A messaging application allows users to post comments that are displayed on other users' screens without properly sanitizing embedded script tags, allowing an attacker to inject JavaScript that runs in other users' browsers when they view the comment. What vulnerability type does this represent?","options":["Cross-site scripting (XSS)","SQL injection","Buffer overflow","A race condition (time-of-check to time-of-use)"],"correctIndex":0,"explanation":"injecting malicious script into content that is later rendered in other users' browsers, because the application fails to sanitize embedded script tags, is the defining characteristic of cross-site scripting, distinct from database-focused SQL injection or memory-focused buffer overflows.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":562,"question":"A file-sharing application checks whether a user has permission to delete a file, but a brief delay occurs between that permission check and the actual deletion, during which an attacker swaps the target file for a different, unauthorized one, causing the wrong file to be deleted. What type of vulnerability does this describe?","options":["A time-of-check to time-of-use (TOCTOU) race condition","A cross-site scripting flaw","A SQL injection flaw","An end-of-life software vulnerability"],"correctIndex":0,"explanation":"a vulnerability arising from the gap between when a condition is checked (permission verified) and when it is actually used (file deleted), during which an attacker can alter the state to cause unintended behavior, is a time-of-check to time-of-use race condition.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":563,"question":"An organization continues running a specialized piece of manufacturing control software on an operating system version that the vendor stopped releasing security patches for over two years ago, because upgrading would require costly recertification of the manufacturing line. What category of vulnerability does this unpatched, unsupported software represent?","options":["An end-of-life (unsupported) software vulnerability, since no future security patches will be released to fix newly discovered flaws","A zero-day vulnerability, since the flaw was never publicly disclosed","A cross-site scripting vulnerability specific to web applications","A misconfiguration vulnerability unrelated to software support status"],"correctIndex":0,"explanation":"continuing to run software that the vendor no longer supports or patches, even for a legitimate business reason like avoiding costly recertification, represents an end-of-life software vulnerability, since any newly discovered flaws in that software will never receive an official fix, leaving the system permanently exposed.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":564,"question":"A security researcher discovers and exploits a previously unknown, unpatched flaw in a widely used operating system before the vendor has any awareness of the issue or a chance to release a fix. What type of vulnerability is being exploited?","options":["A zero-day vulnerability","A default configuration vulnerability","A legacy platform vulnerability","A weak encryption vulnerability"],"correctIndex":0,"explanation":"a flaw that is unknown to the software vendor, and therefore has no available patch, is by definition a zero-day vulnerability, named because the vendor has had zero days to address it before it becomes known or exploited.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":565,"question":"A newly deployed network switch is installed with its factory-set administrator username and password still active, and no one on the IT team changes them before putting the device into production. What type of vulnerability does this represent?","options":["A default configuration vulnerability, since factory-set credentials are often publicly documented and easily guessed by attackers","A zero-day vulnerability, since the flaw was never disclosed by the manufacturer","A cross-site scripting vulnerability specific to web browsers","A supply chain vulnerability originating from a compromised software update"],"correctIndex":0,"explanation":"leaving factory-set default credentials active on a production device is a default configuration vulnerability, and it is especially dangerous because manufacturer default credentials are frequently publicly documented, making them trivial for an attacker to guess or look up.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":566,"question":"A hospital continues to operate several critical patient-monitoring devices running an operating system that is over a decade old, because the device manufacturer never released an option to upgrade the embedded software, and the devices themselves are too expensive to replace. What term BEST describes the security risk posed by these legacy devices?","options":["Legacy platform vulnerabilities, since these systems can never receive modern security updates and remain permanently exposed to known flaws","A misconfiguration vulnerability that can be quickly fixed with a settings change","A weak cipher suite vulnerability unrelated to the operating system's age","A race condition vulnerability specific to multi-threaded applications"],"correctIndex":0,"explanation":"devices running outdated, unsupported operating systems that cannot be upgraded represent legacy platform vulnerabilities, which are particularly risky in environments like healthcare because the devices remain permanently exposed to known security flaws with no realistic path to remediation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":567,"question":"A company's web server is configured to use an outdated encryption protocol that has known cryptographic weaknesses, allowing a sufficiently motivated attacker to decrypt intercepted traffic given enough time and computing resources. What type of vulnerability does this represent?","options":["A cryptographic vulnerability due to weak or outdated encryption algorithms/protocols","A buffer overflow vulnerability in the web server's memory handling","A broken access control vulnerability in the application's authorization logic","A cross-site request forgery vulnerability in the web application"],"correctIndex":0,"explanation":"using an outdated encryption protocol with known cryptographic weaknesses, which could allow an attacker to eventually decrypt intercepted traffic, is a cryptographic vulnerability, distinct from application-layer flaws like broken access control or memory-handling issues like buffer overflows.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":568,"question":"A web application's file download feature accepts a file name directly from user input to determine which file to serve, but does not validate that the requested path stays within the intended directory, allowing an attacker to request '../../etc/passwd' and retrieve sensitive system files. What type of vulnerability does this represent?","options":["A directory traversal (path traversal) vulnerability","A cross-site scripting vulnerability","A weak cipher suite vulnerability","An open permissions vulnerability specific to cloud storage"],"correctIndex":0,"explanation":"failing to validate that a user-supplied file path stays within an intended directory, allowing an attacker to navigate outside of it using sequences like '../../' to access unauthorized files, is a directory traversal (or path traversal) vulnerability.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":569,"question":"A company's internal HR application allows any logged-in employee to view any other employee's salary information simply by changing a numeric employee ID in the web address, with no check to confirm the requester should have access to that particular record. What type of vulnerability does this represent?","options":["Broken access control, specifically an insecure direct object reference","A buffer overflow in the application's memory handling","A weak encryption cipher used to protect the salary data at rest","A supply chain vulnerability in a third-party library"],"correctIndex":0,"explanation":"allowing a user to access another user's data simply by manipulating an identifier in the URL, with no server-side check confirming the requester is authorized to view that specific record, is a broken access control flaw known as an insecure direct object reference.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":570,"question":"A mobile banking application stores a user's full account number and PIN in an unencrypted plain-text file on the device's local storage, where any other application with file system access could potentially read it. What type of vulnerability does this represent?","options":["Improper data protection through lack of encryption for sensitive stored data","A cross-site scripting vulnerability specific to web browsers","A race condition vulnerability in multi-threaded processing","A default configuration vulnerability involving factory credentials"],"correctIndex":0,"explanation":"storing highly sensitive information like an account number and PIN in unencrypted plain text, where other applications could potentially access it, is an improper data protection vulnerability, since encryption of sensitive data at rest is a fundamental control that was not applied.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":571,"question":"A company's firewall rule set includes an old, overly permissive rule from years ago that allows unrestricted inbound traffic on a range of ports, and no one has reviewed or removed it since the original project that required it ended. What type of vulnerability does this represent?","options":["A misconfiguration vulnerability resulting from outdated, overly permissive rules that were never cleaned up","A zero-day vulnerability in the firewall's underlying software","A cross-site scripting vulnerability in the firewall's management interface","A supply chain vulnerability involving the firewall vendor"],"correctIndex":0,"explanation":"an overly permissive firewall rule that was never reviewed or removed after its original purpose ended is a misconfiguration vulnerability, since the security control exists and functions as designed, but its configuration leaves an unnecessary and unmanaged exposure.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":572,"question":"A software development team hardcodes a database connection password directly into the application's source code, which is later pushed to a public code repository, exposing the credential to anyone who views the repository. What type of vulnerability does this represent?","options":["Improper credential management, specifically hardcoded and publicly exposed secrets","A buffer overflow in the application's runtime memory","A cross-site request forgery vulnerability in the web interface","A legacy platform vulnerability tied to an unsupported operating system"],"correctIndex":0,"explanation":"hardcoding sensitive credentials directly into source code, especially code that ends up in a publicly accessible repository, is an improper credential management vulnerability, exposing secrets that should have been stored securely outside the codebase, such as in a secrets manager.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":573,"question":"A company's e-commerce checkout process does not verify that a request to change an order's total price actually originated from the legitimate checkout page, allowing an attacker to craft and submit a forged request from a malicious website that changes the price while the victim is still logged in. What type of vulnerability does this represent?","options":["Cross-site request forgery (CSRF)","SQL injection targeting the order database","A buffer overflow in the checkout process","A weak cipher suite used during the checkout transaction"],"correctIndex":0,"explanation":"tricking a logged-in user's browser into submitting an unauthorized request to a legitimate site, because that site fails to verify the request's true origin, is the defining characteristic of cross-site request forgery, distinct from SQL injection or memory-based vulnerabilities.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":574,"question":"A vendor releases a critical security patch for a widely used software product, but a company's IT team does not apply it for six months due to a backlog of change requests, leaving the known, publicly disclosed flaw exploitable the entire time. What does this scenario illustrate?","options":["An unpatched (known) vulnerability, where a fix already exists but has not yet been applied, unlike a zero-day where no fix exists at all","A zero-day vulnerability, since the flaw was not publicly known","A misconfiguration vulnerability unrelated to patch management","A legacy platform vulnerability requiring hardware replacement"],"correctIndex":0,"explanation":"a flaw for which a vendor patch already exists, but has simply not yet been applied by the organization, is an unpatched known vulnerability, which is meaningfully different from a zero-day, where no fix exists yet at all; timely patch management is the direct remediation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":575,"question":"A company's mobile application communicates with its backend server but fails to properly validate the server's SSL/TLS certificate, allowing an attacker performing a man-in-the-middle attack to present a fraudulent certificate that the app accepts without warning. What type of vulnerability does this represent?","options":["Improper certificate validation, allowing encrypted communications to be intercepted despite the presence of TLS","A SQL injection vulnerability in the backend database","A buffer overflow vulnerability in the mobile app's memory handling","An open permissions vulnerability in cloud storage configuration"],"correctIndex":0,"explanation":"failing to properly validate a server's TLS certificate, allowing a fraudulent certificate presented during a man-in-the-middle attack to be silently accepted, is an improper certificate validation vulnerability, which undermines the security that TLS encryption is supposed to provide even though encryption is technically in use.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":576,"question":"A cloud storage bucket used by a healthcare provider to hold patient records is left configured with 'public' access permissions by mistake during initial setup, and this misconfiguration goes unnoticed for months until a researcher discovers it. What type of vulnerability does this scenario MOST directly represent?","options":["Open permissions, a misconfiguration vulnerability that exposes sensitive data without requiring any attacker exploitation technique","A zero-day vulnerability in the cloud provider's underlying infrastructure","A cross-site scripting vulnerability in the healthcare provider's patient portal","A weak cipher suite vulnerability affecting data in transit"],"correctIndex":0,"explanation":"configuring a storage location with overly permissive, publicly accessible permissions is an open permissions misconfiguration, and it is especially dangerous because it exposes data passively, requiring no active exploitation technique from an attacker beyond simply finding and accessing the resource.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":577,"question":"A company's identity and access management system does not enforce a maximum limit on failed login attempts, allowing an attacker to repeatedly guess passwords indefinitely without being locked out or triggering an alert. What type of vulnerability does this represent?","options":["Improper authentication controls, specifically a missing account lockout/rate-limiting mechanism that enables brute-force attacks","A buffer overflow vulnerability in the login form's input handling","A cross-site scripting vulnerability in the login page's rendering","A supply chain vulnerability involving the identity provider's software"],"correctIndex":0,"explanation":"failing to limit or slow down repeated failed login attempts is an improper authentication control, specifically the absence of account lockout or rate-limiting, which directly enables brute-force password guessing attacks to continue indefinitely without detection or prevention.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.3","objective":"Vulnerability Types","source":"original-2026-batch"},{"id":578,"question":"After a breach investigation reveals that an attacker moved freely between a company's finance servers and its manufacturing floor equipment because both sat on the same flat network, the security team proposes splitting the network into isolated zones with strict traffic rules between them. What mitigation technique is being proposed?","options":["Network segmentation","Patch management","Multi-factor authentication","Data encryption at rest"],"correctIndex":0,"explanation":"dividing a flat network into isolated zones with controlled traffic between them, so that a compromise in one area cannot freely spread to another, is network segmentation, a mitigation technique that directly limits an attacker's ability to move laterally.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":579,"question":"A company implements a policy requiring that critical security patches be tested in a staging environment and deployed to production systems within 72 hours of release, rather than the previous ad hoc, months-long delay. What mitigation technique does this policy represent?","options":["Patch management, reducing the window of exposure for known vulnerabilities","Encryption of data in transit","Least privilege access control","Application allow listing"],"correctIndex":0,"explanation":"establishing a formal, timely process for testing and deploying security patches directly reduces the window during which known vulnerabilities remain unaddressed and exploitable, which is the core purpose of patch management as a mitigation technique.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":580,"question":"A company configures its endpoint devices so that only pre-approved, digitally signed applications are permitted to execute, and any unrecognized program is automatically blocked from running, even if a user attempts to install it. What mitigation technique does this represent?","options":["Application allow listing (whitelisting)","Network segmentation","Multi-factor authentication","Data loss prevention"],"correctIndex":0,"explanation":"permitting only a pre-approved, signed set of applications to run, while automatically blocking anything not on that list, is application allow listing, a mitigation technique that prevents unauthorized or malicious software from executing even if it reaches the endpoint.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":581,"question":"An organization requires employees to provide both a password and a one-time code generated by an authenticator app before accessing sensitive financial systems, so that a stolen password alone is not enough for an attacker to gain access. What mitigation technique does this represent?","options":["Multi-factor authentication (MFA)","Encryption of data at rest","Application allow listing","Network segmentation"],"correctIndex":0,"explanation":"requiring a second independent factor, such as a time-based one-time code, in addition to a password directly mitigates the risk of credential theft alone being sufficient for unauthorized access, which is the purpose of multi-factor authentication.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":582,"question":"A database administrator configures the database so that a compromised web application account can only read customer names and email addresses, but cannot access, modify, or delete billing records, even though the underlying database technically supports those operations. What mitigation principle does this configuration reflect?","options":["The principle of least privilege, limiting an account's access to only what is strictly necessary for its function","Data masking, which hides sensitive fields from all users","Full disk encryption, protecting data if the physical drive is stolen","Application allow listing, restricting which programs can run"],"correctIndex":0,"explanation":"restricting an account's permissions to only the specific data and operations it actually needs, rather than granting broad access simply because the underlying system supports it, reflects the principle of least privilege, which limits the potential damage if that account is ever compromised.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":583,"question":"A company deploys a system that continuously monitors outbound network traffic for patterns matching known data exfiltration techniques and automatically blocks any transfer that includes strings matching credit card number formats leaving the network. What mitigation technique does this represent?","options":["Data loss prevention (DLP)","Network segmentation","Multi-factor authentication","Patch management"],"correctIndex":0,"explanation":"monitoring and automatically blocking outbound data that matches sensitive patterns, such as credit card number formats, before it leaves the network is the core function of data loss prevention, a mitigation technique specifically aimed at preventing unauthorized data exfiltration.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":584,"question":"After a ransomware incident encrypted a company's primary file server, the organization was able to fully recover within hours because it maintained daily backups stored on a separate, isolated system that the ransomware could not reach. What mitigation strategy allowed this quick recovery?","options":["Regular, isolated (offline or air-gapped) backups, ensuring a clean recovery point unaffected by the compromised production environment","Multi-factor authentication on the file server","Application allow listing on end-user workstations","Network segmentation between the finance and HR departments"],"correctIndex":0,"explanation":"maintaining regular backups that are isolated from the production environment, so that a compromise like ransomware cannot also encrypt or delete the backups themselves, is what enabled the organization to recover quickly to a known-good, unaffected state.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":585,"question":"A security team configures automated encryption of all laptop hard drives across the organization, so that if a device is lost or stolen, the data on it remains unreadable to anyone without the correct decryption key. What mitigation technique does this represent?","options":["Full disk encryption, protecting data at rest on physical devices","Network segmentation, isolating laptops from sensitive servers","Data loss prevention, monitoring outbound data transfers","Patch management, addressing known software vulnerabilities"],"correctIndex":0,"explanation":"encrypting the entire contents of a device's storage so that data remains unreadable without the proper key, even if the physical device itself is lost or stolen, is full disk encryption, a mitigation technique focused on protecting data at rest.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":586,"question":"A company deploys a system in its network's demilitarized zone that intentionally mimics a vulnerable production server, complete with fake data, specifically to attract and study attacker behavior without risking any real assets. What mitigation and detection technique does this represent?","options":["A honeypot, used to lure and study attackers while diverting them from genuine production systems","A firewall rule blocking all inbound traffic","Full disk encryption applied to production servers","A patch management schedule for the demilitarized zone"],"correctIndex":0,"explanation":"deploying a decoy system designed to look like a real, vulnerable target in order to attract and study attacker behavior, while keeping actual production assets safe, is a honeypot, which serves both as a diversion and as a source of threat intelligence.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":587,"question":"An organization implements a policy requiring that any employee's access to sensitive systems be automatically reviewed and revoked if unused for more than 90 days, ensuring that dormant accounts do not remain as unnecessary attack surface. What mitigation concept does this policy reflect?","options":["Access control review and account deprovisioning based on the principle of least privilege over time","Data loss prevention focused on outbound file transfers","Application allow listing for approved software","Multi-factor authentication enforcement"],"correctIndex":0,"explanation":"periodically reviewing and revoking access that has gone unused for an extended period directly reduces the attack surface created by dormant, forgotten accounts, reflecting an ongoing application of least privilege through access control review and deprovisioning.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":588,"question":"A company configures its firewall so that servers in the internal network segment cannot initiate outbound connections to the internet at all, only responding to requests that originate from inside, specifically to prevent malware on a compromised server from 'calling home' to an attacker's command and control infrastructure. What mitigation technique does this represent?","options":["Egress filtering, restricting outbound traffic to prevent command-and-control communication","Ingress filtering, restricting inbound traffic from the internet","Multi-factor authentication for server administrators","Full disk encryption on the internal servers"],"correctIndex":0,"explanation":"restricting outbound connections from internal servers specifically to prevent compromised systems from communicating with external attacker infrastructure is egress filtering, a mitigation technique focused on controlling traffic leaving the network rather than entering it.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":589,"question":"A security awareness program requires all employees to complete quarterly training modules covering current phishing tactics, and the company tracks completion rates while following up with employees who fail simulated phishing tests. What mitigation category does this ongoing training and testing program represent?","options":["User training and awareness, addressing the human element of security risk","Technical network segmentation","Encryption of data at rest","Patch management for endpoint software"],"correctIndex":0,"explanation":"ongoing training combined with simulated phishing tests to reinforce awareness and measure improvement addresses the human element of security risk directly, making it a user training and awareness mitigation rather than a purely technical control.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":590,"question":"A company configures its web application firewall to specifically detect and block common SQL injection patterns before they ever reach the underlying web application or database. What mitigation technique does this represent?","options":["Input validation/filtering enforced at the network perimeter via a web application firewall","Full disk encryption of the database server","Multi-factor authentication for database administrators","Physical security controls for the data center"],"correctIndex":0,"explanation":"detecting and blocking malicious input patterns, such as those associated with SQL injection, before they reach the application is a form of input validation and filtering, in this case enforced at the perimeter by a web application firewall rather than solely within the application's own code.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":591,"question":"After several employees fell for a phishing campaign that harvested their passwords, the security team implements a policy requiring hardware security keys for all logins to sensitive systems, since a stolen password alone can no longer be used to authenticate. What mitigation technique specifically addresses the root cause of this incident?","options":["Multi-factor authentication using a hardware security key as a possession-based factor","Network segmentation between departments","Data loss prevention for outbound email","Patch management for the email server"],"correctIndex":0,"explanation":"requiring a physical hardware security key in addition to a password directly addresses the root cause of the incident, since a phished password alone becomes useless to an attacker without also possessing the physical key, which is a possession-based multi-factor authentication mitigation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":592,"question":"A company's incident response plan includes a documented procedure to immediately isolate any endpoint suspected of malware infection from the rest of the network, cutting off its ability to communicate while investigation proceeds. What mitigation and response technique does this represent?","options":["Isolation/containment, limiting the spread of a threat while investigation and remediation occur","Least privilege access control, limiting a user's permissions","Full disk encryption, protecting data on the isolated endpoint","Application allow listing, restricting which programs can execute"],"correctIndex":0,"explanation":"immediately cutting off network communication for a suspected compromised endpoint, so the potential threat cannot spread further while it is investigated, is an isolation or containment technique, a key mitigation step during active incident response.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":593,"question":"An organization requires that all newly provisioned cloud servers be automatically configured according to a predefined, security-reviewed template that disables unnecessary services, closes unused ports, and enforces strong password policies from the moment the server is created. What mitigation technique does this represent?","options":["System hardening through secure baseline configuration templates","Data loss prevention applied to cloud storage buckets","Multi-factor authentication for cloud administrator accounts","Network segmentation between cloud and on-premises environments"],"correctIndex":0,"explanation":"automatically applying a predefined, security-reviewed configuration that disables unnecessary services, closes unused ports, and enforces strong policies from the moment a system is created is system hardening via a secure baseline, reducing the attack surface of every new system by default.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":594,"question":"A company implements a policy requiring that any software installation request from an employee first be evaluated against a list of approved vendors and undergo a basic security review before being granted, rather than allowing unrestricted installation of any software an employee finds online. What mitigation technique does this process support?","options":["Application allow listing/vetting, reducing the risk of unauthorized or malicious software entering the environment","Full disk encryption for all company laptops","Network segmentation between departments","Multi-factor authentication for cloud services"],"correctIndex":0,"explanation":"requiring software to be vetted against an approved list and undergo review before installation directly reduces the risk of unauthorized, unvetted, or malicious software entering the environment, which is the underlying purpose of application allow listing and vetting processes.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":595,"question":"A company deploys redundant power supplies, redundant internet connections from two different providers, and a clustered database configuration so that the failure of any single component does not bring down the entire service. What mitigation concept does this architecture reflect?","options":["Redundancy and elimination of single points of failure to support system resilience and availability","Data loss prevention for sensitive customer records","Multi-factor authentication for administrative access","Application allow listing for approved software"],"correctIndex":0,"explanation":"deploying redundant components, such as power supplies, internet connections, and clustered databases, so that no single failure can take down the entire service, reflects the mitigation concept of eliminating single points of failure to improve overall system resilience and availability.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":596,"question":"A financial company requires that any employee wishing to initiate a wire transfer above a certain dollar threshold obtain a second employee's independent review and approval before the transfer is processed. What mitigation concept does this dual-approval requirement represent?","options":["Separation of duties, ensuring no single individual can unilaterally complete a high-risk transaction","Least privilege, limiting what data a single employee can view","Encryption of the transaction data in transit","Patch management for the wire transfer system"],"correctIndex":0,"explanation":"requiring two independent individuals to be involved before a high-risk action, like a large wire transfer, can be completed is separation of duties, a mitigation technique designed to prevent any single person from being able to unilaterally commit fraud or make a costly error.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":597,"question":"A company's security team runs monthly automated scans against all internet-facing systems specifically to identify missing patches, weak configurations, and other known weaknesses before an attacker can find and exploit them. What mitigation process does this represent?","options":["Vulnerability scanning, proactively identifying weaknesses so they can be remediated before exploitation","Data loss prevention, monitoring outbound data transfers","Multi-factor authentication, verifying user identity at login","Full disk encryption, protecting data stored on the scanned systems"],"correctIndex":0,"explanation":"regularly and proactively scanning systems to identify missing patches, weak configurations, and other known weaknesses before attackers can exploit them is vulnerability scanning, a mitigation process focused on identifying and enabling remediation of risk ahead of exploitation.","domain":"2.0 Threats, Vulnerabilities & Mitigations","objectiveId":"2.5","objective":"Mitigation Techniques","source":"original-2026-batch"},{"id":598,"question":"A company migrates its customer-facing application from an on-premises data center to a cloud provider, where the provider is responsible for the underlying hardware and hypervisor, but the company remains responsible for configuring firewall rules, managing user access, and securing the application code itself. What architecture concept does this division of duties represent?","options":["The shared responsibility model, dividing security obligations between the cloud provider and the customer","On-premises architecture, since the customer retains all security responsibilities","Zero trust architecture, since every access request is verified","Air-gapped architecture, since the systems are physically isolated"],"correctIndex":0,"explanation":"a cloud arrangement where the provider secures the underlying infrastructure while the customer remains responsible for configuration, access management, and application-level security reflects the shared responsibility model, which defines who owns which security obligations in a cloud environment.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":599,"question":"A hospital designs its network architecture so that every access request to a patient records system, whether from inside the hospital's building or from a remote clinic, must be explicitly authenticated and authorized before access is granted, with no location automatically treated as trusted. What architecture model does this represent?","options":["Zero trust architecture, where trust is never assumed based on network location alone","A traditional perimeter-based architecture, trusting all internal traffic by default","An air-gapped architecture, physically isolating the patient records system","A serverless architecture, eliminating the need for authentication entirely"],"correctIndex":0,"explanation":"requiring explicit authentication and authorization for every access request regardless of whether it originates inside or outside the traditional network perimeter, with no implicit trust granted by location, is the defining principle of zero trust architecture.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":600,"question":"A manufacturing plant keeps its industrial control systems on a completely isolated network with no physical or logical connection whatsoever to the internet or the corporate IT network, specifically to prevent any remote attacker from reaching the critical equipment. What architecture concept does this isolation represent?","options":["An air-gapped network architecture, physically isolating critical systems from external connectivity","A hybrid cloud architecture, splitting workloads between providers","A software-defined networking architecture, virtualizing network functions","A zero trust architecture, requiring continuous authentication"],"correctIndex":0,"explanation":"maintaining a network with no physical or logical connection to the internet or other external networks at all, specifically to prevent remote access by any attacker, is an air-gapped architecture, the most extreme form of network isolation.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":601,"question":"A company decides to run some of its workloads on its own physical servers in a private data center while simultaneously running other workloads on a public cloud provider, integrating both environments through a shared identity and networking layer. What architecture model does this combination represent?","options":["A hybrid cloud architecture, combining on-premises and public cloud resources","A purely on-premises architecture with no cloud involvement","An air-gapped architecture, isolating all systems from each other","A serverless architecture, eliminating the need for any infrastructure management"],"correctIndex":0,"explanation":"combining privately owned, on-premises infrastructure with public cloud resources, integrated together through shared identity and networking, is a hybrid cloud architecture, which allows an organization to balance control, cost, and scalability across both environments.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":602,"question":"A development team builds a new application using small, independent, loosely coupled services, each responsible for a single business function and communicating with each other over well-defined APIs, rather than building one large, tightly integrated application. What architecture concept does this design represent?","options":["Microservices architecture, decomposing an application into small, independently deployable services","Monolithic architecture, building a single large integrated application","Air-gapped architecture, physically isolating each service","Zero trust architecture, focused solely on authentication of users"],"correctIndex":0,"explanation":"decomposing an application into small, independently deployable services, each handling a single business function and communicating through defined APIs, is a microservices architecture, which is a design approach distinct from network isolation or authentication-focused models like zero trust.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":603,"question":"A retail company designs its network so that point-of-sale systems, guest Wi-Fi, and corporate HR systems each sit in entirely separate network zones with a firewall enforcing strict rules about what traffic is allowed to pass between them, ensuring a compromise in one zone cannot easily spread to another. What architecture concept is this design applying?","options":["Network segmentation as part of a defense-in-depth architecture, limiting the blast radius of a compromise","A serverless architecture, eliminating the need for network zones entirely","A single flat network architecture, treating all systems as equally trusted","An air-gapped architecture with zero connectivity between any systems"],"correctIndex":0,"explanation":"designing a network with distinct zones for different functions, each separated by firewall rules that limit what traffic can pass between them, applies network segmentation as part of a broader defense-in-depth architecture, containing the impact of a compromise to a single zone rather than the whole network.","domain":"3.0 Security Architecture","objectiveId":"3.1","objective":"Architecture Models","source":"original-2026-batch"},{"id":604,"question":"A company places its public-facing web server in a dedicated network segment that sits between the internet and the internal corporate network, allowing external users to reach the web server while still blocking direct access from the internet to internal systems like the HR database. What infrastructure security concept does this segment represent?","options":["A demilitarized zone (DMZ), isolating public-facing services from the internal network","A virtual private network (VPN), encrypting traffic between remote users and the office","A honeypot, designed to lure attackers away from real assets","A load balancer, distributing traffic across multiple servers"],"correctIndex":0,"explanation":"placing public-facing servers in a dedicated network segment positioned between the internet and the internal network, allowing controlled external access while blocking direct paths to internal systems, is the defining purpose of a demilitarized zone (DMZ).","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":605,"question":"A remote employee connects to the corporate network from a coffee shop by first establishing an encrypted tunnel to the company's gateway, ensuring that anyone monitoring the coffee shop's Wi-Fi cannot read the employee's traffic. What infrastructure security technology is being used?","options":["A virtual private network (VPN)","A demilitarized zone (DMZ)","A honeynet, deployed to study attacker behavior","A jump server used only for administrative access"],"correctIndex":0,"explanation":"establishing an encrypted tunnel between a remote user and the corporate network, so that traffic remains protected even over an untrusted public network like coffee shop Wi-Fi, is the core function of a virtual private network (VPN).","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":606,"question":"A network administrator configures a device that inspects incoming traffic for known attack signatures and can automatically block malicious packets in real time, rather than only alerting an analyst after the fact. What type of security device does this represent?","options":["An intrusion prevention system (IPS), actively blocking malicious traffic in real time","An intrusion detection system (IDS), which only alerts but does not block traffic","A simple packet-filtering router with no inspection capability","A load balancer distributing traffic across servers"],"correctIndex":0,"explanation":"a device that inspects traffic for known attack signatures and can automatically take action to block malicious packets in real time, rather than simply generating an alert for later review, is an intrusion prevention system (IPS), distinguished from a purely passive intrusion detection system (IDS).","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":607,"question":"A company requires that all administrators connect to a single, tightly monitored and hardened server before being allowed to make any changes to production systems, rather than connecting to production systems directly from their everyday workstations. What infrastructure security concept does this represent?","options":["A jump server (jump box), providing a controlled, monitored access point for administrative connections","A demilitarized zone, isolating public-facing web servers","A load balancer, distributing administrative traffic across multiple servers","A honeypot, designed to attract and study attackers"],"correctIndex":0,"explanation":"requiring administrators to pass through a single, tightly monitored and hardened intermediary server before reaching production systems, rather than connecting directly, is the purpose of a jump server, which centralizes and secures administrative access.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":608,"question":"A company deploys a device at the network perimeter that examines traffic based on source and destination addresses, ports, and protocols, allowing or denying traffic according to a configured rule set, but without deeply inspecting the actual content of each packet. What type of device does this describe?","options":["A traditional stateful firewall, filtering based on addresses, ports, and protocols","A web application firewall, inspecting HTTP request content specifically","An intrusion prevention system, focused on signature-based content inspection","A wireless access point, providing network connectivity to end users"],"correctIndex":0,"explanation":"a perimeter device that filters traffic based on addresses, ports, and protocols according to a rule set, without deeply inspecting packet content, describes a traditional stateful firewall, which is distinct from more content-aware devices like a web application firewall.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":609,"question":"An e-commerce company deploys a specialized device in front of its web servers specifically designed to detect and block malicious HTTP requests, such as those attempting SQL injection or cross-site scripting, while allowing normal web traffic through. What type of device is being used?","options":["A web application firewall (WAF), specifically inspecting and filtering HTTP-layer traffic","A traditional network firewall, filtering solely on IP address and port","A VPN concentrator, terminating encrypted remote access tunnels","A network switch, forwarding traffic within a local network segment"],"correctIndex":0,"explanation":"a device specifically designed to inspect and filter HTTP-layer traffic for web application attacks like SQL injection and cross-site scripting, while permitting normal web traffic, is a web application firewall (WAF), which operates at a higher layer than a traditional network firewall.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":610,"question":"A company's data center distributes incoming web traffic evenly across ten identical web servers, so that no single server becomes overwhelmed and the service remains available even if one server fails. What infrastructure component provides this capability?","options":["A load balancer, distributing traffic across multiple servers for performance and availability","A demilitarized zone, isolating servers from the internet","An intrusion detection system, monitoring for malicious traffic patterns","A jump server, providing controlled administrative access"],"correctIndex":0,"explanation":"distributing incoming traffic evenly across multiple identical servers, improving performance and ensuring the service remains available even if one server fails, is the core function of a load balancer, which is primarily an availability and performance component rather than a detection or access control tool.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":611,"question":"A company's network monitoring team notices unusual traffic patterns and wants a device that can passively analyze copies of network traffic for suspicious activity and generate alerts, without having the ability to block or modify the traffic itself. What type of device fits this description?","options":["An intrusion detection system (IDS), passively monitoring and alerting on suspicious traffic","An intrusion prevention system (IPS), which actively blocks malicious traffic","A load balancer, distributing traffic across servers","A VPN gateway, encrypting traffic between sites"],"correctIndex":0,"explanation":"a device that passively analyzes network traffic and generates alerts on suspicious activity, without the ability to actively block or modify that traffic, is an intrusion detection system (IDS), distinguished from an intrusion prevention system (IPS), which can take direct blocking action.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":612,"question":"An organization implements a network access control (NAC) solution that checks whether a device meets minimum security requirements, such as having up-to-date antivirus software and current patches, before allowing it to connect to the corporate network at all. What security concept does this pre-connection check represent?","options":["Posture assessment/health checking as part of network access control, verifying device compliance before granting network access","A demilitarized zone, isolating non-compliant devices","A honeypot, luring non-compliant devices into a monitored trap","A load balancer, distributing connection requests across servers"],"correctIndex":0,"explanation":"verifying that a device meets minimum security requirements, such as current antivirus and patch levels, before granting it network access is a posture assessment performed by network access control (NAC), ensuring that only compliant devices can connect to protected network resources.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":613,"question":"A company segments its network using virtual local area networks (VLANs) so that devices in the finance department cannot directly communicate with devices in the guest Wi-Fi network, even though both may be physically connected to the same switch hardware. What does this VLAN configuration achieve?","options":["Logical network segmentation, isolating traffic between groups even when they share physical infrastructure","Physical air-gapping, completely severing any connection between the departments","Data loss prevention, inspecting the content of files being transferred","Multi-factor authentication for devices connecting to the switch"],"correctIndex":0,"explanation":"using VLANs to logically separate traffic between groups of devices, even when those devices share the same physical switch, achieves logical network segmentation, isolating traffic without requiring physically separate hardware for each group.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":614,"question":"A company's security architecture requires that traffic between two internal servers exchanging sensitive financial data be encrypted, even though both servers reside on the same internal, presumably trusted network. What principle does this internal encryption requirement reflect?","options":["Defense in depth and a zero trust mindset, not assuming internal network traffic is automatically safe from interception","A belief that internal networks can never be compromised, making encryption purely optional","A requirement that only applies to traffic crossing the internet, never internal traffic","A misunderstanding of network security, since internal encryption provides no real benefit"],"correctIndex":0,"explanation":"encrypting traffic even between two servers on the same internal network reflects a defense-in-depth, zero-trust mindset, since assuming internal traffic is automatically safe from interception ignores the risk of an attacker who has already gained a foothold inside the network.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":615,"question":"A company's infrastructure team configures automated systems to continuously deploy identical, version-controlled server configurations to every new virtual machine, ensuring consistency and eliminating manual, error-prone setup steps across the environment. What infrastructure security concept does this represent?","options":["Infrastructure as code combined with configuration management, ensuring consistent, repeatable, and auditable system builds","A demilitarized zone, isolating newly deployed virtual machines","A honeypot, deployed to distract attackers from real infrastructure","A load balancer, distributing traffic across the new virtual machines"],"correctIndex":0,"explanation":"using automated, version-controlled processes to consistently deploy identical server configurations, rather than manual and error-prone setup, reflects infrastructure as code and configuration management, which improves consistency, reduces misconfiguration risk, and supports auditability across the environment.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":616,"question":"A company places its most sensitive database servers in an isolated network segment that can only be reached through a specific set of application servers, with no direct path from end-user workstations or the internet, even if an attacker compromises a workstation. What infrastructure security concept BEST describes this design?","options":["Network segmentation combined with defense in depth, minimizing the pathways an attacker could use to directly reach sensitive systems","A single flat network design, since all systems ultimately share the same physical infrastructure","A honeypot, since the database servers are intentionally exposed as bait","A load balancer, since traffic is being distributed across application servers"],"correctIndex":0,"explanation":"isolating sensitive database servers so they can only be reached through a specific, controlled path of application servers, with no direct route from end-user workstations or the internet, reflects network segmentation as part of a defense-in-depth strategy, minimizing the number of pathways an attacker could exploit even after compromising another part of the network.","domain":"3.0 Security Architecture","objectiveId":"3.2","objective":"Enterprise Infrastructure Security","source":"original-2026-batch"},{"id":617,"question":"A hospital classifies patient diagnosis records as 'restricted,' internal memos as 'internal use only,' and its publicly posted visiting hours as 'public.' What data protection concept does this three-tier labeling system represent?","options":["Data classification, categorizing information based on sensitivity to determine appropriate handling and protection","Data masking, hiding sensitive fields from unauthorized viewers","Tokenization, replacing sensitive values with non-sensitive substitutes","Data sovereignty, determining which country's laws govern the data"],"correctIndex":0,"explanation":"assigning sensitivity-based labels, such as restricted, internal use only, and public, to determine how each category of information should be handled and protected is data classification, which forms the foundation for applying appropriate security controls to different types of data.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":618,"question":"A company's customer support application displays only the last four digits of a customer's credit card number to support agents, with the rest of the number replaced by asterisks, even though the full number is stored securely elsewhere in the system. What data protection technique does this represent?","options":["Data masking, obscuring sensitive portions of data from users who do not need to see the full value","Full disk encryption, protecting the entire database at rest","Data sovereignty, determining where the data can legally be stored","Data loss prevention, blocking the data from leaving the network"],"correctIndex":0,"explanation":"displaying only a portion of sensitive data, such as the last four digits of a credit card number, while obscuring the rest from users who do not need full visibility, is data masking, which reduces exposure of sensitive information without necessarily encrypting or blocking it entirely.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":619,"question":"A payment processing company replaces actual credit card numbers stored in its database with randomly generated substitute values that have no mathematical relationship to the original numbers, keeping the mapping between real and substitute values in a separate, highly secured vault. What data protection technique does this represent?","options":["Tokenization, replacing sensitive data with a non-reversible substitute value stored separately from the original","Encryption, mathematically transforming data using a reversible key-based algorithm","Data masking, partially obscuring data for display purposes only","Data classification, labeling data according to its sensitivity level"],"correctIndex":0,"explanation":"replacing sensitive values with randomly generated substitutes that have no mathematical relationship to the originals, and storing the real values separately in a secure vault, is tokenization, which differs from encryption because the substitute token cannot be mathematically reversed back to the original without accessing the separate vault.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":620,"question":"A European company storing customer data for European Union citizens ensures that data remains physically stored on servers located within the European Union, rather than being transferred to data centers in other countries, due to regulatory requirements. What data protection concept does this requirement represent?","options":["Data sovereignty, ensuring data is subject to and remains within the legal jurisdiction that governs it","Data masking, hiding sensitive fields from view","Tokenization, substituting sensitive values with tokens","Data minimization, collecting only the data that is strictly necessary"],"correctIndex":0,"explanation":"ensuring that data remains physically located within a specific legal jurisdiction, in this case the European Union, due to regulatory requirements governing that data, is data sovereignty, which is distinct from techniques like masking or tokenization that alter how the data itself appears.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":621,"question":"A company encrypts customer records while they sit in its database, ensuring that even if an attacker gains unauthorized access to the physical storage or steals a backup file, the data remains unreadable without the correct decryption key. What data protection state does this describe?","options":["Data at rest, referring to data stored on a device or medium rather than actively moving across a network","Data in transit, referring to data actively being transmitted between systems","Data in use, referring to data actively being processed in memory","Data in transit only, since encryption only applies to network traffic"],"correctIndex":0,"explanation":"encrypting data while it is stored on a device or medium, such as within a database or backup file, rather than while it is actively moving across a network, describes protecting data at rest, one of the three states in which data protection controls are commonly applied.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":622,"question":"A company encrypts all traffic between a customer's web browser and its online banking application using TLS, ensuring that anyone intercepting the network traffic between the two endpoints cannot read the transmitted account information. What data protection state does this scenario describe?","options":["Data in transit, referring to data actively moving between two systems over a network","Data at rest, referring to data stored on a hard drive or database","Data in use, referring to data actively being processed by an application in memory","Data sovereignty, referring to which jurisdiction's laws apply to the data"],"correctIndex":0,"explanation":"encrypting data while it is actively being transmitted between two systems over a network, such as between a browser and a banking application, describes protecting data in transit, distinct from protecting data while it is stored (at rest) or actively being processed (in use).","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":623,"question":"A financial services company uses specialized hardware and software techniques to keep sensitive data encrypted even while it is actively being processed by an application in server memory, protecting against certain advanced attacks that attempt to read data directly from RAM. What data protection state does this address?","options":["Data in use, referring to data actively being processed rather than merely stored or transmitted","Data at rest, referring to data stored on a physical disk","Data in transit, referring to data moving across a network connection","Data classification, referring to labeling data by sensitivity"],"correctIndex":0,"explanation":"protecting sensitive data even while it is actively being processed in memory by an application, rather than only while stored on disk or transmitted over a network, addresses the data in use state, which requires specialized techniques beyond standard at-rest or in-transit encryption.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":624,"question":"A company's privacy policy states that it will only collect the specific pieces of customer information strictly necessary to complete a transaction, and will not request or store additional personal details that are not needed for that purpose. What data protection principle does this policy reflect?","options":["Data minimization, collecting only the data necessary for a specific, defined purpose","Data sovereignty, determining which jurisdiction governs the collected data","Tokenization, substituting collected data with non-sensitive tokens","Data masking, partially hiding collected data from view"],"correctIndex":0,"explanation":"deliberately limiting data collection to only what is strictly necessary for a specific, defined purpose, rather than gathering extra information 'just in case,' reflects the data minimization principle, which reduces the overall risk and liability associated with holding unnecessary sensitive data.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":625,"question":"A company designates specific employees as 'data owners' for different categories of information, giving them ultimate accountability for deciding who can access that data and ensuring it is properly classified and protected. What data governance concept does this role represent?","options":["Data ownership, assigning accountability for a specific category of data's classification, access, and protection","Data masking, technically obscuring the data from unauthorized viewers","Tokenization, replacing the data with non-sensitive substitute values","Data sovereignty, determining the legal jurisdiction governing the data"],"correctIndex":0,"explanation":"assigning specific individuals ultimate accountability for a category of data, including decisions about classification, access, and protection, defines the data ownership role within data governance, distinct from technical protection techniques like masking or tokenization.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":626,"question":"A company's records retention policy requires that customer transaction data be automatically and permanently deleted seven years after the transaction date, in accordance with both regulatory requirements and the company's own data minimization goals. What data protection lifecycle concept does this policy represent?","options":["Data retention and disposal, defining how long data is kept and ensuring it is properly destroyed afterward","Data classification, labeling data according to its sensitivity level","Tokenization, replacing sensitive data with substitute values","Data masking, partially hiding sensitive fields from view"],"correctIndex":0,"explanation":"defining a specific timeframe for how long data will be kept, followed by automatic and permanent deletion once that period expires, addresses data retention and disposal, an important part of the data lifecycle that limits how long sensitive information remains exposed to risk.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":627,"question":"A company deploys a system that automatically scans outbound email attachments for patterns matching social security numbers and blocks any email containing such data from being sent to an external recipient without explicit authorization. What does this system protect against?","options":["Unauthorized data exfiltration, by identifying and blocking sensitive data from leaving the organization improperly","Data at rest exposure, by encrypting stored files on the email server","Data sovereignty violations, by controlling which country the email is routed through","Data classification errors, by automatically relabeling misclassified documents"],"correctIndex":0,"explanation":"automatically scanning outbound communications for sensitive data patterns and blocking unauthorized transmission is a data loss prevention control aimed at preventing unauthorized data exfiltration, protecting sensitive information like social security numbers from improperly leaving the organization.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":628,"question":"A healthcare organization designates a specific role responsible for overseeing compliance with data protection regulations, coordinating with legal counsel, and serving as the point of contact for any data breach notifications. What role does this describe?","options":["A data protection officer (or privacy officer), overseeing regulatory compliance and breach response coordination","A data owner, responsible only for day-to-day access decisions on a specific dataset","A system administrator, responsible for the technical configuration of servers","A network engineer, responsible for maintaining network connectivity"],"correctIndex":0,"explanation":"a role specifically responsible for overseeing regulatory compliance related to data protection, coordinating with legal counsel, and serving as the point of contact for breach notifications describes a data protection officer or privacy officer, which is a broader governance role than a technical system administrator or a specific data owner.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":629,"question":"A company backs up its customer database nightly, encrypts each backup file before it is written to storage, and stores the encrypted backups in a facility in a different geographic region from the primary data center. What combination of data protection concepts does this practice reflect?","options":["Protecting data at rest through encryption, combined with geographic redundancy to support resilience against regional disasters","Data masking combined with tokenization of the entire database","Data sovereignty violations, since the backup is stored in a different region","Data minimization, since only some of the database is being backed up"],"correctIndex":0,"explanation":"encrypting backup files to protect data at rest, combined with storing those encrypted backups in a geographically distant location to support recovery in case of a regional disaster, reflects both data-at-rest protection and geographic redundancy, two complementary data protection practices rather than a sovereignty violation.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":630,"question":"A company's legal team determines that certain customer data falls under a specific country's data protection regulation, which grants individuals the right to request a copy of their data or have it permanently deleted upon request. What broader data protection concept do these individual rights fall under?","options":["Data subject rights, granting individuals control over how their personal data is collected, used, and deleted","Data classification, labeling information according to sensitivity","Tokenization, substituting sensitive values with non-sensitive tokens","Data masking, partially obscuring sensitive fields from view"],"correctIndex":0,"explanation":"legal rights granting individuals control over their own personal data, such as the right to request a copy or permanent deletion, fall under the broader concept of data subject rights, which many privacy regulations establish to give individuals agency over how organizations handle their personal information.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":631,"question":"A retailer collects detailed purchase history for its loyalty program members but strips out any information that could directly identify a specific individual before sharing aggregated purchasing trend data with a marketing analytics partner. What data protection technique does this represent?","options":["Data anonymization/de-identification, removing identifying details before sharing data externally","Full disk encryption, protecting the data while stored on the retailer's own servers","Data sovereignty, determining the legal jurisdiction for the shared data","Data classification, labeling the data by sensitivity level only"],"correctIndex":0,"explanation":"removing information that could directly identify specific individuals before sharing aggregated data externally is data anonymization or de-identification, a technique that allows organizations to share useful trend data while reducing privacy risk to the individuals whose original data contributed to it.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":632,"question":"A company implements role-based access controls so that only members of the HR department can view employee salary records, while the broader finance team can only see aggregated payroll totals without access to individual salary figures. What data protection concept does this tiered access reflect?","options":["Access control aligned with data classification and the principle of least privilege, limiting exposure of sensitive data to only those who need it","Data masking applied uniformly to every user regardless of role","Tokenization applied only to the finance team's view of the data","Data sovereignty, since HR and finance are in different legal jurisdictions"],"correctIndex":0,"explanation":"restricting access to sensitive data, such as individual salary records, to only the specific roles that need it, while giving other roles a more limited or aggregated view, reflects access control aligned with data classification and least privilege, ensuring sensitive details are exposed only to those with a genuine need.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":633,"question":"A company discovers during an audit that a decommissioned laptop, previously used to store customer records, was sold at a used equipment auction without its hard drive being wiped or destroyed. What data protection failure does this represent?","options":["A failure of proper data disposal/sanitization procedures for end-of-life hardware","A failure of data classification, since the laptop was never labeled","A failure of data sovereignty, since the laptop crossed a jurisdictional boundary","A failure of tokenization, since the data was not substituted with tokens"],"correctIndex":0,"explanation":"failing to wipe or destroy the storage on a decommissioned device before disposal, allowing sensitive data to potentially be recovered by a new owner, represents a failure of proper data disposal and sanitization procedures, a critical step in the data lifecycle for any hardware that once held sensitive information.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":634,"question":"A software company builds its new customer relationship management platform with encryption for stored data, role-based access controls, and automated data retention rules built into the system architecture from the very first design phase, rather than added afterward. What data protection principle does this approach reflect?","options":["Privacy/security by design, embedding data protection controls into a system's architecture from the outset rather than as an afterthought","Data masking, since encryption obscures the data from view","Tokenization, since access controls substitute values with tokens","Data sovereignty, since retention rules determine jurisdiction"],"correctIndex":0,"explanation":"deliberately embedding data protection controls, such as encryption, access controls, and retention rules, into a system's architecture from the very beginning of the design process, rather than retrofitting them later, reflects the principle of privacy or security by design.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":635,"question":"A multinational corporation maintains separate data processing agreements and technical controls for its European customer data versus its United States customer data, tailoring each to comply with the differing privacy regulations of each region. What data protection challenge is this company managing?","options":["Cross-border data sovereignty and jurisdictional compliance, since different regions impose different legal requirements on the same categories of data","Data masking requirements, which are identical in every jurisdiction worldwide","Tokenization standards, which are universally identical across all countries","Data classification labels, which are legally mandated to be identical everywhere"],"correctIndex":0,"explanation":"maintaining separate agreements and controls tailored to the differing privacy regulations of different regions reflects the challenge of managing cross-border data sovereignty and jurisdictional compliance, since the same category of data can be subject to different legal requirements depending on where the data subject or the data itself is located.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":636,"question":"A company's disaster recovery plan specifies that, in the event of a total data center failure, critical systems must be restored and operational within four hours to avoid unacceptable business impact. What term describes this four-hour target?","options":["Recovery time objective (RTO), the maximum acceptable duration to restore a system after a disruption","Recovery point objective (RPO), the maximum acceptable amount of data loss measured in time","Mean time between failures (MTBF), the average time a system operates before failing","Mean time to repair (MTTR), the average time to fix a failed component"],"correctIndex":0,"explanation":"the maximum acceptable amount of time a system can be down before it must be restored to avoid unacceptable business impact is the recovery time objective (RTO), distinct from the recovery point objective, which instead measures acceptable data loss.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":637,"question":"A company's backup policy states that in the event of data loss, the organization can tolerate losing no more than one hour of data, meaning backups must occur at least hourly. What term describes this one-hour tolerance?","options":["Recovery point objective (RPO), the maximum acceptable amount of data loss measured in time","Recovery time objective (RTO), the maximum acceptable downtime before restoration","Mean time between failures (MTBF), the average operational time before a failure occurs","Single point of failure, a component whose failure would bring down the entire system"],"correctIndex":0,"explanation":"the maximum acceptable amount of data an organization can afford to lose, measured backward in time from the point of failure, is the recovery point objective (RPO), which directly determines how frequently backups must be taken.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":638,"question":"A company maintains a fully staffed, fully equipped secondary data center that mirrors its primary site in real time, allowing operations to fail over almost instantly with virtually no data loss if the primary site goes down, though this approach is significantly more expensive to maintain than other options. What type of recovery site does this describe?","options":["A hot site, providing near-instant failover with fully synchronized systems and data","A cold site, providing only basic infrastructure with no pre-installed systems","A warm site, providing partially configured systems that require some setup time","A honeypot, designed to attract and study attackers rather than support recovery"],"correctIndex":0,"explanation":"a fully staffed, fully equipped secondary site that mirrors the primary site in real time, enabling near-instant failover with minimal data loss, is a hot site, the most expensive but fastest-recovering type of alternate processing site.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":639,"question":"A company maintains a backup facility with basic power, cooling, and network connectivity already in place, but no servers or data pre-installed, meaning equipment must be procured and configured, and data restored from backups, before operations can resume, a process that could take days or weeks. What type of recovery site does this describe?","options":["A cold site, providing only basic infrastructure that requires significant setup before it becomes operational","A hot site, providing fully synchronized systems ready for near-instant failover","A warm site, providing partially configured systems ready within hours","A jump server, used solely for controlled administrative access"],"correctIndex":0,"explanation":"a backup facility with only basic infrastructure like power, cooling, and connectivity, but no pre-installed servers or data, requiring significant time to become operational, is a cold site, the least expensive but slowest-recovering type of alternate processing site.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":640,"question":"A company's recovery site maintains pre-configured servers and periodically updated backups, allowing operations to be restored within about 24 hours if the primary site fails, striking a balance between the extreme cost of a fully mirrored site and the slow recovery of a bare facility. What type of recovery site does this describe?","options":["A warm site, balancing cost and recovery speed with partially configured systems","A hot site, offering near-instant failover with fully synchronized systems","A cold site, offering only basic infrastructure with no pre-installed systems","A demilitarized zone, isolating public-facing services from the internal network"],"correctIndex":0,"explanation":"a recovery site with pre-configured servers and periodically updated backups, enabling a moderate recovery time that balances cost against speed, is a warm site, positioned between the fast but expensive hot site and the slow but inexpensive cold site.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":641,"question":"A company designs its critical database infrastructure with two independent database servers running in an active-active configuration, so that if either server fails, the other continues serving requests without any interruption to users. What resilience concept does this design demonstrate?","options":["Redundancy, eliminating a single point of failure by duplicating a critical component","Data minimization, reducing the amount of data stored on each server","Data masking, obscuring sensitive data from unauthorized users","Tokenization, substituting sensitive database values with tokens"],"correctIndex":0,"explanation":"duplicating a critical component, such as running two independent database servers so that either can continue serving requests if the other fails, is redundancy, a resilience concept aimed at eliminating single points of failure.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":642,"question":"After a fire destroys a company's primary office, the organization discovers it has no documented, tested procedure for how employees should resume critical business functions, leading to weeks of confusion and lost revenue beyond the technical outage itself. What type of plan would have addressed this broader organizational gap?","options":["A business continuity plan (BCP), addressing how the organization as a whole continues critical functions during and after a disruption","A disaster recovery plan (DRP) focused solely on restoring IT systems and infrastructure","An incident response plan focused solely on cybersecurity incidents","A change management plan focused on IT change approvals"],"correctIndex":0,"explanation":"a documented, tested plan addressing how the organization as a whole, including people, facilities, and processes, continues its critical business functions during and after a disruption is a business continuity plan (BCP), which is broader in scope than a disaster recovery plan focused specifically on restoring IT systems.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":643,"question":"A company's IT team maintains a detailed, tested runbook specifically describing how to restore servers, applications, and data from backups in the correct sequence following a major system failure. What type of plan does this runbook represent?","options":["A disaster recovery plan (DRP), focused specifically on restoring IT systems and infrastructure after a disruption","A business continuity plan (BCP), addressing the organization's broader operational continuity","An incident response plan, focused specifically on cybersecurity incident handling","A change management plan, focused on approving IT changes"],"correctIndex":0,"explanation":"a detailed, tested procedure specifically describing how to restore servers, applications, and data in the correct sequence after a major failure is a disaster recovery plan (DRP), which is narrower in scope than a business continuity plan and focuses specifically on IT systems restoration.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":644,"question":"A company follows a backup strategy that maintains three total copies of its data, stored on two different types of media, with one copy kept at an offsite location, specifically to protect against scenarios where a single disaster could destroy both the primary data and a co-located backup. What backup strategy does this represent?","options":["The 3-2-1 backup rule, ensuring redundancy across multiple copies, media types, and locations","A single full backup strategy with no redundancy across locations","A tokenization-based backup strategy, substituting sensitive backup values","A cold-site-only strategy, relying solely on a single recovery facility"],"correctIndex":0,"explanation":"maintaining three copies of data across two different media types with one copy stored offsite is the widely recommended 3-2-1 backup rule, designed specifically to protect against a single disaster destroying both the primary data and any co-located backup copies.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":645,"question":"A company schedules quarterly exercises in which its IT and business continuity teams simulate a major outage on paper, walking through their documented recovery procedures step by step to identify gaps, without actually taking any systems offline. What type of resilience testing does this represent?","options":["A tabletop exercise, discussing and walking through a disaster scenario without actually executing the technical recovery steps","A full-scale live failover test, actually shifting production traffic to the backup site","A vulnerability scan, identifying missing patches and misconfigurations","A penetration test, actively attempting to exploit systems"],"correctIndex":0,"explanation":"discussing and walking through a simulated disaster scenario step by step, using the documented plan, without actually executing any technical recovery actions, is a tabletop exercise, a lower-impact but still valuable way to identify gaps in a recovery plan before a real disaster occurs.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":646,"question":"A company periodically shifts a portion of its live production traffic to its backup data center, verifying that the failover process works correctly under real conditions, rather than relying solely on documentation review. What type of resilience testing does this represent, and why is it valuable compared to a tabletop exercise?","options":["A live failover test, which validates that the technical recovery process actually works under real conditions, uncovering issues a tabletop discussion alone could miss","A tabletop exercise, since no actual systems are involved in either test type","A vulnerability scan, since both approaches identify the same categories of issues","A penetration test, since both approaches simulate the same type of adversarial activity"],"correctIndex":0,"explanation":"actually shifting live production traffic to a backup site to verify the failover process works correctly under real conditions is a live failover test, which is valuable because it can reveal practical issues, such as configuration drift or untested dependencies, that a purely discussion-based tabletop exercise might miss.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":647,"question":"A company identifies that a single aging network switch, if it failed, would take down connectivity for its entire headquarters building, since no backup switch or redundant path exists. What resilience concept does this switch represent, and what should the company do to address it?","options":["A single point of failure, which should be addressed by introducing redundancy such as a backup switch or redundant network path","A properly redundant component that requires no further action","A cold site, which should be upgraded to a hot site immediately","A recovery point objective, which should be shortened to reduce risk"],"correctIndex":0,"explanation":"a single component whose failure would bring down an entire system or facility, with no backup or alternate path available, is a single point of failure, and the appropriate mitigation is to introduce redundancy, such as a backup switch or an alternate network path, to eliminate that risk.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":648,"question":"A company performs a business impact analysis and determines that its order processing system is far more critical to revenue than its internal employee directory application, leading the company to prioritize faster recovery times and more frequent backups for the order processing system. What planning process led to this prioritization?","options":["A business impact analysis (BIA), identifying and prioritizing critical systems based on their impact to the organization if disrupted","A vulnerability assessment, identifying technical weaknesses in each system","A penetration test, identifying exploitable flaws in each system","A change management review, evaluating proposed changes to each system"],"correctIndex":0,"explanation":"systematically evaluating which systems are most critical to the organization based on the impact of their disruption, and using that analysis to prioritize recovery resources and timelines, is a business impact analysis (BIA), which directly informs decisions like setting differentiated RTOs and RPOs for different systems.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":649,"question":"A manufacturing company maintains a documented alternative process for taking customer orders by phone and paper form, specifically for use during extended outages of its primary online ordering system, ensuring the business can continue generating revenue even without the technology in place. What resilience concept does this manual fallback represent?","options":["A continuity of operations strategy, maintaining an alternate manual process to sustain critical business functions during a technology outage","A recovery point objective, defining acceptable data loss during an outage","A cold site, providing basic infrastructure for eventual system restoration","Tokenization, substituting sensitive order data with non-sensitive tokens"],"correctIndex":0,"explanation":"maintaining a documented alternate process, such as taking orders manually by phone and paper, to sustain a critical business function even when the primary technology is unavailable, is a continuity of operations strategy, ensuring the business function itself survives independent of any single technical system.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":650,"question":"After a major regional power outage caused extended downtime, a company's post-incident review recommends installing an uninterruptible power supply (UPS) for critical servers and a backup generator capable of running the data center for 48 hours. What resilience concept do these recommendations address?","options":["Power redundancy and resilience, reducing the risk of downtime caused by the loss of a single utility power source","Data classification, ensuring power-related data is properly labeled","Tokenization, substituting sensitive power consumption data with tokens","Data sovereignty, ensuring backup power complies with jurisdictional law"],"correctIndex":0,"explanation":"installing a UPS and a backup generator specifically to protect against the loss of a single power source addresses power redundancy and resilience, reducing the organization's dependency on any single utility power source to keep critical systems running during an outage.","domain":"3.0 Security Architecture","objectiveId":"3.4","objective":"Resilience & Recovery","source":"original-2026-batch"},{"id":651,"question":"A systems administrator disables unused network services, closes unnecessary listening ports, and removes default sample applications from a newly provisioned web server before placing it into production. What security process does this represent?","options":["System hardening, reducing the attack surface of a system by removing unnecessary functionality","Patch management, applying vendor-released security updates","Network segmentation, isolating the server from other systems","Data loss prevention, monitoring outbound data transfers"],"correctIndex":0,"explanation":"disabling unused services, closing unnecessary ports, and removing default sample applications before deployment is system hardening, a process focused on reducing a system's attack surface by eliminating unnecessary functionality that could otherwise be exploited.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":652,"question":"A company enforces a policy requiring that every server's BIOS/UEFI firmware be updated to the latest vendor version, secure boot be enabled, and unused physical ports be disabled in the firmware settings before deployment. What layer of hardening does this policy address?","options":["Firmware-level hardening, securing the foundational layer beneath the operating system itself","Application-level hardening, securing software running on top of the operating system","Network-level hardening, securing traffic flowing between systems","Data-level hardening, securing information stored within a database"],"correctIndex":0,"explanation":"updating firmware, enabling secure boot, and disabling unused physical ports at the firmware level addresses hardening of the foundational layer beneath the operating system itself, which is important because a compromise at this level can undermine security controls implemented at higher layers.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":653,"question":"A company configures its servers so that only specific, documented administrative accounts can install new software or change system configurations, while standard user accounts are restricted to running approved applications only. What hardening principle does this configuration reflect?","options":["The principle of least privilege, limiting administrative capability to only those accounts that genuinely require it","Network segmentation, isolating administrative accounts on a separate network","Data loss prevention, monitoring what data administrative accounts can access","Full disk encryption, protecting data on servers accessed by these accounts"],"correctIndex":0,"explanation":"restricting the ability to install software or change configurations to only specific, documented administrative accounts, while limiting standard accounts to approved application use, reflects the principle of least privilege as applied to endpoint and server hardening.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":654,"question":"A company's endpoint security policy requires that every workstation have host-based firewall rules enabled, blocking all unsolicited inbound connections from other devices on the local network, even though the corporate network already has a perimeter firewall. What hardening concept does this layered approach represent?","options":["Defense in depth, applying host-level controls in addition to network-level controls","Network segmentation alone, without any host-level controls","Data classification, labeling workstation data by sensitivity","Tokenization, substituting sensitive workstation data with tokens"],"correctIndex":0,"explanation":"applying host-based firewall rules on individual workstations, even though a perimeter firewall already exists at the network edge, reflects defense in depth, layering additional security controls at the host level rather than relying on a single point of protection.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":655,"question":"A company's server hardening checklist requires renaming or disabling the built-in administrator account on every Windows server and creating a separate, uniquely named account with administrative privileges instead. Why is this a recommended hardening practice?","options":["Because the built-in administrator account name is widely known and predictable, making it a common target for automated brute-force login attempts","Because Windows servers cannot function correctly with the built-in administrator account enabled","Because renaming the account automatically encrypts all data on the server","Because this practice eliminates the need for any password policy at all"],"correctIndex":0,"explanation":"the built-in administrator account name is well known and predictable across countless systems, making it a frequent target for automated brute-force login attempts; renaming or disabling it and creating a uniquely named administrative account removes this easily guessed target.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":656,"question":"A company configures its mobile device management (MDM) solution to require that all company-issued smartphones use a minimum six-digit passcode, automatically encrypt local storage, and wipe all data after ten consecutive failed unlock attempts. What hardening category do these MDM policies address?","options":["Mobile endpoint hardening, reducing the risk of data exposure if a device is lost, stolen, or subjected to brute-force unlock attempts","Network segmentation, isolating mobile devices from the corporate Wi-Fi","Data loss prevention, monitoring outbound file transfers from the device","Vulnerability scanning, identifying missing patches on the device"],"correctIndex":0,"explanation":"requiring a minimum passcode length, automatic encryption of local storage, and an automatic wipe after repeated failed unlock attempts are mobile endpoint hardening measures, specifically aimed at reducing the risk of data exposure if a device is lost, stolen, or targeted by a brute-force unlock attempt.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":657,"question":"A company's cloud security team reviews every virtual machine image before it is approved for use, removing unnecessary pre-installed software, applying the latest security patches, and disabling default accounts, then saves the result as an approved 'golden image' for future deployments. What hardening concept does this golden image represent?","options":["A secure baseline configuration, ensuring every new deployment starts from a consistently hardened state","A honeypot, designed to attract and study attackers","A jump server, providing controlled administrative access","A demilitarized zone, isolating the virtual machines from the internet"],"correctIndex":0,"explanation":"creating a reviewed, pre-hardened virtual machine image that removes unnecessary software, applies patches, and disables default accounts, then using it as the standard starting point for future deployments, establishes a secure baseline configuration, ensuring consistency and reducing the chance of an insecure system being deployed.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":658,"question":"A company disables the ability for USB storage devices to be recognized on workstations in its research and development department, specifically to reduce the risk of both malware introduction and unauthorized data exfiltration via removable media. What hardening technique does this represent?","options":["Peripheral/port control, restricting the use of removable media as an attack and exfiltration vector","Network segmentation, isolating the R&D department from the rest of the network","Multi-factor authentication, requiring a second factor for workstation logins","Full disk encryption, protecting data stored on the workstations"],"correctIndex":0,"explanation":"disabling recognition of USB storage devices to reduce both the risk of malware introduction and unauthorized data exfiltration is peripheral or port control, a hardening technique that restricts a specific physical attack and exfiltration vector at the endpoint level.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":659,"question":"A company configures its database servers so that the database service runs under a dedicated, low-privilege service account rather than under a full administrative account, meaning that if the database software is ever compromised, the attacker's access is limited to only what that low-privilege account can do. What hardening principle does this configuration reflect?","options":["Least privilege applied to service accounts, limiting the blast radius of a potential compromise","Data masking, obscuring sensitive database fields from view","Network segmentation, isolating the database server from other systems","Multi-factor authentication, requiring a second factor for database access"],"correctIndex":0,"explanation":"running a service under a dedicated, low-privilege account rather than a full administrative account limits what an attacker could do if that specific service is ever compromised, directly reflecting the least privilege principle applied specifically to service accounts rather than user accounts.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":660,"question":"A company's IT policy requires disabling Bluetooth and Wi-Fi direct file-sharing features on all company laptops by default, only enabling them temporarily and with approval when a legitimate business need arises. What hardening concept does this default-disabled approach reflect?","options":["Reducing the attack surface by disabling unnecessary wireless features that are not needed for normal business operations","Network segmentation, isolating Bluetooth traffic from Wi-Fi traffic","Data loss prevention, scanning Bluetooth transfers for sensitive content","Multi-factor authentication applied specifically to Bluetooth connections"],"correctIndex":0,"explanation":"disabling wireless features like Bluetooth and Wi-Fi direct file sharing by default, only enabling them temporarily when genuinely needed, reduces the attack surface by eliminating functionality that isn't required for normal operations but could otherwise be exploited.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":661,"question":"A company standardizes on a single, well-supported Linux distribution for all of its servers and decommissions several older, mismatched operating systems that were previously scattered across the environment, each requiring separate patching processes and expertise. What security benefit does this standardization primarily provide?","options":["Simplified, consistent patch management and hardening across the environment, reducing the risk of overlooked or inconsistently secured systems","Complete elimination of the need for any future patching","Automatic encryption of all data across the standardized environment","Guaranteed immunity from all future vulnerabilities"],"correctIndex":0,"explanation":"standardizing on a single, well-supported operating system simplifies and makes more consistent the process of patching and hardening across the environment, reducing the risk that a mismatched, less familiar system gets overlooked or inconsistently secured compared to a more heterogeneous environment.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":662,"question":"A company configures group policy to disable the AutoRun/AutoPlay feature on all Windows workstations, preventing removable media from automatically executing programs the moment it is inserted. What type of threat does this hardening step specifically help mitigate?","options":["Malware that spreads via infected removable media that would otherwise execute automatically upon insertion","Phishing emails that trick users into clicking malicious links","Weak passwords that could be brute-forced by an attacker","Unpatched software vulnerabilities in a web browser"],"correctIndex":0,"explanation":"disabling automatic execution of programs from removable media specifically mitigates malware that relies on AutoRun/AutoPlay to spread automatically the moment infected media, such as a USB drive, is inserted into a system, without requiring any further hardening step to address unrelated threats like phishing or browser vulnerabilities.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":663,"question":"A company requires that its network switches disable any physical port that is not actively assigned to a known, authorized device, and require 802.1X authentication before any device can gain network access through an active port. What hardening concept does this represent?","options":["Port security, ensuring only authorized, authenticated devices can gain network access through a physical connection","Data masking, hiding sensitive information from unauthorized users on the network","Data loss prevention, blocking sensitive data from leaving the network","Tokenization, substituting sensitive data with non-sensitive tokens"],"correctIndex":0,"explanation":"disabling unused physical switch ports and requiring authentication before any device can use an active port is port security, a hardening technique that ensures only authorized, authenticated devices can gain network access through a physical connection point.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":664,"question":"A company reviews the list of services running on its servers and discovers that a legacy file transfer protocol (FTP) service, which transmits credentials in plain text, is still enabled on several systems even though it hasn't been used in years. What hardening action should the company take?","options":["Disable and remove the unused, insecure FTP service, replacing any legitimate remaining need with a secure alternative like SFTP","Leave the service running since it hasn't caused any known incidents yet","Increase the FTP service's logging level as the only necessary action","Move the FTP service to a different port to reduce the risk of discovery"],"correctIndex":0,"explanation":"an unused, insecure service that transmits credentials in plain text represents an unnecessary attack surface with no legitimate business justification if it hasn't been used in years, and the appropriate hardening action is to disable and remove it, replacing any genuine remaining need with a secure alternative such as SFTP, rather than merely relying on obscurity or additional logging.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":665,"question":"A company configures endpoint detection and response (EDR) software on every workstation and server to continuously monitor for suspicious process behavior, such as a Word document spawning a command-line shell, and automatically isolate the affected device from the network when such behavior is detected. What security capability does this represent?","options":["Endpoint detection and response, providing continuous behavioral monitoring and automated containment at the host level","Network segmentation, isolating departments from one another","A demilitarized zone, isolating public-facing services","A jump server, providing controlled administrative access"],"correctIndex":0,"explanation":"continuously monitoring individual endpoints for suspicious behavioral patterns, such as unusual process relationships, and automatically isolating an affected device when such behavior is detected is the core function of endpoint detection and response (EDR), a host-level security capability distinct from network-level segmentation or perimeter controls.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":666,"question":"A company's workstation hardening policy requires that local administrator rights be removed from standard end-user accounts, meaning employees can use approved applications but cannot install new software or change system settings without going through IT. What is the PRIMARY security benefit of this policy?","options":["It limits the potential damage from malware or user error, since a compromised standard account cannot make system-wide changes","It completely eliminates the possibility of any malware infection on the workstation","It removes the need for any endpoint antivirus software","It guarantees that IT never needs to install software on any workstation again"],"correctIndex":0,"explanation":"removing local administrator rights from standard user accounts limits the potential damage from malware or accidental user error, since a compromised or misused standard account lacks the elevated privileges needed to make system-wide changes, install unauthorized software, or disable security controls.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":667,"question":"A company reviews its wireless access points and disables the older WPA and WEP encryption protocols, ensuring that only WPA3 is available for client devices to connect, even though this means some very old legacy devices can no longer connect to the corporate wireless network. What hardening tradeoff does this decision reflect?","options":["Prioritizing modern, stronger security protocols over backward compatibility with legacy, less secure devices","Prioritizing legacy compatibility over any consideration of encryption strength","Eliminating the need for any wireless network monitoring going forward","Guaranteeing that no future wireless vulnerabilities can ever be discovered"],"correctIndex":0,"explanation":"disabling older, weaker wireless encryption protocols in favor of exclusively supporting a stronger modern standard, even at the cost of legacy device compatibility, reflects a deliberate hardening tradeoff that prioritizes security strength over backward compatibility with outdated, less secure devices.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":668,"question":"A company configures its servers to log all administrative command execution to a centralized, tamper-evident logging system that administrators themselves cannot modify or delete, ensuring an accurate record exists even if an administrative account is later compromised. What hardening and accountability concept does this represent?","options":["Centralized, protected logging that supports non-repudiation and accountability, even against a compromised privileged account","Network segmentation, isolating logging servers from production systems","Full disk encryption, protecting the confidentiality of log file contents","Data minimization, reducing the total volume of logs collected"],"correctIndex":0,"explanation":"sending administrative command logs to a centralized system that even administrators cannot modify or delete supports non-repudiation and accountability, ensuring a trustworthy record of activity remains available for investigation even if a privileged account is later compromised and used maliciously.","domain":"4.0 Security Operations","objectiveId":"4.1","objective":"Securing Computing Resources & Hardening","source":"original-2026-batch"},{"id":669,"question":"During a security audit, a company discovers a server running in its data center that does not appear in any inventory system, was never assigned an owner, and no one on the current IT team can explain its purpose. What term describes this type of previously unknown, unmanaged system?","options":["Shadow IT (an unmanaged/unauthorized asset), representing a significant blind spot in the organization's security posture","A properly documented production asset that simply needs a label update","A honeypot, intentionally deployed to attract attackers","A cold site, maintained for disaster recovery purposes"],"correctIndex":0,"explanation":"a system running without any record in inventory, no assigned owner, and no documented purpose is a form of shadow IT, an unmanaged or unauthorized asset that represents a significant blind spot, since it likely isn't receiving patches, monitoring, or any of the security controls applied to properly tracked systems.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":670,"question":"A company implements a policy requiring that every new server, laptop, and network device be entered into a centralized asset inventory system, including its owner, location, and criticality rating, before it is allowed to connect to the production network. What foundational security practice does this policy support?","options":["Asset management, maintaining an accurate inventory as the foundation for applying appropriate security controls","Data loss prevention, monitoring outbound data transfers from each device","Data masking, obscuring sensitive information on each device","Tokenization, replacing sensitive identifiers with non-sensitive tokens"],"correctIndex":0,"explanation":"maintaining a centralized, accurate inventory of every asset, including its owner, location, and criticality, before it connects to the production network is asset management, a foundational security practice since an organization cannot properly protect, patch, or monitor assets it does not know it has.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":671,"question":"A company's asset inventory assigns each server a criticality rating of high, medium, or low based on the business impact if that server were compromised or became unavailable. Why is this criticality rating valuable for security operations?","options":["It helps prioritize limited security resources, such as patching urgency and monitoring intensity, toward the assets that matter most to the business","It has no practical security value and exists only for accounting purposes","It automatically encrypts high-criticality servers without any further action","It eliminates the need to patch low-criticality servers at all, indefinitely"],"correctIndex":0,"explanation":"assigning a criticality rating to each asset helps the security team prioritize limited resources, such as how urgently a vulnerability needs to be patched or how closely a system needs to be monitored, toward the assets whose compromise would have the greatest business impact, rather than treating every asset identically.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":672,"question":"When an employee's laptop reaches the end of its useful life and is being retired, the IT department follows a documented procedure to securely wipe all data from the drive, remove the device from the asset inventory system, and update records to reflect its disposal. What phase of the asset lifecycle does this represent?","options":["Decommissioning/disposal, the final phase of the asset lifecycle, ensuring data is properly removed and records are updated","Acquisition, the initial phase when a new asset is purchased and provisioned","Maintenance, the ongoing phase of patching and monitoring an active asset","Classification, the phase of assigning a sensitivity label to an asset"],"correctIndex":0,"explanation":"securely wiping data, removing a device from active inventory, and updating records when a device reaches end of life represents the decommissioning or disposal phase of the asset lifecycle, the final stage that ensures sensitive data does not persist on retired hardware and inventory records remain accurate.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":673,"question":"A company requires that every new employee's laptop be formally assigned to them in the asset management system at the moment it is issued, creating a clear record of who is responsible for that specific device. What security benefit does this assignment of ownership provide?","options":["Clear accountability for the device's proper use, security, and eventual return, simplifying incident investigation if the device is later involved in a security event","No meaningful security benefit, since ownership records are purely administrative","Automatic encryption of the device the moment ownership is assigned","Guaranteed prevention of the device ever being lost or stolen"],"correctIndex":0,"explanation":"formally assigning ownership of a device to a specific individual creates clear accountability for its proper use and security, and simplifies incident investigation, since if that device is later involved in a security event, there is no ambiguity about who was responsible for it.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":674,"question":"A company's asset management process includes a quarterly reconciliation step, where the security team compares the list of devices actively connecting to the corporate network against the official asset inventory, investigating any devices that appear on the network but not in the inventory. What does this reconciliation process help detect?","options":["Unauthorized or unmanaged devices (shadow IT) that have connected to the network without going through proper asset intake procedures","Only cosmetic discrepancies in device naming conventions with no security relevance","Whether employees have changed their desktop wallpaper without authorization","Whether the company's internet service provider is experiencing an outage"],"correctIndex":0,"explanation":"comparing devices actively seen on the network against the official inventory and investigating any mismatches helps detect unauthorized or unmanaged devices, commonly called shadow IT, that connected without going through proper intake and therefore likely lack proper security controls and oversight.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":675,"question":"A company maintains a software asset inventory that tracks every licensed application installed across its environment, including version numbers, in order to quickly identify which systems are running a specific application when a new vulnerability is disclosed for that software. What security value does this software inventory provide?","options":["It enables rapid identification of affected systems during vulnerability response, since the organization already knows exactly where a given application is installed","It has no value beyond license compliance and cost tracking","It automatically patches vulnerable software the moment a new version is released","It eliminates the need for any further vulnerability scanning going forward"],"correctIndex":0,"explanation":"maintaining an accurate software inventory, including version numbers, allows a security team to rapidly identify exactly which systems are running a newly vulnerable application when a security advisory is published, dramatically speeding up vulnerability response compared to having to manually search the entire environment.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":676,"question":"A company classifies its data assets, labeling a customer database as 'high value/high sensitivity' and an internal cafeteria menu document as 'low value/low sensitivity,' then applies correspondingly different levels of access control, encryption, and monitoring to each. What asset management concept does this differentiated treatment reflect?","options":["Asset classification and valuation, aligning the level of protection applied to an asset with its actual business value and sensitivity","Data minimization, reducing the total number of assets the company tracks","Tokenization, substituting sensitive asset identifiers with tokens","Network segmentation, physically isolating assets of different value"],"correctIndex":0,"explanation":"labeling assets according to their business value and sensitivity, then applying correspondingly appropriate levels of protection, is asset classification and valuation, ensuring that security resources like encryption and monitoring are focused where they matter most rather than applied uniformly regardless of actual risk.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":677,"question":"During an incident investigation, a security analyst discovers that a compromised server had no documented owner, no recorded patch history, and no clear record of what business function it supported, significantly slowing down the investigation and remediation process. What does this scenario illustrate about the importance of asset management?","options":["Incomplete asset records directly hinder incident response by making it harder to understand a compromised system's context, ownership, and history","Asset management has no meaningful connection to incident response speed or effectiveness","Incident response teams should always assume every server is equally critical regardless of documentation","Patch history is irrelevant to investigating a security incident"],"correctIndex":0,"explanation":"missing ownership, patch history, and business context for a compromised server directly slows down incident investigation and remediation, illustrating why thorough, accurate asset management records are a practical prerequisite for effective and timely incident response, not merely an administrative formality.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":678,"question":"A company implements automated network discovery scanning that runs weekly, comparing newly detected devices against the existing asset inventory and automatically flagging any unrecognized device for security review. What asset management practice does this automation support?","options":["Continuous asset discovery, helping keep the inventory accurate and catching unauthorized devices closer to when they first appear","Data loss prevention, blocking sensitive data from leaving flagged devices","Tokenization, substituting device identifiers with non-sensitive tokens","Full disk encryption, automatically applied to all newly discovered devices"],"correctIndex":0,"explanation":"running automated scans that compare newly detected network devices against the existing inventory and flag unrecognized ones for review is continuous asset discovery, helping the organization keep its inventory accurate over time and catch unauthorized or shadow IT devices sooner after they first appear.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":679,"question":"A company's mergers and acquisitions team completes the purchase of a smaller company, and as part of the integration process, the security team conducts a full asset inventory of the acquired company's IT environment before connecting its network to the parent company's systems. Why is this pre-integration asset inventory an important security step?","options":["It identifies unknown risks, unpatched systems, or unmanaged assets in the acquired environment before they could introduce risk into the parent company's network","It is purely a financial accounting exercise with no bearing on network security","It guarantees the acquired company's systems are already fully compliant with the parent company's policies","It replaces the need for any further security review of the acquired systems"],"correctIndex":0,"explanation":"conducting a thorough asset inventory of an acquired company's environment before connecting it to the parent company's network identifies unknown risks, unpatched systems, or unmanaged assets that could otherwise introduce security risk into the parent organization, making it an important step in merger and acquisition security due diligence.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":680,"question":"A company tags each cloud virtual machine instance with metadata identifying its owning department, environment (production, staging, or development), and data sensitivity level at the moment it is provisioned. What asset management benefit does this tagging practice provide?","options":["It enables automated policy enforcement and easier identification of an asset's context and required protections, even in a highly dynamic cloud environment","It has no security benefit and exists purely for cloud billing purposes","It automatically prevents any misconfiguration from ever occurring","It eliminates the need for any human review of cloud resources"],"correctIndex":0,"explanation":"tagging cloud resources with metadata about ownership, environment, and sensitivity at the moment of provisioning enables automated policy enforcement, such as applying stricter security controls to production or high-sensitivity resources, and makes it far easier to understand an asset's context in a highly dynamic, rapidly changing cloud environment.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":681,"question":"A company discovers that several employees have been using unapproved, free cloud file-sharing services to collaborate on sensitive project documents, entirely outside of the company's sanctioned, monitored, and encrypted collaboration platform. What term describes this unauthorized use of external technology?","options":["Shadow IT, representing unmanaged and unmonitored use of technology outside official approval and oversight","A properly sanctioned business process requiring no further action","A honeypot, intentionally established to study employee behavior","A cold site, used exclusively for disaster recovery purposes"],"correctIndex":0,"explanation":"employees using unapproved external tools to handle sensitive company data, entirely outside official approval, monitoring, and security controls, is a classic example of shadow IT, which creates risk precisely because the organization has no visibility into how that data is being protected.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":682,"question":"A company's IT asset management policy requires that every asset be assigned an explicit 'end of support' or 'end of life' date at the time of acquisition, tracked centrally, so that replacement planning can begin well before a system becomes unpatchable. What risk does this practice help the organization avoid?","options":["Unknowingly continuing to operate unsupported, unpatchable systems well past the point where they stopped receiving security updates","The risk of ever having to replace hardware under any circumstances","The risk of employees choosing their own hardware vendors","The risk of asset management software becoming outdated"],"correctIndex":0,"explanation":"tracking end-of-support dates centrally and using them to drive proactive replacement planning helps the organization avoid unknowingly continuing to operate systems well past the point where they stopped receiving security patches, which is a common and preventable source of long-term vulnerability exposure.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":683,"question":"A company's asset inventory records not only what hardware and software exist, but also maps the dependencies between systems, such as which application servers rely on which specific database server. Why is this dependency mapping valuable during incident response?","options":["It helps responders quickly understand the potential blast radius of an incident and identify which other systems might be affected or need isolation","It has no practical value beyond satisfying an internal documentation requirement","It automatically resolves any incident without requiring further human investigation","It replaces the need to maintain a basic hardware and software inventory"],"correctIndex":0,"explanation":"mapping dependencies between systems, such as which application servers rely on a particular database, helps incident responders quickly understand the potential blast radius of a compromise and identify which other systems might be affected or should be proactively isolated, speeding up an effective, well-scoped response.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":684,"question":"A company discovers that a decommissioned but not properly disposed-of old firewall, still connected to the network with outdated firmware, was quietly providing an unmonitored path around the current security controls. What foundational asset management failure allowed this risk to persist?","options":["A failure to properly track and complete the decommissioning/disposal phase of the asset lifecycle for retired equipment","A failure of data classification, since the firewall was never labeled by sensitivity","A failure of tokenization, since the firewall's configuration was never tokenized","A failure of data sovereignty, since the firewall was in the wrong jurisdiction"],"correctIndex":0,"explanation":"an old device that was supposed to be decommissioned but remained connected and unmonitored, with outdated firmware, represents a failure to properly complete the decommissioning and disposal phase of the asset lifecycle, allowing an unmanaged, unpatched device to persist as an unmonitored path around current security controls.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":685,"question":"A company's asset management program requires that every asset record include not just technical details, but also a designated business owner responsible for approving access requests and confirming the asset's continued business justification during periodic reviews. What overall security governance benefit does this ownership requirement provide?","options":["It ties technical assets to accountable business stakeholders, supporting informed decisions about access, risk acceptance, and continued necessity over time","It has no governance value and exists purely to satisfy a documentation checklist","It automatically eliminates the need for any technical security controls on the asset","It guarantees the asset can never be compromised regardless of other factors"],"correctIndex":0,"explanation":"requiring every asset to have a designated business owner ties technical assets to accountable stakeholders who can make informed decisions about access requests, risk acceptance, and whether the asset is still genuinely needed, supporting stronger security governance over time rather than leaving assets to drift without oversight.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":686,"question":"A company's security team uses its asset inventory to generate a report showing exactly how many servers are still running an operating system version reaching end of support in 90 days, allowing leadership to budget and plan for upgrades well in advance. What does this scenario demonstrate about the strategic value of accurate asset management?","options":["Accurate, well-maintained asset data enables proactive, informed risk and budget planning rather than reactive scrambling once systems become unsupported","Asset management data is only useful for day-to-day technical troubleshooting, never for strategic planning","This report could have been generated just as easily without any centralized asset inventory","End-of-support planning has no meaningful connection to an organization's asset inventory"],"correctIndex":0,"explanation":"being able to generate an accurate report of exactly how many systems face an upcoming end-of-support deadline demonstrates how well-maintained asset management data enables proactive, informed planning around risk and budget, rather than the organization being caught off guard and forced into reactive, poorly planned remediation.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":687,"question":"A security operations center (SOC) analyst configures a dashboard that aggregates login events from every system across the company, correlates them, and generates a single alert when the same user account logs in from two geographically distant countries within a short time window. What security monitoring capability does this represent?","options":["A security information and event management (SIEM) system correlating logs across sources to detect anomalous patterns like impossible travel","A single antivirus agent scanning one workstation's local files","A firewall blocking traffic based on IP address alone","A backup system replicating files to an offsite location"],"correctIndex":0,"explanation":"aggregating and correlating login events from many different systems into a single view, then generating an alert based on a pattern spanning multiple data sources such as impossible travel, is a core function of a security information and event management (SIEM) system, which centralizes and correlates monitoring data that would be difficult to connect manually.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"original-2026-batch"},{"id":688,"question":"A company's security team configures its monitoring system to generate a high-priority alert whenever a privileged administrative account is used outside of normal business hours, since this pattern has historically indicated either a compromised credential or unauthorized activity. What monitoring concept does this represent?","options":["Behavioral/anomaly-based alerting, flagging activity that deviates from an established normal pattern","Signature-based detection, matching traffic against a known list of malicious file hashes","Full disk encryption, protecting data on the administrative account's workstation","Data loss prevention, blocking sensitive files from leaving the network"],"correctIndex":0,"explanation":"generating alerts based on activity that deviates from an established normal pattern, such as privileged account use outside business hours, is behavioral or anomaly-based alerting, which can catch suspicious activity that wouldn't necessarily match a known malicious signature.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"original-2026-batch"},{"id":689,"question":"A company's security monitoring team notices that its alerting system generates hundreds of low-value notifications every day, many of which analysts have learned to ignore because they are rarely tied to genuine threats, causing a real alert to be missed among the noise. What term describes this situation, and why is it a security risk?","options":["Alert fatigue, where an overwhelming volume of low-value alerts causes analysts to overlook or dismiss genuinely important ones","A properly tuned monitoring system requiring no further adjustment","A sign that the organization needs fewer, not more, security monitoring tools entirely","Evidence that all security alerts are equally important and should be treated identically"],"correctIndex":0,"explanation":"an overwhelming volume of low-value alerts that causes analysts to become desensitized and potentially overlook a genuinely important one describes alert fatigue, a real security risk that highlights the importance of properly tuning alerting thresholds and prioritization rather than simply generating alerts for every possible event.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"original-2026-batch"},{"id":690,"question":"A company deploys sensors throughout its network specifically to monitor traffic patterns and generate an alert if a large, unusual volume of data suddenly begins flowing from an internal server to an external IP address late at night. What security concern is this specific monitoring configuration designed to detect?","options":["Potential data exfiltration, indicated by an unusual, large outbound data transfer at an unusual time","A routine software update being downloaded during business hours","A properly scheduled internal backup process with no external destination","A planned, authorized network maintenance window"],"correctIndex":0,"explanation":"monitoring specifically for a large, unusual volume of outbound data flowing to an external destination at an unusual time is designed to detect potential data exfiltration, since this traffic pattern deviates significantly from normal, expected data flows and timing.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"original-2026-batch"},{"id":691,"question":"A company's security operations center uses automated playbooks so that when a specific type of alert fires, such as detection of a known malware hash on an endpoint, the system automatically isolates that endpoint from the network and opens an investigation ticket, without waiting for a human analyst to manually perform each step. What monitoring and response concept does this represent?","options":["Security orchestration, automation, and response (SOAR), automatically executing a predefined response workflow when a specific alert is triggered","A purely manual incident response process with no automation involved","A vulnerability scan, identifying missing patches on the endpoint","A tabletop exercise, simulating a response scenario without real action"],"correctIndex":0,"explanation":"automatically executing a predefined sequence of response actions, such as isolating an endpoint and opening a ticket, the moment a specific type of alert fires, without waiting for manual intervention at each step, is security orchestration, automation, and response (SOAR), which speeds up response time for well-understood, repeatable alert types.","domain":"4.0 Security Operations","objectiveId":"4.4","objective":"Security Monitoring & Alerting","source":"original-2026-batch"},{"id":692,"question":"A company's security team writes a script that automatically checks every newly provisioned cloud server against a security baseline and immediately remediates any deviation, such as an open port that shouldn't be exposed, without requiring a human to manually review each new server. What is the PRIMARY benefit of this automation compared to manual review?","options":["Consistency and speed, ensuring every new server is checked and corrected the same way immediately, rather than depending on manual review that could be delayed or inconsistent","It completely eliminates the need for any security baseline going forward","It guarantees that no cloud server will ever have a misconfiguration again under any circumstances","It removes all need for human oversight of the cloud environment permanently"],"correctIndex":0,"explanation":"automating a consistency check and remediation process ensures every new server is evaluated the same way immediately upon provisioning, rather than relying on manual review that could be delayed, inconsistent, or skipped due to human workload, which is the primary practical benefit automation provides over a manual process.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":693,"question":"A company integrates its vulnerability scanner with its ticketing system so that whenever a critical vulnerability is discovered on a production server, a ticket is automatically created, assigned to the correct team based on the server's owner, and flagged with an appropriate priority, without requiring a security analyst to manually create it. What automation concept does this represent?","options":["Workflow orchestration, automatically connecting the output of one security tool into the appropriate downstream process","A tabletop exercise, simulating a vulnerability response without real action","A honeypot, designed to attract attackers automatically","A cold site, providing automated disaster recovery infrastructure"],"correctIndex":0,"explanation":"automatically connecting the output of one tool, such as a vulnerability scanner's findings, into the correct downstream process, such as ticket creation and assignment, without manual intervention, is workflow orchestration, which streamlines and speeds up routine security operations tasks.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":694,"question":"A company's security team builds an automated playbook that, when triggered by a phishing report from an employee, automatically extracts the sender's email address and any links, checks them against threat intelligence feeds, and if malicious, automatically blocks the sender and removes similar emails from all other employee inboxes. What benefit does this automated playbook provide over a fully manual process?","options":["Significantly faster response time, containing a phishing threat across the entire organization before it can spread further through manual, individual investigation","No practical benefit, since email investigation always requires a fully manual process","Complete elimination of the need for any human security analyst going forward","Guaranteed prevention of all future phishing attempts against the organization"],"correctIndex":0,"explanation":"automating threat intelligence checks and organization-wide remediation actions in response to a phishing report provides significantly faster containment than a fully manual process, since the automated playbook can act across the entire email environment far more quickly than an analyst manually investigating and remediating one mailbox at a time.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":695,"question":"A DevOps team configures its deployment pipeline so that a security scanning tool automatically checks every code change for known vulnerable dependencies before that code is allowed to be merged into the main branch, blocking the merge automatically if a critical issue is found. What automation concept does this represent?","options":["Automated security gating within a continuous integration/continuous deployment (CI/CD) pipeline, catching vulnerabilities before they reach production","A manual code review process performed entirely by human reviewers","A tabletop exercise simulating a vulnerable dependency scenario","A honeypot deployed within the development environment"],"correctIndex":0,"explanation":"automatically scanning every code change for known vulnerabilities and blocking the merge if a critical issue is found, without requiring a human to remember to run the check, is automated security gating within a CI/CD pipeline, catching vulnerable dependencies before they ever reach production.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":696,"question":"A company automates the process of provisioning new employee accounts, so that when HR marks a new hire as starting, the correct email account, application access, and security group memberships are automatically created based on the employee's department and role, without requiring IT to manually configure each system. What is a security benefit of this automated provisioning, compared to a manual process?","options":["Reduced risk of human error, such as accidentally granting excessive permissions, since access is consistently derived from a predefined role-based template","Complete elimination of the need to ever review employee access again","Guaranteed prevention of any insider threat from ever occurring","No further need for HR and IT departments to communicate about new hires"],"correctIndex":0,"explanation":"automating account provisioning based on a predefined, role-based template reduces the risk of human error, such as a manual process accidentally granting excessive or inconsistent permissions, since access consistently follows the same defined rules for every new hire in a given role.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":697,"question":"A company's security orchestration platform automatically pulls threat intelligence feeds every hour and updates firewall block lists across all locations simultaneously, rather than requiring a network administrator to manually update each firewall individually whenever new threat data becomes available. What automation benefit is MOST directly illustrated by this scenario?","options":["Timeliness and consistency, ensuring protective measures are applied everywhere at the same time rather than depending on manual updates that could lag or be inconsistent across locations","A complete elimination of the need for firewalls at every location","Guaranteed prevention of every future threat, regardless of source","A reduction in the total number of security tools an organization needs"],"correctIndex":0,"explanation":"automatically and simultaneously updating block lists across every location the moment new threat intelligence becomes available ensures timely, consistent protection everywhere, rather than depending on a manual process that could introduce delays or inconsistencies between different locations' firewalls.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":698,"question":"A company automates its patch management process so that non-critical, low-risk patches are automatically tested in a staging environment and deployed to production during a scheduled maintenance window, while high-risk patches are still flagged for manual review before deployment. What does this hybrid approach illustrate about the appropriate use of automation in security operations?","options":["Automation is best applied to well-understood, lower-risk, repeatable tasks, while higher-risk decisions still benefit from human judgment and review","All patches, regardless of risk level, should always be fully automated with no human review under any circumstances","Automation should never be used for any part of patch management due to inherent risk","Manual review is always superior to automation for every category of security task"],"correctIndex":0,"explanation":"applying automation to well-understood, lower-risk, repeatable tasks like routine low-risk patching, while still routing higher-risk decisions to human reviewers, illustrates the general principle that automation is most valuable for consistent, well-defined tasks, while situations involving greater risk or judgment often still benefit from human oversight.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":699,"question":"A company uses infrastructure as code to define its cloud network security groups in version-controlled configuration files, so that any change to a firewall rule must go through a code review and automated deployment pipeline, rather than being made manually and undocumented through a web console. What security benefit does this approach provide?","options":["Improved auditability and consistency, since every change is documented, reviewed, and deployed through a repeatable, trackable process","Complete elimination of the need for any firewall rules whatsoever","Guaranteed prevention of any future network misconfiguration under any circumstances","No further need for a change management process of any kind"],"correctIndex":0,"explanation":"managing firewall rules through version-controlled infrastructure as code, requiring review and automated deployment rather than undocumented manual console changes, improves auditability and consistency, since every change is tracked, reviewed, and applied through a repeatable process rather than being made ad hoc.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":700,"question":"A company's security automation initiative includes a script that runs nightly to identify and automatically disable user accounts that have not logged in for more than 60 days, flagging them for review by the IT team before permanent removal. What security risk does this automated process help reduce?","options":["The risk posed by dormant, unused accounts remaining active and providing unnecessary attack surface or potential targets for compromise","The risk of any employee ever losing access to a needed system","The risk of the company having too many active projects at once","The risk of IT staff having too little work to do"],"correctIndex":0,"explanation":"automatically identifying and disabling accounts that have gone unused for an extended period reduces the risk posed by dormant accounts, which represent unnecessary attack surface since they are rarely monitored closely and could be compromised or misused without being noticed quickly.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":701,"question":"A company evaluates whether to automate a particular incident response action, such as automatically blocking an IP address the moment a single failed login attempt is detected, and decides against it due to the high risk of blocking legitimate users based on a single, potentially harmless event. What consideration does this decision illustrate about automation in security operations?","options":["Automation decisions must weigh the risk of false positives causing unintended business disruption against the benefit of faster response","Automation should always be applied regardless of the potential for false positives","A single failed login attempt should always trigger an automatic permanent block","There is no meaningful downside to over-aggressive security automation"],"correctIndex":0,"explanation":"declining to automate an overly aggressive response, like blocking based on a single failed login, because it could cause unintended disruption to legitimate users, illustrates that automation decisions must carefully weigh the risk of false positives and unintended business impact against the benefit of a faster automated response.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":702,"question":"A company's automated system periodically re-runs vulnerability scans against all production assets and automatically compares the results to the previous scan, generating a report highlighting only newly introduced vulnerabilities rather than requiring an analyst to manually compare two large reports side by side. What automation benefit does this represent?","options":["Reduced manual effort and faster identification of new risk, by having the system handle the tedious comparison work rather than a human analyst","A complete elimination of the need to ever run vulnerability scans again","Guaranteed prevention of any new vulnerability from ever being introduced","No further need for a security analyst to review scan results at all"],"correctIndex":0,"explanation":"automatically comparing successive vulnerability scan results and surfacing only newly introduced findings reduces manual effort and speeds up identification of new risk, letting the automated system handle tedious comparison work so analysts can focus their attention on genuinely new issues rather than re-reviewing everything.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":703,"question":"A company automates the enforcement of multi-factor authentication so that any account attempting to log in without it configured is automatically blocked from accessing sensitive systems until the employee completes MFA enrollment through a self-service portal. What does this automated enforcement help ensure, compared to a policy that simply asks employees to enable MFA voluntarily?","options":["Consistent, guaranteed policy compliance, since the technical control enforces the requirement rather than depending on voluntary employee action","No practical difference at all, since employees would enable MFA voluntarily just as reliably","Complete elimination of the need for any password requirements","Guaranteed prevention of any future account compromise regardless of other factors"],"correctIndex":0,"explanation":"automatically enforcing a technical block on accounts without MFA configured ensures consistent, guaranteed compliance with the policy, since the system itself enforces the requirement rather than depending on voluntary employee action, which historically tends to have much lower and less consistent compliance rates.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":704,"question":"A company's security team builds an automated workflow that correlates alerts from its endpoint detection tool, its network monitoring tool, and its identity provider, automatically enriching a single alert with context from all three sources before it ever reaches a human analyst's queue. What benefit does this cross-tool automation provide?","options":["A more complete, context-rich picture presented to the analyst immediately, reducing the manual investigation time needed to piece together data from separate tools","No practical benefit, since analysts would gather the same information equally quickly by checking each tool manually","Complete elimination of the need for any of the three underlying security tools","Guaranteed detection of every possible type of security incident without exception"],"correctIndex":0,"explanation":"automatically correlating and enriching an alert with context pulled from multiple separate security tools before it reaches an analyst provides a more complete picture immediately, significantly reducing the manual investigation time an analyst would otherwise spend individually checking each separate tool to piece the same context together.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":705,"question":"During an investigation into a suspected data breach, a forensic analyst carefully documents each person who handles a seized hard drive, the time it was collected, and every location it was stored, from the moment of seizure through final analysis. What forensic concept does this documentation represent?","options":["Chain of custody, maintaining a documented, unbroken record of evidence handling to preserve its integrity and admissibility","Data classification, labeling the hard drive according to its sensitivity level","Data masking, obscuring sensitive information found on the hard drive","Tokenization, substituting sensitive data on the drive with tokens"],"correctIndex":0,"explanation":"documenting exactly who handled a piece of evidence, when, and where it was stored throughout an investigation maintains chain of custody, which is essential for preserving the evidence's integrity and ensuring it can be trusted and potentially used in legal proceedings.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":706,"question":"A forensic analyst investigating a compromised server first captures the contents of the system's volatile memory (RAM) before powering it down, since data such as running processes and network connections would be permanently lost otherwise. What forensic principle does this action reflect?","options":["Order of volatility, collecting the most easily lost evidence first before it disappears","Chain of custody, documenting who handled the evidence","Data classification, labeling evidence by sensitivity","Legal hold, preserving evidence for pending litigation"],"correctIndex":0,"explanation":"capturing volatile memory contents before powering down a system, since that data would be permanently lost the moment power is removed, reflects the order of volatility principle, which guides investigators to collect the most fragile, easily lost evidence first.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":707,"question":"An investigator creates a bit-for-bit copy of a suspect hard drive, then calculates a cryptographic hash of both the original and the copy to confirm they are identical before conducting any analysis solely on the copy. What forensic purpose does this hashing step serve?","options":["Verifying the forensic copy is a perfect, unaltered duplicate, and preserving the original evidence untouched for future verification","Encrypting the hard drive to prevent unauthorized access during analysis","Classifying the data found on the drive by sensitivity level","Automatically identifying the specific individual who created each file"],"correctIndex":0,"explanation":"calculating and comparing cryptographic hashes of the original drive and its forensic copy verifies the copy is a perfect, unaltered duplicate, allowing analysis to be performed on the copy while preserving the original evidence untouched, which supports both accuracy and the evidence's integrity.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":708,"question":"An organization receives formal notice of pending litigation and immediately issues instructions to all relevant employees to preserve any potentially relevant emails, documents, and files, suspending normal automatic deletion policies for that data. What term describes this preservation obligation?","options":["A legal hold, requiring preservation of potentially relevant evidence in anticipation of litigation","Chain of custody, documenting who handled the evidence","Data minimization, reducing the total amount of data retained","Tokenization, substituting sensitive data with non-sensitive tokens"],"correctIndex":0,"explanation":"issuing instructions to preserve potentially relevant data and suspend normal deletion policies once litigation becomes reasonably anticipated is a legal hold, a legal obligation distinct from routine data retention policy that specifically applies once relevant evidence must be preserved for potential legal proceedings.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":709,"question":"A security analyst investigating a suspected intrusion reviews a server's authentication logs, finding a record of every login attempt, including the username, source IP address, and timestamp for both successful and failed attempts. What type of data source is being used in this part of the investigation?","options":["Log data (specifically authentication/security event logs), providing a historical record of system activity","Network packet captures, providing the raw contents of network traffic","Volatile memory (RAM) contents, providing a snapshot of running processes","A forensic disk image, providing a bit-for-bit copy of storage media"],"correctIndex":0,"explanation":"reviewing recorded authentication events, including usernames, source IP addresses, and timestamps for login attempts, is analysis of log data, specifically security event logs, which provide a historical record of system activity useful for reconstructing a timeline during an investigation.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":710,"question":"An investigator examining a compromised network uses a tool that captured full copies of network traffic at the time of the incident, allowing them to reconstruct the exact data exchanged between the attacker's system and the victim's server. What type of forensic data source is being analyzed?","options":["Full packet capture (PCAP) data, providing a complete record of network traffic content at a specific point in time","Authentication logs, providing a record of login attempts only","A memory dump, providing a snapshot of RAM contents","A forensic disk image, providing a bit-for-bit copy of a hard drive"],"correctIndex":0,"explanation":"analyzing captured copies of network traffic that allow reconstruction of the exact data exchanged between systems is full packet capture (PCAP) data, a network-based forensic data source distinct from host-based sources like logs, memory dumps, or disk images.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":711,"question":"A forensic investigator reviewing a compromised workstation examines the Windows registry and file system metadata, including file creation, modification, and access timestamps, to determine exactly when a suspicious file was first placed on the system. What forensic concept does this timestamp analysis support?","options":["Timeline reconstruction, establishing the sequence and timing of events during an incident","Chain of custody, documenting who handled the physical workstation","Data classification, labeling the suspicious file by sensitivity","Legal hold, preserving the workstation for pending litigation"],"correctIndex":0,"explanation":"examining file system metadata such as creation, modification, and access timestamps to determine exactly when a suspicious file appeared supports timeline reconstruction, helping investigators establish the sequence and timing of events that occurred during an incident.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":712,"question":"An investigator collecting evidence from a cloud-based email system requests provider-side logs showing exactly when a specific email account's password was changed and from what IP address, since this data is not available directly from the affected employee's local device. What does this scenario illustrate about forensic data sources in cloud environments?","options":["Cloud-hosted services often require provider-side cooperation to obtain forensic data that would not otherwise be visible on local devices alone","Cloud-based forensic investigation is always technically impossible under any circumstances","Provider-side logs are legally inadmissible under all conditions","Only physical hard drive images are ever considered valid forensic evidence"],"correctIndex":0,"explanation":"requesting provider-side logs for a cloud email account, since certain activity like a password change from a specific IP address is only recorded on the provider's systems rather than the local device, illustrates that cloud-hosted services often require cooperation with the provider to obtain forensic data not otherwise visible from local endpoints alone.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":713,"question":"A forensic analyst reviewing a suspected phishing incident examines the full email headers, not just the visible sender name, to trace the actual originating mail server and identify signs of address spoofing. What forensic data source is being analyzed in this step?","options":["Email headers/metadata, revealing routing and origin information not visible in the standard displayed message","File system metadata, revealing file creation and modification timestamps","Network packet captures, revealing the raw contents of network traffic","Volatile memory contents, revealing currently running processes"],"correctIndex":0,"explanation":"examining the full technical headers of an email, rather than just the visible sender name shown to a typical user, to trace the actual originating server and detect spoofing is analysis of email headers and metadata, a data source that reveals routing and origin details hidden from normal view.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":714,"question":"During an investigation, a forensic analyst notices that a suspect's computer clock was found to be set 45 minutes ahead of the actual time when the system was seized, and carefully documents this discrepancy before analyzing any timestamped evidence from that machine. Why is this step important?","options":["Failing to account for clock drift or misconfiguration could lead to an inaccurate timeline reconstruction when correlating events across multiple systems","It has no bearing on the investigation and is purely a technical curiosity","It automatically invalidates all evidence found on the affected computer","It proves conclusively that the suspect deliberately tampered with evidence"],"correctIndex":0,"explanation":"documenting a discrepancy between a system's internal clock and actual time is important because failing to account for such clock drift or misconfiguration could lead to an inaccurate timeline when correlating timestamped evidence from that system against other systems with correctly set clocks.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":715,"question":"An organization's incident response team maintains a centralized log repository where logs from firewalls, servers, and applications are automatically forwarded and retained for one year, specifically so that historical data remains available for investigation even if an individual device's local logs are later deleted or overwritten by an attacker. What forensic benefit does this centralized retention provide?","options":["It preserves evidence that might otherwise be lost if an attacker deletes or overwrites logs on the compromised device itself","It has no forensic value beyond simplifying regular IT troubleshooting tasks","It automatically identifies the specific attacker responsible for any incident","It eliminates the need to ever analyze a compromised device directly"],"correctIndex":0,"explanation":"forwarding and centrally retaining logs separately from their source devices preserves evidence that might otherwise be lost if an attacker deletes or overwrites local logs on the compromised device itself, which is a common technique attackers use to cover their tracks.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":716,"question":"A forensic analyst investigating a mobile device uses specialized forensic software to extract call records, text messages, application data, and location history, generating a comprehensive report while preserving the original device's data untouched. What type of investigation is being performed?","options":["Mobile device forensics, extracting and preserving evidence from a smartphone or tablet","Network forensics, focused on captured network traffic","Memory forensics, focused on volatile RAM contents","Cloud forensics, focused on provider-hosted service logs"],"correctIndex":0,"explanation":"using specialized forensic tools to extract call records, messages, application data, and location history from a smartphone, while preserving the original device untouched, is mobile device forensics, a discipline distinct from network-based or memory-based forensic investigation.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":717,"question":"A company's security team investigating a suspected insider threat reviews badge access logs showing exactly when an employee physically entered and exited the building, correlating this with the times sensitive files were accessed on the network. What does combining these two distinct data sources illustrate about forensic investigation?","options":["Correlating physical security data with digital evidence can build a more complete picture than either data source alone","Physical access logs are never relevant to a digital forensic investigation","Only one data source should ever be used at a time during an investigation","Badge access logs are legally inadmissible in any type of investigation"],"correctIndex":0,"explanation":"correlating physical badge access logs with digital file access records to determine whether the employee was physically present when sensitive files were accessed illustrates how combining multiple, distinct data sources, both physical and digital, can build a more complete and reliable picture during a forensic investigation than relying on either source alone.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":718,"question":"A company's risk register lists a specific risk as having a 'high likelihood' and 'high impact,' and after weighing the cost of mitigation against the potential loss, leadership decides to purchase a cybersecurity insurance policy to help offset potential financial damage rather than eliminating the underlying risk entirely. What risk management strategy does this represent?","options":["Risk transference, shifting some of the financial impact of a risk to a third party such as an insurer","Risk avoidance, eliminating the activity that creates the risk entirely","Risk acceptance, taking no action and absorbing the full potential impact","Risk mitigation, directly reducing the likelihood of the risk occurring"],"correctIndex":0,"explanation":"purchasing insurance to offset the potential financial impact of a risk, rather than directly reducing its likelihood or eliminating the underlying activity, is risk transference, shifting a portion of the financial consequence to a third party such as an insurance provider.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"original-2026-batch"},{"id":719,"question":"After conducting a risk assessment, a company's leadership determines that a particular low-likelihood, low-impact risk does not justify the cost of any additional mitigation controls, and formally documents the decision to take no further action while continuing to monitor the risk. What risk management strategy does this represent?","options":["Risk acceptance, formally acknowledging and choosing to tolerate a risk after weighing its cost against the cost of mitigation","Risk avoidance, eliminating the activity that creates the risk entirely","Risk transference, shifting the risk's impact to a third party","Risk mitigation, implementing new controls to reduce the risk"],"correctIndex":0,"explanation":"formally documenting a decision to take no further mitigating action on a risk, after determining that the cost of additional controls isn't justified relative to the risk's low likelihood and impact, is risk acceptance, a deliberate and documented strategy rather than simply ignoring the risk.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.2","objective":"Risk Management","source":"original-2026-batch"},{"id":720,"question":"Before signing a contract with a new cloud storage provider, a company requires the vendor to complete a detailed security questionnaire covering its encryption practices, incident response procedures, and past breach history. What third-party risk management activity does this represent?","options":["Vendor due diligence/security assessment, evaluating a third party's security posture before establishing a business relationship","Data classification, labeling the vendor's data by sensitivity","Change management, reviewing internal configuration changes","Chain of custody, documenting evidence handling procedures"],"correctIndex":0,"explanation":"requiring a detailed security questionnaire covering a prospective vendor's encryption practices, incident response procedures, and breach history before signing a contract is vendor due diligence, a third-party risk management activity aimed at evaluating a vendor's security posture before establishing a business relationship.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":721,"question":"A company's contract with a payroll processing vendor includes a specific clause requiring the vendor to notify the company within 24 hours of discovering any security incident that could affect the company's employee data. What contractual mechanism does this represent?","options":["A service level agreement (SLA) or contractual security clause, defining specific security obligations and notification timelines","A non-disclosure agreement, focused solely on preventing information sharing","A memorandum of understanding, which is generally non-binding","A business continuity plan, focused on the company's own internal recovery"],"correctIndex":0,"explanation":"including a specific contractual clause that obligates a vendor to notify the company within a defined timeframe after discovering a security incident is a contractual security clause, often part of a service level agreement, which formally defines the vendor's security-related obligations and expectations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":722,"question":"A company that outsources its customer support function to a third-party call center requires that vendor's employees to complete the same security awareness training the company's own employees receive, given that the vendor's staff will have access to sensitive customer data. What third-party risk management principle does this requirement reflect?","options":["Extending appropriate security controls and expectations to third parties who have access to sensitive data, since risk follows the data regardless of who accesses it","A belief that vendors are entirely responsible for their own security with no need for any alignment with the client company","A requirement that applies only to internal employees and never to outsourced staff","A purely cosmetic requirement with no bearing on actual data security"],"correctIndex":0,"explanation":"requiring a third-party vendor's staff to complete comparable security training, since they will have access to sensitive customer data, reflects the principle that appropriate security controls and expectations must extend to any party with access to sensitive data, because risk follows the data regardless of who is handling it.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":723,"question":"A company conducts an annual review of all its active vendor contracts, re-assessing each vendor's security posture, checking for any reported breaches in the past year, and confirming that contractual security requirements are still being met. What ongoing third-party risk management practice does this represent?","options":["Continuous vendor risk monitoring, ensuring a vendor's security posture is periodically reassessed rather than evaluated only once at the start of the relationship","A one-time vendor onboarding process with no further action ever required","A penetration test performed against the vendor's own internal network","A tabletop exercise simulating a vendor-related incident scenario"],"correctIndex":0,"explanation":"conducting periodic reviews of an already-engaged vendor's security posture, rather than assessing security only once during initial onboarding, is continuous vendor risk monitoring, recognizing that a vendor's security posture can change significantly over the life of a business relationship.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":724,"question":"A retail company discovers that a data breach at one of its third-party payment processors exposed customer credit card data, even though the retailer's own systems were never directly compromised. What does this scenario illustrate about third-party risk?","options":["An organization's overall risk exposure includes the security posture of its vendors and partners, not just its own directly controlled systems","Third-party vendors can never introduce any risk to the organizations that use their services","A breach at a vendor has no bearing on the reputation or liability of the company that used that vendor","Only directly controlled internal systems need to be considered when assessing organizational risk"],"correctIndex":0,"explanation":"a breach occurring at a third-party payment processor, exposing customer data the retailer was ultimately responsible for even though the retailer's own systems were untouched, illustrates that an organization's overall risk exposure includes the security posture of its vendors and partners, not solely its own directly controlled infrastructure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":725,"question":"Before granting a new software vendor's support team remote access to its internal systems for troubleshooting purposes, a company requires that access be limited to only the specific systems relevant to the support issue, time-limited, and logged for review. What risk management principle is being applied to this vendor access?","options":["Least privilege and monitored access, applied specifically to third-party vendor connections rather than only internal employee accounts","Unrestricted trust, since the vendor has already signed a contract","Data sovereignty, since the access request originates from another company","Full disk encryption, applied specifically to the vendor's own systems"],"correctIndex":0,"explanation":"limiting a vendor's remote access to only the specific systems needed, for a limited time, with logging in place, extends the least privilege and monitored access principles specifically to third-party vendor connections, recognizing that vendor access represents a risk that should be controlled with the same rigor as internal employee access.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":726,"question":"A company evaluating a potential new software-as-a-service vendor requests a copy of the vendor's most recent independent security audit report (such as a SOC 2 report) rather than relying solely on the vendor's own self-reported claims about its security practices. Why is requesting this independent audit report valuable during vendor risk assessment?","options":["It provides objective, third-party-verified evidence of the vendor's security controls, rather than relying solely on unverified self-reported claims","It has no additional value beyond what the vendor already claims in its marketing materials","It automatically guarantees the vendor will never experience a future security incident","It replaces the need for any ongoing vendor monitoring of the vendor relationship"],"correctIndex":0,"explanation":"requesting an independent audit report, such as a SOC 2 report, provides objective, third-party-verified evidence of a vendor's actual security controls, which is considerably more reliable during risk assessment than relying solely on the vendor's own unverified self-reported claims about its practices.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":727,"question":"A manufacturing company that relies on a single overseas supplier for a critical electronic component begins actively identifying and qualifying a second, geographically separate supplier for the same component, specifically to reduce the business impact if the primary supplier experiences a disruption. What risk management concept does this diversification represent?","options":["Supply chain risk management, reducing dependency on a single third party to improve resilience against disruption","Data loss prevention, focused on protecting sensitive supplier data","Tokenization, substituting sensitive supplier data with tokens","Change management, focused on internal manufacturing process changes"],"correctIndex":0,"explanation":"actively qualifying a second, independent supplier to reduce dependency on a single overseas source for a critical component is supply chain risk management, specifically addressing the risk of relying too heavily on any single third party whose disruption could significantly impact the business.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":728,"question":"A company's vendor management policy requires classifying each vendor into a risk tier, high, medium, or low, based on factors such as the sensitivity of data the vendor can access and the criticality of the service they provide, then applying correspondingly more rigorous due diligence to higher-tier vendors. What does this tiered approach reflect?","options":["Risk-based prioritization, focusing more rigorous due diligence resources on the vendors that pose the greatest potential impact if compromised","A belief that every vendor poses an identical level of risk regardless of the service provided","A policy that applies identical due diligence uniformly to every vendor, high-risk or low-risk alike","A requirement that only applies to vendors located in a specific country"],"correctIndex":0,"explanation":"classifying vendors into risk tiers based on data sensitivity and service criticality, then applying more rigorous due diligence to higher-risk vendors, reflects risk-based prioritization, ensuring limited assessment resources are focused on the vendor relationships that pose the greatest potential impact if something goes wrong.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":729,"question":"A company terminates its relationship with a former cloud service vendor and, as part of the offboarding process, formally requests written confirmation that all of the company's data has been securely deleted from the vendor's systems, rather than simply assuming it happened automatically. What third-party risk management step does this represent?","options":["Vendor offboarding/data disposal verification, ensuring sensitive data does not persist with a vendor after the relationship ends","Vendor onboarding, the process of initially establishing a new vendor relationship","A service level agreement negotiation, focused on ongoing uptime commitments","A business impact analysis, focused on internal system criticality"],"correctIndex":0,"explanation":"formally requesting written confirmation that data has been securely deleted after ending a vendor relationship, rather than assuming it happened automatically, is a vendor offboarding and data disposal verification step, ensuring sensitive company data does not persist indefinitely with a vendor who no longer has a legitimate need for it.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":730,"question":"A hospital system contractually requires all of its third-party billing vendors to sign a business associate agreement (BAA) specifying how patient health information must be protected, in accordance with healthcare privacy regulations. What third-party risk management concept does this required agreement represent?","options":["A regulatory-driven contractual requirement, formally extending specific legal data protection obligations to third parties who handle regulated data","A voluntary, non-binding recommendation with no legal significance","A requirement that applies only to the hospital's own internal staff","A one-time formality with no bearing on the vendor's actual data handling practices"],"correctIndex":0,"explanation":"requiring third-party billing vendors to sign a business associate agreement specifying how regulated patient health information must be protected is a regulatory-driven contractual requirement, formally extending specific legal data protection obligations to any third party that handles that regulated data on the organization's behalf.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":731,"question":"A company discovers that a vendor it uses for cloud backup services has itself outsourced part of its infrastructure to a separate, unreviewed sub-vendor that the company was never informed about. What third-party risk concept does this unreviewed relationship represent?","options":["Fourth-party (subcontractor) risk, where a vendor's own vendors introduce additional, less visible risk into the supply chain","A properly disclosed and fully reviewed vendor relationship requiring no further action","A risk that exists only if the sub-vendor is located in a different country","A risk that is automatically eliminated once a contract with the primary vendor is signed"],"correctIndex":0,"explanation":"discovering that a vendor has outsourced part of its infrastructure to an undisclosed sub-vendor represents fourth-party or subcontractor risk, where a vendor's own vendors introduce additional layers of risk into the supply chain that the original company may have little visibility into or control over.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":732,"question":"A company negotiates a contract with a critical software vendor that includes a specific service level agreement guaranteeing 99.9% uptime, along with financial penalties if that threshold is not met. What risk management purpose does this SLA penalty clause serve?","options":["It creates a financial incentive for the vendor to maintain agreed-upon service reliability, while also providing the company some compensation if the vendor fails to do so","It has no practical effect on vendor behavior since penalty clauses are never enforced","It completely eliminates the possibility of the vendor ever experiencing an outage","It replaces the need for the company to have any internal business continuity plan"],"correctIndex":0,"explanation":"including a financial penalty clause tied to a specific uptime guarantee creates an incentive for the vendor to maintain the agreed-upon reliability standard, while also providing the client company some financial compensation as a risk management measure if the vendor fails to meet that standard.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":733,"question":"A company's procurement process requires legal, security, and privacy teams to jointly review and approve any new vendor contract that involves access to customer data, rather than allowing individual business units to sign vendor agreements independently. What risk management benefit does this cross-functional review process provide?","options":["It ensures multiple relevant perspectives evaluate vendor risk before a binding commitment is made, reducing the chance that a risky vendor relationship goes unreviewed","It slows down every vendor relationship with no corresponding security benefit whatsoever","It eliminates the need for any technical security assessment of the vendor","It applies only to vendors based outside of the company's home country"],"correctIndex":0,"explanation":"requiring legal, security, and privacy teams to jointly review vendor contracts involving customer data access, rather than allowing individual business units to sign agreements independently, ensures multiple relevant perspectives evaluate vendor risk before a binding commitment is made, reducing the chance that a risky relationship is approved without proper scrutiny.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":734,"question":"A company that relies on a critical third-party logistics vendor includes the vendor in its own business continuity and disaster recovery testing exercises, specifically to confirm the vendor has a viable plan to continue operations if the vendor itself experiences a major disruption. What does including the vendor in these exercises help validate?","options":["That the company's own continuity planning realistically accounts for the resilience, or lack thereof, of a critical third party it depends on","That the vendor's financial statements are accurate and complete","That the vendor's marketing claims about its services are legally binding","That the company no longer needs its own internal disaster recovery plan"],"correctIndex":0,"explanation":"including a critical vendor in continuity and disaster recovery testing exercises helps validate that the company's own continuity planning realistically accounts for the resilience of a third party it depends on, since the company's own recovery could be undermined if a critical vendor cannot also recover in a timely manner.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":735,"question":"A company discovers during a vendor risk review that a long-standing supplier's security practices have significantly declined since the original contract was signed years ago, with the supplier no longer meeting the security standards the company now requires. What is an appropriate next step?","options":["Reassess the risk this vendor now poses and either require remediation, renegotiate the contract with updated security requirements, or begin transitioning to a different vendor","Ignore the finding since the original contract terms are considered permanently binding regardless of any changes","Automatically terminate the entire business relationship immediately with no further discussion","Assume the finding is incorrect, since a vendor's security posture can never decline over time"],"correctIndex":0,"explanation":"discovering that a long-standing vendor's security practices have declined below current requirements calls for reassessing the risk and taking an appropriate action, such as requiring remediation, renegotiating contract terms, or beginning a transition to a different vendor, rather than ignoring the finding or assuming it must be incorrect.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":736,"question":"A company evaluating a new artificial intelligence vendor specifically asks how the vendor trains its models, whether the company's own submitted data could be used to train models accessible to other customers, and what data retention practices apply to submitted data. What third-party risk concern is this line of questioning specifically addressing?","options":["The risk of the company's sensitive data being inappropriately retained, exposed to other customers, or used in ways beyond the intended business purpose","A concern that has no relevance to evaluating any type of software vendor","A concern that only applies to vendors offering physical hardware products","A concern that is fully addressed automatically by any vendor's standard terms of service"],"correctIndex":0,"explanation":"specifically asking how a vendor handles data used for model training, retention, and potential exposure to other customers addresses the risk of the company's sensitive data being inappropriately retained, exposed to unrelated third parties, or used beyond its intended business purpose, which is a particularly relevant third-party risk concern for AI and data-processing vendors.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":737,"question":"A hospital's compliance officer ensures that every system storing patient health records meets the specific technical and administrative safeguards required by federal healthcare privacy law, and conducts regular internal audits to verify continued adherence. What compliance concept does this ongoing verification represent?","options":["Regulatory compliance monitoring, ensuring continued adherence to legally mandated requirements over time, not just at a single point in time","A one-time certification requiring no further review after the initial audit","A voluntary industry best practice with no legal requirement behind it","A purely internal policy with no connection to any external legal requirement"],"correctIndex":0,"explanation":"conducting regular internal audits to verify continued adherence to legally mandated healthcare privacy requirements, rather than assuming compliance achieved once remains permanent, is regulatory compliance monitoring, recognizing that compliance must be actively maintained and verified over time.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":738,"question":"A retail company that processes credit card payments undergoes an annual assessment against the Payment Card Industry Data Security Standard (PCI DSS), verifying that it meets specific requirements for protecting cardholder data. What type of compliance framework is PCI DSS?","options":["An industry-mandated security standard, required for organizations that handle payment card data regardless of which country they operate in","A purely voluntary framework with no consequences for non-adherence","A framework that only applies to financial institutions, never retailers","A government law enacted by a single specific country's legislature"],"correctIndex":0,"explanation":"PCI DSS is an industry-mandated security standard, established by the payment card industry itself, that applies to any organization handling payment card data, requiring adherence regardless of the country in which that organization operates, distinguishing it from a government-enacted law.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":739,"question":"A European company processing personal data of EU residents ensures its data handling practices comply with the General Data Protection Regulation (GDPR), including obtaining explicit consent for data collection and honoring requests for data deletion. What type of compliance requirement does GDPR represent?","options":["A government-enacted legal regulation, carrying the force of law within its jurisdiction and applying to data of EU residents regardless of where the processing company is based","A purely voluntary industry best practice with no legal enforcement mechanism","A framework that applies only to companies physically headquartered within the European Union","A standard developed and enforced solely by a private industry consortium"],"correctIndex":0,"explanation":"GDPR is a government-enacted legal regulation carrying the force of law, and it notably applies based on the location of the data subjects (EU residents) rather than solely the location of the company processing that data, making it a legal requirement rather than a voluntary industry framework.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":740,"question":"A company's compliance team maintains a centralized document mapping each specific regulatory requirement it must follow to the internal control or policy that satisfies it, making it easy to demonstrate compliance during an external audit. What does this mapping document represent?","options":["A compliance control matrix (or crosswalk), demonstrating how internal controls satisfy specific external regulatory requirements","A business continuity plan, focused on operational resilience during a disruption","A vendor risk assessment, focused on evaluating third-party security","A network diagram, focused on technical infrastructure layout"],"correctIndex":0,"explanation":"maintaining a document that maps each specific regulatory requirement to the internal control that satisfies it is a compliance control matrix or crosswalk, which makes it far easier to demonstrate to an external auditor exactly how the organization meets each individual regulatory obligation.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":741,"question":"An organization operating in multiple countries discovers that a specific data handling practice, permitted under the laws of one country where it operates, is explicitly prohibited under the laws of another country where it also operates. What compliance challenge does this scenario illustrate?","options":["Multi-jurisdictional compliance complexity, where differing legal requirements across regions can directly conflict and must be carefully reconciled","A situation that has no practical compliance implications since laws are always identical across every country","A problem that can always be solved simply by following the most permissive country's laws everywhere","A scenario that only affects companies operating exclusively within a single country"],"correctIndex":0,"explanation":"discovering that a practice permitted in one country is explicitly prohibited in another illustrates multi-jurisdictional compliance complexity, a real challenge for multinational organizations that must carefully reconcile directly conflicting legal requirements across the different regions where they operate, rather than assuming a uniform global standard.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":742,"question":"A company's internal audit team conducts a self-assessment against a specific compliance framework's requirements before the organization's official external audit, specifically to identify and remediate any gaps in advance. What is the primary benefit of this internal self-assessment?","options":["It allows the organization to identify and fix compliance gaps proactively, before those gaps are discovered by an external auditor and potentially result in findings or penalties","It has no practical benefit, since only the official external audit results actually matter","It completely replaces the need for any external audit going forward","It guarantees a perfect result on every future external audit, regardless of any changes"],"correctIndex":0,"explanation":"conducting an internal self-assessment before an official external audit allows an organization to proactively identify and remediate compliance gaps, reducing the risk of significant findings, penalties, or reputational damage that could result from an external auditor discovering those same gaps first.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":743,"question":"A company's compliance officer determines that a recently passed data privacy law will require significant changes to how the company collects and stores customer information, and works with legal, IT, and business teams to develop an implementation plan well ahead of the law's effective date. What compliance activity does this proactive planning represent?","options":["Regulatory change management, proactively adapting internal practices ahead of new or changing legal requirements","A purely reactive response occurring only after a violation has already been identified","A voluntary best practice with no connection to any actual legal requirement","An activity relevant only to the company's marketing department"],"correctIndex":0,"explanation":"proactively coordinating across legal, IT, and business teams to prepare for a new law's requirements well ahead of its effective date is regulatory change management, reflecting a proactive rather than reactive approach to adapting internal practices as legal and regulatory requirements evolve.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":744,"question":"A financial services company undergoes a formal external audit specifically to obtain a Service Organization Control (SOC 2) report, which it can then share with prospective customers as evidence of its security practices, rather than each customer needing to conduct its own separate audit. What compliance benefit does this shared audit report provide?","options":["It provides standardized, independently verified evidence of security practices that can be reused across multiple customer relationships, reducing redundant assessment effort","It has no practical benefit beyond internal recordkeeping with no external audience","It automatically satisfies every possible regulatory requirement the company could ever face","It replaces the need for the company to maintain any internal security controls whatsoever"],"correctIndex":0,"explanation":"obtaining a standardized, independently audited report like a SOC 2 that can be shared across multiple customer relationships provides reusable, independently verified evidence of security practices, reducing the redundant effort of each individual customer needing to conduct its own separate assessment of the same company.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":745,"question":"A company's compliance program includes mapping specific technical controls, such as encryption and access logging, directly to the exact regulatory clauses they satisfy, so that auditors can trace a straight line from a legal requirement to the technical evidence that fulfills it. What does this traceability primarily support?","options":["Audit readiness and defensibility, making it easier to demonstrate compliance with clear, direct evidence during a formal review","A purely cosmetic documentation exercise with no bearing on actual audit outcomes","An activity relevant only to organizations that have never previously undergone an audit","A requirement that applies exclusively to physical, non-technical security controls"],"correctIndex":0,"explanation":"mapping specific technical controls directly to the regulatory clauses they satisfy supports audit readiness and defensibility, making it considerably easier to demonstrate compliance with clear, traceable evidence when an auditor formally reviews the organization's practices.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":746,"question":"A company discovers during a compliance review that one of its business units has been retaining customer data far longer than the regulatory maximum retention period allows, due to a misconfigured deletion policy that was never properly updated. What is the appropriate response to this compliance gap?","options":["Remediate the misconfiguration promptly, document the finding and corrective action, and assess whether any regulatory disclosure obligation applies","Ignore the finding since it was caused by a technical misconfiguration rather than intentional wrongdoing","Wait until the next scheduled external audit to address the issue, regardless of ongoing exposure","Assume no further action is needed once the deletion policy is eventually corrected at some future date"],"correctIndex":0,"explanation":"discovering a compliance gap, such as data being retained beyond a regulatory maximum due to a misconfiguration, calls for prompt remediation, thorough documentation of the finding and corrective action taken, and an assessment of whether the situation triggers any regulatory disclosure obligation, rather than delaying action or assuming intent matters more than actual continued exposure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":747,"question":"A company's compliance training program requires every employee to complete an annual certification confirming they understand and will abide by the organization's data handling policies, with completion tracked and reported to leadership. What compliance concept does this tracked certification support?","options":["Accountability and evidence of compliance culture, providing documented proof that employees have acknowledged their compliance obligations","A purely symbolic exercise with no value during a regulatory investigation","A requirement that applies only to employees in the legal department","An activity that replaces the need for any technical security controls"],"correctIndex":0,"explanation":"requiring and tracking an annual certification where employees acknowledge their compliance obligations supports accountability and provides documented evidence of a compliance-aware culture, which can be valuable evidence during a regulatory investigation showing the organization took reasonable steps to ensure employee awareness.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":748,"question":"A company that suffers a data breach involving personal information determines, based on applicable law, that it must notify affected individuals and a government regulator within a specific number of days after discovering the breach. What compliance concept does this notification requirement represent?","options":["A breach notification requirement, a specific legal obligation triggered by a qualifying security incident involving certain types of data","A voluntary best practice with no binding legal deadline attached","A requirement that applies only if the company chooses to disclose the breach publicly on its own initiative","An obligation that only applies to breaches affecting more than one million individuals"],"correctIndex":0,"explanation":"a legal requirement to notify affected individuals and a regulator within a specific timeframe after discovering a qualifying breach is a breach notification requirement, a binding legal obligation under many privacy and data protection laws, distinct from a purely voluntary disclosure practice.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":749,"question":"A company's legal team reviews new contracts with international clients to determine whether specific data transfer mechanisms, such as standard contractual clauses, are required to legally move personal data across certain international borders. What compliance concern does this contract review address?","options":["Cross-border data transfer compliance, ensuring personal data moved between jurisdictions meets applicable legal requirements for that transfer","A purely commercial negotiation point with no connection to any legal requirement","A concern that only applies to physical shipments of paper records","A requirement that has been eliminated entirely by modern cloud computing"],"correctIndex":0,"explanation":"reviewing whether specific legal mechanisms are required before personal data can be transferred across certain international borders addresses cross-border data transfer compliance, since many privacy laws impose specific legal requirements on how personal data may be moved between different jurisdictions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":750,"question":"A publicly traded company's compliance program includes specific controls required under securities law to ensure the accuracy and integrity of financial reporting systems, including access controls and change management for systems that feed into financial statements. What compliance driver is this program primarily addressing?","options":["Financial regulatory compliance, addressing legal requirements specifically tied to the integrity of financial reporting for a publicly traded company","A purely voluntary internal quality improvement initiative with no legal basis","A requirement that applies equally to every company regardless of whether it is publicly traded","A framework focused exclusively on customer data privacy rather than financial reporting"],"correctIndex":0,"explanation":"implementing specific controls around access and change management for systems that feed into financial statements, as required for publicly traded companies under securities law, addresses financial regulatory compliance, a distinct legal driver from general data privacy or industry security standards.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":751,"question":"A company's compliance dashboard tracks the status of every open audit finding, showing which have been remediated, which are in progress, and which are overdue past their committed remediation date, with automatic escalation to leadership for overdue items. What compliance management concept does this tracking process support?","options":["Remediation tracking and accountability, ensuring identified compliance gaps are actually resolved in a timely manner rather than being identified and then forgotten","A purely cosmetic reporting exercise with no real operational impact","A process that only applies to findings identified by internal, not external, auditors","An activity that eliminates the need for future audits once all current findings are closed"],"correctIndex":0,"explanation":"tracking the status of every audit finding through to remediation, with automatic escalation for overdue items, supports remediation tracking and accountability, ensuring identified compliance gaps are actually resolved in a timely manner rather than being documented once and then forgotten without follow-through.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":752,"question":"A company sends simulated phishing emails to its employees on a regular basis, tracking which employees click the link, and automatically enrolling those who click into a short, targeted follow-up training module about recognizing phishing red flags. What security awareness concept does this program represent?","options":["Simulated phishing testing combined with targeted, just-in-time training, reinforcing awareness based on actual employee behavior rather than a generic annual session","A penetration test, actively attempting to exploit technical vulnerabilities","A vulnerability scan, identifying missing patches across the environment","A tabletop exercise, simulating an incident response scenario for the IT team"],"correctIndex":0,"explanation":"sending simulated phishing emails and automatically providing targeted follow-up training to employees who click is simulated phishing testing combined with just-in-time training, which reinforces awareness based on actual observed employee behavior rather than relying solely on a generic, one-size-fits-all annual training session.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":753,"question":"A company's security awareness program includes short, five-minute training modules delivered monthly on a single focused topic, such as recognizing social engineering or safely handling sensitive documents, rather than a single lengthy annual training session covering everything at once. What learning principle does this approach reflect?","options":["Microlearning/spaced repetition, breaking training into smaller, more frequent sessions to improve retention compared to a single lengthy session","A belief that security awareness training provides no measurable benefit regardless of format","A requirement that only applies to new employees during their first week","An approach that eliminates the need for any annual compliance training entirely"],"correctIndex":0,"explanation":"delivering short, focused training modules on a regular monthly basis, rather than one long annual session, reflects the microlearning and spaced repetition principle, which research suggests improves long-term retention of information compared to infrequent, lengthy training sessions.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":754,"question":"During new employee onboarding, a company requires every new hire to complete security awareness training covering the company's acceptable use policy, password requirements, and how to report a suspected security incident, before their account is granted full system access. What does timing this training during onboarding help ensure?","options":["Employees understand their security responsibilities and reporting procedures from their very first days with access to company systems","Employees never need any further security training for the remainder of their employment","The training requirement applies only to employees in technical IT roles","New employees are exempt from following the acceptable use policy during their first month"],"correctIndex":0,"explanation":"requiring security awareness training as part of onboarding, before full system access is granted, ensures employees understand their security responsibilities and how to report a suspected incident from their very first days with access, rather than leaving a gap where a new employee has access without understanding the expectations.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":755,"question":"A company's security awareness training includes a module specifically covering how to recognize and respond to business email compromise attempts, using real (anonymized) examples of past incidents that targeted similar organizations. What benefit does using real, anonymized examples provide compared to purely hypothetical scenarios?","options":["Real examples make the training more relatable and credible, helping employees understand that these threats are genuinely occurring rather than purely theoretical","Real examples have no advantage over purely hypothetical scenarios in terms of employee engagement or retention","Using real examples is prohibited under all circumstances due to privacy concerns","Real examples eliminate the need to update training content in the future"],"correctIndex":0,"explanation":"using real, anonymized examples of past incidents makes security awareness training more relatable and credible for employees, helping them understand that the threats being discussed are genuinely occurring rather than purely theoretical, which tends to improve engagement and retention compared to abstract hypothetical scenarios alone.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":756,"question":"A company's security awareness program includes role-specific training, where finance department employees receive additional training focused on wire transfer fraud and invoice scams, while software developers receive additional training on secure coding practices. What training design principle does this role-specific approach reflect?","options":["Tailoring training content to the specific risks and responsibilities relevant to each employee's role, rather than delivering identical generic content to everyone","A belief that only employees in technical roles need any security training at all","A requirement that finance and development employees receive no training in common at all","An approach that eliminates the need for any organization-wide baseline training"],"correctIndex":0,"explanation":"providing additional, role-specific training content tailored to the particular risks relevant to a given department, such as wire transfer fraud for finance staff or secure coding for developers, reflects the principle of tailoring training to actual role-based risk rather than delivering identical generic content to every employee regardless of their specific exposure.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":757,"question":"A company's security team tracks metrics such as the percentage of employees who complete required training on time, the click rate on simulated phishing tests over successive quarters, and the number of security incidents self-reported by employees, using these metrics to evaluate the training program's effectiveness. Why is tracking metrics like these valuable?","options":["It provides measurable evidence of whether the training program is actually changing employee behavior over time, rather than assuming completion alone equals genuine awareness","It has no practical value since training completion is the only meaningful measure of program success","It is required solely to satisfy an unrelated financial reporting obligation","It replaces the need to ever update or improve the training content itself"],"correctIndex":0,"explanation":"tracking metrics such as phishing click rates over time and self-reported incidents provides measurable evidence of whether the training program is actually changing employee behavior, since simply tracking completion rates alone doesn't confirm that employees genuinely understood or retained the material, or that real-world behavior actually improved.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":758,"question":"A company's security awareness training explicitly covers how to identify and report suspicious behavior from coworkers, such as unusual data access patterns or unexplained financial hardship, as part of its insider threat awareness efforts. What broader security goal does this specific training content support?","options":["Building a culture where employees feel empowered and knowledgeable enough to help identify potential insider threats, complementing technical monitoring controls","A goal that has no connection to any technical security control whatsoever","A requirement that applies only to employees working in human resources","An effort focused exclusively on external attackers, never insider risks"],"correctIndex":0,"explanation":"training employees to recognize and report signs of potential insider threats builds a security-aware culture that complements technical monitoring controls, since employees interacting daily with coworkers may notice behavioral warning signs that automated technical systems alone would not detect.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":759,"question":"A company's security awareness program includes a clearly publicized, simple process for employees to report a suspected phishing email or security concern with a single click, without fear of embarrassment or blame if the report turns out to be a false alarm. Why is removing the fear of blame an important design element of this reporting process?","options":["It encourages employees to report suspicious activity promptly rather than staying silent out of fear of being wrong or getting in trouble, which is critical for early detection","It has no bearing on how quickly or frequently employees report suspicious activity","It is only relevant for employees who have already made a reporting mistake in the past","It eliminates the need for the security team to ever investigate any reported incident"],"correctIndex":0,"explanation":"removing fear of blame or embarrassment from the reporting process encourages employees to report suspicious activity promptly, even when they aren't entirely certain, which is critical for early detection, since a culture of fear tends to cause employees to stay silent rather than risk being wrong.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":760,"question":"A company's annual security awareness training includes a section specifically on safe practices for remote and hybrid work, covering topics like securing home Wi-Fi networks, avoiding public Wi-Fi for sensitive work, and properly locking devices when stepping away in a shared space like a coffee shop. What does the inclusion of this section reflect about effective security awareness programs?","options":["Training content should evolve to address the organization's actual current work environment and risks, rather than remaining static regardless of how work practices change","Training content should never change once it has been initially developed and approved","Remote work security has no meaningful connection to overall organizational security awareness","This type of content is only relevant for employees who have never worked in an office"],"correctIndex":0,"explanation":"including content specifically addressing remote and hybrid work risks reflects the principle that effective security awareness training should evolve to address the organization's actual current work environment and risks, rather than remaining a static, one-size-fits-all program that ignores how work practices have changed over time.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":761,"question":"A company's security awareness training includes an interactive module where employees must correctly identify several example emails as either legitimate or phishing, receiving immediate feedback and an explanation for each answer, rather than simply reading a static document about phishing indicators. What learning benefit does this interactive, feedback-driven format provide?","options":["Active engagement with immediate feedback tends to improve retention and practical skill-building compared to passively reading static content","Interactive formats have been shown to provide no additional benefit compared to passive reading","This format is only appropriate for training new employees during their first day","Interactive training eliminates any need for employees to ever encounter real phishing attempts"],"correctIndex":0,"explanation":"actively engaging with example scenarios and receiving immediate feedback with explanations tends to improve both retention and practical skill-building compared to passively reading a static document, since active practice with feedback more closely mirrors the real decision-making employees must do when encountering an actual suspicious email.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":762,"question":"A company's executive leadership team completes the same core security awareness training required of all employees, and senior leaders visibly reference the training's importance during company meetings. What security culture benefit does this visible leadership participation provide?","options":["It reinforces that security awareness is a genuine organizational priority rather than a mere compliance checkbox, encouraging broader employee buy-in","It has no measurable effect on how seriously other employees take the training program","It is only a symbolic gesture required for regulatory purposes with no cultural impact","It exempts executives from any further individual security responsibility"],"correctIndex":0,"explanation":"visible participation and vocal support from executive leadership reinforces that security awareness is a genuine organizational priority, not merely a compliance checkbox exercise, which tends to encourage broader employee buy-in and engagement with the training program across the organization.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":763,"question":"A company's security awareness training includes specific guidance on how to verify a suspicious request for a wire transfer or gift card purchase that appears to come from a senior executive, such as confirming the request through a separate, known communication channel before acting. What type of social engineering threat does this specific guidance address?","options":["Business email compromise (CEO fraud), where an attacker impersonates a senior executive to pressure an employee into an unauthorized financial action","A technical malware infection unrelated to social engineering","A physical tailgating attempt to gain unauthorized building access","A wireless evil twin attack targeting the corporate Wi-Fi network"],"correctIndex":0,"explanation":"guidance on verifying suspicious executive-impersonation requests for wire transfers or gift cards through a separate communication channel specifically addresses business email compromise, also known as CEO fraud, a social engineering threat that exploits authority and urgency to pressure a hasty financial action.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":764,"question":"A company measures the success of its security awareness program not just by training completion rates, but by tracking a steady decline in the number of employees who click on simulated phishing links over several successive training cycles. What does this declining trend suggest about the training program?","options":["The training appears to be effectively changing employee behavior over time, rather than merely satisfying a completion requirement without real impact","The training program has failed, since any level of clicking above zero percent indicates complete failure","This metric has no meaningful relationship to the actual effectiveness of security awareness training","The company should immediately discontinue the training program since improvement has already been achieved"],"correctIndex":0,"explanation":"a steady decline in simulated phishing click rates over successive training cycles suggests the training is effectively changing actual employee behavior over time, providing more meaningful evidence of real-world impact than completion rates alone, which only measure participation rather than genuine behavioral change.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":765,"question":"A company requires that employees who repeatedly fail simulated phishing tests receive additional one-on-one coaching from the security team, rather than simply being flagged and left to click through the same generic training module again. What does this escalated, personalized approach reflect about effective training design?","options":["Training approaches may need to be adapted for individuals who don't respond to standard methods, rather than applying a uniform response regardless of demonstrated need","Repeated phishing test failures should always result in immediate termination with no coaching offered","Standard generic training modules are always sufficient for every employee regardless of their individual results","Personalized coaching has no meaningful advantage over repeating the same generic module"],"correctIndex":0,"explanation":"providing escalated, personalized coaching for employees who repeatedly fail simulated phishing tests, rather than just repeating the same generic training, reflects the recognition that some individuals may need an adapted approach to genuinely absorb the material, since a uniform response that isn't working the first few times is unlikely to suddenly succeed through pure repetition.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":766,"question":"A company's security awareness training program is reviewed and updated at least annually to reflect newly emerging threats, such as a rise in deepfake voice phishing attempts impersonating executives, rather than being left unchanged for years at a time. What principle does this regular content review reflect?","options":["Security awareness training must evolve alongside the current threat landscape to remain relevant and effective, rather than becoming outdated","Once security awareness training content is created, it never needs to be reviewed or changed again","Only technical security controls, never training content, need to be updated as threats evolve","Emerging threats like deepfake voice phishing have no relevance to employee-facing training content"],"correctIndex":0,"explanation":"regularly reviewing and updating training content to reflect newly emerging threats, such as deepfake voice phishing, reflects the principle that security awareness training must evolve alongside the current threat landscape to remain relevant and effective, rather than becoming outdated and failing to prepare employees for the threats they are actually likely to encounter.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"},{"id":767,"question":"A company encrypts its customer database backups before storing them, but investigators later discover the encryption keys were stored in the same location as the backups themselves, meaning anyone who accessed the backup storage could also decrypt the data. What data protection principle was violated?","options":["Proper key management, which requires storing encryption keys separately from the data they protect","Data classification, which requires labeling data by sensitivity","Data minimization, which requires collecting only necessary data","Data sovereignty, which requires data to stay within a specific jurisdiction"],"correctIndex":0,"explanation":"storing encryption keys in the same location as the encrypted data defeats the purpose of encryption, since anyone who can access the data can also access the keys needed to decrypt it; proper key management requires keeping keys separate from the data they protect.","domain":"3.0 Security Architecture","objectiveId":"3.3","objective":"Data Protection Concepts","source":"original-2026-batch"},{"id":768,"question":"A company's asset inventory records the physical location of every server, but after a departmental reorganization, dozens of servers were physically relocated to a new data center without anyone updating the inventory, leaving the records inaccurate for months. What risk does this outdated inventory create?","options":["Difficulty responding to a physical security incident or disaster, since responders would be relying on inaccurate location information","No risk at all, since physical location has no bearing on any security process","A risk that only affects the company's real estate budget, not its security posture","A risk that is automatically corrected the next time a server reboots"],"correctIndex":0,"explanation":"an outdated asset inventory that lists incorrect physical locations creates real risk during a physical security incident or disaster response, since responders relying on that inaccurate information could waste critical time looking in the wrong place or fail to account for assets that were actually moved.","domain":"4.0 Security Operations","objectiveId":"4.2","objective":"Asset Management","source":"original-2026-batch"},{"id":769,"question":"A company's security team builds an automated script that checks every newly created user account against a list of already-departed employees each night, automatically disabling any account that shouldn't still be active. What risk does this specific automation address?","options":["The risk of terminated employees retaining active access due to a manual offboarding step being missed or delayed","The risk of new employees never receiving any system access at all","The risk of the company running out of available usernames","The risk of a scheduled software update failing to install"],"correctIndex":0,"explanation":"automatically cross-checking active accounts against a list of departed employees and disabling any that shouldn't still be active directly addresses the risk of a terminated employee retaining access because a manual offboarding step was missed or delayed, which is a common and serious insider risk if left unaddressed.","domain":"4.0 Security Operations","objectiveId":"4.7","objective":"Automation & Orchestration","source":"original-2026-batch"},{"id":770,"question":"A forensic analyst investigating a compromised point-of-sale system requests transaction logs from the payment processor, since the local device's own logs were deleted by the attacker before the compromise was discovered. What does reliance on this external log source illustrate?","options":["Maintaining logs in multiple independent locations, including with external partners, can preserve evidence even when local logs are destroyed by an attacker","External log sources are always legally inadmissible regardless of the circumstances","Payment processors never retain any transaction-related logs that could assist an investigation","Local device logs are always more reliable than any externally maintained log source"],"correctIndex":0,"explanation":"successfully obtaining transaction logs from an external payment processor after local logs were deleted by the attacker illustrates the value of maintaining logs in multiple independent locations, since evidence held by an external party can still be recovered even when an attacker successfully destroys logs on the compromised local device itself.","domain":"4.0 Security Operations","objectiveId":"4.9","objective":"Digital Forensics & Investigation Data Sources","source":"original-2026-batch"},{"id":771,"question":"A company discovers that a critical software vendor it relies on has filed for bankruptcy with no clear plan for continued product support, leaving the company without a path to future security patches for that software. What third-party risk management step, if taken earlier, would have helped the company prepare for this scenario?","options":["Assessing vendor financial stability and having a contingency or exit plan as part of ongoing vendor risk management","Assuming vendor bankruptcy can never actually happen and requires no contingency planning","Relying solely on the vendor's marketing materials to gauge its long-term viability","Waiting until after the bankruptcy to begin any contingency planning"],"correctIndex":0,"explanation":"assessing a vendor's financial stability and maintaining a contingency or exit plan as an ongoing part of vendor risk management would have helped the company prepare for a scenario like vendor bankruptcy, rather than being caught without any patching path once the vendor could no longer support its product.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.3","objective":"Third-Party Risk Management","source":"original-2026-batch"},{"id":772,"question":"A company operating in a heavily regulated industry designates a specific committee, including representatives from legal, security, and business operations, to formally review and approve any new compliance-related policy before it takes effect. What compliance governance concept does this committee structure represent?","options":["Formal compliance governance, ensuring cross-functional review and accountability before new policies are adopted","A purely informal, ad hoc process with no defined structure or accountability","A structure that applies only to policies unrelated to any regulatory requirement","A committee whose approval has no actual bearing on whether a policy takes effect"],"correctIndex":0,"explanation":"designating a formal, cross-functional committee to review and approve compliance-related policies before adoption represents structured compliance governance, ensuring accountability and multiple relevant perspectives are considered before a policy affecting regulatory obligations takes effect.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.4","objective":"Security Compliance","source":"original-2026-batch"},{"id":773,"question":"A company's security awareness program includes a brief, mandatory refresher training triggered automatically whenever an employee changes roles into a position with access to more sensitive data than their previous role. What does this role-change trigger reflect about effective training design?","options":["Training should be responsive to changes in an individual's actual risk exposure, not delivered only on a fixed annual schedule regardless of role changes","Training should only ever be delivered once, at the very start of an employee's very first day","Role changes have no bearing on what security training content is relevant to a given employee","A fixed annual training schedule is always sufficient regardless of any change in an employee's responsibilities"],"correctIndex":0,"explanation":"automatically triggering refresher training when an employee moves into a role with greater data access reflects the principle that training should be responsive to actual changes in an individual's risk exposure, rather than relying solely on a fixed annual schedule that might not account for a role change granting significantly more sensitive access mid-year.","domain":"5.0 Security Program Management & Oversight","objectiveId":"5.6","objective":"Security Awareness Training","source":"original-2026-batch"}];
